bool lower_binary_to_x(LoweringContext& context, const Expression& expression,
                       bool allow_constant_fold = true) {
  if (can_reuse_x_param_value_call_temp(context, expression)) {
    const std::optional<std::string> scratch = x_param_value_scratch_name(context);
    if (!scratch.has_value() || expression.left == nullptr || expression.right == nullptr)
      return false;
    if (!lower_call_to_x(context, *expression.left))
      return false;
    if (!lower_call_to_x(context, *expression.right))
      return false;
    emit_recall(context, *scratch);
    context.emitter.emit_op(0x10, "+", "expr +");
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    context.optimizations.push_back(OptimizationReport{
        .name = "x-param-value-call-temp-reuse",
        .detail = "Hoisted 1 nested X-parameter value function call through " + *scratch + ".",
    });
    return true;
  }
  auto expr_api = expression_emit_api(context, allow_constant_fold);
  return core::emit::lower_binary_expression_to_x(expr_api, context, expression,
                                                  allow_constant_fold);
}

std::string function_label(const std::string& name) {
  return "__fn_" + name;
}

void mark_last_emitted_call_role(LoweringContext& context, std::string role) {
  if (context.emitter.items.size() < 2U)
    return;
  context.emitter.items.at(context.emitter.items.size() - 2U).roles.push_back(std::move(role));
}

std::string x_param_y_stack_stored_entry_label(const std::string& name) {
  return "__xparam_ystack_entry_" + name;
}

std::string packed_line_family_score_zero_entry_label(const std::string& name) {
  return "__packed_line_family_score_zero_entry_" + name;
}

bool lower_rule_arguments(LoweringContext& context, const V2Rule& rule,
                          const std::vector<Expression>& args) {
  if (args.size() > rule.params.size()) {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                             "Too many native arguments for '" + rule.name + "'"));
    return false;
  }
  const bool terminal_rule =
      statements_always_stop(context, rule.body) && !statements_contain_return(rule.body);
  for (std::size_t index = 0; index < args.size(); ++index) {
    std::vector<const Expression*> nested_calls;
    collect_expression_calls(args.at(index), nested_calls);
    if (!nested_calls.empty()) {
      context.optimizations.push_back(OptimizationReport{
          .name = "function-call-lifting",
          .detail = "Hoisted nested function call argument " + std::to_string(index + 1U) +
                    " for " + rule.name + ".",
      });
    }
    if (!lower_expression_to_x(context, args.at(index)))
      return false;
    emit_store(context, rule.params.at(index),
               terminal_rule ? "set " + rule.params.at(index)
                             : "arg " + rule.params.at(index) + " for " + rule.name);
  }
  return true;
}

bool compile_x_param_first_expression(LoweringContext& context, const Expression& expression,
                                      const std::string& param, int line) {
  if (!expression_can_consume_identifier_from_x(expression, param))
    return false;
  if (expression.kind == "identifier")
    return expression.name == param;
  if (expression.kind == "unary") {
    if (expression.op != "-" || expression.expr == nullptr ||
        !compile_x_param_first_expression(context, *expression.expr, param, line))
      return false;
    context.emitter.emit_op(0x0b, "/-/", "x-param unary minus", line);
    return true;
  }
  if (expression.kind == "binary") {
    if (expression.left == nullptr || expression.right == nullptr)
      return false;
    const bool left_uses = expression_contains_identifier(*expression.left, param);
    const bool right_uses = expression_contains_identifier(*expression.right, param);
    if (left_uses == right_uses)
      return false;
    if (left_uses) {
      if (!compile_x_param_first_expression(context, *expression.left, param, line))
        return false;
      if (!lower_expression_to_x(context, *expression.right))
        return false;
    } else {
      if (expression.op != "+" && expression.op != "*")
        return false;
      if (!compile_x_param_first_expression(context, *expression.right, param, line))
        return false;
      if (!lower_expression_to_x(context, *expression.left))
        return false;
    }
    const std::optional<std::pair<int, std::string>> op = binary_opcode(expression.op);
    if (!op.has_value())
      return false;
    context.emitter.emit_op(op->first, op->second, "x-param expr " + expression.op, line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }
  if (expression.kind == "call" && expression.args.size() == 1) {
    if (!compile_x_param_first_expression(context, expression.args.front(), param, line))
      return false;
    const std::optional<std::pair<int, std::string>> opcode =
        x_transform_unary_opcode(expression.callee);
    if (!opcode.has_value())
      return false;
    context.emitter.emit_op(opcode->first, opcode->second, "x-param " + expression.callee + "()",
                            line);
    return true;
  }
  return false;
}

bool lower_x_param_rule_call(LoweringContext& context, const V2Rule& rule,
                             const std::vector<Expression>& args, int line) {
  const auto lowering_it = context.x_param_procs.find(rule.name);
  if (lowering_it == context.x_param_procs.end())
    return false;
  const XParamProcLowering& lowering = lowering_it->second;
  if (args.size() != 1) {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                             rule.name + " expects one native argument"));
    return false;
  }
  const bool already_in_x = args.front().kind == "identifier" &&
                            (context.emitter.current_x_variable == args.front().name ||
                             context.emitter.current_x_aliases.contains(args.front().name));
  if (!lower_expression_to_x(context, args.front()))
    return false;
  if (statements_always_stop(context, rule.body) && !statements_contain_return(rule.body)) {
    context.emitter.emit_jump(0x51, "БП", function_label(rule.name),
                              "terminal rule " + rule.name, line);
    context.optimizations.push_back(OptimizationReport{
        .name = "x-param-proc-call",
        .detail = "Passed " + lowering.param + " to " + rule.name + " through X" +
                  std::string(already_in_x ? " (already in X)." : "."),
    });
    context.optimizations.push_back(OptimizationReport{
        .name = "terminal-rule-tail-call",
        .detail = "Compiled terminal rule " + rule.name +
                  " as a direct jump instead of a subroutine call.",
    });
    clear_current_x_facts(context);
    return true;
  }
  context.emitter.emit_jump(0x53, "ПП", function_label(rule.name), "call function " + rule.name,
                            line);
  mark_last_emitted_call_role(context, "statement-proc-call");
  mark_last_emitted_call_role(context, "x-argument-call");
  context.optimizations.push_back(OptimizationReport{
      .name = "x-param-proc-call",
      .detail = "Passed " + lowering.param + " to " + rule.name + " through X" +
                std::string(already_in_x ? " (already in X)." : "."),
  });
  if (const std::optional<std::string> return_x = proc_return_x_variable(context, rule)) {
    mark_current_x(context, *return_x);
    context.emitter.current_x_known_zero = false;
  } else {
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
  }
  return true;
}

bool lower_inline_param_rule_call(LoweringContext& context, const V2Rule& rule,
                                  const std::vector<Expression>& args, int line) {
  if (!context.inline_statement_rules.contains(rule.name) || rule.params.size() != 1U ||
      args.size() != 1U || rule.body.empty() || statements_contain_return(rule.body) ||
      count_identifier_reads_in_statements(rule.body, rule.params.front()) != 1 ||
      context.inline_call_stack.contains(rule.name)) {
    return false;
  }

  if (!lower_expression_to_x(context, args.front()))
    return false;

  context.inline_call_stack.insert(rule.name);
  mark_current_x(context, rule.params.front());
  context.emitter.current_x_known_zero = false;
  const bool lowered = lower_statement_block(context, rule.body);
  context.inline_call_stack.erase(rule.name);
  if (lowered) {
    const int uses =
        context.proc_call_counts.contains(rule.name) ? context.proc_call_counts[rule.name] : 1;
    context.optimizations.push_back(OptimizationReport{
        .name = uses == 1 ? "single-use-rule-inline" : "size-model-rule-inline",
        .detail = uses == 1 ? "Inlined single-use rule " + rule.name + " at line " +
                                  std::to_string(line) + "."
                            : "Inlined " + std::to_string(uses) + "-use rule " + rule.name +
                                  " because it is smaller than a ПП/В/О subroutine.",
    });
    context.optimizations.push_back(OptimizationReport{
        .name = "dead-store-elimination",
        .detail = "Removed 1 store(s) to register(s) never read before the next assignment.",
    });
  }
  return lowered;
}

bool compile_x_param_return_decay_body(LoweringContext& context, const XParamReturnDecay& decay) {
  context.emitter.emit_op(0x0e, "В↑", "x-param decay keep base", decay.line);
  if (!lower_expression_to_x(context, decay.factor))
    return false;
  context.emitter.emit_op(0x12, "*", "x-param decay scale", decay.line);
  if (!lower_expression_to_x(context, decay.divisor))
    return false;
  context.emitter.emit_op(0x13, "/", "x-param decay divide", decay.line);
  context.emitter.emit_op(0x34, "К [x]", "x-param decay int", decay.line);
  context.emitter.emit_op(0x11, "-", "x-param decay subtract", decay.line);
  return true;
}

bool emit_x_param_return_decay_call(LoweringContext& context, const V2Rule& rule,
                                    const XParamReturnDecay& decay, int line,
                                    bool through_x_detail) {
  context.emitter.emit_jump(0x53, "ПП", function_label(rule.name), "call function " + rule.name,
                            line);
  mark_last_emitted_call_role(context, "x-argument-call");
  context.optimizations.push_back(OptimizationReport{
      .name = "x-param-return-decay-call",
      .detail = through_x_detail ? "Passed " + decay.param + " to " + rule.name + " through X."
                                 : "Passed current X to " + rule.name + ".",
  });
  clear_current_x_facts(context);
  return true;
}

bool lower_x_param_return_decay_call(LoweringContext& context, const V2Rule& rule,
                                     const std::vector<Expression>& args, int line) {
  const std::optional<XParamReturnDecay> decay = match_x_param_return_decay(rule);
  if (!decay.has_value())
    return false;
  if (args.size() != 1) {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                             rule.name + " expects one native argument"));
    return false;
  }
  if (!lower_expression_to_x(context, args.front()))
    return false;
  return emit_x_param_return_decay_call(context, rule, *decay, line, true);
}

void emit_positive_modulo_of_current_x(LoweringContext& context, int width, int line) {
  const std::string width_text = std::to_string(width);
  context.emitter.emit_op(0x34, "К [x]", "x-param value integer part", line);
  emit_number_or_preload(context, width_text, std::nullopt, line);
  context.emitter.emit_op(0x13, "/", "x-param value modulo quotient", line);
  context.emitter.emit_op(0x35, "К {x}", "x-param value modulo fraction", line);
  emit_number_or_preload(context, width_text, std::nullopt, line);
  context.emitter.emit_op(0x12, "*", "x-param value modulo scale", line);
}

bool compile_x_param_value_function_body(LoweringContext& context, const V2Rule& rule,
                                         const XParamValueFunctionMatch& match,
                                         const std::string& scratch) {
  emit_positive_modulo_of_current_x(context, match.width, match.line);
  emit_store(context, scratch, "set " + scratch);

  V2Statement positive_assign;
  positive_assign.kind = "v2_assign";
  positive_assign.target = scratch;
  positive_assign.expr = scratch + " + " + std::to_string(match.width);
  positive_assign.line = match.line;

  V2Statement branch;
  branch.kind = "v2_if";
  branch.predicate = V2Predicate{
      .kind = "v2_compare",
      .left = scratch,
      .op = "<=",
      .right = "0",
  };
  branch.then_body = {positive_assign};
  branch.line = match.line;

  V2Statement ret;
  ret.kind = "v2_return";
  ret.expr = scratch;
  ret.line = match.line;

  if (!lower_statement_block(context, {branch, ret}))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "x-param-value-function",
      .detail = "Compiled " + rule.name + " to consume " + match.param +
                " directly from X through " + scratch + ".",
  });
  return true;
}

bool lower_x_param_value_function_call(LoweringContext& context, const V2Rule& rule,
                                       const std::vector<Expression>& args, int line) {
  if (!context.x_param_value_functions)
    return false;
  const std::optional<std::string> scratch = x_param_value_scratch_name(context);
  const std::optional<XParamValueFunctionMatch> match = match_x_param_value_function(rule);
  if (!scratch.has_value() || !match.has_value())
    return false;
  if (args.size() != 1) {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                             rule.name + " expects one native argument"));
    return false;
  }
  if (!lower_expression_to_x(context, args.front()))
    return false;
  context.emitter.emit_jump(0x53, "ПП", function_label(rule.name), "call function " + rule.name,
                            line);
  context.optimizations.push_back(OptimizationReport{
      .name = "x-param-value-function-call",
      .detail = "Passed " + match->param + " to " + rule.name + " through X.",
  });
  clear_current_x_facts(context);
  return true;
}

struct PackedScoreTerm {
  Expression line_value;
  Expression index;
  int line = 0;
};

struct PackedLineFamilyScoreRule {
  std::string score;
  std::string normalizer;
  std::string normalizer_param;
  std::string normalizer_return;
  PackedScoreTerm first;
  PackedScoreTerm second;
  PackedScoreTerm diagonal_add;
  PackedScoreTerm diagonal_sub;
  Expression shared;
  Expression partial;
  int diagonal_add_raw_line = 0;
  int diagonal_sub_raw_line = 0;
  int diagonal_add_score_line = 0;
  int diagonal_sub_score_line = 0;
  int line = 0;
};

bool expression_equals(const Expression& left, const Expression& right) {
  return expression_to_json(left) == expression_to_json(right);
}

bool is_simple_stack_load(const Expression& expression) {
  return expression.kind == "identifier" || expression.kind == "number";
}

std::optional<PackedScoreTerm> packed_score_term(const Expression& expression, int line) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "packed_score" ||
      expression.args.size() != 2)
    return std::nullopt;
  return PackedScoreTerm{
      .line_value = expression.args.at(0),
      .index = expression.args.at(1),
      .line = line,
  };
}

std::optional<std::pair<PackedScoreTerm, PackedScoreTerm>>
packed_score_pair(const Expression& expression, int line) {
  if (expression.kind != "binary" || expression.op != "+" || expression.left == nullptr ||
      expression.right == nullptr)
    return std::nullopt;
  const std::optional<PackedScoreTerm> first = packed_score_term(*expression.left, line);
  const std::optional<PackedScoreTerm> second = packed_score_term(*expression.right, line);
  if (!first.has_value() || !second.has_value())
    return std::nullopt;
  return std::pair{*first, *second};
}

std::optional<PackedScoreTerm> packed_score_accumulator_term(const V2Statement& statement,
                                                             const std::string& score,
                                                             const std::string& index_name) {
  if (!statement.target.has_value() || *statement.target != score || !statement.expr.has_value())
    return std::nullopt;
  if (statement.kind == "v2_update" && statement.op == "+=") {
    const Expression expression = parse_expression(*statement.expr, statement.line);
    std::optional<PackedScoreTerm> term = packed_score_term(expression, statement.line);
    if (term.has_value() && term->index.kind == "identifier" && term->index.name == index_name)
      return term;
  }
  if (statement.kind == "v2_assign") {
    const Expression expression = parse_expression(*statement.expr, statement.line);
    if (expression.kind == "binary" && expression.op == "+" && expression.left != nullptr &&
        expression.right != nullptr) {
      const Expression target = identifier_expression(score);
      if (expression_equals(*expression.left, target)) {
        std::optional<PackedScoreTerm> term = packed_score_term(*expression.right, statement.line);
        if (term.has_value() && term->index.kind == "identifier" && term->index.name == index_name)
          return term;
      }
      if (expression_equals(*expression.right, target)) {
        std::optional<PackedScoreTerm> term = packed_score_term(*expression.left, statement.line);
        if (term.has_value() && term->index.kind == "identifier" && term->index.name == index_name)
          return term;
      }
    }
  }
  return std::nullopt;
}

std::optional<std::pair<Expression, Expression>> shared_add_sub_operands(const Expression& add,
                                                                         const Expression& sub) {
  if (add.kind != "binary" || add.op != "+" || sub.kind != "binary" || sub.op != "-" ||
      add.left == nullptr || add.right == nullptr || sub.left == nullptr || sub.right == nullptr)
    return std::nullopt;
  if (!expression_equals(*add.left, *sub.left) || !expression_equals(*add.right, *sub.right))
    return std::nullopt;
  if (!is_simple_stack_load(*add.left) || !is_simple_stack_load(*add.right))
    return std::nullopt;
  return std::pair{*add.left, *add.right};
}

std::optional<PackedLineFamilyScoreRule>
packed_line_family_score_rule(const LoweringContext& context, const V2Rule& rule) {
  if (rule.body.empty())
    return std::nullopt;

  const V2Statement& first_assign = rule.body.front();
  if (first_assign.kind != "v2_assign" || !first_assign.target.has_value() ||
      !first_assign.expr.has_value()) {
    return std::nullopt;
  }

  const Expression first_expression = parse_expression(*first_assign.expr, first_assign.line);
  const std::optional<std::pair<PackedScoreTerm, PackedScoreTerm>> first_pair =
      packed_score_pair(first_expression, first_assign.line);
  if (!first_pair.has_value())
    return std::nullopt;

  auto finish_match = [&](const V2Statement& add_call, const V2Statement& add_score,
                          const V2Statement& sub_call, const V2Statement& sub_score,
                          const Expression& add_arg, const Expression& sub_arg,
                          int add_raw_line,
                          int sub_raw_line) -> std::optional<PackedLineFamilyScoreRule> {
    if (add_call.kind != "v2_invoke" || sub_call.kind != "v2_invoke" ||
        !add_call.name.has_value() || !sub_call.name.has_value() ||
        *add_call.name != *sub_call.name) {
      return std::nullopt;
    }

    const auto normalizer_it = context.x_param_procs.find(*add_call.name);
    if (normalizer_it == context.x_param_procs.end() ||
        !normalizer_it->second.first.target.has_value()) {
      return std::nullopt;
    }
    const std::string& normalizer_return = *normalizer_it->second.first.target;

    const std::optional<PackedScoreTerm> add_term =
        packed_score_accumulator_term(add_score, *first_assign.target, normalizer_return);
    const std::optional<PackedScoreTerm> sub_term =
        packed_score_accumulator_term(sub_score, *first_assign.target, normalizer_return);
    if (!add_term.has_value() || !sub_term.has_value()) {
      return std::nullopt;
    }

    const std::optional<std::pair<Expression, Expression>> diagonal =
        shared_add_sub_operands(add_arg, sub_arg);
    if (!diagonal.has_value()) {
      return std::nullopt;
    }

    return PackedLineFamilyScoreRule{
        .score = *first_assign.target,
        .normalizer = *add_call.name,
        .normalizer_param = normalizer_it->second.param,
        .normalizer_return = normalizer_return,
        .first = first_pair->first,
        .second = first_pair->second,
        .diagonal_add = *add_term,
        .diagonal_sub = *sub_term,
        .shared = diagonal->first,
        .partial = diagonal->second,
        .diagonal_add_raw_line = add_raw_line,
        .diagonal_sub_raw_line = sub_raw_line,
        .diagonal_add_score_line = add_score.line,
        .diagonal_sub_score_line = sub_score.line,
        .line = first_assign.line,
    };
  };

  if (rule.body.size() == 5) {
    const V2Statement& add_call = rule.body.at(1);
    const V2Statement& add_score = rule.body.at(2);
    const V2Statement& sub_call = rule.body.at(3);
    const V2Statement& sub_score = rule.body.at(4);
    if (add_call.args.size() != 1U || sub_call.args.size() != 1U)
      return std::nullopt;
    return finish_match(add_call, add_score, sub_call, sub_score,
                        parse_expression(add_call.args.front(), add_call.line),
                        parse_expression(sub_call.args.front(), sub_call.line), add_call.line,
                        sub_call.line);
  }

  if (rule.body.size() == 7) {
    const V2Statement& add_raw = rule.body.at(1);
    const V2Statement& add_call = rule.body.at(2);
    const V2Statement& add_score = rule.body.at(3);
    const V2Statement& sub_raw = rule.body.at(4);
    const V2Statement& sub_call = rule.body.at(5);
    const V2Statement& sub_score = rule.body.at(6);
    if (add_raw.kind != "v2_assign" || !add_raw.target.has_value() ||
        !add_raw.expr.has_value() || sub_raw.kind != "v2_assign" ||
        !sub_raw.target.has_value() || !sub_raw.expr.has_value() ||
        *add_raw.target != *sub_raw.target) {
      return std::nullopt;
    }
    const auto normalizer_it = add_call.name.has_value()
                                   ? context.x_param_procs.find(*add_call.name)
                                   : context.x_param_procs.end();
    if (normalizer_it == context.x_param_procs.end() ||
        normalizer_it->second.param != *add_raw.target) {
      return std::nullopt;
    }
    return finish_match(add_call, add_score, sub_call, sub_score,
                        parse_expression(*add_raw.expr, add_raw.line),
                        parse_expression(*sub_raw.expr, sub_raw.line), add_raw.line,
                        sub_raw.line);
  }

  return std::nullopt;
}

bool lower_packed_line_family_score_rule(LoweringContext& context, const V2Rule& rule) {
  const std::optional<PackedLineFamilyScoreRule> match =
      packed_line_family_score_rule(context, rule);
  if (!match.has_value())
    return false;

  const std::string helper = context.emitter.fresh_label("packed_line_family_score_accumulator");
  auto emit_score = [&](const PackedScoreTerm& term) -> bool {
    if (!lower_expression_to_x(context, term.line_value))
      return false;
    if (!lower_expression_to_x(context, term.index))
      return false;
    context.emitter.emit_jump(0x53, "ПП", helper, "packed-line score accumulator helper",
                              term.line);
    mark_current_x(context, match->score);
    context.emitter.current_x_known_zero = false;
    return true;
  };

  context.emitter.current_x_known_zero = false;
  context.emitter.emit_number("0");
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "packed-line score accumulator";
  context.emitter.emit_label(packed_line_family_score_zero_entry_label(rule.name),
                             {.hidden = true});
  if (!emit_score(match->first))
    return false;
  if (!emit_score(match->second))
    return false;

  const std::string tail = context.emitter.fresh_label("packed_line_family_score_tail");
  if (!lower_expression_to_x(context, match->partial))
    return false;
  context.emitter.emit_jump(0x53, "ПП", tail, "packed-line shared diagonal score",
                            match->diagonal_add_score_line);
  mark_current_x(context, match->score);
  context.emitter.current_x_known_zero = false;

  if (!lower_expression_to_x(context, match->partial))
    return false;
  context.emitter.emit_op(0x0b, "/-/", "packed-line negative diagonal index",
                          match->diagonal_sub_raw_line);
  context.emitter.emit_label(tail);
  if (!lower_expression_to_x(context, match->shared))
    return false;
  context.emitter.emit_op(0x10, "+", "packed-line diagonal index", match->diagonal_add_raw_line);
  context.emitter.emit_jump(0x53, "ПП", function_label(match->normalizer),
                            "proc call " + match->normalizer, match->diagonal_add_raw_line);
  mark_current_x(context, match->normalizer_return);
  context.emitter.emit_jump(0x53, "ПП", helper, "packed-line score accumulator helper",
                            match->diagonal_add_score_line);
  if (context.stack_only_state_fields.contains(match->score)) {
    mark_current_x(context, match->score);
    context.emitter.current_x_known_zero = false;
  } else {
    emit_store(context, match->score, "set " + match->score);
  }
  context.emitter.emit_op(0x52, "В/О", "packed-line family score return",
                          match->diagonal_sub_score_line);

  context.emitter.emit_label(helper);
  context.emitter.emit_op(0x15, "F 10^x", "packed-line score helper pow10", match->line);
  context.emitter.emit_op(0x13, "/", "packed-line score helper divide", match->line);
  context.emitter.emit_op(0x35, "К {x}", "packed-line score helper frac", match->line);
  emit_number_or_preload(context, "0.41200076");
  context.emitter.emit_op(0x11, "-", "packed-line score helper center", match->line);
  context.emitter.emit_op(0x22, "F x^2", "packed-line score helper square", match->line);
  context.emitter.emit_op(0x10, "+", "packed-line score helper accumulate", match->line);
  context.emitter.emit_op(0x52, "В/О", "packed-line score helper return", match->line);
  context.optimizations.push_back(OptimizationReport{
      .name = "packed-line-family-score-accumulator",
      .detail = "Accumulated four packed_score() terms through one helper while sharing diagonal "
                "scoring for " +
                expression_to_source(add_expression(match->shared, match->partial)) + " and " +
                expression_to_source(subtract_expression(match->shared, match->partial)) + " in " +
                rule.name + ".",
  });
  return true;
}

struct IndexedPackedUpdateTailRule {
  std::string update_rule;
  std::string param;
  std::string selector;
  int selector_register = 0;
  std::string y_name;
  Expression target;
  Expression factor;
  std::string op;
  Expression mask;
  int update_line = 0;
  int branch_line = 0;
  int halt_line = 0;
};

struct PackedLineFamilyUpdateStep {
  Expression line_expr;
  int slot = 0;
  int source_line = 0;
  std::optional<std::string> normalizer;
};

struct PackedLineFamilyUpdateRule {
  std::string rule;
  std::string update_rule;
  std::string delta_name;
  IndexedPackedUpdateTailRule update;
  std::vector<PackedLineFamilyUpdateStep> steps;
  int line = 0;
};

enum class PackedLineSelectorMode {
  Allocation,
  Direct,
  Mutating,
};

std::optional<int> integer_value_of_expression(const LoweringContext& context,
                                               const Expression& expression) {
  const std::optional<double> value = numeric_value_of_expression(context, expression);
  if (!value.has_value() || std::fabs(*value - std::round(*value)) >= 1e-12)
    return std::nullopt;
  return static_cast<int>(round_to_long_long(*value));
}

bool is_zero_expression(const LoweringContext& context, const Expression& expression) {
  const std::optional<double> value = numeric_value_of_expression(context, expression);
  return value.has_value() && std::fabs(*value) < 1e-12;
}

std::optional<int> physical_indexed_selector_register(const LoweringContext& context,
                                                      const Expression& target,
                                                      const std::string& selector) {
  if (target.kind != "indexed" || target.index == nullptr || target.index->kind != "identifier" ||
      target.index->name != selector)
    return std::nullopt;

  const auto selector_it = context.register_index_by_name.find(selector);
  if (selector_it == context.register_index_by_name.end())
    return std::nullopt;

  const std::string key = bank_member_key(target.base, target.field);
  const auto bank_it = context.state_banks.find(key);
  if (bank_it == context.state_banks.end() || !bank_it->second->bank.has_value())
    return std::nullopt;

  const V2StateField& field = *bank_it->second;
  for (int index = field.bank->min; index <= field.bank->max; ++index) {
    const auto element_it =
        context.register_index_by_name.find(state_bank_element_name(field, index));
    if (element_it == context.register_index_by_name.end() || element_it->second != index)
      return std::nullopt;
  }
  return selector_it->second;
}

std::optional<int> direct_physical_indexed_selector_register(const LoweringContext& context,
                                                             const Expression& target,
                                                             const std::string& selector) {
  const std::optional<int> selector_register =
      physical_indexed_selector_register(context, target, selector);
  if (!selector_register.has_value() || *selector_register < 7)
    return std::nullopt;
  return selector_register;
}

std::optional<Expression> bit_and_mask_for_target(const Expression& expression,
                                                  const Expression& target) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "bit_and" ||
      expression.args.size() != 2)
    return std::nullopt;
  if (expression_equals(expression.args.at(0), target))
    return expression.args.at(1);
  if (expression_equals(expression.args.at(1), target))
    return expression.args.at(0);
  return std::nullopt;
}

std::optional<Expression> fractional_bit_and_mask_for_target(const Expression& expression,
                                                             const Expression& target) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "frac" ||
      expression.args.size() != 1)
    return std::nullopt;
  return bit_and_mask_for_target(expression.args.front(), target);
}

bool branch_is_identifier_fractional_report_trap(const LoweringContext& context,
                                                 const V2Statement& branch,
                                                 const std::string& report_name) {
  if (branch.kind != "v2_if" || !branch.predicate.has_value() || branch.negated ||
      !branch.else_body.empty() || branch.then_body.size() != 1)
    return false;
  const V2Statement& halt = branch.then_body.front();
  if (halt.kind != "v2_stop" || !halt.target.has_value())
    return false;
  const Expression halt_expr = parse_expression(*halt.target, halt.line);
  if (halt_expr.kind != "identifier" || halt_expr.name != report_name)
    return false;

  const V2Predicate& predicate = *branch.predicate;
  if (predicate.kind != "v2_compare" || predicate.op != "!=")
    return false;
  const Expression left = parse_expression(predicate.left, branch.line);
  const Expression right = parse_expression(predicate.right, branch.line);
  const auto is_report_frac = [&](const Expression& expression) {
    return expression.kind == "call" && lower_ascii(expression.callee) == "frac" &&
           expression.args.size() == 1 && expression.args.front().kind == "identifier" &&
           expression.args.front().name == report_name;
  };
  return (is_report_frac(left) && is_zero_expression(context, right)) ||
         (is_report_frac(right) && is_zero_expression(context, left));
}

struct FractionalReportTail {
  Expression mask;
  int branch_line = 0;
  int halt_line = 0;
};

std::optional<FractionalReportTail> fractional_report_tail(const LoweringContext& context,
                                                           const Expression& target,
                                                           const std::vector<V2Statement>& tail) {
  if (tail.size() == 1 && tail.front().kind == "v2_if" && tail.front().predicate.has_value() &&
      !tail.front().then_body.empty()) {
    const V2Statement& branch = tail.front();
    const V2Predicate& predicate = *branch.predicate;
    if (predicate.kind == "v2_compare" && predicate.op == "!=" && !branch.negated &&
        branch.else_body.empty() && branch.then_body.size() == 1 &&
        branch.then_body.front().kind == "v2_stop" && branch.then_body.front().target.has_value()) {
      const Expression left = parse_expression(predicate.left, branch.line);
      const Expression right = parse_expression(predicate.right, branch.line);
      const Expression halt_expr =
          parse_expression(*branch.then_body.front().target, branch.then_body.front().line);
      const auto build_fractional =
          [&](const Expression& fractional_report,
              const Expression& zero) -> std::optional<FractionalReportTail> {
        if (fractional_report.kind != "call" || lower_ascii(fractional_report.callee) != "frac" ||
            fractional_report.args.size() != 1 || !is_zero_expression(context, zero)) {
          return std::nullopt;
        }
        const Expression& report_expression = fractional_report.args.front();
        const std::optional<Expression> mask = bit_and_mask_for_target(report_expression, target);
        if (!mask.has_value() || !is_simple_stack_load(*mask) ||
            !expression_equals(halt_expr, report_expression)) {
          return std::nullopt;
        }
        return FractionalReportTail{
            .mask = *mask, .branch_line = branch.line, .halt_line = branch.then_body.front().line};
      };
      if (std::optional<FractionalReportTail> report = build_fractional(left, right))
        return report;
      if (std::optional<FractionalReportTail> report = build_fractional(right, left))
        return report;
    }
  }

  if (tail.size() != 2)
    return std::nullopt;
  const V2Statement& report_assign = tail.at(0);
  const V2Statement& branch = tail.at(1);
  if (report_assign.kind != "v2_assign" || !report_assign.target.has_value() ||
      !report_assign.expr.has_value())
    return std::nullopt;
  const Expression report_expression = parse_expression(*report_assign.expr, report_assign.line);
  std::optional<Expression> mask = bit_and_mask_for_target(report_expression, target);
  if (!mask.has_value() || !is_simple_stack_load(*mask))
    return std::nullopt;
  if (!branch_is_identifier_fractional_report_trap(context, branch, *report_assign.target))
    return std::nullopt;
  return FractionalReportTail{
      .mask = *mask,
      .branch_line = branch.line,
      .halt_line = branch.then_body.empty() ? branch.line : branch.then_body.front().line};
}

std::optional<std::pair<std::string, Expression>>
pow10_identifier_factor(const Expression& expression) {
  if (expression.kind == "call") {
    const std::string callee = lower_ascii(expression.callee);
    if (callee == "pow10" && expression.args.size() == 1 &&
        expression.args.front().kind == "identifier") {
      return std::pair{expression.args.front().name, number_expression("1")};
    }
    if (callee == "pow" && expression.args.size() == 2 && expression.args.at(0).kind == "number" &&
        normalize_number_key(expression.args.at(0).raw) == "10" &&
        expression.args.at(1).kind == "identifier") {
      return std::pair{expression.args.at(1).name, number_expression("1")};
    }
  }
  if (expression.kind != "binary" || expression.op != "*" || expression.left == nullptr ||
      expression.right == nullptr)
    return std::nullopt;
  if (const std::optional<std::pair<std::string, Expression>> left =
          pow10_identifier_factor(*expression.left)) {
    if (is_simple_stack_load(*expression.right))
      return std::pair{left->first, *expression.right};
  }
  if (const std::optional<std::pair<std::string, Expression>> right =
          pow10_identifier_factor(*expression.right)) {
    if (is_simple_stack_load(*expression.left))
      return std::pair{right->first, *expression.left};
  }
  return std::nullopt;
}

std::optional<std::tuple<std::string, std::string, Expression>>
indexed_packed_pow10_delta_update(const Expression& target, const Expression& expression) {
  if (expression.kind == "call" && lower_ascii(expression.callee) == "packed_add" &&
      expression.args.size() == 3) {
    if (!expression_equals(expression.args.at(0), target) ||
        expression.args.at(1).kind != "identifier" ||
        !is_simple_stack_load(expression.args.at(2))) {
      return std::nullopt;
    }
    return std::tuple{std::string("+"), expression.args.at(1).name, expression.args.at(2)};
  }

  if (expression.kind != "binary" || (expression.op != "+" && expression.op != "-") ||
      expression.left == nullptr || expression.right == nullptr ||
      !expression_equals(*expression.left, target))
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> pow10 =
      pow10_identifier_factor(*expression.right);
  if (!pow10.has_value())
    return std::nullopt;
  return std::tuple{expression.op, pow10->first, pow10->second};
}

std::optional<std::string> direct_indexed_selector_name(const Expression& target) {
  if (target.kind != "indexed" || target.index == nullptr || target.index->kind != "identifier")
    return std::nullopt;
  return target.index->name;
}

bool emit_indexed_packed_pow10_delta_from_stack_index(LoweringContext& context,
                                                      const Expression& target,
                                                      const std::string& selector,
                                                      int selector_register, const std::string& op,
                                                      const Expression& factor, int line,
                                                      bool index_in_y) {
  if (index_in_y)
    context.emitter.emit_op(0x14, "X↔Y", "stack-carried packed digit index", line);
  context.emitter.emit_op(0x15, "F 10^x", "stack-carried packed digit pow10", line);
  if (!lower_expression_to_x(context, factor))
    return false;
  context.emitter.emit_op(0x12, "*", "stack-carried packed digit delta", line);
  context.emitter.emit_op(0xd0 + selector_register,
                          "К П->X " + core::register_name_for_index(selector_register),
                          "indexed packed digit update base", line);
  const std::optional<std::pair<int, std::string>> opcode = binary_opcode(op);
  if (!opcode.has_value())
    return false;
  context.emitter.emit_op(opcode->first, opcode->second, "indexed packed digit update", line);
  emit_prepared_indirect_indexed_store(context, target,
                                       PreparedIndexedSelector{.selector = selector}, line);
  return true;
}

bool lower_indexed_packed_pow10_delta_statement(LoweringContext& context,
                                                const V2Statement& statement) {
  if (statement.kind != "v2_assign" || !statement.target.has_value() || !statement.expr.has_value())
    return false;
  const Expression target = parse_expression(*statement.target, statement.line);
  if (target.kind != "indexed" || target.index == nullptr ||
      numeric_index_value(*target.index).has_value() ||
      !expression_pure_for_substitution(*target.index))
    return false;

  const Expression expression = parse_expression(*statement.expr, statement.line);
  const std::optional<std::tuple<std::string, std::string, Expression>> delta =
      indexed_packed_pow10_delta_update(target, expression);
  if (!delta.has_value())
    return false;

  const std::string& op = std::get<0>(*delta);
  const std::string& index_name = std::get<1>(*delta);
  const Expression& factor = std::get<2>(*delta);
  const std::optional<std::string> direct_selector = direct_indexed_selector_name(target);
  const std::optional<int> direct_selector_register =
      direct_selector.has_value()
          ? direct_physical_indexed_selector_register(context, target, *direct_selector)
          : std::nullopt;

  if (direct_selector_register.has_value()) {
    const bool x_holds_index = context.emitter.current_x_variable == index_name ||
                               context.emitter.current_x_aliases.contains(index_name);
    if (x_holds_index) {
      if (!emit_indexed_packed_pow10_delta_from_stack_index(context, target, *direct_selector,
                                                            *direct_selector_register, op, factor,
                                                            statement.line, false))
        return false;
      context.optimizations.push_back(OptimizationReport{
          .name = "indexed-packed-x-stack-pow10-delta",
          .detail = "Used " + index_name + " already in X as the pow10 index for " +
                    bank_member_key(target.base, target.field) + " at line " +
                    std::to_string(statement.line) + ".",
      });
      return true;
    }

    if (context.current_y_variable == index_name) {
      if (!emit_indexed_packed_pow10_delta_from_stack_index(context, target, *direct_selector,
                                                            *direct_selector_register, op, factor,
                                                            statement.line, true))
        return false;
      context.current_y_variable.reset();
      context.optimizations.push_back(OptimizationReport{
          .name = "indexed-packed-y-stack-pow10-delta",
          .detail = "Used " + index_name + " carried in Y as the pow10 index for " +
                    bank_member_key(target.base, target.field) + " at line " +
                    std::to_string(statement.line) + ".",
      });
      return true;
    }
  }

  const std::optional<PreparedIndexedSelector> prepared_selector =
      prepare_indirect_index_selector(context, target, statement.line);
  if (!prepared_selector.has_value())
    return false;
  context.emitter.emit_op(0xd0 + register_index_for(context, prepared_selector->selector),
                          "К П->X " + register_text_for(context, prepared_selector->selector),
                          "indexed packed digit update base", statement.line);
  if (!lower_expression_to_x(context, factor))
    return false;
  const std::optional<std::pair<int, std::string>> opcode = binary_opcode(op);
  if (!opcode.has_value())
    return false;
  context.emitter.emit_op(opcode->first, opcode->second, "indexed packed digit update",
                          statement.line);
  emit_prepared_indirect_indexed_store(context, target, *prepared_selector, statement.line);
  context.optimizations.push_back(OptimizationReport{
      .name = "indexed-packed-pow10-delta",
      .detail = "Updated " + bank_member_key(target.base, target.field) +
                " by a pow10-shaped term at line " + std::to_string(statement.line) + ".",
  });
  return true;
}

struct IndexedPackedReportBranch {
  bool fractional = false;
  Expression mask;
  Expression neutral;
  int halt_line = 0;
};

std::optional<Expression> halt_bit_and_mask_for_target(const V2Statement& halt,
                                                       const Expression& target) {
  if (halt.kind != "v2_stop" || !halt.target.has_value())
    return std::nullopt;
  const Expression halt_expression = parse_expression(*halt.target, halt.line);
  return bit_and_mask_for_target(halt_expression, target);
}

std::optional<IndexedPackedReportBranch>
indexed_packed_pow10_delta_report_branch(const LoweringContext& context, const V2Statement& assign,
                                         const V2Statement& branch) {
  if (assign.kind != "v2_assign" || !assign.target.has_value() || !assign.expr.has_value() ||
      branch.kind != "v2_if" || !branch.predicate.has_value() || branch.negated ||
      !branch.else_body.empty() || branch.then_body.size() != 1)
    return std::nullopt;
  const V2Predicate& predicate = *branch.predicate;
  if (predicate.kind != "v2_compare" || predicate.op != "!=")
    return std::nullopt;
  const Expression target = parse_expression(*assign.target, assign.line);
  if (target.kind != "indexed")
    return std::nullopt;
  const Expression update_expression = parse_expression(*assign.expr, assign.line);
  if (!indexed_packed_pow10_delta_update(target, update_expression).has_value())
    return std::nullopt;

  const V2Statement& halt = branch.then_body.front();
  const Expression left = parse_expression(predicate.left, branch.line);
  const Expression right = parse_expression(predicate.right, branch.line);
  const auto build_fractional =
      [&](const Expression& report,
          const Expression& zero) -> std::optional<IndexedPackedReportBranch> {
    const std::optional<Expression> mask = fractional_bit_and_mask_for_target(report, target);
    if (!mask.has_value() || !is_zero_expression(context, zero))
      return std::nullopt;
    const std::optional<Expression> halt_mask = halt_bit_and_mask_for_target(halt, target);
    if (!halt_mask.has_value() || !expression_equals(*halt_mask, *mask))
      return std::nullopt;
    return IndexedPackedReportBranch{
        .fractional = true,
        .mask = *mask,
        .neutral = number_expression("0"),
        .halt_line = halt.line,
    };
  };
  if (std::optional<IndexedPackedReportBranch> fractional = build_fractional(left, right))
    return fractional;
  if (std::optional<IndexedPackedReportBranch> fractional = build_fractional(right, left))
    return fractional;

  const auto build_bit_report =
      [&](const Expression& report,
          const Expression& neutral) -> std::optional<IndexedPackedReportBranch> {
    const std::optional<Expression> mask = bit_and_mask_for_target(report, target);
    if (!mask.has_value())
      return std::nullopt;
    const std::optional<Expression> halt_mask = halt_bit_and_mask_for_target(halt, target);
    if (!halt_mask.has_value() || !expression_equals(*halt_mask, *mask))
      return std::nullopt;
    return IndexedPackedReportBranch{
        .fractional = false,
        .mask = *mask,
        .neutral = neutral,
        .halt_line = halt.line,
    };
  };
  if (std::optional<IndexedPackedReportBranch> report = build_bit_report(left, right))
    return report;
  return build_bit_report(right, left);
}

bool lower_indexed_packed_pow10_delta_report_branch(LoweringContext& context,
                                                    const V2Statement& assign,
                                                    const V2Statement& branch,
                                                    bool proc_tail_x2 = false) {
  const std::optional<IndexedPackedReportBranch> report =
      indexed_packed_pow10_delta_report_branch(context, assign, branch);
  if (!report.has_value())
    return false;
  if (!lower_indexed_packed_pow10_delta_statement(context, assign))
    return false;

  if (report->fractional) {
    if (!lower_expression_to_x(context, report->mask))
      return false;
    context.emitter.emit_op(0x37, "К ∧", "updated packed fractional report mask", branch.line);
    if (proc_tail_x2) {
      // When the fractional report check is the whole procedure tail, branch
      // straight to the halt path on a win and let the no-win path fall into a
      // bare В/О. The win path recalls the masked report through X2 (last-X),
      // which `К {x}` left behind, saving the explicit В↑ keep + F reverse pair.
      context.emitter.emit_op(0x35, "К {x}", "updated packed fractional report predicate",
                              branch.line);
      const std::string halt_label = context.emitter.fresh_label("packed_frac_report_x2_halt");
      context.emitter.emit_jump(0x5e, "F x=0", halt_label,
                                "true branch for packed fractional report !=", branch.line);
      context.emitter.emit_op(0x52, "В/О", "packed fractional report return", branch.line);
      context.emitter.emit_label(halt_label);
      context.emitter.emit_op(0x0a, ".", "updated packed fractional report X2 restore",
                              branch.line);
      context.emitter.emit_op(0x50, "С/П", "halt", report->halt_line);
      clear_current_x_facts(context);
      context.optimizations.push_back(OptimizationReport{
          .name = "indexed-packed-fractional-report-x2-tail",
          .detail = "Restored the terminal fractional packed report through X2 after branching "
                    "directly to the halt path at line " +
                    std::to_string(branch.line) + ".",
      });
      return true;
    }
    context.emitter.emit_op(0x0e, "В↑", "updated packed fractional report keep", branch.line);
    context.emitter.emit_op(0x35, "К {x}", "updated packed fractional report predicate",
                            branch.line);
    const std::string false_label = context.emitter.fresh_label("packed_frac_report_false");
    context.emitter.emit_jump(0x57, "F x≠0", false_label,
                              "false branch for packed fractional report !=", branch.line);
    context.emitter.emit_op(0x25, "F reverse", "updated packed fractional report restore",
                            branch.line);
    context.emitter.emit_op(0x50, "С/П", "halt", report->halt_line);
    context.emitter.emit_label(false_label, {.hidden = true});
    context.optimizations.push_back(OptimizationReport{
        .name = "indexed-packed-fractional-report-branch",
        .detail =
            "Reused an indexed packed update left in X for fractional report branch at line " +
            std::to_string(branch.line) + ".",
    });
    return true;
  }

  if (!lower_expression_to_x(context, report->mask))
    return false;
  context.emitter.emit_op(0x37, "К ∧", "updated packed report mask", branch.line);
  if (!lower_expression_to_x(context, report->neutral))
    return false;
  context.emitter.emit_op(0x11, "-", "updated packed report compare", branch.line);
  const std::string false_label = context.emitter.fresh_label("packed_report_false");
  context.emitter.emit_jump(0x57, "F x≠0", false_label,
                            "false branch for packed report !=", branch.line);
  if (!lower_expression_to_x(context, report->neutral))
    return false;
  context.emitter.emit_op(0x10, "+", "updated packed report restore", branch.line);
  context.emitter.emit_op(0x50, "С/П", "halt", report->halt_line);
  context.emitter.emit_label(false_label, {.hidden = true});
  context.optimizations.push_back(OptimizationReport{
      .name = "indexed-packed-bit-report-branch",
      .detail = "Reused an indexed packed update left in X for bit report branch at line " +
                std::to_string(branch.line) + ".",
  });
  return true;
}

std::optional<IndexedPackedUpdateTailRule> x_param_indexed_fractional_report_tail_rule(
    const LoweringContext& context, const V2Rule& rule,
    PackedLineSelectorMode mode = PackedLineSelectorMode::Direct) {
  const auto lowering_it = context.x_param_procs.find(rule.name);
  if (lowering_it == context.x_param_procs.end() || lowering_it->second.kind != "copy" ||
      rule.body.size() < 3)
    return std::nullopt;

  const V2Statement& first = rule.body.at(0);
  const V2Statement& update = rule.body.at(1);
  if (first.kind != "v2_assign" || !first.target.has_value() || !first.expr.has_value() ||
      update.kind != "v2_assign" || !update.target.has_value() || !update.expr.has_value())
    return std::nullopt;
  if (*first.target != lowering_it->second.first.target || *first.expr != lowering_it->second.param)
    return std::nullopt;

  const Expression target = parse_expression(*update.target, update.line);
  if (target.kind != "indexed")
    return std::nullopt;
  int selector_register = 0;
  if (mode == PackedLineSelectorMode::Direct) {
    const std::optional<int> direct_selector =
        direct_physical_indexed_selector_register(context, target, *first.target);
    if (!direct_selector.has_value())
      return std::nullopt;
    selector_register = *direct_selector;
  } else if (mode == PackedLineSelectorMode::Mutating) {
    const std::optional<int> mutating_selector =
        physical_indexed_selector_register(context, target, *first.target);
    if (!mutating_selector.has_value() || core::indirect_selector_mutation(*mutating_selector) !=
                                              core::IndirectSelectorMutation::PreDecrement)
      return std::nullopt;
    selector_register = *mutating_selector;
  }

  const Expression update_expression = parse_expression(*update.expr, update.line);
  const std::optional<std::tuple<std::string, std::string, Expression>> delta =
      indexed_packed_pow10_delta_update(target, update_expression);
  if (!delta.has_value())
    return std::nullopt;

  std::vector<V2Statement> tail(rule.body.begin() + 2, rule.body.end());
  const std::optional<FractionalReportTail> report = fractional_report_tail(context, target, tail);
  if (!report.has_value())
    return std::nullopt;

  return IndexedPackedUpdateTailRule{
      .update_rule = rule.name,
      .param = lowering_it->second.param,
      .selector = *first.target,
      .selector_register = selector_register,
      .y_name = std::get<1>(*delta),
      .target = target,
      .factor = std::get<2>(*delta),
      .op = std::get<0>(*delta),
      .mask = report->mask,
      .update_line = update.line,
      .branch_line = report->branch_line,
      .halt_line = report->halt_line,
  };
}

bool packed_line_family_update_slot_matches_bank(const LoweringContext& context,
                                                 const Expression& target, int slot) {
  const std::string key = bank_member_key(target.base, target.field);
  const auto bank_it = context.state_banks.find(key);
  if (bank_it == context.state_banks.end() || !bank_it->second->bank.has_value())
    return false;
  return slot >= bank_it->second->bank->min && slot <= bank_it->second->bank->max;
}

std::optional<PackedLineFamilyUpdateStep> packed_line_family_update_direct_step(
    const LoweringContext& context, const std::vector<V2Statement>& statements, std::size_t cursor,
    const IndexedPackedUpdateTailRule& update, std::size_t& consumed) {
  if (cursor + 1U >= statements.size())
    return std::nullopt;
  const V2Statement& line_assign = statements.at(cursor);
  const V2Statement& call = statements.at(cursor + 1U);
  if (line_assign.kind != "v2_assign" || !line_assign.target.has_value() ||
      *line_assign.target != update.y_name || !line_assign.expr.has_value() ||
      call.kind != "v2_invoke" || !call.name.has_value() || *call.name != update.update_rule ||
      call.args.size() != 1)
    return std::nullopt;

  const Expression slot_expression = parse_expression(call.args.front(), call.line);
  const std::optional<int> slot = integer_value_of_expression(context, slot_expression);
  if (!slot.has_value())
    return std::nullopt;
  consumed = 2;
  return PackedLineFamilyUpdateStep{
      .line_expr = parse_expression(*line_assign.expr, line_assign.line),
      .slot = *slot,
      .source_line = line_assign.line,
  };
}

std::optional<PackedLineFamilyUpdateStep> packed_line_family_update_normalized_step(
    const LoweringContext& context, const std::vector<V2Statement>& statements, std::size_t cursor,
    const IndexedPackedUpdateTailRule& update, std::size_t& consumed) {
  if (cursor + 1U >= statements.size())
    return std::nullopt;
  const V2Statement& normalizer_call = statements.at(cursor);
  const V2Statement& call = statements.at(cursor + 1U);
  if (normalizer_call.kind != "v2_invoke" || !normalizer_call.name.has_value() ||
      normalizer_call.args.size() != 1 || call.kind != "v2_invoke" || !call.name.has_value() ||
      *call.name != update.update_rule || call.args.size() != 1)
    return std::nullopt;

  const auto normalizer_it = context.x_param_procs.find(*normalizer_call.name);
  if (normalizer_it == context.x_param_procs.end() || !normalizer_it->second.first.target ||
      *normalizer_it->second.first.target != update.y_name)
    return std::nullopt;

  const Expression slot_expression = parse_expression(call.args.front(), call.line);
  const std::optional<int> slot = integer_value_of_expression(context, slot_expression);
  if (!slot.has_value())
    return std::nullopt;
  consumed = 2;
  return PackedLineFamilyUpdateStep{
      .line_expr = parse_expression(normalizer_call.args.front(), normalizer_call.line),
      .slot = *slot,
      .source_line = normalizer_call.line,
      .normalizer = *normalizer_call.name,
  };
}

std::optional<std::vector<PackedLineFamilyUpdateStep>>
packed_line_family_update_steps(const LoweringContext& context,
                                const std::vector<V2Statement>& statements,
                                const IndexedPackedUpdateTailRule& update) {
  std::vector<PackedLineFamilyUpdateStep> steps;
  std::optional<std::string> normalizer;
  std::size_t cursor = 0;
  while (cursor < statements.size()) {
    std::size_t consumed = 0;
    if (std::optional<PackedLineFamilyUpdateStep> direct =
            packed_line_family_update_direct_step(context, statements, cursor, update, consumed)) {
      steps.push_back(std::move(*direct));
      cursor += consumed;
      continue;
    }
    if (std::optional<PackedLineFamilyUpdateStep> normalized =
            packed_line_family_update_normalized_step(context, statements, cursor, update,
                                                      consumed)) {
      if (normalizer.has_value() && normalized->normalizer != normalizer)
        return std::nullopt;
      normalizer = normalized->normalizer;
      steps.push_back(std::move(*normalized));
      cursor += consumed;
      continue;
    }
    return std::nullopt;
  }

  if (steps.size() < 4)
    return std::nullopt;
  std::set<int> unique_slots;
  for (const PackedLineFamilyUpdateStep& step : steps) {
    unique_slots.insert(step.slot);
    if (!packed_line_family_update_slot_matches_bank(context, update.target, step.slot))
      return std::nullopt;
  }
  if (unique_slots.size() < 4)
    return std::nullopt;
  return steps;
}

bool packed_line_family_update_steps_descend_by_one(
    const std::vector<PackedLineFamilyUpdateStep>& steps) {
  if (steps.size() < 2)
    return false;
  for (std::size_t index = 1; index < steps.size(); ++index) {
    if (steps.at(index - 1).slot - steps.at(index).slot != 1)
      return false;
  }
  return true;
}

bool expression_preserves_previous_x_as_y_for_packed_line(const Expression& expression) {
  if (is_simple_stack_load(expression))
    return true;
  if (expression.kind == "unary")
    return expression.op == "-" && expression.expr != nullptr &&
           expression_preserves_previous_x_as_y_for_packed_line(*expression.expr);
  if (expression.kind == "binary") {
    return (expression.op == "+" || expression.op == "-" || expression.op == "*" ||
            expression.op == "/") &&
           expression.left != nullptr && expression.right != nullptr &&
           expression_preserves_previous_x_as_y_for_packed_line(*expression.left) &&
           expression_preserves_previous_x_as_y_for_packed_line(*expression.right);
  }
  if (expression.kind == "call") {
    return expression.args.size() == 1 && x_transform_unary_opcode(expression.callee).has_value() &&
           expression_preserves_previous_x_as_y_for_packed_line(expression.args.front());
  }
  return false;
}

bool x_param_proc_preserves_caller_y(const LoweringContext& context, const std::string& rule_name) {
  const auto lowering_it = context.x_param_procs.find(rule_name);
  if (lowering_it == context.x_param_procs.end())
    return false;
  if (lowering_it->second.kind == "copy" || lowering_it->second.kind == "add")
    return true;
  if (lowering_it->second.kind != "expr" || !lowering_it->second.first.expr.has_value())
    return false;
  const Expression expression =
      parse_expression(*lowering_it->second.first.expr, lowering_it->second.first.line);
  return expression_preserves_previous_x_as_y_for_packed_line(expression);
}

bool packed_line_family_update_steps_preserve_y(
    const LoweringContext& context, const std::vector<PackedLineFamilyUpdateStep>& steps) {
  return std::all_of(steps.begin(), steps.end(), [&](const PackedLineFamilyUpdateStep& step) {
    if (!expression_preserves_previous_x_as_y_for_packed_line(step.line_expr))
      return false;
    return !step.normalizer.has_value() ||
           x_param_proc_preserves_caller_y(context, *step.normalizer);
  });
}

std::optional<PackedLineFamilyUpdateRule>
packed_line_family_update_rule(const LoweringContext& context, const V2Rule& rule,
                               PackedLineSelectorMode mode = PackedLineSelectorMode::Direct) {
  if (rule.body.size() < 5)
    return std::nullopt;
  const V2Statement& first = rule.body.front();
  if (first.kind != "v2_assign" || !first.target.has_value() || !first.expr.has_value())
    return std::nullopt;
  const Expression first_expression = parse_expression(*first.expr, first.line);
  if (first_expression.kind != "identifier")
    return std::nullopt;

  for (const auto& [unused_name, candidate] : context.rules) {
    (void)unused_name;
    if (candidate == nullptr)
      continue;
    const std::optional<IndexedPackedUpdateTailRule> update =
        x_param_indexed_fractional_report_tail_rule(context, *candidate, mode);
    if (!update.has_value() || update->factor.kind != "identifier" ||
        update->factor.name != *first.target)
      continue;
    std::vector<V2Statement> rest(rule.body.begin() + 1, rule.body.end());
    std::optional<std::vector<PackedLineFamilyUpdateStep>> steps =
        packed_line_family_update_steps(context, rest, *update);
    if (!steps.has_value())
      continue;
    if (mode == PackedLineSelectorMode::Mutating &&
        (!packed_line_family_update_steps_descend_by_one(*steps) ||
         !packed_line_family_update_steps_preserve_y(context, *steps))) {
      continue;
    }
    return PackedLineFamilyUpdateRule{
        .rule = rule.name,
        .update_rule = candidate->name,
        .delta_name = *first.target,
        .update = *update,
        .steps = std::move(*steps),
        .line = first.line,
    };
  }
  return std::nullopt;
}

void apply_packed_line_family_mutating_selector_hints(const LoweringContext& context,
                                                      const V2Program& program,
                                                      const RegisterCollection& collection,
                                                      RegisterHints& hints) {
  std::map<std::string, const V2Rule*> rules;
  for (const V2Rule& rule : program.rules)
    rules[rule.name] = &rule;

  LoweringContext probe = context;
  probe.rules = std::move(rules);

  std::set<std::string> selectors;
  for (const V2Rule& rule : program.rules) {
    if (const std::optional<PackedLineFamilyUpdateRule> match =
            packed_line_family_update_rule(probe, rule, PackedLineSelectorMode::Allocation)) {
      if (packed_line_family_update_steps_descend_by_one(match->steps) &&
          packed_line_family_update_steps_preserve_y(probe, match->steps)) {
        selectors.insert(match->update.selector);
      }
    }
  }

  const std::vector<int> preferred = {0x3, 0x0, 0x1, 0x2};
  std::set<int> used;
  for (const auto& [unused_name, hint] : hints) {
    (void)unused_name;
    used.insert(hint.index);
  }
  for (const std::string& selector : selectors) {
    if (!collection.variables.contains(selector) || hints.contains(selector))
      continue;
    const auto candidate = std::find_if(preferred.begin(), preferred.end(),
                                        [&](int index) { return !used.contains(index); });
    if (candidate == preferred.end())
      return;
    hints[selector] = RegisterHint{.mode = RegisterHintMode::Prefer, .index = *candidate};
    used.insert(*candidate);
  }
}

void emit_packed_line_family_update_check_tail(LoweringContext& context,
                                               const IndexedPackedUpdateTailRule& update) {
  emit_store(context, update.selector, "set " + update.selector + " from X parameter");
  context.emitter.emit_op(0x14, "X<->Y", "stack-carried packed digit index", update.update_line);
  context.emitter.emit_op(0x15, "F 10^x", "stack-carried packed digit pow10", update.update_line);
  (void)lower_expression_to_x(context, update.factor);
  context.emitter.emit_op(0x12, "*", "stack-carried packed digit delta", update.update_line);
  context.emitter.emit_op(0xd0 + update.selector_register,
                          "К П->X " + core::register_name_for_index(update.selector_register),
                          "indexed packed digit update base", update.update_line);
  const std::optional<std::pair<int, std::string>> op = binary_opcode(update.op);
  if (op.has_value())
    context.emitter.emit_op(op->first, op->second, "indexed packed digit update",
                            update.update_line);
  emit_prepared_indirect_indexed_store(context, update.target,
                                       PreparedIndexedSelector{.selector = update.selector},
                                       update.update_line);

  (void)lower_expression_to_x(context, update.mask);
  context.emitter.emit_op(0x37, "К ∧", "updated packed fractional report mask", update.branch_line);
  context.emitter.emit_op(0x35, "К {x}", "updated packed fractional report predicate",
                          update.branch_line);
  const std::string halt_label = context.emitter.fresh_label("packed_frac_report_x2_halt");
  context.emitter.emit_jump(0x5e, "F x=0", halt_label,
                            "true branch for packed fractional report !=", update.branch_line);
  context.emitter.emit_op(0x52, "В/О", "packed fractional report return", update.branch_line);
  context.emitter.emit_label(halt_label);
  context.emitter.emit_op(0x0a, ".", "updated packed fractional report X2 restore",
                          update.branch_line);
  context.emitter.emit_op(0x50, "С/П", "halt", update.halt_line);
  context.optimizations.push_back(OptimizationReport{
      .name = "indexed-packed-fractional-report-x2-tail",
      .detail = "Restored the terminal fractional packed report through X2 after branching "
                "directly to the halt path at line " +
                std::to_string(update.branch_line) + ".",
  });
  clear_current_x_facts(context);
}

Expression packed_line_family_update_step_line_value(const IndexedPackedUpdateTailRule& update,
                                                     const PackedLineFamilyUpdateStep& step) {
  Expression target = update.target;
  target.index = std::make_shared<Expression>(number_expression(std::to_string(step.slot)));
  return target;
}

bool lower_expression_preserving_previous_x_as_y(LoweringContext& context,
                                                 const Expression& expression, int line) {
  if (is_simple_stack_load(expression))
    return lower_expression_to_x(context, expression);
  if (expression.kind == "unary" && expression.op == "-" && expression.expr != nullptr) {
    if (!lower_expression_preserving_previous_x_as_y(context, *expression.expr, line))
      return false;
    context.emitter.emit_op(0x0b, "/-/", "stack-preserving unary minus", line);
    return true;
  }
  if (expression.kind == "binary" && expression.left != nullptr && expression.right != nullptr &&
      (expression.op == "+" || expression.op == "-" || expression.op == "*" ||
       expression.op == "/")) {
    if (!lower_expression_preserving_previous_x_as_y(context, *expression.left, line))
      return false;
    if (!lower_expression_preserving_previous_x_as_y(context, *expression.right, line))
      return false;
    const std::optional<std::pair<int, std::string>> op = binary_opcode(expression.op);
    if (!op.has_value())
      return false;
    context.emitter.emit_op(op->first, op->second, "expr " + expression.op, line);
    clear_current_x_facts(context);
    return true;
  }
  if (expression.kind == "call" && expression.args.size() == 1) {
    const std::optional<std::pair<int, std::string>> opcode =
        x_transform_unary_opcode(expression.callee);
    if (!opcode.has_value())
      return false;
    if (!lower_expression_preserving_previous_x_as_y(context, expression.args.front(), line))
      return false;
    context.emitter.emit_op(opcode->first, opcode->second, expression.callee + "()", line);
    return true;
  }
  return false;
}

void emit_packed_line_family_mutating_update_check_tail(LoweringContext& context,
                                                        const IndexedPackedUpdateTailRule& update) {
  context.emitter.emit_op(0x15, "F 10^x", "stack-carried packed digit pow10", update.update_line);
  (void)lower_expression_to_x(context, update.factor);
  context.emitter.emit_op(0x12, "*", "stack-carried packed digit delta", update.update_line);
  const std::optional<std::pair<int, std::string>> op = binary_opcode(update.op);
  if (op.has_value())
    context.emitter.emit_op(op->first, op->second, "mutating-selector packed digit update",
                            update.update_line);
  context.emitter.emit_op(0xb0 + update.selector_register,
                          "К X->П " + core::register_name_for_index(update.selector_register),
                          "predecrement indexed set " +
                              bank_member_key(update.target.base, update.target.field),
                          update.update_line);

  (void)lower_expression_to_x(context, update.mask);
  context.emitter.emit_op(0x37, "К ∧", "updated packed fractional report mask", update.branch_line);
  context.emitter.emit_op(0x35, "К {x}", "updated packed fractional report predicate",
                          update.branch_line);
  const std::string halt_label = context.emitter.fresh_label("packed_frac_report_x2_halt");
  context.emitter.emit_jump(0x5e, "F x=0", halt_label,
                            "true branch for packed fractional report !=", update.branch_line);
  context.emitter.emit_op(0x52, "В/О", "packed fractional report return", update.branch_line);
  context.emitter.emit_label(halt_label);
  context.emitter.emit_op(0x0a, ".", "updated packed fractional report X2 restore",
                          update.branch_line);
  context.emitter.emit_op(0x50, "С/П", "halt", update.halt_line);
  context.optimizations.push_back(OptimizationReport{
      .name = "indexed-packed-fractional-report-x2-tail",
      .detail = "Restored the terminal fractional packed report through X2 after branching "
                "directly to the halt path at line " +
                std::to_string(update.branch_line) + ".",
  });
  clear_current_x_facts(context);
}

bool lower_x_param_indexed_fractional_report_tail_rule(LoweringContext& context,
                                                       const V2Rule& rule) {
  const auto y_stack_it = context.x_param_y_stack_procs.find(rule.name);
  if (y_stack_it == context.x_param_y_stack_procs.end())
    return false;
  const std::optional<IndexedPackedUpdateTailRule> match =
      x_param_indexed_fractional_report_tail_rule(context, rule);
  if (!match.has_value() || match->y_name != y_stack_it->second.y_name)
    return false;

  if (context.x_param_y_stack_stored_entry) {
    emit_store(context, match->selector, "set " + match->selector + " from X parameter");
    context.emitter.emit_op(0x14, "X↔Y", "stack-carried packed digit index", match->update_line);
    mark_current_x(context, match->y_name);
    context.emitter.emit_label(x_param_y_stack_stored_entry_label(rule.name), {.hidden = true});
    context.emitter.emit_op(0x15, "F 10^x", "stack-carried packed digit pow10", match->update_line);
    if (!lower_expression_to_x(context, match->factor))
      return false;
    context.emitter.emit_op(0x12, "*", "stack-carried packed digit delta", match->update_line);
    context.emitter.emit_op(0xd0 + match->selector_register,
                            "К П->X " + core::register_name_for_index(match->selector_register),
                            "indexed packed digit update base", match->update_line);
    const std::optional<std::pair<int, std::string>> op = binary_opcode(match->op);
    if (!op.has_value())
      return false;
    context.emitter.emit_op(op->first, op->second, "indexed packed digit update",
                            match->update_line);
    emit_prepared_indirect_indexed_store(context, match->target,
                                         PreparedIndexedSelector{.selector = match->selector},
                                         match->update_line);

    if (!lower_expression_to_x(context, match->mask))
      return false;
    context.emitter.emit_op(0x37, "К ∧", "updated packed fractional report mask",
                            match->branch_line);
    context.emitter.emit_op(0x35, "К {x}", "updated packed fractional report predicate",
                            match->branch_line);
    const std::string halt_label = context.emitter.fresh_label("packed_frac_report_x2_halt");
    context.emitter.emit_jump(0x5e, "F x=0", halt_label,
                              "true branch for packed fractional report !=", match->branch_line);
    context.emitter.emit_op(0x52, "В/О", "packed fractional report return", match->branch_line);
    context.emitter.emit_label(halt_label);
    context.emitter.emit_op(0x0a, ".", "updated packed fractional report X2 restore",
                            match->branch_line);
    context.emitter.emit_op(0x50, "С/П", "halt", match->halt_line);
    context.optimizations.push_back(OptimizationReport{
        .name = "indexed-packed-fractional-report-x2-tail",
        .detail = "Restored the terminal fractional packed report through X2 after branching "
                  "directly to the halt path at line " +
                  std::to_string(match->branch_line) + ".",
    });
    clear_current_x_facts(context);
  } else {
    emit_packed_line_family_update_check_tail(context, *match);
  }

  context.current_y_variable.reset();
  context.optimizations.push_back(OptimizationReport{
      .name = context.x_param_y_stack_stored_entry ? "x-param-y-stack-multi-entry"
                                                   : "x-param-proc-entry",
      .detail = context.x_param_y_stack_stored_entry
                    ? "Compiled rule " + rule.name +
                          " with a secondary entry after its X-parameter store and Y-stack swap."
                    : "Compiled rule " + rule.name + " to copy " + y_stack_it->second.x_param +
                          " directly from X.",
  });
  context.optimizations.push_back(OptimizationReport{
      .name = "indexed-packed-y-stack-pow10-delta",
      .detail = "Used " + match->y_name + " carried in Y as the pow10 index for " +
                bank_member_key(match->target.base, match->target.field) + " at line " +
                std::to_string(match->update_line) + ".",
  });
  context.optimizations.push_back(OptimizationReport{
      .name = "indexed-packed-fractional-report-branch",
      .detail = "Reused an indexed packed update left in X for fractional report branch at line " +
                std::to_string(match->branch_line) + ".",
  });
  return true;
}

bool lower_packed_line_family_mutating_update_rule(LoweringContext& context, const V2Rule& rule) {
  const std::optional<PackedLineFamilyUpdateRule> match =
      packed_line_family_update_rule(context, rule, PackedLineSelectorMode::Mutating);
  if (!match.has_value())
    return false;

  emit_store(context, match->delta_name, "set " + match->delta_name + " from X parameter");
  const int first_slot = match->steps.front().slot;
  emit_number_or_preload(context, std::to_string(first_slot + 1),
                         "packed-line mutating selector start", match->line);
  emit_store(context, match->update.selector,
             "packed-line mutating selector start " + std::to_string(first_slot + 1));

  const std::string tail_label =
      context.emitter.fresh_label("packed_line_family_mutating_update_check_tail");
  for (std::size_t index = 0; index < match->steps.size(); ++index) {
    const PackedLineFamilyUpdateStep& step = match->steps.at(index);
    if (!lower_expression_to_x(context,
                               packed_line_family_update_step_line_value(match->update, step)))
      return false;
    if (!lower_expression_preserving_previous_x_as_y(context, step.line_expr, step.source_line))
      return false;
    if (step.normalizer.has_value()) {
      context.emitter.emit_jump(0x53, "ПП", function_label(*step.normalizer),
                                "proc call " + *step.normalizer, step.source_line);
      mark_current_x(context, match->update.y_name);
    }
    if (index + 1U == match->steps.size()) {
      context.emitter.emit_label(tail_label);
    } else {
      context.emitter.emit_jump(0x53, "ПП", tail_label,
                                "packed-line mutating shared update/check tail", step.source_line);
      clear_current_x_facts(context);
    }
  }

  emit_packed_line_family_mutating_update_check_tail(context, match->update);
  return true;
}

bool lower_packed_line_family_update_rule(LoweringContext& context, const V2Rule& rule) {
  const std::optional<PackedLineFamilyUpdateRule> match =
      packed_line_family_update_rule(context, rule);
  if (!match.has_value())
    return false;

  emit_store(context, match->delta_name, "set " + match->delta_name + " from X parameter");
  const std::string tail_label =
      context.emitter.fresh_label("packed_line_family_update_check_tail");

  for (std::size_t index = 0; index < match->steps.size(); ++index) {
    const PackedLineFamilyUpdateStep& step = match->steps.at(index);
    if (!lower_expression_to_x(context, step.line_expr))
      return false;
    if (step.normalizer.has_value()) {
      context.emitter.emit_jump(0x53, "ПП", function_label(*step.normalizer),
                                "proc call " + *step.normalizer, step.source_line);
      mark_current_x(context, match->update.y_name);
    } else {
      mark_current_x(context, match->update.y_name);
    }
    emit_number_or_preload(context, std::to_string(step.slot), std::nullopt, step.source_line);
    if (index + 1U == match->steps.size()) {
      context.emitter.emit_label(tail_label);
    } else {
      context.emitter.emit_jump(0x53, "ПП", tail_label, "packed-line shared update/check tail",
                                step.source_line);
      clear_current_x_facts(context);
    }
  }

  emit_packed_line_family_update_check_tail(context, match->update);
  return true;
}

bool is_numeric_zero_expression(const LoweringContext& context, const Expression& expression) {
  const std::optional<double> value = numeric_value_of_expression(context, expression);
  return value.has_value() && std::fabs(*value) < 1e-12;
}

Expression random_range_expression(const Expression& min, const Expression& max) {
  return add_expression(
      min, multiply_expression(call_expression("random", {}), subtract_expression(max, min)));
}

bool lower_random_call_to_x(LoweringContext& context, const Expression& expression) {
  if (expression.args.empty()) {
    context.emitter.emit_op(0x3b, "К СЧ", "random()");
    return true;
  }

  if (expression.args.size() == 2) {
    if (!is_numeric_zero_expression(context, expression.args.at(0))) {
      if (!lower_expression_to_x(
              context, random_range_expression(expression.args.at(0), expression.args.at(1))))
        return false;
      context.optimizations.push_back(OptimizationReport{
          .name = "random-range-lowering",
          .detail = "Lowered random(min, max) as min + random() * (max - min).",
      });
      return true;
    }
    if (!lower_random_call_to_x(context, Expression{
                                             .kind = "call",
                                             .callee = "random",
                                             .args = {expression.args.at(1)},
                                         }))
      return false;
    return true;
  }

  if (expression.args.size() != 1) {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                             "random() expects zero, one, or two arguments, got " +
                                                 std::to_string(expression.args.size())));
    return false;
  }

  if (expression.args.at(0).kind == "identifier") {
    const auto board_it = context.boards.find(expression.args.at(0).name);
    if (board_it != context.boards.end())
      return lower_random_board_call_to_x(context, *board_it->second, 0);
    const auto world_it = context.worlds.find(expression.args.at(0).name);
    if (world_it != context.worlds.end())
      return lower_random_world_call_to_x(context, *world_it->second, 0);
  }

  context.emitter.emit_op(0x3b, "К СЧ", "random()");
  if (!lower_expression_to_x(context, expression.args.at(0)))
    return false;
  context.emitter.emit_op(0x12, "*", "expr *");
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  context.optimizations.push_back(OptimizationReport{
      .name = "random-range-lowering",
      .detail = "Lowered random(max) as random() * max.",
  });
  return true;
}

bool expression_contains_valid_random(const Expression& expression) {
  if (expression.kind == "number" || expression.kind == "string" || expression.kind == "identifier")
    return false;
  if (expression.kind == "indexed")
    return expression.index != nullptr && expression_contains_valid_random(*expression.index);
  if (expression.kind == "unary")
    return expression.expr != nullptr && expression_contains_valid_random(*expression.expr);
  if (expression.kind == "binary") {
    return (expression.left != nullptr && expression_contains_valid_random(*expression.left)) ||
           (expression.right != nullptr && expression_contains_valid_random(*expression.right));
  }
  if (expression.kind == "call") {
    if (lower_ascii(expression.callee) == "random" && expression.args.size() <= 2)
      return true;
    return std::any_of(expression.args.begin(), expression.args.end(),
                       [](const Expression& arg) { return expression_contains_valid_random(arg); });
  }
  return false;
}

bool expression_contains_random_call(const Expression& expression) {
  if (expression.kind == "number" || expression.kind == "string" || expression.kind == "identifier")
    return false;
  if (expression.kind == "indexed")
    return expression.index != nullptr && expression_contains_random_call(*expression.index);
  if (expression.kind == "unary")
    return expression.expr != nullptr && expression_contains_random_call(*expression.expr);
  if (expression.kind == "binary") {
    return (expression.left != nullptr && expression_contains_random_call(*expression.left)) ||
           (expression.right != nullptr && expression_contains_random_call(*expression.right));
  }
  if (expression.kind == "call") {
    if (lower_ascii(expression.callee) == "random")
      return true;
    return std::any_of(expression.args.begin(), expression.args.end(),
                       [](const Expression& arg) { return expression_contains_random_call(arg); });
  }
  return false;
}

bool is_unit_random_call(const Expression& expression) {
  return expression.kind == "call" && lower_ascii(expression.callee) == "random" &&
         expression.args.empty();
}

bool is_zero_based_random_range_call(const LoweringContext& context, const Expression& expression) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "random")
    return false;
  if (expression.args.size() == 1U) {
    if (expression.args.front().kind == "identifier" &&
        is_domain_name(context, expression.args.front().name))
      return true;
    return !expression_contains_random_call(expression.args.front());
  }
  return expression.args.size() == 2U &&
         is_numeric_zero_expression(context, expression.args.at(0)) &&
         !expression_contains_random_call(expression.args.at(1));
}

bool is_random_scaled_integer(const LoweringContext& context, const Expression& expression) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "int" ||
      expression.args.size() != 1U)
    return false;
  const Expression& arg = expression.args.front();
  if (is_zero_based_random_range_call(context, arg))
    return true;
  if (arg.kind != "binary" || arg.op != "*" || arg.left == nullptr || arg.right == nullptr)
    return false;
  if (is_unit_random_call(*arg.left))
    return !expression_contains_random_call(*arg.right);
  if (is_unit_random_call(*arg.right))
    return !expression_contains_random_call(*arg.left);
  return false;
}

bool is_random_cell_expression_shape(const LoweringContext& context, const Expression& expression) {
  if (expression.kind == "call" && lower_ascii(expression.callee) == "random" &&
      expression.args.size() == 1U && expression.args.front().kind == "identifier" &&
      is_domain_name(context, expression.args.front().name)) {
    return true;
  }
  if (is_random_scaled_integer(context, expression))
    return true;
  if (expression.kind != "binary" || expression.left == nullptr || expression.right == nullptr)
    return false;
  if (expression.op == "+") {
    return (is_random_scaled_integer(context, *expression.left) &&
            numeric_value_of_expression(context, *expression.right).has_value()) ||
           (numeric_value_of_expression(context, *expression.left).has_value() &&
            is_random_scaled_integer(context, *expression.right));
  }
  if (expression.op == "-") {
    return is_random_scaled_integer(context, *expression.left) &&
           numeric_value_of_expression(context, *expression.right).has_value();
  }
  return false;
}

int random_cell_helper_expression_cost(const LoweringContext& context,
                                       const Expression& expression) {
  if (expression.kind == "number" || expression.kind == "identifier")
    return 1;
  if (expression.kind == "string")
    return 0;
  if (expression.kind == "indexed")
    return expression.index == nullptr
               ? 2
               : random_cell_helper_expression_cost(context, *expression.index) + 2;
  if (expression.kind == "unary")
    return expression.expr == nullptr
               ? 1
               : random_cell_helper_expression_cost(context, *expression.expr) + 1;
  if (expression.kind == "binary") {
    const int left = expression.left == nullptr
                         ? 0
                         : random_cell_helper_expression_cost(context, *expression.left);
    const int right = expression.right == nullptr
                          ? 0
                          : random_cell_helper_expression_cost(context, *expression.right);
    return left + right + 1;
  }
  if (expression.kind != "call")
    return 1;
  const std::string callee = lower_ascii(expression.callee);
  if (callee == "random") {
    if (expression.args.empty())
      return 1;
    if (expression.args.size() == 1U && expression.args.front().kind == "identifier") {
      const auto board_it = context.boards.find(expression.args.front().name);
      if (board_it != context.boards.end()) {
        const std::optional<int> base = board_random_base(*board_it->second);
        return 6 + (base.has_value() && *base != 0 ? 2 : 0);
      }
      const auto world_it = context.worlds.find(expression.args.front().name);
      if (world_it != context.worlds.end()) {
        const std::optional<int> base = world_random_base(*world_it->second);
        return 6 + (base.has_value() && *base != 0 ? 2 : 0);
      }
    }
    int cost = 2;
    for (const Expression& arg : expression.args)
      cost += random_cell_helper_expression_cost(context, arg);
    return cost;
  }
  int cost = 1;
  for (const Expression& arg : expression.args)
    cost += random_cell_helper_expression_cost(context, arg);
  return cost;
}

bool should_share_random_cell_expression(const LoweringContext& context,
                                         const Expression& expression) {
  if (!is_random_cell_expression_shape(context, expression))
    return false;
  const std::string key = expression_to_json(expression);
  const auto count_it = context.expression_use_counts.find(key);
  if (count_it == context.expression_use_counts.end() || count_it->second < 2)
    return false;
  const int uses = count_it->second;
  const int cost = random_cell_helper_expression_cost(context, expression);
  const int inline_total = uses * cost;
  const int helper_total = uses * 2 + cost + 1;
  const int threshold = context.share_random_cell ? 1 : 4;
  return inline_total - helper_total >= threshold;
}

const RandomCellHelperRequest* ensure_random_cell_helper(LoweringContext& context,
                                                         const Expression& expression) {
  const std::string key = expression_to_json(expression);
  const auto existing = context.random_cell_helper_labels.find(key);
  if (existing != context.random_cell_helper_labels.end()) {
    const auto helper =
        std::find_if(context.random_cell_helpers.begin(), context.random_cell_helpers.end(),
                     [&](const RandomCellHelperRequest& candidate) {
                       return candidate.label == existing->second;
                     });
    if (helper != context.random_cell_helpers.end())
      return &*helper;
  }
  const std::string label = "__random_coord_" + std::to_string(context.random_cell_helpers.size());
  context.random_cell_helper_labels[key] = label;
  context.random_cell_helpers.push_back(RandomCellHelperRequest{
      .key = key,
      .label = label,
      .expr = expression,
  });
  return &context.random_cell_helpers.back();
}

const RandomCellHelperRequest* shared_random_cell_helper(LoweringContext& context,
                                                         const Expression& expression) {
  if (context.emitting_random_cell_helper ||
      !should_share_random_cell_expression(context, expression))
    return nullptr;
  return ensure_random_cell_helper(context, expression);
}

bool should_share_expression(const LoweringContext& context, const Expression& expression) {
  if (!expression_pure_for_substitution(expression))
    return false;
  if (expression.kind == "number" || expression.kind == "identifier")
    return false;
  constexpr int kExpressionHelperMinCost = 8;
  constexpr int kExpressionHelperMinSavings = 4;
  const int cost = guarded_estimate_expression_cost(expression);
  if (cost < kExpressionHelperMinCost)
    return false;
  const std::string key = expression_to_json(expression);
  const auto count_it = context.expression_use_counts.find(key);
  if (count_it == context.expression_use_counts.end() || count_it->second < 2)
    return false;
  const int uses = count_it->second;
  const int inline_total = uses * cost;
  const int helper_total = uses * 2 + cost + 1;
  return inline_total - helper_total >= kExpressionHelperMinSavings;
}

const ExpressionHelperRequest* ensure_expression_helper(LoweringContext& context,
                                                        const Expression& expression) {
  const std::string key = expression_to_json(expression);
  const auto existing = context.expression_helper_labels.find(key);
  if (existing != context.expression_helper_labels.end()) {
    const auto helper =
        std::find_if(context.expression_helpers.begin(), context.expression_helpers.end(),
                     [&](const ExpressionHelperRequest& candidate) {
                       return candidate.label == existing->second;
                     });
    if (helper != context.expression_helpers.end())
      return &*helper;
  }
  const std::string label = "__expr_" + std::to_string(context.expression_helpers.size());
  context.expression_helper_labels[key] = label;
  context.expression_helpers.push_back(ExpressionHelperRequest{
      .key = key,
      .label = label,
      .expr = expression,
  });
  return &context.expression_helpers.back();
}

const ExpressionHelperRequest* shared_expression_helper(LoweringContext& context,
                                                        const Expression& expression) {
  if (context.emitting_expression_helper || !should_share_expression(context, expression))
    return nullptr;
  return ensure_expression_helper(context, expression);
}

bool lower_random_integer_call_to_x(LoweringContext& context, const Expression& expression) {
  if (lower_ascii(expression.callee) != "int" || expression.args.size() != 1 ||
      !expression_contains_valid_random(expression.args.front())) {
    return false;
  }
  if (!lower_expression_to_x(context, expression.args.front()))
    return false;
  context.emitter.emit_op(0x0e, "В↑", "random int keep scaled draw");
  context.emitter.emit_op(0x35, "К {x}", "random int fractional part");
  context.emitter.emit_op(0x11, "-", "random int floor");
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  context.optimizations.push_back(OptimizationReport{
      .name = "int-random-range-lowering",
      .detail = "Lowered int(random...) without К [x] so the MK-61 random sequence keeps moving.",
  });
  return true;
}

bool emit_negative_zero_threshold_raw(LoweringContext& context, const Expression& value,
                                      const Expression& bound, std::optional<int> source_line) {
  if (!reserve_negative_zero_degree_register(context)) {
    context.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                   "Internal: negative-zero threshold selector was emitted without a reserved "
                   "register."));
    return false;
  }
  if (!lower_expression_to_x(context, divide_expression(value, bound)))
    return false;
  emit_recall(context, *context.negative_zero_degree_register);
  if (!context.emitter.items.empty()) {
    context.emitter.items.back().comment = "negative-zero threshold sentinel";
    context.emitter.items.back().source_line = source_line;
  }
  context.emitter.emit_op(0x14, "X↔Y", "place threshold value above negative-zero sentinel",
                          source_line);
  context.emitter.emit_op(0x12, "*", "negative-zero threshold zero-through", source_line);
  context.emitter.emit_op(0x0e, "В↑", "normalize negative-zero threshold result", source_line);
  clear_current_x_facts(context);
  return true;
}

bool lower_builtin_call_to_x(LoweringContext& context, const Expression& expression) {
  const std::string callee = lower_ascii(expression.callee);
  if (is_small_set_macro_name(callee)) {
    if (!small_set_macro_arity_ok(callee, expression.args.size())) {
      context.diagnostics.push_back(diagnostic(
          DiagnosticSeverity::Error, "native-unsupported",
          expression.callee + "() expects " + small_set_macro_arity_text(callee) + ", got " +
              std::to_string(expression.args.size()) + "."));
      return false;
    }
    const std::optional<Expression> small_set_macro =
        small_set_expression_macro(callee, expression.args);
    if (!small_set_macro.has_value() || !lower_expression_to_x(context, *small_set_macro))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "small-set-primitive-lowering",
        .detail = "Lowered " + expression.callee + "() to coordinate-set arithmetic.",
    });
    return true;
  }
  if (callee == kNegativeZeroDegreeSelectorGe) {
    if (expression.args.size() != 2U) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     std::string(kNegativeZeroDegreeSelectorGe) + "() expects two arguments."));
      return false;
    }
    if (!emit_negative_zero_threshold_raw(context, expression.args.at(0), expression.args.at(1),
                                          std::nullopt))
      return false;
    context.emitter.emit_op(0x32, "К ЗН", "negative-zero threshold selector");
    context.optimizations.push_back(OptimizationReport{
        .name = "negative-zero-threshold-selector",
        .detail = "Used preloaded " + std::string(kNegativeZeroDegreePreloadValue) + " in R" +
                  register_text_for(context, *context.negative_zero_degree_register) + " for " +
                  expression_to_source(expression.args.at(0)) +
                  " >= " + expression_to_source(expression.args.at(1)) + ".",
    });
    clear_current_x_facts(context);
    return true;
  }
  if (callee == "int" && lower_random_integer_call_to_x(context, expression))
    return true;

  if (callee == "packed_score" && context.use_packed_score_helper) {
    if (expression.args.size() != 2) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Function " + expression.callee + " expects two arguments"));
      return false;
    }
    if (!lower_expression_to_x(context, expression.args.at(0)))
      return false;
    if (!lower_expression_to_x(context, expression.args.at(1)))
      return false;
    context.emitter.emit_jump(0x53, "ПП", packed_score_helper_label(context),
                              "packed_score helper");
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    context.optimizations.push_back(OptimizationReport{
        .name = "packed-score-stack-helper-call",
        .detail = "Reused shared packed_score stack helper for packed-line scoring.",
    });
    return true;
  }

  if (callee == "bit_not" && expression.args.size() == 1U &&
      expression.args.front().kind == "binary") {
    auto expr_api = expression_emit_api(context);
    if (!core::emit::lower_binary_expression_to_x(expr_api, context, expression.args.front(),
                                                  false))
      return false;
    context.emitter.emit_op(0x3a, "К ИНВ", "bit_not()");
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }

  auto expr_api = expression_emit_api(context);
  if (const std::optional<bool> calculator_builtin =
          core::emit::lower_calculator_builtin_call_to_x(expr_api, context, expression)) {
    return *calculator_builtin;
  }

  if (callee == "random")
    return lower_random_call_to_x(context, expression);

  if (callee == "line_count") {
    if (lower_coord_list_line_count_to_x(context, expression))
      return true;
    if (has_errors(context.diagnostics))
      return false;
    if (lower_spatial_line_count_loop_to_x(context, expression))
      return true;
    if (has_errors(context.diagnostics))
      return false;
  }

  if (callee == "line_count" || callee == "neighbor_count") {
    if (expression.args.size() != 2) {
      context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                               expression.callee + "() expects two arguments"));
      return false;
    }
    if (callee == "neighbor_count" && lower_spatial_neighbor_count_loop_to_x(context, expression))
      return true;
    if (has_errors(context.diagnostics))
      return false;
    const Expression expanded = spatial_count_expression(context, callee, expression.args);
    if (!expanded.kind.empty()) {
      if (!lower_expression_to_x(context, expanded))
        return false;
      if (!context.emitter.items.empty())
        context.emitter.items.back().comment = callee + " result";
      context.optimizations.push_back(OptimizationReport{
          .name = "spatial-count-hit-helper",
          .detail = "Lowered " + callee + "() through shared spatial hit helper calls.",
      });
      return true;
    }
  }

  if (callee == kSpatialHitCallee) {
    if (expression.args.size() != 2) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     std::string(kSpatialHitCallee) + "() expects two arguments"));
      return false;
    }
    if (expression.args.at(0).kind == "identifier" &&
        is_segmented_cells_name(context, expression.args.at(0).name)) {
      return lower_segmented_bitplane_hit_to_x(context, expression.args.at(0).name,
                                               expression.args.at(1), 0);
    }
    return lower_bit_membership_to_x(context, expression.args.at(0), expression.args.at(1), 0,
                                     "spatial hit test");
  }

  if (callee == "bit_mask") {
    if (expression.args.size() != 1) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Function " + expression.callee + " expects one argument"));
      return false;
    }
    return lower_bit_mask_to_x(context, expression.args.at(0), 0);
  }

  if (callee == "bit_has") {
    if (expression.args.size() != 2) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Function " + expression.callee + " expects two arguments"));
      return false;
    }
    if (expression.args.at(0).kind == "identifier" &&
        is_segmented_cells_name(context, expression.args.at(0).name)) {
      return lower_segmented_bitplane_hit_to_x(context, expression.args.at(0).name,
                                               expression.args.at(1), 0);
    }
    return lower_bit_membership_to_x(context, expression.args.at(0), expression.args.at(1), 0,
                                     "bit membership test");
  }

  if (callee == "cell_mask") {
    if (expression.args.size() != 2) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Function " + expression.callee + " expects two arguments"));
      return false;
    }
    return lower_expression_to_x(
        context, cell_mask_expression(expression.args.at(0), expression.args.at(1)));
  }

  if (callee == "packed_add") {
    if (expression.args.size() != 3) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Function " + expression.callee + " expects three arguments"));
      return false;
    }
    return lower_expression_to_x(
        context, add_expression(multiply_expression(expression.args.at(2),
                                                    pow10_expression(expression.args.at(1))),
                                expression.args.at(0)));
  }

  if (callee == "packed_digit") {
    if (expression.args.size() != 2) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Function " + expression.callee + " expects two arguments"));
      return false;
    }
    return lower_expression_to_x(
        context, frac_expression(divide_expression(expression.args.at(0),
                                                   pow10_expression(expression.args.at(1)))));
  }

  if (callee == "packed_score") {
    if (expression.args.size() != 2) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Function " + expression.callee + " expects two arguments"));
      return false;
    }
    return lower_expression_to_x(
        context,
        call_expression("sqr", {subtract_expression(frac_expression(divide_expression(
                                                        expression.args.at(0),
                                                        pow10_expression(expression.args.at(1)))),
                                                    number_expression("0.41200076"))}));
  }

  return false;
}

bool lower_call_to_x(LoweringContext& context, const Expression& expression) {
  if (expression.kind != "call")
    return false;
  const auto rule_it = context.rules.find(expression.callee);
  if (rule_it == context.rules.end()) {
    if (lower_builtin_call_to_x(context, expression))
      return true;
    if (has_errors(context.diagnostics))
      return false;
    context.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                   "Native lowering does not support call to '" + expression.callee + "' yet"));
    return false;
  }
  const V2Rule& rule = *rule_it->second;
  if (const std::optional<TrigNearRuleMatch> trig_near = match_trig_near_rule(rule)) {
    if (expression.args.size() != 1U) {
      context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                               rule.name + " expects one native argument"));
      return false;
    }
    if (!lower_expression_to_x(context, expression.args.front()))
      return false;
    if (!lower_expression_to_x(context, trig_near->value))
      return false;
    context.emitter.emit_op(0x11, "-", "near() delta");
    context.emitter.emit_op(0x1d, "F cos", "near() cosine");
    if (!lower_expression_to_x(context, trig_near->threshold))
      return false;
    context.emitter.emit_op(0x11, "-", "near() margin");
    context.optimizations.push_back(OptimizationReport{
        .name = "trig-near-value-function-inline",
        .detail = "Inlined " + rule.name + "() as cos-distance margin without a parameter register.",
    });
    return true;
  }
  if (rule.name == "square") {
    if (expression.args.size() != 1) {
      context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                               "square expects one native argument"));
      return false;
    }
    if (!lower_expression_to_x(context, expression.args.at(0)))
      return false;
    context.emitter.emit_jump(0x53, "ПП", function_label("square"), "call function square");
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }
  if (rule.name == "sum_of_squares") {
    if (expression.args.size() != 2) {
      context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                               "sum_of_squares expects two native arguments"));
      return false;
    }
    if (!lower_expression_to_x(context, expression.args.at(0)))
      return false;
    emit_store(context, "a", "arg a for sum_of_squares");
    if (!lower_expression_to_x(context, expression.args.at(1)))
      return false;
    emit_store(context, "b", "arg b for sum_of_squares");
    context.emitter.emit_jump(0x53, "ПП", function_label("sum_of_squares"),
                              "call function sum_of_squares");
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }
  if (lower_x_param_value_function_call(context, rule, expression.args, 0))
    return true;
  if (match_x_param_stack_stop_risk_rule(rule).has_value()) {
    const std::optional<XParamStackStopRiskRule> risk_rule =
        match_x_param_stack_stop_risk_rule(rule);
    if (expression.args.size() != 1) {
      context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                               rule.name + " expects one native argument"));
      return false;
    }
    if (!lower_expression_to_x(context, expression.args.front()))
      return false;
    const int uses =
        context.proc_call_counts.contains(rule.name) ? context.proc_call_counts[rule.name] : 0;
    if (risk_rule.has_value() && uses == 1) {
      context.emitter.emit_op(0x0e, "В↑", "x-param inline keep displayed value");
      const std::string display_name =
          rule.body.empty() ? risk_rule->param
                            : rule.body.front().inline_name.value_or(risk_rule->param);
      context.emitter.emit_op(0x50, "С/П", "show " + display_name);
      compile_stack_stop_risk_tail(context, risk_rule->risk, rule.body.back().line,
                                   rule.body.back().line);
      context.optimizations.push_back(OptimizationReport{
          .name = "x-param-stack-stop-risk-inline",
          .detail = "Inlined single-use X-parameter stack-stop risk helper " + rule.name + ".",
      });
      return true;
    }
    context.emitter.emit_jump(0x53, "ПП", function_label(rule.name), "call function " + rule.name);
    context.optimizations.push_back(OptimizationReport{
        .name = "x-param-stack-stop-risk-call",
        .detail = "Called X-parameter stack-stop risk helper " + rule.name + ".",
    });
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }
  if (lower_x_param_return_decay_call(context, rule, expression.args, 0))
    return true;
  if (context.x_param_procs.contains(rule.name))
    return lower_x_param_rule_call(context, rule, expression.args, 0);
  if (expression.args.empty() && context.emitter.current_x_known_zero) {
    const std::optional<PackedLineFamilyScoreRule> score_rule =
        packed_line_family_score_rule(context, rule);
    if (score_rule.has_value() && context.stack_only_state_fields.contains(score_rule->score)) {
      context.emitter.emit_jump(0x53, "ПП", packed_line_family_score_zero_entry_label(rule.name),
                                "call function " + rule.name + " zero-accumulator entry");
      mark_current_x(context, score_rule->score);
      context.emitter.current_x_known_zero = false;
      return true;
    }
  }
  if (!lower_rule_arguments(context, rule, expression.args))
    return false;
  context.emitter.emit_jump(0x53, "ПП", function_label(rule.name), "call function " + rule.name);
  context.optimizations.push_back(OptimizationReport{
      .name = "function-call",
      .detail = "Called function " + rule.name + ".",
  });
  if (const std::optional<std::string> return_x = proc_return_x_variable(context, rule)) {
    mark_current_x(context, *return_x);
    context.emitter.current_x_known_zero = false;
  } else {
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
  }
  return true;
}

bool lower_expression_to_x(LoweringContext& context, const Expression& expression,
                           bool allow_constant_fold) {
  if (context.emitter.current_x_expression != nullptr &&
      expression_equals(*context.emitter.current_x_expression, expression)) {
    if (expression.kind == "indexed") {
      context.optimizations.push_back(OptimizationReport{
          .name = "current-x-indexed-reuse",
          .detail = "Reused " + expression_to_source(expression) + " already in X.",
      });
    }
    return true;
  }

  if (const RandomCellHelperRequest* helper = shared_random_cell_helper(context, expression);
      helper != nullptr) {
    context.emitter.emit_jump(0x53, "ПП", helper->label,
                              "random cell " + expression_comment_text(context, expression));
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    context.emitter.current_x_expression.reset();
    context.emitter.current_x_known_zero = false;
    context.optimizations.push_back(OptimizationReport{
        .name = "random-cell-helper-call",
        .detail = "Reused shared random cell helper for " +
                  expression_comment_text(context, expression) + ".",
    });
    return true;
  }

  if (const ExpressionHelperRequest* helper = shared_expression_helper(context, expression);
      helper != nullptr) {
    context.emitter.emit_jump(0x53, "ПП", helper->label,
                              "expr " + expression_to_source(expression));
    clear_current_x_facts(context);
    context.optimizations.push_back(OptimizationReport{
        .name = "expression-helper-call",
        .detail = "Reused shared helper for " + expression_to_source(expression) + ".",
    });
    return true;
  }

  if (expression.kind == "call" && lower_ascii(expression.callee) == "bit_not" &&
      expression.args.size() == 1U && expression.args.front().kind == "binary") {
    return lower_call_to_x(context, expression);
  }

  if (allow_constant_fold && expression.kind != "number" && expression.kind != "identifier") {
    const std::optional<double> folded = numeric_value_of_expression(context, expression);
    if (folded.has_value() && std::isfinite(*folded)) {
      emit_number_or_preload(context, format_number_literal(*folded));
      context.optimizations.push_back(OptimizationReport{
          .name = "expression-constant-folder",
          .detail = "Folded a compile-time expression to " + format_number_literal(*folded) + ".",
      });
      return true;
    }
  }
  auto expr_api = expression_emit_api(context, allow_constant_fold);
  if (const std::optional<bool> basic =
          core::emit::lower_basic_expression_to_x(expr_api, context, expression)) {
    return *basic;
  }
  if (expression.kind == "binary")
    return lower_binary_to_x(context, expression, allow_constant_fold);
  if (expression.kind == "indexed")
    return emit_indexed_recall(context, expression, 0);
  if (expression.kind == "call")
    return lower_call_to_x(context, expression);
  context.diagnostics.push_back(
      diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                 "Native lowering does not support expression kind '" + expression.kind + "' yet"));
  return false;
}

std::string invert_comparison_op(const std::string& op) {
  if (op == "==")
    return "!=";
  if (op == "!=")
    return "==";
  if (op == "<")
    return ">=";
  if (op == "<=")
    return ">";
  if (op == ">")
    return "<=";
  if (op == ">=")
    return "<";
  return op;
}

bool lower_coord_list_contains_false_branch(LoweringContext& context, const V2Predicate& predicate,
                                            bool negated, const std::string& false_label,
                                            int source_line,
                                            std::optional<std::string> branch_comment) {
  const bool entered_with_allocation_failure =
      has_register_allocation_failure(context.diagnostics);
  const std::optional<std::vector<std::string>> items =
      coord_list_items_for(context, trim_ascii(predicate.collection));
  if (!items.has_value())
    return false;
  if (!entered_with_allocation_failure && has_errors(context.diagnostics))
    return false;

  const std::string list_name = trim_ascii(predicate.collection);
  if (!negated) {
    const Expression item = parse_expression(predicate.item, source_line);
    const Expression probe =
        call_expression("line_count", {identifier_expression(list_name), item});
    const std::optional<CoordListIndirectContext> indirect =
        coord_list_indirect_context(context, probe);
    if (indirect.has_value()) {
      const bool scaled = context.scaled_coord_lists.contains(list_name);
      if (scaled && !scale_coord_list_cell_in_place(context, indirect->cell, source_line))
        return false;

      auto api = coord_list_emit_api(context);
      const std::string true_label = context.emitter.fresh_label("coord_list_hit");
      core::emit::lowering::emit_coord_list_loop_setup(api, *indirect, source_line);
      const std::string start_label = context.emitter.fresh_label("coord_list_has_loop");
      context.emitter.emit_label(start_label, {.hidden = true});
      if (!lower_expression_to_x(context, indirect->cell))
        return false;
      core::emit::lowering::emit_coord_list_indirect_recall(api, indirect->pointer, source_line,
                                                            "coord_list candidate");
      context.emitter.emit_op(0x11, "-", "coord_list hit compare", source_line);
      context.emitter.emit_jump(0x57, "F x!=0", true_label, "coord_list hit", source_line);
      core::emit::lowering::emit_coord_list_counter_loop(api, indirect->counter, start_label,
                                                         source_line, "coord_list has loop");
      context.emitter.emit_jump(0x51, "БП", false_label, "coord_list miss", source_line);
      context.emitter.emit_label(true_label, {.hidden = true});
      context.optimizations.push_back(OptimizationReport{
          .name = scaled ? "coord-list-scaled-membership" : "coord-list-indirect-membership",
          .detail = scaled ? "Lowered coord_list membership through scaled decimal coordinates at "
                             "line " +
                                 std::to_string(source_line) + "."
                           : "Lowered coord_list membership through an indirect register walk at "
                             "line " +
                                 std::to_string(source_line) + ".",
      });
      return true;
    }
    if (entered_with_allocation_failure) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Function coord_list_has expects one argument."));
      return false;
    }
  }

  if (negated) {
    for (const std::string& item : *items) {
      if (!lower_condition_false_branch(context, compare_predicate(item, "!=", predicate.item),
                                        false, false_label, source_line,
                                        branch_comment.value_or("coord_list not-in found item"))) {
        return false;
      }
    }
    return true;
  }

  const std::string found_label = context.emitter.fresh_label("coord_list_contains");
  for (const std::string& item : *items) {
    if (!lower_condition_false_branch(context, compare_predicate(item, "!=", predicate.item), false,
                                      found_label, source_line,
                                      branch_comment.value_or("coord_list contains found item"))) {
      return false;
    }
  }
  context.emitter.emit_jump(0x51, "БП", false_label, "coord_list contains miss", source_line);
  context.emitter.emit_label(found_label, {.hidden = true});
  return true;
}

bool lower_cells_contains_false_branch_with_bit_mask_helper(
    LoweringContext& context, const V2Predicate& predicate, bool negated,
    const std::string& false_label, int source_line, std::optional<std::string> branch_comment) {
  const std::string collection = trim_ascii(predicate.collection);
  const V2StateField* collection_field = state_field_named(context, collection);
  if (collection_field == nullptr || collection_field->type != "cells" ||
      is_segmented_cells_name(context, collection)) {
    return false;
  }

  Expression item = parse_expression(predicate.item, source_line);
  const V2Board* board = board_for_cells_mask(context, identifier_expression(collection));
  item = spatial_bit_index_expression_for_board(board, std::move(item));
  if (!lower_expression_to_x(context, item))
    return false;
  if (!emit_bit_mask_helper_call_from_current_x(context, source_line))
    return false;
  if (!lower_expression_to_x(context, identifier_expression(collection)))
    return false;
  context.emitter.emit_op(0x37, "К ∧", "bit_and()", source_line);
  context.emitter.emit_op(0x35, "К {x}", "bit membership fraction", source_line);

  const std::string op = negated ? "==" : "!=";
  const int branch_opcode = negated ? 0x5e : 0x57;
  const std::string branch_mnemonic = negated ? "F x=0" : "F x!=0";
  context.emitter.emit_jump(branch_opcode, branch_mnemonic, false_label,
                            branch_comment.value_or("false branch for " + op), source_line);
  ++context.bit_mask_condition_helper_calls;
  context.optimizations.push_back(OptimizationReport{
      .name = "bit-mask-condition-helper",
      .detail = "Tested bit_has() through the shared bit_mask helper at line " +
                std::to_string(source_line) + ".",
  });
  return true;
}

void emit_membership_fraction_if_needed(LoweringContext& context, const Expression& mask,
                                        std::string comment, int line);
bool expression_is_x2_preserving_decimal_membership_mask(const Expression& expression);

bool lower_cells_contains_false_branch_with_mask_expression(
    LoweringContext& context, const V2Predicate& predicate, bool negated,
    const std::string& false_label, int source_line, std::optional<std::string> branch_comment) {
  const std::string collection = trim_ascii(predicate.collection);
  const V2StateField* collection_field = state_field_named(context, collection);
  if (collection_field == nullptr || collection_field->type != "cells" ||
      is_segmented_cells_name(context, collection)) {
    return false;
  }

  const Expression item = parse_expression(predicate.item, source_line);
  const std::optional<Expression> mask =
      cell_mask_expression_for_collection(context, collection, item);
  if (!mask.has_value())
    return false;

  const bool collection_available_in_x2 =
      x_holds_identifier(context, collection) &&
      expression_is_x2_preserving_decimal_membership_mask(*mask);
  if (!lower_expression_to_x(context, *mask))
    return false;
  if (!collection_available_in_x2 && !lower_expression_to_x(context, identifier_expression(collection)))
    return false;
  context.emitter.emit_op(0x37, "К ∧", "bit_and()", source_line);
  emit_membership_fraction_if_needed(context, *mask, "bit membership fraction", source_line);

  const std::string op = negated ? "==" : "!=";
  const int branch_opcode = negated ? 0x5e : 0x57;
  const std::string branch_mnemonic = negated ? "F x=0" : "F x!=0";
  context.emitter.emit_jump(branch_opcode, branch_mnemonic, false_label,
                            branch_comment.value_or("false branch for " + op), source_line);
  return true;
}

bool lower_cells_contains_false_branch_with_spatial_hit_helper(
    LoweringContext& context, const V2Predicate& predicate, bool negated,
    const std::string& false_label, int source_line, std::optional<std::string> branch_comment) {
  const std::string collection = trim_ascii(predicate.collection);
  const V2StateField* collection_field = state_field_named(context, collection);
  if (collection_field == nullptr || collection_field->type != "cells" ||
      is_segmented_cells_name(context, collection)) {
    return false;
  }
  const std::string scratch = spatial_hit_scratch_name(collection);
  if (!context.register_index_by_name.contains(scratch))
    return false;

  Expression item = parse_expression(predicate.item, source_line);
  const V2Board* board = board_for_cells_mask(context, identifier_expression(collection));
  item = spatial_bit_index_expression_for_board(board, std::move(item));
  if (!lower_expression_to_x(context, item))
    return false;
  if (!emit_spatial_hit_helper_call_from_current_x(context, collection, source_line))
    return false;

  const std::string op = negated ? "==" : "!=";
  const int branch_opcode = negated ? 0x5e : 0x57;
  const std::string branch_mnemonic = negated ? "F x=0" : "F x!=0";
  context.emitter.emit_jump(branch_opcode, branch_mnemonic, false_label,
                            branch_comment.value_or("false branch for " + op), source_line);
  context.optimizations.push_back(OptimizationReport{
      .name = "spatial-hit-condition-helper",
      .detail = "Tested bit_has() through the shared spatial hit helper at line " +
                std::to_string(source_line) + ".",
  });
  return true;
}

bool expression_has_spatial_count_for_mask(const Expression& expression, const std::string& mask) {
  if (expression.kind == "call") {
    const std::string callee = lower_ascii(expression.callee);
    if ((callee == "line_count" || callee == "neighbor_count") && !expression.args.empty() &&
        expression.args.front().kind == "identifier" && expression.args.front().name == mask) {
      return true;
    }
    for (const Expression& arg : expression.args) {
      if (expression_has_spatial_count_for_mask(arg, mask))
        return true;
    }
  }
  if (expression.index != nullptr && expression_has_spatial_count_for_mask(*expression.index, mask))
    return true;
  if (expression.expr != nullptr && expression_has_spatial_count_for_mask(*expression.expr, mask))
    return true;
  if (expression.left != nullptr && expression_has_spatial_count_for_mask(*expression.left, mask))
    return true;
  return expression.right != nullptr && expression_has_spatial_count_for_mask(*expression.right, mask);
}

bool expression_text_has_spatial_count_for_mask(const std::string& text, int line,
                                                const std::string& mask) {
  try {
    return expression_has_spatial_count_for_mask(parse_expression(text, line), mask);
  } catch (const std::exception&) {
    return false;
  }
}

bool statement_has_spatial_count_for_mask(const V2Statement& statement, const std::string& mask);

bool statements_have_spatial_count_for_mask(const std::vector<V2Statement>& statements,
                                            const std::string& mask) {
  return std::any_of(statements.begin(), statements.end(), [&](const V2Statement& statement) {
    return statement_has_spatial_count_for_mask(statement, mask);
  });
}

bool statement_has_spatial_count_for_mask(const V2Statement& statement, const std::string& mask) {
  if (statement.target.has_value() &&
      expression_text_has_spatial_count_for_mask(*statement.target, statement.line, mask))
    return true;
  if (statement.expr.has_value() &&
      expression_text_has_spatial_count_for_mask(*statement.expr, statement.line, mask))
    return true;
  if (statement.predicate.has_value()) {
    const V2Predicate& predicate = *statement.predicate;
    if ((!predicate.left.empty() &&
         expression_text_has_spatial_count_for_mask(predicate.left, statement.line, mask)) ||
        (!predicate.right.empty() &&
         expression_text_has_spatial_count_for_mask(predicate.right, statement.line, mask)) ||
        (!predicate.collection.empty() &&
         expression_text_has_spatial_count_for_mask(predicate.collection, statement.line, mask)) ||
        (!predicate.item.empty() &&
         expression_text_has_spatial_count_for_mask(predicate.item, statement.line, mask))) {
      return true;
    }
  }
  for (const std::string& arg : statement.args) {
    if (expression_text_has_spatial_count_for_mask(arg, statement.line, mask))
      return true;
  }
  for (const V2MatchCase& match_case : statement.cases) {
    for (const std::string& value : match_case.values) {
      if (expression_text_has_spatial_count_for_mask(value, match_case.line, mask))
        return true;
    }
    if (match_case.action != nullptr &&
        statement_has_spatial_count_for_mask(*match_case.action, mask)) {
      return true;
    }
  }
  if (statement.otherwise != nullptr &&
      statement_has_spatial_count_for_mask(*statement.otherwise, mask)) {
    return true;
  }
  return statements_have_spatial_count_for_mask(statement.body, mask) ||
         statements_have_spatial_count_for_mask(statement.then_body, mask) ||
         statements_have_spatial_count_for_mask(statement.else_body, mask);
}

bool program_has_spatial_count_for_mask(const V2Program& program, const std::string& mask) {
  if (statements_have_spatial_count_for_mask(program.body, mask))
    return true;
  return std::any_of(program.rules.begin(), program.rules.end(), [&](const V2Rule& rule) {
    return statements_have_spatial_count_for_mask(rule.body, mask);
  });
}

bool lower_segmented_bitplane_condition_false_branch(LoweringContext& context,
                                                     const V2Predicate& predicate,
                                                     const std::string& false_label,
                                                     int source_line,
                                                     std::optional<std::string> branch_comment) {
  if (predicate.kind != "v2_compare" ||
      !is_zero_expression(context, parse_expression(predicate.right, source_line)))
    return false;
  if (predicate.op != "==" && predicate.op != "!=" && predicate.op != ">=" && predicate.op != "<")
    return false;
  const Expression left = parse_expression(predicate.left, source_line);
  if (left.kind != "call" || lower_ascii(left.callee) != "bit_has" || left.args.size() != 2U)
    return false;
  const Expression& collection = left.args.at(0);
  if (collection.kind != "identifier" || !is_segmented_cells_name(context, collection.name))
    return false;
  if (!lower_segmented_bitplane_hit_to_x(context, collection.name, left.args.at(1), source_line))
    return false;

  int branch_opcode = 0;
  std::string branch_mnemonic;
  if (predicate.op == "==") {
    branch_opcode = 0x5e;
    branch_mnemonic = "F x=0";
  } else if (predicate.op == "!=") {
    branch_opcode = 0x57;
    branch_mnemonic = "F x!=0";
  } else if (predicate.op == ">=") {
    branch_opcode = 0x59;
    branch_mnemonic = "F x>=0";
  } else {
    branch_opcode = 0x5c;
    branch_mnemonic = "F x<0";
  }
  context.emitter.emit_jump(branch_opcode, branch_mnemonic, false_label,
                            branch_comment.value_or("false branch for " + predicate.op),
                            source_line);
  context.optimizations.push_back(OptimizationReport{
      .name = "segmented-bitplane-condition-helper",
      .detail = "Tested " + collection.name +
                " through the shared segmented bitplane helper at line " +
                std::to_string(source_line) + ".",
  });
  return true;
}

std::string swap_comparison_sides_op(const std::string& op) {
  if (op == "<")
    return ">";
  if (op == "<=")
    return ">=";
  if (op == ">")
    return "<";
  if (op == ">=")
    return "<=";
  return op;
}

std::string condition_text(const V2Predicate& predicate) {
  const auto strip_outer_parens = [](const std::string& text) {
    if (text.size() < 2 || text.front() != '(' || text.back() != ')')
      return text;
    int depth = 0;
    for (std::size_t index = 0; index < text.size(); ++index) {
      if (text[index] == '(')
        ++depth;
      else if (text[index] == ')')
        --depth;
      if (depth == 0 && index + 1 < text.size())
        return text;
    }
    return text.substr(1, text.size() - 2);
  };
  return strip_outer_parens(predicate.left) + " " + predicate.op + " " +
         strip_outer_parens(predicate.right);
}

bool is_known_integer_condition_expression(const LoweringContext& context,
                                           const Expression& expression) {
  if (expression.kind != "identifier")
    return false;
  const auto field_it = context.state_fields.find(expression.name);
  if (field_it == context.state_fields.end() || field_it->second == nullptr)
    return false;
  const V2StateField& field = *field_it->second;
  if (field.type == "flag")
    return true;
  if (field.type != "counter" && field.type != "range")
    return false;
  return field.min.has_value() && field.max.has_value() &&
         guarded_is_safe_integer_value(static_cast<double>(*field.min)) &&
         guarded_is_safe_integer_value(static_cast<double>(*field.max));
}

std::optional<std::pair<std::string, long long>> shifted_integer_boundary(const std::string& op,
                                                                          long long value) {
  if (op == "<" && value > std::numeric_limits<long long>::min())
    return std::pair<std::string, long long>{"<=", value - 1};
  if (op == "<=" && value < std::numeric_limits<long long>::max())
    return std::pair<std::string, long long>{"<", value + 1};
  if (op == ">" && value < std::numeric_limits<long long>::max())
    return std::pair<std::string, long long>{">=", value + 1};
  if (op == ">=" && value > std::numeric_limits<long long>::min())
    return std::pair<std::string, long long>{">", value - 1};
  return std::nullopt;
}

std::vector<V2Predicate> equivalent_condition_candidates(const LoweringContext& context,
                                                         const V2Predicate& predicate, int line) {
  std::vector<V2Predicate> candidates{predicate};
  const auto add = [&](V2Predicate candidate) {
    if (std::none_of(candidates.begin(), candidates.end(), [&](const V2Predicate& existing) {
          return common_branch_predicate_equals(existing, candidate, line);
        })) {
      candidates.push_back(std::move(candidate));
    }
  };

  try {
    const Expression left = parse_expression(predicate.left, line);
    const Expression right = parse_expression(predicate.right, line);
    if (left.kind == "number") {
      V2Predicate flipped = predicate;
      flipped.left = predicate.right;
      flipped.op = swap_comparison_sides_op(predicate.op);
      flipped.right = predicate.left;
      add(std::move(flipped));
    }
    if (guarded_expression_is_zero(right) && left.kind == "binary" && left.op == "-" &&
        left.left != nullptr && left.right != nullptr &&
        common_branch_expression_is_deterministic(*left.left) &&
        common_branch_expression_is_deterministic(*left.right)) {
      V2Predicate negated = predicate;
      negated.left = expression_to_source(subtract_expression(*left.right, *left.left));
      negated.op = swap_comparison_sides_op(predicate.op);
      add(std::move(negated));
    }
  } catch (const std::exception&) {
  }

  const std::vector<V2Predicate> current = candidates;
  for (const V2Predicate& candidate : current) {
    try {
      const Expression left = parse_expression(candidate.left, line);
      const Expression right = parse_expression(candidate.right, line);
      const std::optional<double> value = numeric_literal_value(right);
      if (!is_known_integer_condition_expression(context, left) || !value.has_value() ||
          !guarded_is_safe_integer_value(*value)) {
        continue;
      }
      const std::optional<std::pair<std::string, long long>> shifted =
          shifted_integer_boundary(candidate.op, round_to_long_long(*value));
      if (!shifted.has_value())
        continue;
      V2Predicate boundary = candidate;
      boundary.op = shifted->first;
      boundary.right = format_number_literal(static_cast<double>(shifted->second));
      add(std::move(boundary));
    } catch (const std::exception&) {
    }
  }
  return candidates;
}

std::pair<V2Predicate, bool> select_cheaper_equivalent_condition(const LoweringContext& context,
                                                                 const V2Predicate& predicate,
                                                                 int line) {
  V2Predicate best = predicate;
  int best_cost = guarded_condition_compile_cost(predicate, line, &context.preloaded_numbers);
  for (const V2Predicate& candidate : equivalent_condition_candidates(context, predicate, line)) {
    const int cost = guarded_condition_compile_cost(candidate, line, &context.preloaded_numbers);
    if (cost < best_cost) {
      best = candidate;
      best_cost = cost;
    }
  }
  return {best, !common_branch_predicate_equals(best, predicate, line)};
}

std::optional<std::pair<int, std::string>> direct_zero_test_opcode(const std::string& op) {
  if (op == "==")
    return std::pair<int, std::string>{0x5e, "F x=0"};
  if (op == "!=")
    return std::pair<int, std::string>{0x57, "F x!=0"};
  if (op == ">=")
    return std::pair<int, std::string>{0x59, "F x>=0"};
  if (op == "<")
    return std::pair<int, std::string>{0x5c, "F x<0"};
  return std::nullopt;
}

bool lower_direct_zero_false_branch(LoweringContext& context, const V2Predicate& predicate,
                                    const std::string& false_label, int source_line,
                                    std::optional<std::string> branch_comment) {
  const std::optional<std::pair<int, std::string>> opcode = direct_zero_test_opcode(predicate.op);
  if (!opcode.has_value())
    return false;
  const Expression left = parse_expression(predicate.left, source_line);
  const Expression right = parse_expression(predicate.right, source_line);
  if (!is_zero_expression(context, right))
    return false;
  if (!(left.kind == "identifier" && x_holds_identifier(context, left.name))) {
    if (!lower_expression_to_x(context, left))
      return false;
  }
  context.emitter.emit_jump(opcode->first, opcode->second, false_label,
                            branch_comment.value_or("false branch for " + predicate.op),
                            source_line);
  context.optimizations.push_back(OptimizationReport{
      .name = "zero-condition-test",
      .detail = "Tested " + predicate.op + " 0 without materializing a zero literal at line " +
                std::to_string(source_line) + ".",
  });
  return true;
}

bool lower_remainder_zero_false_branch(LoweringContext& context, const V2Predicate& predicate,
                                       const std::string& false_label, int source_line,
                                       std::optional<std::string> branch_comment) {
  if (predicate.op != "==" && predicate.op != "!=")
    return false;
  const Expression left = parse_expression(predicate.left, source_line);
  const Expression right = parse_expression(predicate.right, source_line);
  if (!is_zero_expression(context, right))
    return false;
  const std::optional<core::emit::RemainderByConstantMatch> remainder =
      match_remainder_by_constant(left);
  if (!remainder.has_value())
    return false;
  const std::optional<double> divisor = numeric_literal_value(remainder->divisor);
  if (!divisor.has_value() || *divisor == 0.0)
    return false;

  if (!lower_expression_to_x(context, remainder->value))
    return false;
  if (!lower_expression_to_x(context, remainder->divisor))
    return false;
  context.emitter.emit_op(0x13, "/", "remainder quotient", source_line);
  context.emitter.emit_op(0x35, "К {x}", "remainder zero fractional part", source_line);

  const std::optional<std::pair<int, std::string>> opcode = direct_zero_test_opcode(predicate.op);
  if (!opcode.has_value())
    return false;
  context.emitter.emit_jump(opcode->first, opcode->second, false_label,
                            branch_comment.value_or("false branch for " + predicate.op),
                            source_line);
  clear_current_x_facts(context);
  context.optimizations.push_back(OptimizationReport{
      .name = "remainder-zero-test-lowering",
      .detail = "Tested integer remainder against zero without rescaling the fractional "
                "remainder at line " +
                std::to_string(source_line) + ".",
  });
  return true;
}

bool lower_equality_with_current_x(LoweringContext& context, const V2Predicate& predicate,
                                   const std::string& false_label, int source_line,
                                   std::optional<std::string> branch_comment) {
  if (predicate.op != "==" && predicate.op != "!=")
    return false;
  const Expression left = parse_expression(predicate.left, source_line);
  const Expression right = parse_expression(predicate.right, source_line);
  if (right.kind == "identifier" && x_holds_identifier(context, right.name) &&
      is_simple_stack_load(left)) {
    if (!lower_expression_to_x(context, left))
      return false;
  } else if (left.kind == "identifier" && x_holds_identifier(context, left.name) &&
             is_simple_stack_load(right)) {
    if (!lower_expression_to_x(context, right))
      return false;
  } else {
    return false;
  }

  context.emitter.emit_op(0x11, "-", "condition compare", source_line);
  const int opcode = predicate.op == "==" ? 0x5e : 0x57;
  const std::string mnemonic = predicate.op == "==" ? "F x=0" : "F x!=0";
  context.emitter.emit_jump(opcode, mnemonic, false_label,
                            branch_comment.value_or("false branch for " + predicate.op),
                            source_line);
  context.optimizations.push_back(OptimizationReport{
      .name = "condition-current-x-reuse",
      .detail = "Reused the value already in X for equality comparison at line " +
                std::to_string(source_line) + ".",
  });
  return true;
}

std::optional<std::pair<std::string, std::string>>
negated_zero_test_match(const LoweringContext& context, const V2Predicate& predicate,
                        int source_line, bool require_current_x) {
  const Expression left = parse_expression(predicate.left, source_line);
  const Expression right = parse_expression(predicate.right, source_line);
  if (left.kind == "identifier" && is_zero_expression(context, right) &&
      (!require_current_x || x_holds_identifier(context, left.name))) {
    if (predicate.op == "<=")
      return std::pair<std::string, std::string>{left.name, ">="};
    if (predicate.op == ">")
      return std::pair<std::string, std::string>{left.name, "<"};
  }
  if (is_zero_expression(context, left) && right.kind == "identifier" &&
      (!require_current_x || x_holds_identifier(context, right.name))) {
    if (predicate.op == ">=")
      return std::pair<std::string, std::string>{right.name, ">="};
    if (predicate.op == "<")
      return std::pair<std::string, std::string>{right.name, "<"};
  }
  return std::nullopt;
}

bool lower_negated_zero_false_branch(LoweringContext& context, const V2Predicate& predicate,
                                     const std::string& false_label, int source_line,
                                     std::optional<std::string> branch_comment,
                                     bool require_current_x) {
  const std::optional<std::pair<std::string, std::string>> match =
      negated_zero_test_match(context, predicate, source_line, require_current_x);
  if (!match.has_value())
    return false;
  const std::string& name = match->first;
  if (!require_current_x && !lower_expression_to_x(context, identifier_expression(name)))
    return false;
  context.emitter.emit_op(0x0b, "/-/", "negate " + name + " for zero test", source_line);
  clear_current_x_facts(context);
  const std::optional<std::pair<int, std::string>> opcode = direct_zero_test_opcode(match->second);
  if (!opcode.has_value())
    return false;
  context.emitter.emit_jump(opcode->first, opcode->second, false_label,
                            branch_comment.value_or("false branch for " + predicate.op),
                            source_line);
  context.optimizations.push_back(OptimizationReport{
      .name = require_current_x ? "current-x-negated-zero-test" : "negated-zero-test",
      .detail = (require_current_x ? "Reused " + name + " already in X and negated it for "
                                   : "Negated " + name + " for ") +
                condition_text(predicate) +
                (require_current_x ? "" : " instead of materializing zero") + " at line " +
                std::to_string(source_line) + ".",
  });
  return true;
}

struct NearAnyHelperConditionMatch {
  std::string kind = "near_any";
  Expression value;
  Expression radius;
  std::vector<Expression> candidates;
  std::string op;
};

std::string near_any_helper_key(const std::string& kind, const Expression& value,
                                const Expression& radius) {
  return kind + "|" + expression_to_json(value) + "|" + expression_to_json(radius);
}

std::string near_any_helper_comment_kind(const std::string& kind) {
  return kind == "trig_near" ? "near()" : "near_any";
}

std::string flip_zero_comparison_operands_op(const std::string& op) {
  if (op == "<")
    return ">";
  if (op == "<=")
    return ">=";
  if (op == ">")
    return "<";
  if (op == ">=")
    return "<=";
  return op;
}

std::optional<Expression> near_any_simple_stack_load(LoweringContext& context,
                                                     const Expression& expression,
                                                     bool report_resolution, int source_line) {
  if (is_simple_stack_load(expression))
    return expression;
  if (expression.kind != "indexed" || expression.index == nullptr)
    return std::nullopt;
  const std::string key = bank_member_key(expression.base, expression.field);
  const auto bank_it = context.state_banks.find(key);
  if (bank_it == context.state_banks.end())
    return std::nullopt;
  const V2StateField& field = *bank_it->second;
  const std::optional<double> value = numeric_value_of_expression(context, *expression.index);
  if (!value.has_value() || std::fabs(*value - std::round(*value)) >= 1e-12)
    return std::nullopt;
  const int index = static_cast<int>(round_to_long_long(*value));
  if (index < field.bank->min || index > field.bank->max)
    return std::nullopt;
  if (report_resolution)
    ++context.constant_indexed_state_resolutions;
  (void)source_line;
  return identifier_expression(state_bank_element_name(field, index));
}

std::optional<TrigNearRuleMatch> match_trig_near_rule(const V2Rule& rule) {
  if (rule.params.size() != 1U || rule.body.size() != 1U)
    return std::nullopt;
  const V2Statement& ret = rule.body.front();
  if (ret.kind != "v2_return" || !ret.expr.has_value())
    return std::nullopt;

  Expression margin;
  try {
    margin = parse_expression(*ret.expr, ret.line);
  } catch (const std::exception&) {
    return std::nullopt;
  }
  if (margin.kind != "binary" || margin.op != "-" || margin.left == nullptr ||
      margin.right == nullptr) {
    return std::nullopt;
  }
  const Expression& cos_call = *margin.left;
  if (cos_call.kind != "call" || lower_ascii(cos_call.callee) != "cos" ||
      cos_call.args.size() != 1U) {
    return std::nullopt;
  }
  const Expression& delta = cos_call.args.front();
  if (delta.kind != "binary" || delta.op != "-" || delta.left == nullptr ||
      delta.right == nullptr) {
    return std::nullopt;
  }

  const std::string& param = rule.params.front();
  const Expression* value = nullptr;
  if (identifier_expression_is(*delta.left, param)) {
    value = delta.right.get();
  } else if (identifier_expression_is(*delta.right, param)) {
    value = delta.left.get();
  } else {
    return std::nullopt;
  }
  if (identifier_expression_is(*value, param))
    return std::nullopt;

  return TrigNearRuleMatch{
      .param = param,
      .value = *value,
      .threshold = *margin.right,
      .line = ret.line,
  };
}

bool collect_trig_near_function_candidates(LoweringContext& context, const Expression& expression,
                                           int source_line, bool report_resolution,
                                           std::optional<Expression>& value,
                                           std::optional<Expression>& threshold,
                                           std::vector<Expression>& candidates) {
  if (expression.kind != "call")
    return false;
  if (lower_ascii(expression.callee) == "max" && expression.args.size() >= 2U) {
    for (const Expression& arg : expression.args) {
      if (!collect_trig_near_function_candidates(context, arg, source_line, report_resolution,
                                                 value, threshold, candidates)) {
        return false;
      }
    }
    return true;
  }

  const auto rule_it = context.rules.find(expression.callee);
  if (rule_it == context.rules.end())
    return false;
  const std::optional<TrigNearRuleMatch> near_rule = match_trig_near_rule(*rule_it->second);
  if (!near_rule.has_value() || expression.args.size() != 1U)
    return false;

  std::optional<Expression> rule_value =
      near_any_simple_stack_load(context, near_rule->value, report_resolution, source_line);
  std::optional<Expression> rule_threshold =
      near_any_simple_stack_load(context, near_rule->threshold, report_resolution, source_line);
  std::optional<Expression> candidate =
      near_any_simple_stack_load(context, expression.args.front(), report_resolution, source_line);
  if (!rule_value.has_value() || !rule_threshold.has_value() || !candidate.has_value())
    return false;

  if (value.has_value() && !expression_equals(*value, *rule_value))
    return false;
  if (threshold.has_value() && !expression_equals(*threshold, *rule_threshold))
    return false;
  value = std::move(*rule_value);
  threshold = std::move(*rule_threshold);
  candidates.push_back(std::move(*candidate));
  return true;
}

int condition_expression_cost(const LoweringContext& context, const Expression& expression) {
  if (expression.kind == "number" && has_preloaded_number(context, expression.raw))
    return 1;
  if (expression.kind == "unary" && expression.op == "-" && expression.expr != nullptr &&
      expression.expr->kind == "number" &&
      has_preloaded_number(context, "-" + expression.expr->raw)) {
    return 1;
  }
  if (expression.kind == "string")
    return 0;
  if (expression.kind == "number")
    return guarded_estimate_number_cost(expression.raw);
  if (expression.kind == "identifier")
    return 1;
  if (expression.kind == "indexed")
    return (expression.index == nullptr ? 0
                                        : condition_expression_cost(context, *expression.index)) +
           2;
  if (expression.kind == "unary")
    return (expression.expr == nullptr ? 0 : condition_expression_cost(context, *expression.expr)) +
           1;
  if (expression.kind == "binary") {
    if (expression.op == "*" && expression.left != nullptr && expression.right != nullptr &&
        expression_equals(*expression.left, *expression.right) &&
        expression_pure_for_substitution(*expression.left)) {
      return condition_expression_cost(context, *expression.left) + 1;
    }
    if (expression.op == "/" && expression.left != nullptr && expression.right != nullptr &&
        is_numeric_literal_value(*expression.left, 1)) {
      return condition_expression_cost(context, *expression.right) + 1;
    }
    return (expression.left == nullptr ? 0 : condition_expression_cost(context, *expression.left)) +
           (expression.right == nullptr ? 0
                                        : condition_expression_cost(context, *expression.right)) +
           1;
  }
  if (expression.kind == "call") {
    const std::string name = lower_ascii(expression.callee);
    if (const std::optional<Expression> small_set_macro =
            small_set_expression_macro(name, expression.args)) {
      return condition_expression_cost(context, *small_set_macro);
    }
    if (name == "min" || name == "max" || name == "safe_min" || name == "safe_max" ||
        name == "bit_and" || name == "bit_or" || name == "bit_xor" || name == "pow") {
      return (expression.args.empty() ? 0
                                      : condition_expression_cost(context, expression.args.at(0))) +
             (expression.args.size() < 2U
                  ? 0
                  : condition_expression_cost(context, expression.args.at(1))) +
             1;
    }
    return (expression.args.empty() ? 0
                                    : condition_expression_cost(context, expression.args.front())) +
           1;
  }
  return guarded_estimate_expression_cost(expression);
}

int near_any_margin_cost(const LoweringContext& context, const Expression& value,
                         const Expression& radius, const Expression& candidate) {
  return condition_expression_cost(context, value) + condition_expression_cost(context, candidate) +
         1 + 1 + condition_expression_cost(context, radius) + 1;
}

int trig_near_margin_cost(const LoweringContext& context, const Expression& value,
                          const Expression& threshold, const Expression& candidate) {
  return condition_expression_cost(context, value) + condition_expression_cost(context, candidate) +
         1 + 1 + condition_expression_cost(context, threshold) + 1;
}

int near_any_condition_inline_cost(const LoweringContext& context,
                                   const NearAnyHelperConditionMatch& match) {
  int cost = 0;
  for (const Expression& candidate : match.candidates) {
    cost += match.kind == "trig_near"
                ? trig_near_margin_cost(context, match.value, match.radius, candidate)
                : near_any_margin_cost(context, match.value, match.radius, candidate);
  }
  cost += static_cast<int>(match.candidates.empty() ? 0U : match.candidates.size() - 1U);
  cost += 2;
  return cost;
}

int near_any_helper_condition_call_cost(const LoweringContext& context,
                                        const NearAnyHelperConditionMatch& match) {
  int cost = 0;
  for (const Expression& candidate : match.candidates)
    cost += condition_expression_cost(context, candidate) + 2;
  cost += static_cast<int>(match.candidates.empty() ? 0U : match.candidates.size() - 1U);
  cost += 2;
  return cost;
}

std::optional<NearAnyHelperConditionMatch>
match_near_any_helper_condition(LoweringContext& context, const V2Predicate& predicate,
                                int source_line, bool report_resolution) {
  if (predicate.kind != "v2_compare")
    return std::nullopt;
  Expression tested;
  std::string op;
  try {
    const Expression left = parse_expression(predicate.left, source_line);
    const Expression right = parse_expression(predicate.right, source_line);
    if (is_zero_expression(context, right)) {
      tested = left;
      op = predicate.op;
    } else if (is_zero_expression(context, left)) {
      tested = right;
      op = flip_zero_comparison_operands_op(predicate.op);
    } else {
      return std::nullopt;
    }
  } catch (const std::exception&) {
    return std::nullopt;
  }
  if (op != ">=" && op != "<")
    return std::nullopt;
  if (tested.kind != "call")
    return std::nullopt;
  const std::string kind = lower_ascii(tested.callee);
  if (kind != "near_any") {
    std::optional<Expression> value;
    std::optional<Expression> threshold;
    std::vector<Expression> candidates;
    if (!collect_trig_near_function_candidates(context, tested, source_line, report_resolution,
                                               value, threshold, candidates) ||
        !value.has_value() || !threshold.has_value() || candidates.empty()) {
      return std::nullopt;
    }
    return NearAnyHelperConditionMatch{
        .kind = "trig_near",
        .value = std::move(*value),
        .radius = std::move(*threshold),
        .candidates = std::move(candidates),
        .op = op,
    };
  }
  if (tested.args.size() < 3U)
    return std::nullopt;

  std::optional<Expression> value =
      near_any_simple_stack_load(context, tested.args.at(0), report_resolution, source_line);
  std::optional<Expression> radius =
      near_any_simple_stack_load(context, tested.args.at(1), report_resolution, source_line);
  if (!value.has_value() || !radius.has_value())
    return std::nullopt;

  std::vector<Expression> candidates;
  for (std::size_t index = 2; index < tested.args.size(); ++index) {
    std::optional<Expression> candidate =
        near_any_simple_stack_load(context, tested.args.at(index), report_resolution, source_line);
    if (!candidate.has_value())
      return std::nullopt;
    candidates.push_back(std::move(*candidate));
  }
  if (candidates.empty())
    return std::nullopt;
  return NearAnyHelperConditionMatch{
      .kind = kind,
      .value = std::move(*value),
      .radius = std::move(*radius),
      .candidates = std::move(candidates),
      .op = op,
  };
}

void collect_near_any_helper_stats_for_statement(LoweringContext& context,
                                                 const V2Statement& statement);

void add_near_any_helper_stat(LoweringContext& context, const V2Predicate& predicate,
                              int source_line, bool negated) {
  V2Predicate effective_predicate = predicate;
  if (negated)
    effective_predicate.op = invert_comparison_op(effective_predicate.op);
  const auto [selected_predicate, unused_normalized] =
      select_cheaper_equivalent_condition(context, effective_predicate, source_line);
  (void)unused_normalized;
  const std::optional<NearAnyHelperConditionMatch> match =
      match_near_any_helper_condition(context, selected_predicate, source_line, false);
  if (!match.has_value())
    return;

  const std::string key = near_any_helper_key(match->kind, match->value, match->radius);
  const int helper_condition_cost = near_any_helper_condition_call_cost(context, *match);
  const int ordinary_cost = near_any_condition_inline_cost(context, *match);
  const auto existing = context.near_any_helper_stats.find(key);
  if (existing == context.near_any_helper_stats.end()) {
    const int helper_body_cost = condition_expression_cost(context, match->value) +
                                 condition_expression_cost(context, match->radius) +
                                 (match->kind == "trig_near" ? 4 : 5);
    context.near_any_helper_stats.emplace(
        key, NearAnyHelperStats{
                 .candidate_count = static_cast<int>(match->candidates.size()),
                 .condition_count = 1,
                 .ordinary_cost = ordinary_cost,
                 .helper_call_cost = helper_condition_cost,
                 .helper_cost = helper_body_cost + helper_condition_cost,
             });
    return;
  }
  NearAnyHelperStats& stats = existing->second;
  stats.candidate_count += static_cast<int>(match->candidates.size());
  stats.condition_count += 1;
  stats.ordinary_cost += ordinary_cost;
  stats.helper_call_cost += helper_condition_cost;
  stats.helper_cost += helper_condition_cost;
}

void collect_near_any_helper_stats_for_statements(LoweringContext& context,
                                                  const std::vector<V2Statement>& statements) {
  for (const V2Statement& statement : statements)
    collect_near_any_helper_stats_for_statement(context, statement);
}

void collect_near_any_helper_stats_for_statement(LoweringContext& context,
                                                 const V2Statement& statement) {
  if ((statement.kind == "v2_if" || statement.kind == "v2_while") &&
      statement.predicate.has_value()) {
    add_near_any_helper_stat(context, *statement.predicate, statement.line, statement.negated);
  }
  collect_near_any_helper_stats_for_statements(context, statement.body);
  collect_near_any_helper_stats_for_statements(context, statement.then_body);
  collect_near_any_helper_stats_for_statements(context, statement.else_body);
  for (const V2MatchCase& match_case : statement.cases) {
    if (match_case.action != nullptr)
      collect_near_any_helper_stats_for_statement(context, *match_case.action);
  }
  if (statement.otherwise != nullptr)
    collect_near_any_helper_stats_for_statement(context, *statement.otherwise);
}

void collect_near_any_helper_stats(LoweringContext& context, const V2Program& program) {
  context.near_any_helper_stats.clear();
  collect_near_any_helper_stats_for_statements(context, program.body);
  for (const V2Rule& rule : program.rules)
    collect_near_any_helper_stats_for_statements(context, rule.body);
}

const NearAnyHelperRequest& ensure_near_any_helper(LoweringContext& context,
                                                   const NearAnyHelperConditionMatch& match,
                                                   int source_line) {
  const std::string key = near_any_helper_key(match.kind, match.value, match.radius);
  const auto existing = context.near_any_helper_labels.find(key);
  if (existing != context.near_any_helper_labels.end()) {
    const auto helper = std::find_if(
        context.near_any_helpers.begin(), context.near_any_helpers.end(),
        [&](const NearAnyHelperRequest& candidate) { return candidate.label == existing->second; });
    if (helper != context.near_any_helpers.end())
      return *helper;
  }
  const std::string label_prefix = match.kind == "trig_near" ? "__trig_near_" : "__near_any_";
  const std::string label = label_prefix + std::to_string(context.near_any_helpers.size());
  context.near_any_helper_labels[key] = label;
  context.near_any_helpers.push_back(NearAnyHelperRequest{
      .key = key,
      .label = label,
      .kind = match.kind,
      .value = match.value,
      .radius = match.radius,
      .line = source_line,
  });
  return context.near_any_helpers.back();
}

bool lower_near_any_candidate_for_helper(LoweringContext& context, const Expression& candidate,
                                         int source_line, const std::string& kind) {
  if (candidate.kind == "identifier" && x_holds_identifier(context, candidate.name)) {
    const std::string comment_kind = near_any_helper_comment_kind(kind);
    context.optimizations.push_back(OptimizationReport{
        .name = "stack-current-x-scheduling",
        .detail = "Reused " + candidate.name + " already in X for " + comment_kind +
                  " candidate at line " + std::to_string(source_line) + ".",
    });
    return true;
  }
  return lower_expression_to_x(context, candidate);
}

bool lower_near_any_margin_with_helper(LoweringContext& context,
                                       const NearAnyHelperConditionMatch& match,
                                       const std::string& label, int source_line) {
  const std::string comment_kind = near_any_helper_comment_kind(match.kind);
  for (std::size_t index = 0; index < match.candidates.size(); ++index) {
    if (!lower_near_any_candidate_for_helper(context, match.candidates.at(index), source_line,
                                             match.kind))
      return false;
    context.emitter.emit_jump(0x53, "ПП", label, comment_kind + " candidate", source_line);
    if (index > 0)
      context.emitter.emit_op(0x36, "К max", comment_kind + " max margin", source_line);
  }
  return true;
}

bool lower_near_any_helper_condition_false_branch(LoweringContext& context,
                                                  const V2Predicate& predicate,
                                                  const std::string& false_label, int source_line) {
  if (context.emitting_near_any_helper)
    return false;
  const std::optional<NearAnyHelperConditionMatch> match =
      match_near_any_helper_condition(context, predicate, source_line, true);
  if (!match.has_value())
    return false;
  const std::string key = near_any_helper_key(match->kind, match->value, match->radius);
  const auto stats_it = context.near_any_helper_stats.find(key);
  if (stats_it == context.near_any_helper_stats.end() ||
      stats_it->second.helper_cost >= stats_it->second.ordinary_cost) {
    return false;
  }

  const NearAnyHelperRequest& helper = ensure_near_any_helper(context, *match, source_line);
  if (!lower_near_any_margin_with_helper(context, *match, helper.label, source_line))
    return false;
  const std::optional<std::pair<int, std::string>> opcode = direct_zero_test_opcode(match->op);
  if (!opcode.has_value())
    return false;
  context.emitter.emit_jump(opcode->first, opcode->second, false_label,
                            "false branch for " + match->op, source_line);
  context.optimizations.push_back(OptimizationReport{
      .name = "near-any-helper-lowering",
      .detail = "Lowered " + condition_text(predicate) + " through shared " +
                near_any_helper_comment_kind(match->kind) + " helper at line " +
                std::to_string(source_line) + " (" +
                std::to_string(stats_it->second.helper_cost) + " vs " +
                std::to_string(stats_it->second.ordinary_cost) + " estimated group steps).",
  });
  return true;
}

Expression near_any_margin_expression(const Expression& value, const Expression& radius,
                                      const Expression& candidate) {
  return binary_expression(radius, "-",
                           call_expression("abs", {binary_expression(value, "-", candidate)}));
}

Expression eq_any_difference_expression(const Expression& value, const Expression& candidate) {
  return binary_expression(value, "-", candidate);
}

bool emit_small_set_any_condition(LoweringContext& context, const std::string& kind,
                                  const std::vector<Expression>& tests,
                                  const std::pair<int, std::string>& true_test,
                                  const std::pair<int, std::string>& false_test,
                                  const std::string& false_label, int source_line) {
  if (tests.size() < 2U)
    return false;
  const std::string true_label = context.emitter.fresh_label(kind + "_any_true");
  for (std::size_t index = 0; index + 1U < tests.size(); ++index) {
    if (!lower_expression_to_x(context, tests.at(index)))
      return false;
    context.emitter.emit_jump(true_test.first, true_test.second, true_label, kind + " any hit",
                              source_line);
  }
  if (!lower_expression_to_x(context, tests.back()))
    return false;
  context.emitter.emit_jump(false_test.first, false_test.second, false_label, kind + " any miss",
                            source_line);
  context.emitter.emit_label(true_label, {.hidden = true});
  return true;
}

bool emit_small_set_all_condition(LoweringContext& context, const std::string& kind,
                                  const std::vector<Expression>& tests,
                                  const std::pair<int, std::string>& false_test,
                                  const std::string& false_label, int source_line) {
  if (tests.size() < 2U)
    return false;
  for (const Expression& test : tests) {
    if (!lower_expression_to_x(context, test))
      return false;
    context.emitter.emit_jump(false_test.first, false_test.second, false_label, kind + " all miss",
                              source_line);
  }
  return true;
}

int small_set_condition_cost(
    LoweringContext& context, const std::vector<Expression>& tests) {
  int cost = 0;
  for (const Expression& test : tests) {
    cost += guarded_estimate_expression_cost_for_condition(test, &context.preloaded_numbers) + 2;
  }
  return cost;
}

bool lower_small_set_condition_false_branch(LoweringContext& context, const V2Predicate& predicate,
                                            bool source_negated,
                                            const std::string& false_label, int source_line) {
  if (predicate.kind != "v2_compare")
    return false;
  const Expression right = parse_expression(predicate.right, source_line);
  if (!is_zero_expression(context, right))
    return false;

  const Expression left = parse_expression(predicate.left, source_line);
  if (left.kind != "call")
    return false;

  const std::string callee = lower_ascii(left.callee);
  std::vector<Expression> tests;

  if (callee == "near_any" && left.args.size() >= 4U &&
      (predicate.op == ">=" || predicate.op == "<")) {
    const Expression& value = left.args.at(0);
    const Expression& radius = left.args.at(1);
    for (std::size_t index = 2; index < left.args.size(); ++index)
      tests.push_back(near_any_margin_expression(value, radius, left.args.at(index)));
    const std::optional<std::pair<int, std::string>> true_test = direct_zero_test_opcode("<");
    const std::optional<std::pair<int, std::string>> false_test = direct_zero_test_opcode(">=");
    if (!true_test.has_value() || !false_test.has_value())
      return false;
    if (source_negated || predicate.op == "<") {
      const int selected_cost = small_set_condition_cost(context, tests);
      const int ordinary_cost =
          guarded_condition_compile_cost(predicate, source_line, &context.preloaded_numbers);
      if (selected_cost >= ordinary_cost)
        return false;
    }
    const bool lowered = predicate.op == ">="
                             ? emit_small_set_any_condition(context, "near_any", tests, *true_test,
                                                            *false_test, false_label, source_line)
                             : emit_small_set_all_condition(context, "near_any", tests, *false_test,
                                                            false_label, source_line);
    if (!lowered)
      return false;
  } else if (callee == "eq_any" && left.args.size() >= 3U &&
             (predicate.op == "==" || predicate.op == "!=")) {
    const Expression& value = left.args.at(0);
    for (std::size_t index = 1; index < left.args.size(); ++index)
      tests.push_back(eq_any_difference_expression(value, left.args.at(index)));
    const std::optional<std::pair<int, std::string>> true_test = direct_zero_test_opcode("!=");
    const std::optional<std::pair<int, std::string>> false_test = direct_zero_test_opcode("==");
    if (!true_test.has_value() || !false_test.has_value())
      return false;
    if (source_negated || predicate.op == "!=") {
      const int selected_cost = small_set_condition_cost(context, tests);
      const int ordinary_cost =
          guarded_condition_compile_cost(predicate, source_line, &context.preloaded_numbers);
      if (selected_cost >= ordinary_cost)
        return false;
    }
    const bool lowered = predicate.op == "=="
                             ? emit_small_set_any_condition(context, "eq_any", tests, *true_test,
                                                            *false_test, false_label, source_line)
                             : emit_small_set_all_condition(context, "eq_any", tests, *false_test,
                                                            false_label, source_line);
    if (!lowered)
      return false;
  } else {
    return false;
  }

  context.optimizations.push_back(OptimizationReport{
      .name = "small-set-condition-lowering",
      .detail = "Lowered " + condition_text(predicate) + " as " + std::to_string(tests.size()) +
                " direct small-set tests at line " + std::to_string(source_line) + ".",
  });
  return true;
}

bool lower_negative_zero_threshold_flow_false_branch(LoweringContext& context,
                                                     const V2Predicate& predicate,
                                                     const std::string& false_label,
                                                     int source_line);

bool lower_condition_false_branch(LoweringContext& context, const V2Predicate& predicate,
                                  bool negated, const std::string& false_label, int source_line,
                                  std::optional<std::string> branch_comment) {
  const bool entered_with_errors = has_errors(context.diagnostics);

  if (predicate.kind == "v2_contains") {
    if (lower_coord_list_contains_false_branch(context, predicate, negated, false_label,
                                               source_line, branch_comment)) {
      return true;
    }
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;

    const std::string collection = trim_ascii(predicate.collection);
    if (context.shared_bit_mask_helper_calls && context.program != nullptr &&
        program_has_spatial_count_for_mask(*context.program, collection)) {
      if (lower_cells_contains_false_branch_with_bit_mask_helper(
              context, predicate, negated, false_label, source_line, branch_comment)) {
        return true;
      }
      if (!entered_with_errors && has_errors(context.diagnostics))
        return false;
    }

    if (lower_cells_contains_false_branch_with_spatial_hit_helper(
            context, predicate, negated, false_label, source_line, branch_comment)) {
      return true;
    }
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;

    if (lower_cells_contains_false_branch_with_mask_expression(
            context, predicate, negated, false_label, source_line, branch_comment)) {
      return true;
    }
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;

    if (lower_cells_contains_false_branch_with_bit_mask_helper(
            context, predicate, negated, false_label, source_line, branch_comment)) {
      return true;
    }
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;

    const V2StateField* collection_field =
        state_field_named(context, collection);
    if (collection_field != nullptr && collection_field->type == "cells") {
      V2Predicate bit_has_test;
      bit_has_test.kind = "v2_compare";
      bit_has_test.left = "bit_has(" + predicate.collection + ", " + predicate.item + ")";
      bit_has_test.op = "!=";
      bit_has_test.right = "0";
      return lower_condition_false_branch(
          context, bit_has_test, negated, false_label, source_line,
          branch_comment.value_or(negated ? "false branch for cells not in"
                                          : "false branch for cells in"));
    }

    V2Predicate bit_test;
    bit_test.kind = "v2_compare";
    bit_test.left = "bit_and(" + predicate.collection + ", " + predicate.item + ")";
    bit_test.op = "!=";
    bit_test.right = "0";
    return lower_condition_false_branch(
        context, bit_test, negated, false_label, source_line,
        branch_comment.value_or(negated ? "false branch for not in" : "false branch for in"));
  }

  if (predicate.kind != "v2_compare") {
    context.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                   "Native if lowering currently supports comparison predicates only"));
    return false;
  }

  V2Predicate effective_predicate = predicate;
  if (negated)
    effective_predicate.op = invert_comparison_op(effective_predicate.op);
  if (lower_negative_zero_threshold_flow_false_branch(context, effective_predicate, false_label,
                                                      source_line))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;

  const auto [selected_predicate, normalized] =
      select_cheaper_equivalent_condition(context, effective_predicate, source_line);
  if (normalized) {
    context.optimizations.push_back(OptimizationReport{
        .name = "comparison-boundary-normalization",
        .detail = "Normalized " + condition_text(effective_predicate) + " to " +
                  condition_text(selected_predicate) + " at line " + std::to_string(source_line) +
                  ".",
    });
  }

  if (lower_near_any_helper_condition_false_branch(context, selected_predicate, false_label,
                                                   source_line))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;

  if (lower_small_set_condition_false_branch(context, selected_predicate, negated, false_label,
                                             source_line))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;

  if (lower_remainder_zero_false_branch(context, selected_predicate, false_label, source_line,
                                        branch_comment))
    return true;

  if (lower_segmented_bitplane_condition_false_branch(context, selected_predicate, false_label,
                                                      source_line, branch_comment))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;

  if (lower_direct_zero_false_branch(context, selected_predicate, false_label, source_line,
                                     branch_comment))
    return true;
  if (lower_equality_with_current_x(context, selected_predicate, false_label, source_line,
                                    branch_comment))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;

  if (lower_negated_zero_false_branch(context, selected_predicate, false_label, source_line,
                                      branch_comment, true))
    return true;
  if (lower_negated_zero_false_branch(context, selected_predicate, false_label, source_line,
                                      branch_comment, false))
    return true;

  const std::string op = selected_predicate.op;
  std::string left_text = selected_predicate.left;
  std::string right_text = selected_predicate.right;
  int branch_opcode = 0;
  std::string branch_mnemonic;

  if (op == "==") {
    branch_opcode = 0x5e;
    branch_mnemonic = "F x=0";
  } else if (op == "!=") {
    branch_opcode = 0x57;
    branch_mnemonic = "F x!=0";
  } else if (op == ">=") {
    branch_opcode = 0x59;
    branch_mnemonic = "F x>=0";
  } else if (op == "<") {
    branch_opcode = 0x5c;
    branch_mnemonic = "F x<0";
  } else if (op == ">") {
    std::swap(left_text, right_text);
    branch_opcode = 0x5c;
    branch_mnemonic = "F x<0";
  } else if (op == "<=") {
    std::swap(left_text, right_text);
    branch_opcode = 0x59;
    branch_mnemonic = "F x>=0";
  } else {
    context.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                   "Native if lowering does not support comparison '" + predicate.op + "'"));
    return false;
  }

  const Expression left = parse_expression(left_text, source_line);
  const Expression right = parse_expression(right_text, source_line);
  if (!lower_expression_to_x(context, left))
    return false;
  if (is_zero_expression(context, right)) {
    context.emitter.emit_jump(branch_opcode, branch_mnemonic, false_label,
                              branch_comment.value_or("false branch for " + op), source_line);
    return true;
  }
  if (!lower_expression_to_x(context, right))
    return false;
  context.emitter.emit_op(0x11, "-", "condition compare", source_line);
  context.emitter.emit_jump(branch_opcode, branch_mnemonic, false_label,
                            branch_comment.value_or("false branch for " + op), source_line);
  return true;
}

struct EqualityConstantCondition {
  Expression expr;
  int value = 0;
};

std::optional<int> integer_constant_expression(const LoweringContext& context,
                                               const Expression& expression) {
  const std::optional<double> value = numeric_value_of_expression(context, expression);
  if (!value.has_value() || std::fabs(*value - std::round(*value)) >= 1e-12)
    return std::nullopt;
  return static_cast<int>(round_to_long_long(*value));
}

std::optional<EqualityConstantCondition>
match_equality_constant_predicate(const LoweringContext& context, const V2Predicate& predicate,
                                  int source_line) {
  if (predicate.kind != "v2_compare" || predicate.op != "==")
    return std::nullopt;

  const Expression left = parse_expression(predicate.left, source_line);
  const Expression right = parse_expression(predicate.right, source_line);
  if (const std::optional<int> value = integer_constant_expression(context, right)) {
    return EqualityConstantCondition{.expr = left, .value = *value};
  }
  if (const std::optional<int> value = integer_constant_expression(context, left)) {
    return EqualityConstantCondition{.expr = right, .value = *value};
  }
  return std::nullopt;
}

void emit_residual_else_if_adjustment(LoweringContext& context, int previous_value, int next_value,
                                      int source_line) {
  const int delta = previous_value - next_value;
  if (delta == 0)
    return;
  if (delta > 0) {
    emit_number_or_preload(context, std::to_string(delta));
    context.emitter.emit_op(0x10, "+", "residual else-if compare", source_line);
    return;
  }
  emit_number_or_preload(context, std::to_string(-delta));
  context.emitter.emit_op(0x11, "-", "residual else-if compare", source_line);
}

bool lower_residual_equality_else_if(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() || statement.negated ||
      statement.else_body.size() != 1)
    return false;
  const V2Statement& nested = statement.else_body.front();
  if (nested.kind != "v2_if" || !nested.predicate.has_value() || nested.negated)
    return false;

  const std::optional<EqualityConstantCondition> first =
      match_equality_constant_predicate(context, *statement.predicate, statement.line);
  const std::optional<EqualityConstantCondition> second =
      match_equality_constant_predicate(context, *nested.predicate, nested.line);
  if (!first.has_value() || !second.has_value() || first->value == second->value ||
      !expression_equals(first->expr, second->expr)) {
    return false;
  }

  const std::string first_false_label = context.emitter.fresh_label("if_residual_next");
  const std::string second_false_label = context.emitter.fresh_label("if_residual_false");
  const bool then_stops = statements_always_stop(context, statement.then_body);
  const bool nested_then_stops = statements_always_stop(context, nested.then_body);
  const bool needs_end_label = !then_stops || (!nested.else_body.empty() && !nested_then_stops);
  const std::string end_label =
      needs_end_label ? context.emitter.fresh_label("if_residual_end") : "";

  if (!lower_expression_to_x(context, first->expr))
    return false;
  emit_number_or_preload(context, std::to_string(first->value));
  context.emitter.emit_op(0x11, "-", "condition compare", statement.line);
  context.emitter.emit_jump(0x5e, "F x=0", first_false_label,
                            "false branch for ==", statement.line);
  if (!lower_statement_block(context, statement.then_body))
    return false;
  if (!then_stops && needs_end_label)
    context.emitter.emit_jump(0x51, "БП", end_label, "if end", statement.line);

  context.emitter.emit_label(first_false_label, {.hidden = true});
  emit_residual_else_if_adjustment(context, first->value, second->value, nested.line);
  context.emitter.emit_jump(0x5e, "F x=0", second_false_label, "false branch for ==", nested.line);
  if (!lower_statement_block(context, nested.then_body))
    return false;
  if (!nested.else_body.empty() && !nested_then_stops && needs_end_label)
    context.emitter.emit_jump(0x51, "БП", end_label, "if end", nested.line);

  context.emitter.emit_label(second_false_label, {.hidden = true});
  if (!nested.else_body.empty() && !lower_statement_block(context, nested.else_body))
    return false;
  if (needs_end_label)
    context.emitter.emit_label(end_label, {.hidden = true});

  context.optimizations.push_back(OptimizationReport{
      .name = "residual-elseif-compare",
      .detail = "Reused a failed equality residual for the next equality test at line " +
                std::to_string(nested.line) + ".",
  });
  return true;
}

bool statements_are_domain_error_trap(LoweringContext& context,
                                      const std::vector<V2Statement>& statements,
                                      std::set<std::string>& seen_rules) {
  if (statements.size() != 1)
    return false;
  const V2Statement& statement = statements.front();
  if (statement.kind == "v2_stop") {
    if (statement.items.has_value()) {
      const std::optional<std::string> literal =
          core::emit::collapse_literal_only_display(*statement.items);
      if (literal.has_value()) {
        const std::optional<DisplayLiteralProgram> program = display_literal_program(*literal);
        return program.has_value() && program->kind == "error";
      }
    }
    if (statement.target.has_value()) {
      try {
        const Expression target = parse_expression(*statement.target, statement.line);
        if (target.kind == "string") {
          const std::optional<DisplayLiteralProgram> program = display_literal_program(target.text);
          return program.has_value() && program->kind == "error";
        }
      } catch (const std::exception&) {
        return false;
      }
    }
    return false;
  }

  if (statement.kind == "v2_invoke" && statement.name.has_value() && statement.args.empty()) {
    if (seen_rules.contains(*statement.name))
      return false;
    const auto rule_it = context.rules.find(*statement.name);
    if (rule_it == context.rules.end())
      return false;
    seen_rules.insert(*statement.name);
    return statements_are_domain_error_trap(context, rule_it->second->body, seen_rules);
  }
  return false;
}

bool statements_are_domain_error_trap(LoweringContext& context,
                                      const std::vector<V2Statement>& statements) {
  std::set<std::string> seen_rules;
  return statements_are_domain_error_trap(context, statements, seen_rules);
}

struct DomainErrorGuardPlan {
  Expression first;
  std::optional<Expression> second;
  int trap_opcode = 0;
  std::string trap_mnemonic;
};

struct NumericRange {
  std::optional<double> min;
  std::optional<double> max;
};

bool is_safe_integer_value(double value) {
  return std::isfinite(value) && std::fabs(value - std::round(value)) < 1e-12 &&
         value >= static_cast<double>(std::numeric_limits<long long>::min()) &&
         value <= static_cast<double>(std::numeric_limits<long long>::max());
}

std::optional<NumericRange> numeric_range_for_name(const LoweringContext& context,
                                                   const std::string& name) {
  const auto field_it = context.state_fields.find(name);
  if (field_it == context.state_fields.end() || field_it->second == nullptr)
    return std::nullopt;

  const V2StateField& field = *field_it->second;
  if (field.type == "flag") {
    return NumericRange{.min = 0.0, .max = 1.0};
  }
  if (field.type == "counter" || field.type == "range") {
    NumericRange range;
    if (field.min.has_value())
      range.min = static_cast<double>(*field.min);
    if (field.max.has_value())
      range.max = static_cast<double>(*field.max);
    return range;
  }
  return std::nullopt;
}

std::optional<NumericRange> numeric_range_for_expression(const LoweringContext& context,
                                                         const Expression& expression) {
  const std::optional<double> value = numeric_literal_value(expression);
  if (value.has_value())
    return NumericRange{.min = *value, .max = *value};

  if (expression.kind == "identifier")
    return numeric_range_for_name(context, expression.name);

  if (expression.kind == "unary" && expression.op == "-" && expression.expr != nullptr) {
    const std::optional<NumericRange> range =
        numeric_range_for_expression(context, *expression.expr);
    if (!range.has_value())
      return std::nullopt;
    NumericRange inverted;
    if (range->max.has_value())
      inverted.min = -*range->max;
    if (range->min.has_value())
      inverted.max = -*range->min;
    return inverted;
  }

  if (expression.kind == "call" && lower_ascii(expression.callee) == "abs" &&
      expression.args.size() == 1) {
    const std::optional<NumericRange> range =
        numeric_range_for_expression(context, expression.args.front());
    if (!range.has_value() || !range->min.has_value() || !range->max.has_value())
      return std::nullopt;
    const double min = *range->min;
    const double max = *range->max;
    return NumericRange{
        .min = (min <= 0.0 && max >= 0.0) ? 0.0 : std::min(std::fabs(min), std::fabs(max)),
        .max = std::max(std::fabs(min), std::fabs(max)),
    };
  }

  return std::nullopt;
}

bool is_known_integer_valued_expression(const LoweringContext& context,
                                        const Expression& expression) {
  const std::optional<double> literal = numeric_literal_value(expression);
  if (literal.has_value())
    return is_safe_integer_value(*literal);

  if (expression.kind == "identifier") {
    const std::optional<NumericRange> range = numeric_range_for_name(context, expression.name);
    return range.has_value() && range->min.has_value() && range->max.has_value() &&
           is_safe_integer_value(*range->min) && is_safe_integer_value(*range->max);
  }

  if (expression.kind == "unary" && expression.op == "-" && expression.expr != nullptr)
    return is_known_integer_valued_expression(context, *expression.expr);

  if (expression.kind == "call" && expression.args.size() == 1) {
    const std::string callee = lower_ascii(expression.callee);
    if (callee == "int")
      return true;
    if (callee == "abs")
      return is_known_integer_valued_expression(context, expression.args.front());
  }

  if (expression.kind == "binary" &&
      (expression.op == "+" || expression.op == "-" || expression.op == "*") &&
      expression.left != nullptr && expression.right != nullptr) {
    return is_known_integer_valued_expression(context, *expression.left) &&
           is_known_integer_valued_expression(context, *expression.right);
  }

  return false;
}

struct NegativeZeroThresholdMatch {
  Expression value;
  double bound = 0.0;
  std::string truth;
};

std::optional<V2Predicate> flip_numeric_left_condition(const V2Predicate& predicate) {
  if (predicate.kind != "v2_compare")
    return std::nullopt;
  V2Predicate flipped = predicate;
  flipped.left = predicate.right;
  flipped.right = predicate.left;
  flipped.op = swap_comparison_sides_op(predicate.op);
  return flipped;
}

std::optional<NegativeZeroThresholdMatch>
match_negative_zero_threshold_condition(const LoweringContext& context,
                                        const V2Predicate& predicate, int line) {
  if (predicate.kind != "v2_compare")
    return std::nullopt;

  const Expression left = parse_expression(predicate.left, line);
  if (left.kind == "number") {
    const std::optional<V2Predicate> flipped = flip_numeric_left_condition(predicate);
    return flipped.has_value() ? match_negative_zero_threshold_condition(context, *flipped, line)
                               : std::nullopt;
  }

  const Expression right = parse_expression(predicate.right, line);
  const std::optional<double> bound = numeric_literal_value(right);
  if (!bound.has_value() || !std::isfinite(*bound) || *bound <= 0.0 || *bound > 1e12)
    return std::nullopt;
  if (!is_known_integer_valued_expression(context, left))
    return std::nullopt;
  const std::optional<NumericRange> range = numeric_range_for_expression(context, left);
  if (!range.has_value() || !range->min.has_value() || *range->min < 0.0)
    return std::nullopt;
  if (range->max.has_value() && *range->max / *bound >= 1e60)
    return std::nullopt;

  if (predicate.op == ">=")
    return NegativeZeroThresholdMatch{.value = left, .bound = *bound, .truth = "ge"};
  if (predicate.op == "<")
    return NegativeZeroThresholdMatch{.value = left, .bound = *bound, .truth = "lt"};
  if (predicate.op == ">" && std::floor(*bound + 1.0) == *bound + 1.0)
    return NegativeZeroThresholdMatch{.value = left, .bound = *bound + 1.0, .truth = "ge"};
  if (predicate.op == "<=" && std::floor(*bound + 1.0) == *bound + 1.0)
    return NegativeZeroThresholdMatch{.value = left, .bound = *bound + 1.0, .truth = "lt"};
  return std::nullopt;
}

bool lower_negative_zero_threshold_flow_false_branch(LoweringContext& context,
                                                     const V2Predicate& predicate,
                                                     const std::string& false_label,
                                                     int source_line) {
  const std::optional<NegativeZeroThresholdMatch> threshold =
      match_negative_zero_threshold_condition(context, predicate, source_line);
  if (!threshold.has_value())
    return false;

  const int selected_cost =
      guarded_estimate_negative_zero_threshold_raw_cost(
          threshold->value, number_expression(format_number_literal(threshold->bound))) +
      2;
  const auto [selected_predicate, unused_normalized] =
      select_cheaper_equivalent_condition(context, predicate, source_line);
  (void)unused_normalized;
  const int ordinary_cost = guarded_condition_compile_cost(selected_predicate, source_line);
  if (!can_reserve_negative_zero_degree_register(context) || selected_cost >= ordinary_cost)
    return false;

  if (!emit_negative_zero_threshold_raw(context, threshold->value,
                                        number_expression(format_number_literal(threshold->bound)),
                                        source_line))
    return false;

  const int opcode = threshold->truth == "ge" ? 0x57 : 0x5e;
  const std::string mnemonic = threshold->truth == "ge" ? "F x!=0" : "F x=0";
  context.emitter.emit_jump(opcode, mnemonic, false_label,
                            "negative-zero false branch for " + predicate.op, source_line);
  context.optimizations.push_back(OptimizationReport{
      .name = "negative-zero-threshold-flow",
      .detail = "Tested " + condition_text(predicate) + " through preloaded " +
                std::string(kNegativeZeroDegreePreloadValue) + " in R" +
                register_text_for(context, *context.negative_zero_degree_register) + ".",
  });
  return true;
}

std::optional<Expression>
negative_zero_threshold_selector_expression(const LoweringContext& context,
                                            const V2Predicate& predicate, int line) {
  const std::optional<NegativeZeroThresholdMatch> threshold =
      match_negative_zero_threshold_condition(context, predicate, line);
  if (!threshold.has_value() || !can_reserve_negative_zero_degree_register(context))
    return std::nullopt;
  Expression selector = call_expression(
      std::string(kNegativeZeroDegreeSelectorGe),
      {threshold->value, number_expression(format_number_literal(threshold->bound))});
  if (threshold->truth == "ge")
    return selector;
  return one_minus_expression(std::move(selector));
}

bool range_cannot_trap_below_minus_one(const LoweringContext& context,
                                       const Expression& expression) {
  const std::optional<NumericRange> range = numeric_range_for_expression(context, expression);
  return range.has_value() && range->min.has_value() && *range->min >= -1.0;
}

bool range_cannot_trap_above_one(const LoweringContext& context, const Expression& expression) {
  const std::optional<NumericRange> range = numeric_range_for_expression(context, expression);
  return range.has_value() && range->max.has_value() && *range->max <= 1.0;
}

std::optional<Expression> arc_upper_domain_expression(const LoweringContext& context,
                                                      const V2Predicate& predicate,
                                                      const Expression& left,
                                                      const Expression& right) {
  const std::optional<double> left_value = numeric_literal_value(left);
  const std::optional<double> right_value = numeric_literal_value(right);

  if (predicate.op == ">") {
    if (right_value.has_value() && *right_value == 1.0 &&
        range_cannot_trap_below_minus_one(context, left)) {
      return left;
    }
    return std::nullopt;
  }
  if (predicate.op == "<") {
    if (left_value.has_value() && *left_value == 1.0 &&
        range_cannot_trap_below_minus_one(context, right)) {
      return right;
    }
    return std::nullopt;
  }
  if (predicate.op == ">=") {
    if (right_value.has_value() && *right_value == 2.0 &&
        is_known_integer_valued_expression(context, left) &&
        range_cannot_trap_below_minus_one(context, left)) {
      return left;
    }
    return std::nullopt;
  }
  if (predicate.op == "<=") {
    if (left_value.has_value() && *left_value == 2.0 &&
        is_known_integer_valued_expression(context, right) &&
        range_cannot_trap_below_minus_one(context, right)) {
      return right;
    }
    return std::nullopt;
  }

  return std::nullopt;
}

std::optional<Expression> arc_lower_domain_expression(const LoweringContext& context,
                                                      const V2Predicate& predicate,
                                                      const Expression& left,
                                                      const Expression& right) {
  const std::optional<double> left_value = numeric_literal_value(left);
  const std::optional<double> right_value = numeric_literal_value(right);

  if (predicate.op == "<") {
    if (right_value.has_value() && *right_value == -1.0 &&
        range_cannot_trap_above_one(context, left)) {
      return left;
    }
    return std::nullopt;
  }
  if (predicate.op == ">") {
    if (left_value.has_value() && *left_value == -1.0 &&
        range_cannot_trap_above_one(context, right)) {
      return right;
    }
    return std::nullopt;
  }
  if (predicate.op == "<=") {
    if (right_value.has_value() && *right_value == -2.0 &&
        is_known_integer_valued_expression(context, left) &&
        range_cannot_trap_above_one(context, left)) {
      return left;
    }
    return std::nullopt;
  }
  if (predicate.op == ">=") {
    if (left_value.has_value() && *left_value == -2.0 &&
        is_known_integer_valued_expression(context, right) &&
        range_cannot_trap_above_one(context, right)) {
      return right;
    }
    return std::nullopt;
  }

  return std::nullopt;
}

std::optional<DomainErrorGuardPlan> plan_arc_domain_error_guard(const LoweringContext& context,
                                                                const V2Predicate& predicate,
                                                                const Expression& left,
                                                                const Expression& right) {
  constexpr int kAsinOpcode = 0x19;
  constexpr std::string_view kAsinMnemonic = "F sin^-1";

  std::optional<Expression> expression =
      arc_upper_domain_expression(context, predicate, left, right);
  if (!expression.has_value())
    expression = arc_lower_domain_expression(context, predicate, left, right);
  if (!expression.has_value())
    return std::nullopt;

  return DomainErrorGuardPlan{
      .first = std::move(*expression),
      .trap_opcode = kAsinOpcode,
      .trap_mnemonic = std::string(kAsinMnemonic),
  };
}

std::optional<DomainErrorGuardPlan>
plan_domain_error_guard(LoweringContext& context, const V2Predicate& predicate, int source_line) {
  if (predicate.kind != "v2_compare")
    return std::nullopt;

  Expression left;
  Expression right;
  try {
    left = parse_expression(predicate.left, source_line);
    right = parse_expression(predicate.right, source_line);
  } catch (const std::exception&) {
    return std::nullopt;
  }

  if (const std::optional<DomainErrorGuardPlan> arc_plan =
          plan_arc_domain_error_guard(context, predicate, left, right);
      arc_plan.has_value()) {
    return arc_plan;
  }

  constexpr int kSqrtOpcode = 0x21;
  constexpr int kLgOpcode = 0x17;
  constexpr int kReciprocalOpcode = 0x23;

  int trap_opcode = 0;
  std::string trap_mnemonic;
  std::string first_text;
  std::string second_text;
  bool symmetric = false;
  if (predicate.op == "<") {
    trap_opcode = kSqrtOpcode;
    trap_mnemonic = "F √";
    first_text = predicate.left;
    second_text = predicate.right;
  } else if (predicate.op == "<=") {
    trap_opcode = kLgOpcode;
    trap_mnemonic = "F lg";
    first_text = predicate.left;
    second_text = predicate.right;
  } else if (predicate.op == ">") {
    trap_opcode = kSqrtOpcode;
    trap_mnemonic = "F √";
    first_text = predicate.right;
    second_text = predicate.left;
  } else if (predicate.op == ">=") {
    trap_opcode = kLgOpcode;
    trap_mnemonic = "F lg";
    first_text = predicate.right;
    second_text = predicate.left;
  } else if (predicate.op == "==") {
    trap_opcode = kReciprocalOpcode;
    trap_mnemonic = "F 1/x";
    first_text = predicate.left;
    second_text = predicate.right;
    symmetric = true;
  } else {
    return std::nullopt;
  }

  Expression first = first_text == predicate.left ? left : right;
  Expression second = second_text == predicate.left ? left : right;

  if (is_zero_expression(context, second)) {
    return DomainErrorGuardPlan{
        .first = std::move(first),
        .trap_opcode = trap_opcode,
        .trap_mnemonic = std::move(trap_mnemonic),
    };
  }
  if (is_zero_expression(context, first)) {
    if (!symmetric)
      return std::nullopt;
    return DomainErrorGuardPlan{
        .first = std::move(second),
        .trap_opcode = trap_opcode,
        .trap_mnemonic = std::move(trap_mnemonic),
    };
  }
  return DomainErrorGuardPlan{
      .first = std::move(first),
      .second = std::move(second),
      .trap_opcode = trap_opcode,
      .trap_mnemonic = std::move(trap_mnemonic),
  };
}

void emit_domain_trap_on_x(LoweringContext& context, const DomainErrorGuardPlan& plan,
                           std::string comment, int source_line) {
  context.emitter.emit_op(plan.trap_opcode, plan.trap_mnemonic, std::move(comment), source_line);
  clear_current_x_facts(context);
  context.scaled_coord_variables.clear();
}

bool x_holds_identifier(const LoweringContext& context, const std::string& name) {
  return context.emitter.current_x_variable == name ||
         context.emitter.current_x_aliases.contains(name);
}

bool lower_domain_error_guard(LoweringContext& context, const V2Statement& statement) {
  if (!context.domain_error_guards || statement.kind != "v2_if" ||
      !statement.predicate.has_value() || statement.negated)
    return false;
  if (!statements_are_domain_error_trap(context, statement.then_body))
    return false;
  const std::optional<DomainErrorGuardPlan> plan =
      plan_domain_error_guard(context, *statement.predicate, statement.line);
  if (!plan.has_value())
    return false;

  auto emit_operand = [&](const Expression& expression) -> bool {
    if (expression.kind == "identifier" && x_holds_identifier(context, expression.name))
      return true;
    return lower_expression_to_x(context, expression);
  };

  if (!emit_operand(plan->first))
    return false;
  if (plan->second.has_value()) {
    if (!lower_expression_to_x(context, *plan->second))
      return false;
    context.emitter.emit_op(0x11, "-", "domain guard difference", statement.line);
  }
  emit_domain_trap_on_x(context, *plan, "domain-error guard trap", statement.line);
  if (!statement.else_body.empty() && !lower_statement_block(context, statement.else_body))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "domain-error-guard",
      .detail = "Replaced a \"" + statement.predicate->op +
                "\" terminal-error guard with a self-trapping " + plan->trap_mnemonic +
                " at line " + std::to_string(statement.line) + ".",
  });
  return true;
}

std::optional<Expression> scalar_or_indexed_write_target(const V2Statement& statement) {
  if ((statement.kind != "v2_assign" && statement.kind != "v2_update") ||
      !statement.target.has_value()) {
    return std::nullopt;
  }
  try {
    const Expression target = parse_expression(*statement.target, statement.line);
    if (target.kind == "identifier" || target.kind == "indexed")
      return target;
  } catch (const std::exception&) {
    return std::nullopt;
  }
  return std::nullopt;
}

bool lower_assign_then_domain_trap(LoweringContext& context, const V2Statement& assign,
                                   const V2Statement& branch) {
  const std::optional<Expression> target = scalar_or_indexed_write_target(assign);
  if (!target.has_value())
    return false;
  if (target->kind == "identifier" && !context.register_index_by_name.contains(target->name))
    return false;
  if (branch.kind != "v2_if" || !branch.predicate.has_value() || branch.negated)
    return false;
  if (!statements_are_domain_error_trap(context, branch.then_body))
    return false;
  const std::optional<DomainErrorGuardPlan> plan =
      plan_domain_error_guard(context, *branch.predicate, branch.line);
  if (!plan.has_value() || plan->second.has_value())
    return false;
  if (!expression_equals(plan->first, *target))
    return false;

  if (!lower_statement(context, assign, &branch))
    return false;
  if (target->kind == "identifier" && !x_holds_identifier(context, target->name)) {
    emit_recall(context, target->name);
    if (!context.emitter.items.empty() &&
        context.emitter.items.back().comment == "recall " + target->name) {
      context.emitter.items.back().comment = "trap-test " + target->name;
    }
  }
  const bool indexed = target->kind == "indexed";
  emit_domain_trap_on_x(
      context, *plan,
      indexed ? "indexed assign domain-error guard trap" : "domain-error guard trap", branch.line);
  if (!branch.else_body.empty() && !lower_statement_block(context, branch.else_body))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = indexed ? "indexed-assign-zero-domain-guard" : "assign-zero-domain-guard",
      .detail = indexed ? "Fused indexed store and \"" + branch.predicate->op +
                              " 0\" terminal-error branch through " + plan->trap_mnemonic + "."
                        : "Fused " + target->name + " store and terminal-error branch through " +
                              plan->trap_mnemonic + ".",
  });
  return true;
}

std::optional<double> numeric_self_update_delta(const std::string& target,
                                                const V2Statement& statement) {
  if (!statement.target.has_value() || *statement.target != target || !statement.expr.has_value())
    return std::nullopt;

  const Expression expression = parse_expression(*statement.expr, statement.line);
  if (statement.kind == "v2_update" && statement.op.has_value()) {
    const std::optional<double> delta = numeric_literal_value(expression);
    if (!delta.has_value())
      return std::nullopt;
    if (*statement.op == "+=")
      return *delta;
    if (*statement.op == "-=")
      return -*delta;
    return std::nullopt;
  }

  if (statement.kind != "v2_assign" || expression.kind != "binary" || expression.left == nullptr ||
      expression.right == nullptr) {
    return std::nullopt;
  }

  if (expression.op == "+") {
    if (expression.left->kind == "identifier" && expression.left->name == target)
      return numeric_literal_value(*expression.right);
    if (expression.right->kind == "identifier" && expression.right->name == target)
      return numeric_literal_value(*expression.left);
    return std::nullopt;
  }

  if (expression.op == "-" && expression.left->kind == "identifier" &&
      expression.left->name == target) {
    const std::optional<double> delta = numeric_literal_value(*expression.right);
    return delta.has_value() ? std::optional<double>{-*delta} : std::nullopt;
  }

  return std::nullopt;
}

Expression one_based_modulo_expression(const std::string& target, int width) {
  const std::string width_text = std::to_string(width);
  Expression shifted = add_expression(int_expression(identifier_expression(target)),
                                      number_expression(std::to_string(width - 1)));
  Expression scaled = multiply_expression(
      frac_expression(divide_expression(std::move(shifted), number_expression(width_text))),
      number_expression(width_text));
  return add_expression(std::move(scaled), number_expression("1"));
}

std::optional<int> match_one_based_modulo_normalization(LoweringContext& context,
                                                        const V2Statement& assign,
                                                        const V2Statement& branch) {
  if (assign.kind != "v2_assign" || !assign.target.has_value() || !assign.expr.has_value() ||
      branch.kind != "v2_if" || !branch.predicate.has_value() || branch.has_else_body ||
      !branch.else_body.empty() || branch.then_body.size() != 1U) {
    return std::nullopt;
  }

  const std::string& target = *assign.target;
  const V2Predicate& predicate = *branch.predicate;
  if (predicate.kind != "v2_compare" || predicate.op != "<=")
    return std::nullopt;
  const Expression left = parse_expression(predicate.left, branch.line);
  const Expression right = parse_expression(predicate.right, branch.line);
  if (!identifier_expression_is(left, target) || !is_zero_expression(context, right))
    return std::nullopt;

  const Expression assign_expression = parse_expression(*assign.expr, assign.line);
  const std::optional<int> width = match_positive_modulo_expression(assign_expression, target);
  if (!width.has_value() || *width <= 1)
    return std::nullopt;

  const std::optional<double> delta = numeric_self_update_delta(target, branch.then_body.front());
  if (!delta.has_value() || std::fabs(*delta - static_cast<double>(*width)) >= 1e-12)
    return std::nullopt;

  const V2StateField* field = state_field_named(context, target);
  if (field != nullptr && field->min.value_or(std::numeric_limits<int>::min()) < 0)
    return std::nullopt;

  const Expression normalized = one_based_modulo_expression(target, *width);
  const int lowered_cost = guarded_estimate_expression_cost(normalized) + 1;
  const int ordinary_cost = guarded_estimate_expression_cost(assign_expression) + 1 +
                            guarded_condition_compile_cost(predicate, branch.line) +
                            guarded_estimate_expression_cost(parse_expression(
                                *branch.then_body.front().expr, branch.then_body.front().line)) +
                            1 + 2;
  if (lowered_cost >= ordinary_cost)
    return std::nullopt;

  return width;
}

bool lower_one_based_modulo_normalization(LoweringContext& context, const V2Statement& assign,
                                          const V2Statement& branch) {
  const std::optional<int> width = match_one_based_modulo_normalization(context, assign, branch);
  if (!width.has_value())
    return false;

  const Expression normalized = one_based_modulo_expression(*assign.target, *width);
  if (!lower_expression_to_x(context, normalized))
    return false;
  emit_store(context, *assign.target, "one-based modulo normalize " + *assign.target);
  context.optimizations.push_back(OptimizationReport{
      .name = "one-based-modulo-normalization",
      .detail = "Folded " + *assign.target + " modulo-" + std::to_string(*width) +
                " zero-fix branch into one branchless normalization expression.",
  });
  return true;
}

struct IntOrFracCall {
  std::string fn;
  Expression arg;
};

std::optional<IntOrFracCall> match_int_or_frac_call(const Expression& expression) {
  if (expression.kind != "call" || expression.args.size() != 1U)
    return std::nullopt;
  const std::string fn = lower_ascii(expression.callee);
  if (fn != "int" && fn != "frac")
    return std::nullopt;
  return IntOrFracCall{.fn = fn, .arg = expression.args.front()};
}

bool scalar_register_assignment(const LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_assign" || !statement.target.has_value() || !statement.expr.has_value())
    return false;
  const Expression target = parse_expression(*statement.target, statement.line);
  return target.kind == "identifier" && context.register_index_by_name.contains(target.name);
}

bool lower_int_frac_shared_tail(LoweringContext& context, const V2Statement& first,
                                const V2Statement& second) {
  if (!scalar_register_assignment(context, first) || !scalar_register_assignment(context, second) ||
      *first.target == *second.target) {
    return false;
  }

  const Expression first_expression = parse_expression(*first.expr, first.line);
  const Expression second_expression = parse_expression(*second.expr, second.line);
  const std::optional<IntOrFracCall> first_call = match_int_or_frac_call(first_expression);
  const std::optional<IntOrFracCall> second_call = match_int_or_frac_call(second_expression);
  if (!first_call.has_value() || !second_call.has_value() || first_call->fn == second_call->fn ||
      !expression_equals(first_call->arg, second_call->arg) ||
      !expression_pure_for_substitution(first_call->arg) ||
      guarded_estimate_expression_cost(first_call->arg) <= 2) {
    return false;
  }

  const V2Statement& int_statement = first_call->fn == "int" ? first : second;
  const V2Statement& frac_statement = first_call->fn == "frac" ? first : second;

  if (!lower_expression_to_x(context, first_call->arg))
    return false;
  context.emitter.emit_op(0x0e, "В↑", "duplicate operand for shared int/frac tail", first.line);
  context.emitter.emit_op(0x34, "К [x]", "int()", int_statement.line);
  clear_current_x_facts(context);
  emit_store(context, *int_statement.target, "set " + *int_statement.target);
  context.emitter.emit_op(0x14, "X↔Y", "restore saved operand for frac()", frac_statement.line);
  clear_current_x_facts(context);
  context.emitter.emit_op(0x35, "К {x}", "frac()", frac_statement.line);
  clear_current_x_facts(context);
  emit_store(context, *frac_statement.target, "set " + *frac_statement.target);
  context.optimizations.push_back(OptimizationReport{
      .name = "int-frac-shared-tail",
      .detail = "Computed a shared pure operand once and derived int()/frac() through a shared "
                "В↑/X↔Y tail.",
  });
  return true;
}

struct StackUnaryDerivationCall {
  std::string fn;
  int opcode = 0;
  std::string mnemonic;
  Expression arg;
};

std::optional<StackUnaryDerivationCall>
match_stack_unary_derivation_call(const Expression& expression) {
  if (expression.kind != "call" || expression.args.size() != 1U)
    return std::nullopt;
  const std::string fn = lower_ascii(expression.callee);
  const std::optional<std::pair<int, std::string>> opcode = x_transform_unary_opcode(fn);
  if (!opcode.has_value())
    return std::nullopt;
  return StackUnaryDerivationCall{
      .fn = fn,
      .opcode = opcode->first,
      .mnemonic = opcode->second,
      .arg = expression.args.front(),
  };
}

struct StackUnaryDerivationAssignment {
  const V2Statement* statement = nullptr;
  std::string target;
  StackUnaryDerivationCall call;
};

bool lower_stack_unary_derived_assignments_run(LoweringContext& context,
                                               const std::vector<V2Statement>& statements,
                                               std::size_t start, std::size_t& consumed) {
  consumed = 0;
  if (start >= statements.size())
    return false;
  const V2Statement& first = statements.at(start);
  if (!scalar_register_assignment(context, first))
    return false;

  const Expression first_expression = parse_expression(*first.expr, first.line);
  const std::optional<StackUnaryDerivationCall> first_match =
      match_stack_unary_derivation_call(first_expression);
  if (!first_match.has_value() || !expression_pure_for_substitution(first_match->arg))
    return false;

  std::vector<StackUnaryDerivationAssignment> derivations;
  std::set<std::string> targets;
  const std::size_t end = std::min(statements.size(), start + 4U);
  for (std::size_t index = start; index < end; ++index) {
    const V2Statement& statement = statements.at(index);
    if (!scalar_register_assignment(context, statement))
      break;
    const std::optional<std::string> target = scalar_assignment_target_name(statement);
    if (!target.has_value() || targets.contains(*target))
      break;

    const Expression expression = parse_expression(*statement.expr, statement.line);
    const std::optional<StackUnaryDerivationCall> call =
        match_stack_unary_derivation_call(expression);
    if (!call.has_value() || !expression_equals(call->arg, first_match->arg))
      break;

    targets.insert(*target);
    derivations.push_back(StackUnaryDerivationAssignment{
        .statement = &statement,
        .target = *target,
        .call = *call,
    });
  }

  if (derivations.size() < 3U)
    return false;
  for (const std::string& target : targets) {
    if (expression_contains_identifier(first_match->arg, target))
      return false;
  }

  const int arg_cost = guarded_estimate_expression_cost(first_match->arg);
  const int normal_cost = static_cast<int>(derivations.size()) * (arg_cost + 2);
  const int duplicate_cost = static_cast<int>(derivations.size()) - 1;
  const int restore_cost = 1 + (static_cast<int>(derivations.size()) - 2) * 2;
  const int shared_cost =
      arg_cost + duplicate_cost + static_cast<int>(derivations.size()) * 2 + restore_cost;
  if (shared_cost >= normal_cost)
    return false;

  if (!lower_expression_to_x(context, first_match->arg))
    return false;
  for (std::size_t copy = 1; copy < derivations.size(); ++copy) {
    context.emitter.emit_op(0x0e, "В↑", "duplicate operand for Z-stack derived tail", first.line);
  }

  for (std::size_t index = 0; index < derivations.size(); ++index) {
    const StackUnaryDerivationAssignment& derivation = derivations.at(index);
    if (index == 1U) {
      context.emitter.emit_op(0x14, "X↔Y", "restore shared operand from Y",
                              derivation.statement->line);
      clear_current_x_facts(context);
    } else if (index > 1U) {
      context.emitter.emit_op(0x25, "F reverse", "rotate shared operand from Z",
                              derivation.statement->line);
      context.emitter.emit_op(0x14, "X↔Y", "restore shared operand from stack",
                              derivation.statement->line);
      clear_current_x_facts(context);
    }
    context.emitter.emit_op(derivation.call.opcode, derivation.call.mnemonic,
                            derivation.call.fn + "()", derivation.statement->line);
    clear_current_x_facts(context);
    emit_store(context, derivation.target, "set " + derivation.target);
  }

  std::vector<std::string> functions;
  functions.reserve(derivations.size());
  for (const StackUnaryDerivationAssignment& derivation : derivations)
    functions.push_back(derivation.call.fn + "()");
  context.optimizations.push_back(OptimizationReport{
      .name = "z-stack-derived-value-reuse",
      .detail = std::string("Computed ") + expression_to_source(first_match->arg) +
                " once and derived " + join_strings(functions, "/") + " through " +
                (derivations.size() == 4U ? "X/Y/Z/T" : "X/Y/Z") + " stack copies.",
  });
  consumed = derivations.size();
  return true;
}

struct ResidualGuardedUpdateMatch {
  V2Predicate condition;
  V2Statement assignment;
  std::vector<V2Statement> tail;
  std::string target;
  double bound = 0.0;
  double delta = 0.0;
};

std::optional<ResidualGuardedUpdateMatch>
match_residual_guarded_update(const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() || statement.negated)
    return std::nullopt;
  const V2Predicate& condition = *statement.predicate;
  if (condition.kind != "v2_compare" || (condition.op != "<" && condition.op != ">="))
    return std::nullopt;

  const Expression left = parse_expression(condition.left, statement.line);
  if (left.kind != "identifier")
    return std::nullopt;
  const Expression right = parse_expression(condition.right, statement.line);
  const std::optional<double> bound = numeric_literal_value(right);
  if (!bound.has_value())
    return std::nullopt;

  for (std::size_t index = 0; index < statement.then_body.size(); ++index) {
    const V2Statement& candidate = statement.then_body.at(index);
    if (candidate.kind != "v2_assign" && candidate.kind != "v2_update")
      return std::nullopt;
    if (!candidate.target.has_value() || !candidate.expr.has_value())
      return std::nullopt;

    if (*candidate.target != left.name) {
      const Expression expression = parse_expression(*candidate.expr, candidate.line);
      if (expression_contains_identifier(expression, left.name))
        return std::nullopt;
      continue;
    }

    const std::optional<double> delta = numeric_self_update_delta(left.name, candidate);
    if (!delta.has_value() || *delta == 0.0)
      return std::nullopt;

    std::vector<V2Statement> tail;
    tail.insert(tail.end(), statement.then_body.begin(),
                statement.then_body.begin() + static_cast<std::ptrdiff_t>(index));
    tail.insert(tail.end(), statement.then_body.begin() + static_cast<std::ptrdiff_t>(index + 1U),
                statement.then_body.end());
    return ResidualGuardedUpdateMatch{
        .condition = condition,
        .assignment = candidate,
        .tail = std::move(tail),
        .target = left.name,
        .bound = *bound,
        .delta = *delta,
    };
  }

  return std::nullopt;
}

bool residual_guarded_update_saves(LoweringContext& context,
                                   const ResidualGuardedUpdateMatch& update) {
  const double correction = update.bound + update.delta;
  const std::string correction_raw = format_number_literal(correction);
  int ordinary_update_cost = guarded_estimate_expression_cost(parse_expression(
                                 *update.assignment.expr, update.assignment.line)) +
                             1;
  if (update.assignment.kind == "v2_update") {
    // TS runs this check after V2 lowering, where `room++` has become the full
    // expression `room + 1` plus a store. Native keeps the sugar longer, so the
    // RHS-only expression cost would underprice the ordinary update path.
    ordinary_update_cost = 1 +
                           guarded_estimate_expression_cost(
                               parse_expression(*update.assignment.expr, update.assignment.line)) +
                           1 + 1;
  }
  const int residual_update_cost =
      (std::fabs(correction) < 1e-12
           ? 0
           : estimate_number_or_preload_cost(context, correction_raw) + 1) +
      1;
  return residual_update_cost < ordinary_update_cost;
}

bool compile_residual_guarded_condition(LoweringContext& context,
                                        const ResidualGuardedUpdateMatch& update,
                                        const std::string& false_label, int line) {
  if (!lower_expression_to_x(context, parse_expression(update.condition.left, line)))
    return false;
  if (!lower_expression_to_x(context, parse_expression(update.condition.right, line)))
    return false;
  context.emitter.emit_op(0x11, "-", "condition compare", line);
  const int false_opcode = update.condition.op == "<" ? 0x5c : 0x59;
  const std::string false_mnemonic = update.condition.op == "<" ? "F x<0" : "F x>=0";
  context.emitter.emit_jump(false_opcode, false_mnemonic, false_label,
                            "false branch for " + update.condition.op, line);
  return true;
}

void emit_residual_guarded_update(LoweringContext& context,
                                  const ResidualGuardedUpdateMatch& update) {
  const double correction = update.bound + update.delta;
  if (std::fabs(correction) >= 1e-12) {
    emit_number_or_preload(context, format_number_literal(correction));
    context.emitter.emit_op(0x10, "+", "residual guarded update " + update.target,
                            update.assignment.line);
  }
  emit_store(context, update.target, "set " + update.target);
  context.optimizations.push_back(OptimizationReport{
      .name = "residual-guarded-update",
      .detail = "Reused " + update.target + " - " + format_number_literal(update.bound) +
                " while updating " + update.target + " at line " +
                std::to_string(update.assignment.line) + ".",
  });
}

std::optional<Expression>
residual_expression_for_guarded_update_display(const V2Statement& statement) {
  const std::optional<ResidualGuardedUpdateMatch> match = match_residual_guarded_update(statement);
  if (!match.has_value())
    return std::nullopt;
  return subtract_expression(parse_expression(match->condition.left, statement.line),
                             parse_expression(match->condition.right, statement.line));
}

std::optional<Expression> branch_residual_expression(LoweringContext& context,
                                                     const V2Predicate& predicate, bool negated,
                                                     int line) {
  if (predicate.kind != "v2_compare")
    return std::nullopt;
  V2Predicate effective = predicate;
  if (negated)
    effective.op = invert_comparison_op(effective.op);
  const auto [compiled, unused_changed] =
      select_cheaper_equivalent_condition(context, effective, line);
  (void)unused_changed;
  if (compiled.kind != "v2_compare")
    return std::nullopt;
  try {
    const Expression left = parse_expression(compiled.left, line);
    const Expression right = parse_expression(compiled.right, line);
    if ((compiled.op == "==" || compiled.op == "!=") && is_zero_expression(context, right))
      return std::nullopt;
    if (left.kind == "binary" && match_remainder_by_constant(left).has_value())
      return std::nullopt;
    if (compiled.op == ">" || compiled.op == "<=")
      return subtract_expression(right, left);
    return subtract_expression(left, right);
  } catch (const std::exception&) {
    return std::nullopt;
  }
}

bool display_statement_is_single_expression(const V2Statement& statement,
                                            const Expression& expression) {
  if (statement.kind != "v2_show" || !statement.items.has_value() || statement.items->size() != 1)
    return false;
  const DisplayItem& item = statement.items->front();
  return item.kind == "source" && item.expr.has_value() && !item.width.has_value() &&
         !item.pad.has_value() && expression_equals(*item.expr, expression);
}

void report_branch_residual_reuse(LoweringContext& context, const Expression& residual, int line,
                                  const std::string& branch) {
  context.optimizations.push_back(OptimizationReport{
      .name = "branch-residual-x-reuse",
      .detail = "Reused " + expression_to_source(residual) + " left in X on the " + branch +
                " of a comparison at line " + std::to_string(line) + ".",
  });
}

void mark_branch_residual_reuse(LoweringContext& context, const Expression& residual, int line,
                                std::string branch) {
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  context.emitter.current_x_expression = std::make_shared<Expression>(residual);
  context.emitter.current_x_known_zero = false;
  report_branch_residual_reuse(context, residual, line, branch);
}

bool compile_residual_head_statement(LoweringContext& context, const V2Statement& statement,
                                     const Expression& residual, int line,
                                     const std::string& branch) {
  if (display_statement_is_single_expression(statement, residual)) {
    context.emitter.emit_op(0x50, "С/П", "show", statement.line);
    report_branch_residual_reuse(context, residual, line, branch);
    return true;
  }

  if (statement.kind == "v2_show" && statement.target.has_value()) {
    try {
      if (expression_equals(parse_expression(*statement.target, statement.line), residual)) {
        context.emitter.emit_op(0x50, "С/П", "pause", statement.line);
        report_branch_residual_reuse(context, residual, line, branch);
        return true;
      }
    } catch (const std::exception&) {
      return false;
    }
  }

  if (statement.kind == "v2_stop" && statement.target.has_value() && !statement.items.has_value()) {
    try {
      if (expression_equals(parse_expression(*statement.target, statement.line), residual)) {
        context.emitter.emit_op(0x50, "С/П", "halt", statement.line);
        report_branch_residual_reuse(context, residual, line, branch);
        return true;
      }
    } catch (const std::exception&) {
      return false;
    }
  }

  if (statement.kind == "v2_assign" && statement.target.has_value() && statement.expr.has_value()) {
    try {
      if (!expression_equals(parse_expression(*statement.expr, statement.line), residual))
        return false;
      if (context.register_index_by_name.contains(*statement.target)) {
        emit_store(context, *statement.target, "set " + *statement.target);
      } else if (statement.target->starts_with("__display_expr_")) {
        mark_current_x(context, *statement.target);
      } else {
        return false;
      }
      report_branch_residual_reuse(context, residual, line, branch);
      return true;
    } catch (const std::exception&) {
      return false;
    }
  }

  return false;
}

std::vector<V2Statement> compile_residual_head_if_possible(
    LoweringContext& context, const std::vector<V2Statement>& statements,
    const std::optional<Expression>& residual, int line, const std::string& branch) {
  if (!residual.has_value() || statements.empty())
    return statements;
  if (!compile_residual_head_statement(context, statements.front(), *residual, line, branch))
    return statements;
  return std::vector<V2Statement>(std::next(statements.begin()), statements.end());
}

std::string flip_comparison_operands_op(const std::string& op) {
  if (op == "<")
    return ">";
  if (op == "<=")
    return ">=";
  if (op == ">")
    return "<";
  if (op == ">=")
    return "<=";
  return op;
}

struct NormalizedZeroComparison {
  Expression expression;
  std::string op;
};

std::optional<NormalizedZeroComparison> normalize_zero_comparison(LoweringContext& context,
                                                                  const V2Predicate& predicate,
                                                                  bool negated, int line) {
  if (predicate.kind != "v2_compare")
    return std::nullopt;
  try {
    const std::string effective_op = negated ? invert_comparison_op(predicate.op) : predicate.op;
    const Expression left = parse_expression(predicate.left, line);
    const Expression right = parse_expression(predicate.right, line);
    if (is_zero_expression(context, right))
      return NormalizedZeroComparison{.expression = left, .op = effective_op};
    if (is_zero_expression(context, left)) {
      return NormalizedZeroComparison{
          .expression = right,
          .op = flip_comparison_operands_op(effective_op),
      };
    }
  } catch (const std::exception&) {
    return std::nullopt;
  }
  return std::nullopt;
}

const V2Statement* first_inline_statement(LoweringContext& context,
                                          const std::vector<V2Statement>& statements,
                                          std::set<std::string>& seen) {
  if (statements.empty())
    return nullptr;
  const V2Statement& first = statements.front();
  if (first.kind != "v2_invoke" || !first.name.has_value() || !first.args.empty() ||
      !context.inline_statement_rules.contains(*first.name) || seen.contains(*first.name)) {
    return &first;
  }
  const auto rule_it = context.rules.find(*first.name);
  if (rule_it == context.rules.end())
    return &first;
  seen.insert(*first.name);
  return first_inline_statement(context, rule_it->second->body, seen);
}

std::vector<V2Statement> inline_statement_prefix(LoweringContext& context,
                                                 const std::vector<V2Statement>& statements,
                                                 std::set<std::string>& seen) {
  if (statements.empty())
    return statements;
  const V2Statement& first = statements.front();
  if (first.kind != "v2_invoke" || !first.name.has_value() || !first.args.empty() ||
      !context.inline_statement_rules.contains(*first.name) || seen.contains(*first.name)) {
    return statements;
  }
  const auto rule_it = context.rules.find(*first.name);
  if (rule_it == context.rules.end())
    return statements;
  seen.insert(*first.name);
  return inline_statement_prefix(context, rule_it->second->body, seen);
}

bool branch_expression_can_use_current_x(const Expression& expression, const std::string& name) {
  if (expression.kind != "binary" || (expression.op != "+" && expression.op != "*") ||
      expression.left == nullptr || expression.right == nullptr) {
    return false;
  }
  return (expression.left->kind == "identifier" && expression.left->name == name &&
          is_simple_stack_load(*expression.right)) ||
         (expression.right->kind == "identifier" && expression.right->name == name &&
          is_simple_stack_load(*expression.left));
}

bool branch_condition_can_use_current_x(LoweringContext& context, const V2Predicate& predicate,
                                        bool negated, const std::string& name, int line) {
  const std::optional<NormalizedZeroComparison> normalized =
      normalize_zero_comparison(context, predicate, negated, line);
  return normalized.has_value() &&
         branch_expression_can_use_current_x(normalized->expression, name);
}

bool statement_starts_with_current_x_use(LoweringContext& context, const V2Statement* statement,
                                         const std::string& name) {
  if (statement == nullptr)
    return false;
  if (statement->kind == "v2_if" && statement->predicate.has_value())
    return branch_condition_can_use_current_x(context, *statement->predicate, statement->negated,
                                              name, statement->line);
  if ((statement->kind == "v2_assign" || statement->kind == "v2_update") &&
      statement->expr.has_value()) {
    try {
      if (statement->kind == "v2_update" && statement->op.has_value() &&
          (*statement->op == "+=" || *statement->op == "*=") && statement->target.has_value()) {
        const Expression target = parse_expression(*statement->target, statement->line);
        const Expression update = parse_expression(*statement->expr, statement->line);
        if (update.kind == "identifier" && update.name == name && is_simple_stack_load(target))
          return true;
      }
      return branch_expression_can_use_current_x(
          parse_expression(*statement->expr, statement->line), name);
    } catch (const std::exception&) {
      return false;
    }
  }
  if ((statement->kind == "v2_stop" || statement->kind == "v2_preview") &&
      statement->target.has_value()) {
    try {
      const Expression target = parse_expression(*statement->target, statement->line);
      return target.kind == "identifier" && target.name == name;
    } catch (const std::exception&) {
      return false;
    }
  }
  return false;
}

std::optional<std::string>
fallthrough_current_x_candidate(LoweringContext& context, const V2Predicate& predicate,
                                bool negated, const std::vector<V2Statement>& then_body, int line) {
  const std::optional<NormalizedZeroComparison> normalized =
      normalize_zero_comparison(context, predicate, negated, line);
  if (!normalized.has_value() || !guarded_can_test_against_zero_directly(normalized->op) ||
      normalized->expression.kind != "identifier") {
    return std::nullopt;
  }
  std::set<std::string> seen;
  const V2Statement* first = first_inline_statement(context, then_body, seen);
  if (!statement_starts_with_current_x_use(context, first, normalized->expression.name))
    return std::nullopt;
  return normalized->expression.name;
}

bool fl_opcode_exists_for_register(int index) {
  return fl_loop_opcode_for_register(index).has_value();
}

std::optional<std::string>
false_branch_current_x_candidate(LoweringContext& context, const V2Predicate& predicate,
                                 bool negated, const std::vector<V2Statement>& else_body,
                                 int line) {
  const std::optional<NormalizedZeroComparison> normalized =
      normalize_zero_comparison(context, predicate, negated, line);
  if (!normalized.has_value() || !guarded_can_test_against_zero_directly(normalized->op) ||
      normalized->expression.kind != "identifier") {
    return std::nullopt;
  }

  const std::string preserved = normalized->expression.name;
  std::set<std::string> seen;
  const std::vector<V2Statement> statements = inline_statement_prefix(context, else_body, seen);
  std::size_t index = 0;
  if (!statements.empty()) {
    const V2Statement& first = statements.front();
    if (statement_is_unit_decrement(first) && first.target.has_value() &&
        *first.target != preserved) {
      const auto register_it = context.register_index_by_name.find(*first.target);
      if (register_it != context.register_index_by_name.end() &&
          fl_opcode_exists_for_register(register_it->second)) {
        index = 1;
      }
    }
  }

  if (index >= statements.size() ||
      !statement_starts_with_current_x_use(context, &statements.at(index), preserved)) {
    return std::nullopt;
  }
  return preserved;
}

bool simple_equality_operand(const Expression& expression) {
  return expression.kind == "identifier" || expression.kind == "number";
}

bool equality_true_fallthrough_leaves_zero(LoweringContext&, const V2Predicate& predicate,
                                           bool negated, int line) {
  if (predicate.kind != "v2_compare")
    return false;
  const std::string effective_op = negated ? invert_comparison_op(predicate.op) : predicate.op;
  if (effective_op != "==")
    return false;
  try {
    return simple_equality_operand(parse_expression(predicate.left, line)) &&
           simple_equality_operand(parse_expression(predicate.right, line));
  } catch (const std::exception&) {
    return false;
  }
}

bool statement_can_enter_packed_line_family_score_zero_entry(LoweringContext& context,
                                                             const V2Statement* statement) {
  if (statement == nullptr || statement->kind != "v2_invoke" || !statement->name.has_value() ||
      !statement->args.empty()) {
    return false;
  }
  const auto rule_it = context.rules.find(*statement->name);
  return rule_it != context.rules.end() &&
         packed_line_family_score_rule(context, *rule_it->second).has_value();
}

bool equality_true_fallthrough_can_feed_zero_accumulator(
    LoweringContext& context, const V2Predicate& predicate, bool negated,
    const std::vector<V2Statement>& then_body, int line) {
  const std::optional<NormalizedZeroComparison> normalized =
      normalize_zero_comparison(context, predicate, negated, line);
  if (!normalized.has_value() || normalized->op != "==" ||
      !guarded_can_test_against_zero_directly(normalized->op)) {
    return false;
  }
  if (normalized->expression.kind == "call") {
    const std::string callee = lower_ascii(normalized->expression.callee);
    if (callee == "coord_list_has" || callee == "__mkpro_negative_zero_ge")
      return false;
  }
  return expression_pure_for_substitution(normalized->expression) &&
         statement_can_enter_packed_line_family_score_zero_entry(
             context, then_body.empty() ? nullptr : &then_body.front());
}

bool inequality_false_branch_leaves_zero(LoweringContext& context, const V2Predicate& predicate,
                                         bool negated, int line) {
  const std::optional<NormalizedZeroComparison> normalized =
      normalize_zero_comparison(context, predicate, negated, line);
  if (!normalized.has_value() || normalized->op != "!=")
    return false;
  if (normalized->expression.kind == "call") {
    const std::string callee = lower_ascii(normalized->expression.callee);
    if (callee == "coord_list_has" || callee == "__mkpro_negative_zero_ge")
      return false;
  }
  return true;
}

int branch_order_infinite_cost() {
  return std::numeric_limits<int>::max() / 4;
}

int estimate_branch_order_condition_cost(const LoweringContext& context,
                                         const V2Predicate& predicate, bool negated, int line) {
  if (predicate.kind == "v2_contains") {
    try {
      const Expression collection = parse_expression(predicate.collection, line);
      const Expression item = parse_expression(predicate.item, line);
      Expression test;
      if (collection.kind == "identifier") {
        const V2StateField* collection_field = state_field_named(context, collection.name);
        if (collection_field != nullptr && collection_field->type == "cells") {
          test = call_expression("bit_has", {collection, item});
        } else {
          test = call_expression("bit_and", {collection, item});
        }
      } else {
        test = call_expression("bit_and", {collection, item});
      }
      return guarded_estimate_expression_cost(test) + 2;
    } catch (const std::exception&) {
      return branch_order_infinite_cost();
    }
  }
  if (predicate.kind != "v2_compare")
    return branch_order_infinite_cost();
  try {
    const Expression left = parse_expression(predicate.left, line);
    const Expression right = parse_expression(predicate.right, line);
    const std::string op = negated ? invert_comparison_op(predicate.op) : predicate.op;
    if (is_zero_expression(context, right) &&
        (op == "==" || op == "!=" || op == "<" || op == ">=")) {
      return guarded_estimate_expression_cost(left) + 2;
    }
    return guarded_estimate_expression_cost(left) + guarded_estimate_expression_cost(right) + 3;
  } catch (const std::exception&) {
    return branch_order_infinite_cost();
  }
}

int estimate_branch_order_statement_cost(const LoweringContext& context,
                                         const V2Statement& statement);

int estimate_branch_order_body_cost(const LoweringContext& context,
                                    const std::vector<V2Statement>& statements) {
  int total = 0;
  for (const V2Statement& statement : statements) {
    const int cost = estimate_branch_order_statement_cost(context, statement);
    if (cost >= branch_order_infinite_cost())
      return branch_order_infinite_cost();
    total += cost;
  }
  return total;
}

int estimate_branch_order_display_cost(const std::vector<DisplayItem>& items) {
  const int source_count =
      static_cast<int>(std::count_if(items.begin(), items.end(), [](const DisplayItem& item) {
        return item.kind == "source";
      }));
  return source_count == 0 ? 2 : source_count * 2;
}

int estimate_branch_order_statement_cost(const LoweringContext& context,
                                         const V2Statement& statement) {
  try {
    if ((statement.kind == "v2_assign" || statement.kind == "v2_update") &&
        statement.expr.has_value()) {
      int target_cost = 0;
      if (statement.kind == "v2_update" && statement.target.has_value())
        target_cost = 1;
      if (statement.target.has_value()) {
        const Expression target = parse_expression(*statement.target, statement.line);
        if (target.kind == "indexed" && target.index != nullptr)
          target_cost += guarded_estimate_expression_cost(*target.index);
      }
      return target_cost +
             guarded_estimate_expression_cost(parse_expression(*statement.expr, statement.line)) +
             1;
    }
    if (statement.kind == "v2_preview" && statement.expr.has_value())
      return guarded_estimate_expression_cost(parse_expression(*statement.expr, statement.line));
    if (statement.kind == "v2_return" && statement.expr.has_value())
      return guarded_estimate_expression_cost(parse_expression(*statement.expr, statement.line)) +
             1;
    if (statement.kind == "v2_stop") {
      if (statement.target.has_value())
        return guarded_estimate_expression_cost(
                   parse_expression(*statement.target, statement.line)) +
               1;
      if (statement.items.has_value())
        return estimate_branch_order_display_cost(*statement.items);
      return 1;
    }
    if (statement.kind == "v2_read")
      return 2;
    if (statement.kind == "v2_show" && statement.target.has_value())
      return guarded_estimate_expression_cost(parse_expression(*statement.target, statement.line)) +
             1;
    if (statement.kind == "v2_show" && statement.items.has_value())
      return estimate_branch_order_display_cost(*statement.items);
    if (statement.kind == "v2_invoke")
      return 2;
    if (statement.kind == "v2_raw")
      return static_cast<int>(statement.lines.size());
    if (statement.kind == "v2_if" && statement.predicate.has_value()) {
      const int then_cost = estimate_branch_order_body_cost(context, statement.then_body);
      if (then_cost >= branch_order_infinite_cost())
        return branch_order_infinite_cost();
      const int condition_cost = estimate_branch_order_condition_cost(
          context, *statement.predicate, statement.negated, statement.line);
      if (condition_cost >= branch_order_infinite_cost())
        return branch_order_infinite_cost();
      if (!statement.has_else_body && statement.else_body.empty())
        return condition_cost + then_cost;
      const int else_cost = estimate_branch_order_body_cost(context, statement.else_body);
      if (else_cost >= branch_order_infinite_cost())
        return branch_order_infinite_cost();
      return condition_cost + then_cost + 2 + else_cost;
    }
  } catch (const std::exception&) {
    return branch_order_infinite_cost();
  }
  return branch_order_infinite_cost();
}

bool direct_statement_invokes_rule(const V2Statement& statement, const std::string& rule_name);

bool direct_statement_list_invokes_rule(const std::vector<V2Statement>& statements,
                                        const std::string& rule_name) {
  return std::any_of(statements.begin(), statements.end(), [&](const V2Statement& statement) {
    return direct_statement_invokes_rule(statement, rule_name);
  });
}

bool direct_statement_invokes_rule(const V2Statement& statement, const std::string& rule_name) {
  if (statement.kind == "v2_invoke" && statement.name.has_value() && *statement.name == rule_name)
    return true;
  if (direct_statement_list_invokes_rule(statement.body, rule_name) ||
      direct_statement_list_invokes_rule(statement.then_body, rule_name) ||
      direct_statement_list_invokes_rule(statement.else_body, rule_name)) {
    return true;
  }
  for (const V2MatchCase& match_case : statement.cases) {
    if (match_case.action != nullptr &&
        direct_statement_invokes_rule(*match_case.action, rule_name))
      return true;
  }
  return statement.otherwise != nullptr &&
         direct_statement_invokes_rule(*statement.otherwise, rule_name);
}

bool rule_is_directly_recursive(const V2Rule& rule) {
  return direct_statement_list_invokes_rule(rule.body, rule.name);
}

bool inline_rule_consumes_param_from_x(const LoweringContext& context, const V2Program& program,
                                       const V2Rule& rule, const std::string& param) {
  return context.inline_statement_rules.contains(rule.name) && rule.params.size() == 1U &&
         rule.params.front() == param && !rule.body.empty() && !statements_contain_return(rule.body) &&
         count_identifier_reads_in_statements(rule.body, param) == 1 &&
         all_rule_calls_have_single_argument(program, rule.name);
}

void hide_inline_x_param_report_registers(std::map<std::string, std::string>& registers,
                                          const LoweringContext& context,
                                          const V2Program& program) {
  for (const V2Rule& rule : program.rules) {
    if (rule.params.size() != 1U)
      continue;
    const std::string& param = rule.params.front();
    if (!inline_rule_consumes_param_from_x(context, program, rule, param))
      continue;
    if (identifier_read_outside_proc(program, rule.name, param))
      continue;
    registers.erase(param);
  }
}

void hide_internal_constant_report_registers(std::map<std::string, std::string>& registers) {
  for (auto it = registers.begin(); it != registers.end();) {
    if (it->first.starts_with("__const_")) {
      it = registers.erase(it);
    } else {
      ++it;
    }
  }
}

// TS findInlineProcNamesBySize scores the high-level AST, where `t += d` / `t++`
// are ordinary scalar `assign` nodes whose expr is `t <op> d`. Native's V2 keeps
// them as `v2_update`, and estimate_branch_order_statement_cost charges an extra
// target cell for the in-place update (which is correct for branch-order costing
// but diverges from TS's inline size model). Reconstruct the equivalent assign
// cost/classification here so compiler_inline_statement_rule_names matches TS's
// estimateBranchOrderStatementCost / isStraightLineAssignmentBody exactly.
Expression inline_naming_update_expression(const V2Statement& statement) {
  const Expression target = parse_expression(*statement.target, statement.line);
  const Expression delta = parse_expression(*statement.expr, statement.line);
  if (statement.op.has_value() && *statement.op == "-=")
    return subtract_expression(target, delta);
  return add_expression(target, delta);
}

int inline_naming_statement_cost(const LoweringContext& context, const V2Statement& statement) {
  if (statement.kind == "v2_update" && statement.target.has_value() && statement.expr.has_value()) {
    try {
      const Expression target = parse_expression(*statement.target, statement.line);
      int target_cost = 0;
      if (target.kind == "indexed" && target.index != nullptr)
        target_cost = guarded_estimate_expression_cost(*target.index);
      return target_cost +
             guarded_estimate_expression_cost(inline_naming_update_expression(statement)) + 1;
    } catch (const std::exception&) {
      return branch_order_infinite_cost();
    }
  }
  return estimate_branch_order_statement_cost(context, statement);
}

int inline_naming_body_cost(const LoweringContext& context,
                            const std::vector<V2Statement>& statements) {
  int total = 0;
  for (const V2Statement& statement : statements) {
    const int cost = inline_naming_statement_cost(context, statement);
    if (cost >= branch_order_infinite_cost())
      return branch_order_infinite_cost();
    total += cost;
  }
  return total;
}

// Mirrors TS isStraightLineAssignmentBody: every statement is a scalar `assign`.
// In TS both `t = d` and `t += d` / `t++` are scalar "assign" nodes, while indexed
// stores are a separate "indexed_assign" kind that is NOT straight-line.
bool inline_naming_straight_line_body(const std::vector<V2Statement>& statements) {
  if (statements.empty())
    return false;
  return std::all_of(statements.begin(), statements.end(), [](const V2Statement& statement) {
    if (statement.kind != "v2_assign" && statement.kind != "v2_update")
      return false;
    if (!statement.target.has_value())
      return false;
    try {
      return parse_expression(*statement.target, statement.line).kind == "identifier";
    } catch (const std::exception&) {
      return false;
    }
  });
}

std::set<std::string> compiler_inline_statement_rule_names(const LoweringContext& context,
                                                           const V2Program& program) {
  const std::map<std::string, int> counts = collect_rule_call_counts(program);
  std::set<std::string> names;
  for (const V2Rule& rule : program.rules) {
    const auto uses_it = counts.find(rule.name);
    const int uses = uses_it == counts.end() ? 0 : uses_it->second;
    if (uses == 0)
      continue;
    if (statements_contain_return(rule.body))
      continue;
    if (rule_is_directly_recursive(rule))
      continue;

    const int body_cost = inline_naming_body_cost(context, rule.body);
    if (body_cost >= branch_order_infinite_cost()) {
      if (uses == 1)
        names.insert(rule.name);
      continue;
    }
    const bool terminal = guarded_statement_list_terminates_statically(program, rule.body);
    if (uses > 1 && !inline_naming_straight_line_body(rule.body))
      continue;
    if (uses > 1 && terminal)
      continue;
    const int subroutine_cost = body_cost + (terminal ? 0 : 1) + uses * 2;
    const int inline_cost = body_cost * uses;
    if (inline_cost < subroutine_cost)
      names.insert(rule.name);
  }
  return names;
}

V2Statement branch_order_statement(LoweringContext& context, const V2Statement& statement) {
  if (!context.invert_branch_order || statement.kind != "v2_if" ||
      !statement.predicate.has_value() || statement.else_body.empty()) {
    return statement;
  }
  const int then_cost = estimate_branch_order_body_cost(context, statement.then_body);
  const int else_cost = estimate_branch_order_body_cost(context, statement.else_body);
  if (then_cost >= branch_order_infinite_cost() || else_cost >= branch_order_infinite_cost() ||
      else_cost <= then_cost) {
    return statement;
  }

  const int original_cost = estimate_branch_order_condition_cost(
                                context, *statement.predicate, statement.negated, statement.line) +
                            (statements_always_stop(context, statement.then_body) ? 0 : 2);
  const int inverted_cost = estimate_branch_order_condition_cost(
                                context, *statement.predicate, !statement.negated, statement.line) +
                            (statements_always_stop(context, statement.else_body) ? 0 : 2);
  if (inverted_cost > original_cost)
    return statement;

  V2Statement inverted = statement;
  inverted.negated = !statement.negated;
  inverted.then_body = statement.else_body;
  inverted.else_body = statement.then_body;
  inverted.has_else_body = true;
  context.optimizations.push_back(OptimizationReport{
      .name = "if-branch-order-inversion",
      .detail = "Inverted if/else at line " + std::to_string(statement.line) +
                " so the larger branch falls through (" + std::to_string(else_cost) + " vs " +
                std::to_string(then_cost) + " estimated body cells).",
  });
  return inverted;
}

bool direct_terminal_statement_stops(LoweringContext& context, const V2Statement& statement,
                                     std::set<std::string>& seen_rules);

bool direct_terminal_statements_stop(LoweringContext& context,
                                     const std::vector<V2Statement>& statements,
                                     std::set<std::string>& seen_rules) {
  if (statements.empty())
    return false;
  return direct_terminal_statement_stops(context, statements.back(), seen_rules);
}

bool direct_terminal_statement_stops(LoweringContext& context, const V2Statement& statement,
                                     std::set<std::string>& seen_rules) {
  if (statement.kind == "v2_stop" || statement.kind == "v2_loop" || statement.kind == "v2_return") {
    return true;
  }
  if (statement.kind == "v2_block")
    return direct_terminal_statements_stop(context, statement.body, seen_rules);
  if (statement.kind == "v2_if" && !statement.else_body.empty()) {
    std::set<std::string> then_seen = seen_rules;
    std::set<std::string> else_seen = seen_rules;
    return direct_terminal_statements_stop(context, statement.then_body, then_seen) &&
           direct_terminal_statements_stop(context, statement.else_body, else_seen);
  }
  if (statement.kind == "v2_match" && statement.otherwise != nullptr) {
    std::set<std::string> otherwise_seen = seen_rules;
    if (!direct_terminal_statement_stops(context, *statement.otherwise, otherwise_seen))
      return false;
    return std::all_of(statement.cases.begin(), statement.cases.end(),
                       [&](const V2MatchCase& item) {
                         if (item.action == nullptr)
                           return false;
                         std::set<std::string> case_seen = seen_rules;
                         return direct_terminal_statement_stops(context, *item.action, case_seen);
                       });
  }
  if (statement.kind == "v2_invoke" && statement.name.has_value() && statement.args.empty()) {
    if (seen_rules.contains(*statement.name))
      return false;
    const auto rule_it = context.rules.find(*statement.name);
    if (rule_it == context.rules.end())
      return false;
    seen_rules.insert(*statement.name);
    return direct_terminal_statements_stop(context, rule_it->second->body, seen_rules);
  }
  return false;
}

bool direct_terminal_statements_stop(LoweringContext& context,
                                     const std::vector<V2Statement>& statements) {
  std::set<std::string> seen_rules;
  return direct_terminal_statements_stop(context, statements, seen_rules);
}

std::set<std::string> intersect_sets(const std::set<std::string>& left,
                                     const std::set<std::string>& right) {
  std::set<std::string> result;
  for (const std::string& value : left) {
    if (right.contains(value))
      result.insert(value);
  }
  return result;
}

std::set<std::string> kill_expression_text_reads(const std::optional<std::string>& expression,
                                                 const std::set<std::string>& pending_after,
                                                 int line) {
  std::set<std::string> pending = pending_after;
  if (!expression.has_value())
    return pending;
  for (const std::string& name : pending_after) {
    if (expression_text_contains_identifier(*expression, name, line))
      pending.erase(name);
  }
  return pending;
}

std::set<std::string> kill_predicate_reads(const std::optional<V2Predicate>& predicate,
                                           const std::set<std::string>& pending_after) {
  std::set<std::string> pending = pending_after;
  if (!predicate.has_value())
    return pending;
  for (const std::string& name : pending_after) {
    if (predicate_reads_identifier(*predicate, name))
      pending.erase(name);
  }
  return pending;
}

std::optional<std::string> terminal_underflow_unit_decrement_target(const V2Statement& statement) {
  if (statement.kind == "v2_update" && statement.target.has_value() &&
      statement_is_unit_decrement(statement)) {
    return *statement.target;
  }
  if (statement.kind != "v2_assign" || !statement.target.has_value() ||
      !statement.expr.has_value()) {
    return std::nullopt;
  }
  try {
    const Expression target = parse_expression(*statement.target, statement.line);
    const Expression expression = parse_expression(*statement.expr, statement.line);
    if (target.kind == "identifier" && expression.kind == "binary" && expression.op == "-" &&
        expression.left != nullptr && expression.right != nullptr &&
        expression_equals(*expression.left, target) &&
        is_numeric_literal_value(*expression.right, 1)) {
      return target.name;
    }
  } catch (const std::exception&) {
  }
  return std::nullopt;
}

bool terminal_underflow_statement_may_write_identifier(LoweringContext& context,
                                                       const V2Statement& statement,
                                                       const std::string& name,
                                                       std::set<std::string>& seen_rules);

bool terminal_underflow_statements_may_write_identifier(LoweringContext& context,
                                                        const std::vector<V2Statement>& statements,
                                                        const std::string& name,
                                                        std::set<std::string>& seen_rules) {
  return std::any_of(statements.begin(), statements.end(), [&](const V2Statement& child) {
    std::set<std::string> child_seen = seen_rules;
    return terminal_underflow_statement_may_write_identifier(context, child, name, child_seen);
  });
}

bool terminal_underflow_statement_may_write_identifier(LoweringContext& context,
                                                       const V2Statement& statement,
                                                       const std::string& name,
                                                       std::set<std::string>& seen_rules) {
  if ((statement.kind == "v2_assign" || statement.kind == "v2_update") &&
      statement.target.has_value() && *statement.target == name) {
    return true;
  }
  if (statement.kind == "v2_raw") {
    if (std::any_of(statement.outputs.begin(), statement.outputs.end(),
                    [&](const V2RawOutput& output) { return output.target == name; }))
      return true;
    if (std::find(statement.clobbers.begin(), statement.clobbers.end(), name) !=
        statement.clobbers.end())
      return true;
  }
  if (statement.kind == "v2_if") {
    std::set<std::string> then_seen = seen_rules;
    std::set<std::string> else_seen = seen_rules;
    return terminal_underflow_statements_may_write_identifier(context, statement.then_body, name,
                                                              then_seen) ||
           terminal_underflow_statements_may_write_identifier(context, statement.else_body, name,
                                                              else_seen);
  }
  if (statement.kind == "v2_loop" || statement.kind == "v2_while" || statement.kind == "v2_block") {
    return terminal_underflow_statements_may_write_identifier(context, statement.body, name,
                                                              seen_rules);
  }
  if (statement.kind == "v2_match") {
    for (const V2MatchCase& match_case : statement.cases) {
      if (match_case.action != nullptr) {
        std::set<std::string> case_seen = seen_rules;
        if (terminal_underflow_statement_may_write_identifier(context, *match_case.action, name,
                                                              case_seen)) {
          return true;
        }
      }
    }
    if (statement.otherwise != nullptr) {
      std::set<std::string> otherwise_seen = seen_rules;
      if (terminal_underflow_statement_may_write_identifier(context, *statement.otherwise, name,
                                                            otherwise_seen)) {
        return true;
      }
    }
  }
  if (statement.kind == "v2_invoke" && statement.name.has_value()) {
    if (seen_rules.contains(*statement.name))
      return true;
    const auto rule_it = context.rules.find(*statement.name);
    if (rule_it == context.rules.end())
      return true;
    seen_rules.insert(*statement.name);
    return terminal_underflow_statements_may_write_identifier(context, rule_it->second->body, name,
                                                              seen_rules);
  }
  return false;
}

std::set<std::string>
kill_statement_touches_for_terminal_underflow(LoweringContext& context,
                                              const V2Statement& statement,
                                              const std::set<std::string>& pending_after) {
  std::set<std::string> pending = pending_after;
  for (const std::string& name : pending_after) {
    std::set<std::string> seen_rules;
    if (statement_reads_identifier(statement, name, false) ||
        terminal_underflow_statement_may_write_identifier(context, statement, name, seen_rules)) {
      pending.erase(name);
    }
  }
  return pending;
}

std::optional<std::string> terminal_nonpositive_guard_variable(LoweringContext& context,
                                                               const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() || statement.has_else_body ||
      !statement.else_body.empty() ||
      !direct_terminal_statements_stop(context, statement.then_body))
    return std::nullopt;
  const std::optional<NormalizedZeroComparison> normalized =
      normalize_zero_comparison(context, *statement.predicate, statement.negated, statement.line);
  if (!normalized.has_value() || normalized->expression.kind != "identifier")
    return std::nullopt;
  if (normalized->op == "<" || normalized->op == "<=")
    return normalized->expression.name;
  return std::nullopt;
}

std::set<std::string> analyze_terminal_underflow_statement_list(
    LoweringContext& context, const std::vector<V2Statement>& statements,
    const std::set<std::string>& pending_after, std::set<std::string>& seen_inline,
    std::set<std::pair<std::string, int>>& protected_decrements);

std::set<std::string>
analyze_terminal_underflow_statement(LoweringContext& context, const V2Statement& statement,
                                     const std::set<std::string>& pending_after,
                                     std::set<std::string>& seen_inline,
                                     std::set<std::pair<std::string, int>>& protected_decrements) {
  if (const std::optional<std::string> terminal_guard =
          terminal_nonpositive_guard_variable(context, statement)) {
    std::set<std::string> pending = pending_after;
    pending.insert(*terminal_guard);
    return pending;
  }

  if (statement.kind == "v2_assign" || statement.kind == "v2_update") {
    std::set<std::string> pending =
        kill_expression_text_reads(statement.expr, pending_after, statement.line);
    if (statement.target.has_value() && *statement.target != "" && statement.kind == "v2_assign") {
      pending = kill_expression_text_reads(statement.target, pending, statement.line);
    }
    const std::optional<std::string> decrement_target =
        terminal_underflow_unit_decrement_target(statement);
    if (decrement_target.has_value() && pending_after.contains(*decrement_target)) {
      protected_decrements.insert({*decrement_target, statement.line});
      pending.erase(*decrement_target);
      return pending;
    }
    if (statement.target.has_value())
      pending.erase(*statement.target);
    return pending;
  }

  if (statement.kind == "v2_if") {
    std::set<std::string> then_seen = seen_inline;
    std::set<std::string> else_seen = seen_inline;
    const std::set<std::string> then_pending = analyze_terminal_underflow_statement_list(
        context, statement.then_body, pending_after, then_seen, protected_decrements);
    const std::set<std::string> else_pending =
        statement.has_else_body
            ? analyze_terminal_underflow_statement_list(context, statement.else_body, pending_after,
                                                        else_seen, protected_decrements)
            : pending_after;
    return kill_predicate_reads(statement.predicate, intersect_sets(then_pending, else_pending));
  }

  if (statement.kind == "v2_match") {
    std::set<std::string> pending =
        statement.otherwise == nullptr
            ? pending_after
            : analyze_terminal_underflow_statement(context, *statement.otherwise, pending_after,
                                                   seen_inline, protected_decrements);
    for (const V2MatchCase& match_case : statement.cases) {
      const std::set<std::string> case_pending =
          match_case.action == nullptr
              ? pending_after
              : analyze_terminal_underflow_statement(context, *match_case.action, pending_after,
                                                     seen_inline, protected_decrements);
      pending = intersect_sets(pending, case_pending);
      for (const std::string& value : match_case.values)
        pending = kill_expression_text_reads(value, pending, match_case.line);
    }
    return kill_expression_text_reads(statement.expr, pending, statement.line);
  }

  if (statement.kind == "v2_invoke" && statement.name.has_value()) {
    const auto rule_it = context.rules.find(*statement.name);
    const bool inlineable = rule_it != context.rules.end() &&
                            (context.inline_statement_rules.contains(*statement.name) ||
                             context.proc_call_counts[*statement.name] == 1) &&
                            !seen_inline.contains(*statement.name);
    if (inlineable) {
      std::set<std::string> next_seen = seen_inline;
      next_seen.insert(*statement.name);
      return analyze_terminal_underflow_statement_list(
          context, rule_it->second->body, pending_after, next_seen, protected_decrements);
    }
    return kill_statement_touches_for_terminal_underflow(context, statement, pending_after);
  }

  if (statement.kind == "v2_loop" || statement.kind == "v2_while") {
    std::set<std::string> ignored_seen = seen_inline;
    (void)analyze_terminal_underflow_statement_list(context, statement.body, {}, ignored_seen,
                                                    protected_decrements);
    return kill_statement_touches_for_terminal_underflow(context, statement, pending_after);
  }

  if (statement.kind == "v2_block") {
    return analyze_terminal_underflow_statement_list(context, statement.body, pending_after,
                                                     seen_inline, protected_decrements);
  }

  return kill_statement_touches_for_terminal_underflow(context, statement, pending_after);
}

std::set<std::string> analyze_terminal_underflow_statement_list(
    LoweringContext& context, const std::vector<V2Statement>& statements,
    const std::set<std::string>& pending_after, std::set<std::string>& seen_inline,
    std::set<std::pair<std::string, int>>& protected_decrements) {
  std::set<std::string> pending = pending_after;
  for (auto it = statements.rbegin(); it != statements.rend(); ++it)
    pending = analyze_terminal_underflow_statement(context, *it, pending, seen_inline,
                                                   protected_decrements);
  return pending;
}

std::set<std::pair<std::string, int>>
collect_terminal_underflow_unit_decrements(LoweringContext& context, const V2Program& program) {
  std::set<std::pair<std::string, int>> protected_decrements;
  std::set<std::string> seen_inline;
  (void)analyze_terminal_underflow_statement_list(context, program.body, {}, seen_inline,
                                                  protected_decrements);
  for (const V2Rule& rule : program.rules) {
    std::set<std::string> rule_seen;
    rule_seen.insert(rule.name);
    (void)analyze_terminal_underflow_statement_list(context, rule.body, {}, rule_seen,
                                                    protected_decrements);
  }
  return protected_decrements;
}

std::optional<std::string> direct_terminal_call_target(LoweringContext& context,
                                                       const std::vector<V2Statement>& statements,
                                                       std::set<std::string>& seen_rules) {
  if (statements.size() != 1U)
    return std::nullopt;
  const V2Statement& statement = statements.front();
  if (statement.kind != "v2_invoke" || !statement.name.has_value() || !statement.args.empty())
    return std::nullopt;
  const auto rule_it = context.rules.find(*statement.name);
  if (rule_it == context.rules.end())
    return std::nullopt;
  if (context.inline_statement_rules.contains(*statement.name)) {
    if (seen_rules.contains(*statement.name))
      return std::nullopt;
    seen_rules.insert(*statement.name);
    return direct_terminal_call_target(context, rule_it->second->body, seen_rules);
  }

  std::set<std::string> terminal_seen;
  terminal_seen.insert(*statement.name);
  if (!direct_terminal_statements_stop(context, rule_it->second->body, terminal_seen))
    return std::nullopt;
  return *statement.name;
}

std::optional<std::string> direct_terminal_call_target(LoweringContext& context,
                                                       const std::vector<V2Statement>& statements) {
  std::set<std::string> seen_rules;
  return direct_terminal_call_target(context, statements, seen_rules);
}

bool lower_direct_terminal_if_branch(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value())
    return false;

  const std::optional<std::string> then_target =
      direct_terminal_call_target(context, statement.then_body);
  const std::optional<std::string> else_target =
      statement.else_body.empty() ? std::nullopt
                                  : direct_terminal_call_target(context, statement.else_body);
  if (!then_target.has_value() && !else_target.has_value())
    return false;

  const int original_cost = estimate_branch_order_condition_cost(context, *statement.predicate,
                                                                 statement.negated, statement.line);
  if (original_cost >= branch_order_infinite_cost())
    return false;

  struct Candidate {
    bool branch_when_true = false;
    std::string target;
    int estimated_cost = 0;
    int ordinary_cost = 0;
  };
  std::vector<Candidate> candidates;

  if (then_target.has_value() &&
      (!statement.else_body.empty() || context.aggressive_terminal_direct)) {
    const int inverted_cost = estimate_branch_order_condition_cost(
        context, *statement.predicate, !statement.negated, statement.line);
    if (inverted_cost < branch_order_infinite_cost()) {
      candidates.push_back(Candidate{
          .branch_when_true = true,
          .target = *then_target,
          .estimated_cost = inverted_cost,
          .ordinary_cost = original_cost + 2,
      });
    }
  }

  if (else_target.has_value()) {
    const bool then_terminates = direct_terminal_statements_stop(context, statement.then_body);
    candidates.push_back(Candidate{
        .branch_when_true = false,
        .target = *else_target,
        .estimated_cost = original_cost,
        .ordinary_cost = original_cost + (then_terminates ? 1 : 2),
    });
  }

  std::sort(candidates.begin(), candidates.end(),
            [](const Candidate& left, const Candidate& right) {
              return left.estimated_cost < right.estimated_cost;
            });
  const auto selected_it =
      std::find_if(candidates.begin(), candidates.end(),
                   [](const Candidate& item) { return item.estimated_cost < item.ordinary_cost; });
  if (selected_it == candidates.end())
    return false;

  const std::string target_label = function_label(selected_it->target);
  if (!lower_condition_false_branch(context, *statement.predicate,
                                    selected_it->branch_when_true ? !statement.negated
                                                                  : statement.negated,
                                    target_label, statement.line))
    return false;
  if (selected_it->branch_when_true) {
    if (!statement.else_body.empty() && !lower_statement_block(context, statement.else_body))
      return false;
  } else if (!lower_statement_block(context, statement.then_body)) {
    return false;
  }

  context.optimizations.push_back(OptimizationReport{
      .name = "terminal-if-direct-branch",
      .detail = "Branched directly to terminal " + selected_it->target + " for " +
                std::string(selected_it->branch_when_true ? "true" : "false") + " path at line " +
                std::to_string(statement.line) + " (" +
                std::to_string(selected_it->estimated_cost) + " vs " +
                std::to_string(selected_it->ordinary_cost) + " estimated branch cells).",
  });
  return true;
}

std::string terminal_tail_helper_key(const std::vector<V2Statement>& body) {
  V2Program program;
  program.name = "__terminal_tail";
  program.body = body;
  return v2_program_to_json(program);
}

std::optional<std::string> existing_terminal_tail_helper_label(LoweringContext& context,
                                                               const std::string& key) {
  const auto helper_it =
      std::find_if(context.terminal_tail_helpers.begin(), context.terminal_tail_helpers.end(),
                   [&](const TerminalTailHelperRequest& helper) { return helper.key == key; });
  if (helper_it == context.terminal_tail_helpers.end())
    return std::nullopt;
  return helper_it->label;
}

bool lower_local_terminal_else_tail(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() || statement.else_body.empty())
    return false;
  if (statements_always_stop(context, statement.then_body) ||
      !statements_always_stop(context, statement.else_body)) {
    return false;
  }

  const std::string key = terminal_tail_helper_key(statement.else_body);
  std::optional<TerminalTailHelperRequest> new_helper;
  std::string helper_label;
  if (std::optional<std::string> existing_label =
          existing_terminal_tail_helper_label(context, key)) {
    helper_label = *existing_label;
  } else {
    helper_label = context.emitter.fresh_label("terminal_tail");
    new_helper = TerminalTailHelperRequest{
        .key = key,
        .label = helper_label,
        .body = statement.else_body,
        .line = statement.line,
    };
  }

  if (!lower_condition_false_branch(context, *statement.predicate, statement.negated, helper_label,
                                    statement.line))
    return false;
  if (new_helper.has_value())
    context.terminal_tail_helpers.push_back(std::move(*new_helper));
  if (!lower_statement_block(context, statement.then_body))
    return false;

  context.optimizations.push_back(OptimizationReport{
      .name = "local-terminal-tail-branch",
      .detail = "Branched to a local terminal tail for else path at line " +
                std::to_string(statement.line) + ".",
  });
  return true;
}

struct ArithmeticIfCandidate {
  std::string target;
  Expression expression;
  std::string name;
  std::string detail;
};

struct TerminalSelectCandidate {
  Expression expression;
  std::string name;
  std::string detail;
};

std::optional<V2Predicate> arithmetic_if_comparison_predicate(const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() ||
      statement.predicate->kind != "v2_compare") {
    return std::nullopt;
  }
  V2Predicate predicate = *statement.predicate;
  if (statement.negated)
    predicate.op = invert_comparison_op(predicate.op);
  return predicate;
}

std::optional<Expression> plain_terminal_stop_expression(const V2Statement& statement) {
  if (statement.kind != "v2_stop" || statement.items.has_value() || !statement.target.has_value())
    return std::nullopt;
  Expression expression = parse_expression(*statement.target, statement.line);
  if (expression.kind == "string")
    return std::nullopt;
  return expression;
}

std::optional<std::pair<Expression, Expression>>
plain_terminal_if_stop_expressions(const V2Statement& statement) {
  if (statement.then_body.size() != 1U || statement.else_body.size() != 1U)
    return std::nullopt;
  std::optional<Expression> then_expression =
      plain_terminal_stop_expression(statement.then_body.front());
  std::optional<Expression> else_expression =
      plain_terminal_stop_expression(statement.else_body.front());
  if (!then_expression.has_value() || !else_expression.has_value())
    return std::nullopt;
  return std::pair<Expression, Expression>{*then_expression, *else_expression};
}

Expression terminal_select_expression(const Expression& then_expression,
                                      const Expression& else_expression, Expression selector) {
  const std::optional<double> then_value = numeric_literal_value(then_expression);
  const std::optional<double> else_value = numeric_literal_value(else_expression);
  if (then_value.has_value() && else_value.has_value()) {
    const double delta = *then_value - *else_value;
    if (std::fabs(delta) < 1e-12)
      return number_expression(format_number_literal(*then_value));
    if (std::fabs(*else_value) < 1e-12 && std::fabs(delta - 1.0) < 1e-12)
      return selector;
    if (std::fabs(*else_value - 1.0) < 1e-12 && std::fabs(delta + 1.0) < 1e-12)
      return one_minus_expression(std::move(selector));
    if (std::fabs(*else_value) < 1e-12)
      return multiply_expression(number_expression(format_number_literal(delta)),
                                 std::move(selector));
    if (std::fabs(delta - 1.0) < 1e-12)
      return add_expression(number_expression(format_number_literal(*else_value)),
                            std::move(selector));
    return add_expression(
        number_expression(format_number_literal(*else_value)),
        multiply_expression(number_expression(format_number_literal(delta)), std::move(selector)));
  }
  return add_expression(
      multiply_expression(then_expression, selector),
      multiply_expression(else_expression, one_minus_expression(std::move(selector))));
}

std::optional<TerminalSelectCandidate>
build_negative_zero_terminal_select_candidate(LoweringContext& context,
                                              const V2Statement& statement) {
  const std::optional<V2Predicate> predicate = arithmetic_if_comparison_predicate(statement);
  if (!predicate.has_value() || statement.else_body.empty())
    return std::nullopt;
  const std::optional<std::pair<Expression, Expression>> terminals =
      plain_terminal_if_stop_expressions(statement);
  if (!terminals.has_value())
    return std::nullopt;
  std::optional<Expression> selector =
      negative_zero_threshold_selector_expression(context, *predicate, statement.line);
  if (!selector.has_value())
    return std::nullopt;
  return TerminalSelectCandidate{
      .expression =
          terminal_select_expression(terminals->first, terminals->second, std::move(*selector)),
      .name = "negative-zero-threshold-terminal-select",
      .detail = "Replaced threshold halt if/else with negative-zero selection",
  };
}

bool lower_negative_zero_terminal_select(LoweringContext& context, const V2Statement& statement) {
  const std::optional<TerminalSelectCandidate> candidate =
      build_negative_zero_terminal_select_candidate(context, statement);
  if (!candidate.has_value())
    return false;

  const int ordinary_cost = estimate_branch_order_statement_cost(context, statement);
  if (ordinary_cost >= branch_order_infinite_cost())
    return false;
  const int selected_cost = guarded_estimate_expression_cost(candidate->expression) + 1;
  if (selected_cost >= ordinary_cost)
    return false;

  if (!lower_expression_to_x(context, candidate->expression))
    return false;
  context.emitter.emit_op(0x50, "С/П", "halt", statement.line);
  context.optimizations.push_back(OptimizationReport{
      .name = "branch-removal",
      .detail = candidate->detail + " at line " + std::to_string(statement.line) +
                "; emitted branchless " + candidate->name + ".",
  });
  context.optimizations.push_back(OptimizationReport{
      .name = candidate->name,
      .detail = candidate->detail + " at line " + std::to_string(statement.line) + " (" +
                std::to_string(selected_cost) + " vs " + std::to_string(ordinary_cost) +
                " estimated steps).",
  });
  return true;
}

std::optional<Expression> arithmetic_if_assignment_expression(const LoweringContext& context,
                                                              const V2Statement& statement,
                                                              std::string& target) {
  if ((statement.kind != "v2_assign" && statement.kind != "v2_update") ||
      !statement.target.has_value() || !statement.expr.has_value())
    return std::nullopt;
  const Expression target_expression = parse_expression(*statement.target, statement.line);
  if (target_expression.kind != "identifier" ||
      is_cells_state_name(context, target_expression.name) ||
      is_coord_list_state_name(context, target_expression.name) ||
      is_segmented_cells_name(context, target_expression.name)) {
    return std::nullopt;
  }
  target = target_expression.name;
  if (statement.kind == "v2_assign")
    return parse_expression(*statement.expr, statement.line);
  if (!statement.op.has_value())
    return std::nullopt;
  const Expression current = identifier_expression(target_expression.name);
  const Expression delta = parse_expression(*statement.expr, statement.line);
  if (*statement.op == "+=")
    return add_expression(current, delta);
  if (*statement.op == "-=")
    return subtract_expression(current, delta);
  return std::nullopt;
}

std::optional<std::pair<std::string, Expression>>
single_arithmetic_if_assignment(const LoweringContext& context,
                                const std::vector<V2Statement>& statements) {
  if (statements.size() != 1U)
    return std::nullopt;
  std::string target;
  std::optional<Expression> expression =
      arithmetic_if_assignment_expression(context, statements.front(), target);
  if (!expression.has_value())
    return std::nullopt;
  return std::pair{target, *expression};
}

std::optional<std::pair<std::string, Expression>>
single_effective_arithmetic_if_assignment(const LoweringContext& context,
                                          const V2Statement& statement) {
  std::optional<std::pair<std::string, Expression>> then_assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  if (!then_assign.has_value())
    return std::nullopt;
  if (statement.else_body.empty())
    return then_assign;

  std::optional<std::pair<std::string, Expression>> else_assign =
      single_arithmetic_if_assignment(context, statement.else_body);
  if (!else_assign.has_value() || then_assign->first != else_assign->first)
    return std::nullopt;
  if (!expression_equals(else_assign->second, identifier_expression(else_assign->first)))
    return std::nullopt;
  return then_assign;
}

bool expression_is_numeric_value(const LoweringContext& context, const Expression& expression,
                                 double expected);
std::optional<Expression> match_target_plus_delta(const Expression& expression,
                                                  const std::string& target);
std::optional<Expression> match_target_minus_delta(const Expression& expression,
                                                   const std::string& target);

ArithmeticIfCandidate arithmetic_if_abs_candidate(std::string target, Expression expression) {
  return ArithmeticIfCandidate{
      .target = std::move(target),
      .expression = abs_expression(std::move(expression)),
      .name = "arithmetic-if-abs",
      .detail = "Replaced sign branch with abs()",
  };
}

ArithmeticIfCandidate
arithmetic_if_max_candidate(std::string target, Expression left, Expression right,
                            std::string detail = "Replaced max branch with К max") {
  return ArithmeticIfCandidate{
      .target = std::move(target),
      .expression = max_expression(std::move(left), std::move(right)),
      .name = "arithmetic-if-max",
      .detail = std::move(detail),
  };
}

ArithmeticIfCandidate
arithmetic_if_min_candidate(std::string target, const Expression& left, const Expression& right,
                            std::string detail = "Replaced min branch with min-via-max()") {
  return ArithmeticIfCandidate{
      .target = std::move(target),
      .expression = min_expression(left, right),
      .name = "arithmetic-if-min",
      .detail = std::move(detail),
  };
}

bool arithmetic_if_boolean_variable(const LoweringContext& context, const std::string& name) {
  const std::optional<NumericRange> range = numeric_range_for_name(context, name);
  return range.has_value() && range->min.has_value() && range->max.has_value() &&
         std::fabs(*range->min) < 1e-12 && std::fabs(*range->max - 1.0) < 1e-12;
}

std::optional<Expression> arithmetic_if_boolean_selector(const LoweringContext& context,
                                                         const V2Predicate& predicate, int line) {
  const Expression left = parse_expression(predicate.left, line);
  const Expression right = parse_expression(predicate.right, line);
  std::optional<std::string> variable;
  std::optional<double> value;
  if (left.kind == "identifier") {
    variable = left.name;
    value = numeric_literal_value(right);
  } else if (right.kind == "identifier") {
    variable = right.name;
    value = numeric_literal_value(left);
  }
  if (!variable.has_value() || !value.has_value() ||
      !arithmetic_if_boolean_variable(context, *variable)) {
    return std::nullopt;
  }

  Expression variable_expression = identifier_expression(*variable);
  if ((predicate.op == "==" && std::fabs(*value - 1.0) < 1e-12) ||
      (predicate.op == "!=" && std::fabs(*value) < 1e-12)) {
    return variable_expression;
  }
  if ((predicate.op == "==" && std::fabs(*value) < 1e-12) ||
      (predicate.op == "!=" && std::fabs(*value - 1.0) < 1e-12)) {
    return one_minus_expression(std::move(variable_expression));
  }
  return std::nullopt;
}

std::optional<Expression> arithmetic_if_boolean_identifier(const LoweringContext& context,
                                                           const Expression& expression) {
  if (expression.kind == "identifier" && arithmetic_if_boolean_variable(context, expression.name))
    return expression;
  return std::nullopt;
}

std::optional<Expression> arithmetic_if_one_minus_boolean_identifier(const LoweringContext& context,
                                                                     const Expression& expression) {
  if (expression.kind != "binary" || expression.op != "-" || expression.left == nullptr ||
      expression.right == nullptr) {
    return std::nullopt;
  }
  const std::optional<double> left = numeric_literal_value(*expression.left);
  if (!left.has_value() || std::fabs(*left - 1.0) >= 1e-12)
    return std::nullopt;
  return arithmetic_if_boolean_identifier(context, *expression.right);
}

std::optional<Expression> arithmetic_if_comparison_mask(const V2Predicate& predicate, int line) {
  if (predicate.op != "==" && predicate.op != "!=")
    return std::nullopt;
  Expression left = parse_expression(predicate.left, line);
  Expression right = parse_expression(predicate.right, line);
  Expression not_equal =
      sign_expression(abs_expression(subtract_expression(std::move(left), std::move(right))));
  if (predicate.op == "==")
    return one_minus_expression(std::move(not_equal));
  return not_equal;
}

std::optional<Expression> arithmetic_if_comparison_update_selector(const V2Predicate& predicate,
                                                                   int line) {
  return arithmetic_if_comparison_mask(predicate, line);
}

Expression arithmetic_if_sign_toggle_expression(Expression current, Expression selector) {
  return multiply_expression(
      std::move(current),
      subtract_expression(number_expression("1"),
                          multiply_expression(number_expression("2"), std::move(selector))));
}

std::optional<ArithmeticIfCandidate>
build_arithmetic_if_abs_candidate(const LoweringContext& context, const V2Statement& statement,
                                  const V2Predicate& predicate) {
  if (!expression_is_numeric_value(context, parse_expression(predicate.right, statement.line), 0.0))
    return std::nullopt;
  const Expression left = parse_expression(predicate.left, statement.line);
  const Expression negative_left = unary_expression("-", left);

  const std::optional<std::pair<std::string, Expression>> then_assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  if (!then_assign.has_value())
    return std::nullopt;

  if (statement.else_body.empty()) {
    if (!expression_equals(identifier_expression(then_assign->first), left))
      return std::nullopt;
    if ((predicate.op == "<" || predicate.op == "<=") &&
        expression_equals(then_assign->second, negative_left)) {
      return arithmetic_if_abs_candidate(then_assign->first, left);
    }
    return std::nullopt;
  }

  const std::optional<std::pair<std::string, Expression>> else_assign =
      single_arithmetic_if_assignment(context, statement.else_body);
  if (!else_assign.has_value() || then_assign->first != else_assign->first)
    return std::nullopt;

  if ((predicate.op == "<" || predicate.op == "<=") &&
      expression_equals(then_assign->second, negative_left) &&
      expression_equals(else_assign->second, left)) {
    return arithmetic_if_abs_candidate(then_assign->first, left);
  }
  if ((predicate.op == ">" || predicate.op == ">=") &&
      expression_equals(then_assign->second, left) &&
      expression_equals(else_assign->second, negative_left)) {
    return arithmetic_if_abs_candidate(then_assign->first, left);
  }
  return std::nullopt;
}

std::optional<ArithmeticIfCandidate> build_arithmetic_if_comparison_boolean_candidate(
    const LoweringContext& context, const V2Statement& statement, const V2Predicate& predicate) {
  if (statement.else_body.empty())
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> then_assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  const std::optional<std::pair<std::string, Expression>> else_assign =
      single_arithmetic_if_assignment(context, statement.else_body);
  if (!then_assign.has_value() || !else_assign.has_value() ||
      then_assign->first != else_assign->first) {
    return std::nullopt;
  }
  const std::optional<double> then_value = numeric_literal_value(then_assign->second);
  const std::optional<double> else_value = numeric_literal_value(else_assign->second);
  const bool then_true_else_false = then_value.has_value() && else_value.has_value() &&
                                    std::fabs(*then_value - 1.0) < 1e-12 &&
                                    std::fabs(*else_value) < 1e-12;
  const bool then_false_else_true = then_value.has_value() && else_value.has_value() &&
                                    std::fabs(*then_value) < 1e-12 &&
                                    std::fabs(*else_value - 1.0) < 1e-12;
  if (!then_true_else_false && !then_false_else_true)
    return std::nullopt;
  std::optional<Expression> truth = arithmetic_if_comparison_mask(predicate, statement.line);
  if (!truth.has_value())
    return std::nullopt;
  return ArithmeticIfCandidate{
      .target = then_assign->first,
      .expression = then_true_else_false ? *truth : one_minus_expression(std::move(*truth)),
      .name = "arithmetic-if-comparison-mask",
      .detail = "Replaced comparison-to-boolean branch with arithmetic mask",
  };
}

std::optional<ArithmeticIfCandidate> build_arithmetic_if_boolean_algebra_candidate(
    const LoweringContext& context, const V2Statement& statement, const V2Predicate& predicate) {
  if (statement.else_body.empty())
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> then_assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  const std::optional<std::pair<std::string, Expression>> else_assign =
      single_arithmetic_if_assignment(context, statement.else_body);
  if (!then_assign.has_value() || !else_assign.has_value() ||
      then_assign->first != else_assign->first) {
    return std::nullopt;
  }
  std::optional<Expression> selector =
      arithmetic_if_boolean_selector(context, predicate, statement.line);
  if (!selector.has_value())
    return std::nullopt;

  const std::optional<Expression> other_then =
      arithmetic_if_boolean_identifier(context, then_assign->second);
  const std::optional<Expression> other_else =
      arithmetic_if_boolean_identifier(context, else_assign->second);
  const std::optional<Expression> inverted_then =
      arithmetic_if_one_minus_boolean_identifier(context, then_assign->second);
  const std::optional<double> then_value = numeric_literal_value(then_assign->second);
  const std::optional<double> else_value = numeric_literal_value(else_assign->second);

  if (other_then.has_value() && else_value.has_value() && std::fabs(*else_value) < 1e-12) {
    return ArithmeticIfCandidate{
        .target = then_assign->first,
        .expression = multiply_expression(std::move(*selector), *other_then),
        .name = "arithmetic-if-boolean-algebra",
        .detail = "Replaced boolean AND branch with arithmetic expression",
    };
  }
  if (then_value.has_value() && std::fabs(*then_value - 1.0) < 1e-12 && other_else.has_value()) {
    return ArithmeticIfCandidate{
        .target = then_assign->first,
        .expression = max_expression(std::move(*selector), *other_else),
        .name = "arithmetic-if-boolean-algebra",
        .detail = "Replaced boolean OR branch with arithmetic expression",
    };
  }
  if (other_then.has_value() && other_else.has_value() &&
      expression_equals(*other_then, *other_else)) {
    return std::nullopt;
  }
  if (inverted_then.has_value() && other_else.has_value() &&
      expression_equals(*inverted_then, *other_else)) {
    return ArithmeticIfCandidate{
        .target = then_assign->first,
        .expression = abs_expression(subtract_expression(std::move(*selector), *other_else)),
        .name = "arithmetic-if-boolean-algebra",
        .detail = "Replaced boolean XOR branch with arithmetic expression",
    };
  }
  return std::nullopt;
}

std::optional<ArithmeticIfCandidate>
build_arithmetic_if_max_min_candidate(const LoweringContext& context, const V2Statement& statement,
                                      const V2Predicate& predicate) {
  if (statement.else_body.empty())
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> then_assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  const std::optional<std::pair<std::string, Expression>> else_assign =
      single_arithmetic_if_assignment(context, statement.else_body);
  if (!then_assign.has_value() || !else_assign.has_value() ||
      then_assign->first != else_assign->first) {
    return std::nullopt;
  }

  const Expression left = parse_expression(predicate.left, statement.line);
  const Expression right = parse_expression(predicate.right, statement.line);
  if (predicate.op == ">" || predicate.op == ">=") {
    if (expression_equals(then_assign->second, left) &&
        expression_equals(else_assign->second, right))
      return arithmetic_if_max_candidate(then_assign->first, left, right);
    if (expression_equals(then_assign->second, right) &&
        expression_equals(else_assign->second, left))
      return arithmetic_if_min_candidate(then_assign->first, left, right);
  }
  if (predicate.op == "<" || predicate.op == "<=") {
    if (expression_equals(then_assign->second, right) &&
        expression_equals(else_assign->second, left))
      return arithmetic_if_max_candidate(then_assign->first, left, right);
    if (expression_equals(then_assign->second, left) &&
        expression_equals(else_assign->second, right))
      return arithmetic_if_min_candidate(then_assign->first, left, right);
  }
  return std::nullopt;
}

std::optional<ArithmeticIfCandidate>
build_arithmetic_if_clamp_candidate(const LoweringContext& context, const V2Statement& statement,
                                    const V2Predicate& predicate) {
  const std::optional<std::pair<std::string, Expression>> assign =
      single_effective_arithmetic_if_assignment(context, statement);
  if (!assign.has_value())
    return std::nullopt;
  const Expression target = identifier_expression(assign->first);
  const Expression left = parse_expression(predicate.left, statement.line);
  const Expression right = parse_expression(predicate.right, statement.line);
  if (!expression_equals(left, target) || !expression_equals(assign->second, right))
    return std::nullopt;

  if (predicate.op == "<" || predicate.op == "<=") {
    return arithmetic_if_max_candidate(assign->first, target, right,
                                       "Replaced lower clamp branch with max()");
  }
  if (predicate.op == ">" || predicate.op == ">=") {
    return arithmetic_if_min_candidate(assign->first, target, right,
                                       "Replaced upper clamp branch with min-via-max()");
  }
  return std::nullopt;
}

std::optional<ArithmeticIfCandidate> build_arithmetic_if_saturating_update_candidate(
    const LoweringContext& context, const V2Statement& statement, const V2Predicate& predicate) {
  if (!statement.else_body.empty())
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  if (!assign.has_value())
    return std::nullopt;

  const std::optional<NumericRange> range = numeric_range_for_name(context, assign->first);
  if (!range.has_value() || !range->min.has_value() || !range->max.has_value() ||
      !is_safe_integer_value(*range->min) || !is_safe_integer_value(*range->max)) {
    return std::nullopt;
  }

  const Expression target = identifier_expression(assign->first);
  const Expression left = parse_expression(predicate.left, statement.line);
  const Expression right = parse_expression(predicate.right, statement.line);
  if (!expression_equals(left, target))
    return std::nullopt;

  const std::optional<Expression> decrement =
      match_target_minus_delta(assign->second, assign->first);
  if (decrement.has_value() && predicate.op == ">" &&
      expression_is_numeric_value(context, *decrement, 1.0) &&
      expression_is_numeric_value(context, right, *range->min)) {
    return arithmetic_if_max_candidate(assign->first, assign->second, right,
                                       "Replaced saturating decrement branch with max()");
  }

  const std::optional<Expression> increment =
      match_target_plus_delta(assign->second, assign->first);
  if (increment.has_value() && predicate.op == "<" &&
      expression_is_numeric_value(context, *increment, 1.0) &&
      expression_is_numeric_value(context, right, *range->max)) {
    return arithmetic_if_min_candidate(assign->first, assign->second, right,
                                       "Replaced saturating increment branch with min-via-max()");
  }

  return std::nullopt;
}

bool arithmetic_if_identity_assignment(const std::string& target, const Expression& expression) {
  return expression_equals(expression, identifier_expression(target));
}

std::optional<ArithmeticIfCandidate> build_arithmetic_if_boolean_sign_toggle_candidate(
    const LoweringContext& context, const V2Statement& statement, const V2Predicate& predicate) {
  if (statement.else_body.empty())
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> then_assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  const std::optional<std::pair<std::string, Expression>> else_assign =
      single_arithmetic_if_assignment(context, statement.else_body);
  if (!then_assign.has_value() || !else_assign.has_value() ||
      then_assign->first != else_assign->first ||
      !arithmetic_if_identity_assignment(else_assign->first, else_assign->second)) {
    return std::nullopt;
  }
  std::optional<Expression> selector =
      arithmetic_if_boolean_selector(context, predicate, statement.line);
  if (!selector.has_value())
    return std::nullopt;
  Expression current = identifier_expression(then_assign->first);
  if (!expression_equals(then_assign->second, unary_expression("-", current)))
    return std::nullopt;
  return ArithmeticIfCandidate{
      .target = then_assign->first,
      .expression = arithmetic_if_sign_toggle_expression(current, std::move(*selector)),
      .name = "arithmetic-if-sign-toggle",
      .detail = "Replaced conditional sign toggle with boolean-masked multiplier",
  };
}

std::optional<ArithmeticIfCandidate> build_arithmetic_if_boolean_update_candidate(
    const LoweringContext& context, const V2Statement& statement, const V2Predicate& predicate) {
  if (!statement.else_body.empty())
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  if (!assign.has_value())
    return std::nullopt;
  std::optional<Expression> selector =
      arithmetic_if_boolean_selector(context, predicate, statement.line);
  const bool uses_comparison = !selector.has_value() && context.comparison_guarded_update_selectors;
  if (uses_comparison)
    selector = arithmetic_if_comparison_update_selector(predicate, statement.line);
  if (!selector.has_value())
    return std::nullopt;

  Expression current = identifier_expression(assign->first);
  if (std::optional<Expression> plus = match_target_plus_delta(assign->second, assign->first)) {
    return ArithmeticIfCandidate{
        .target = assign->first,
        .expression = add_expression(current, multiply_expression(*plus, std::move(*selector))),
        .name = uses_comparison ? "arithmetic-if-comparison-update" : "arithmetic-if-update",
        .detail = uses_comparison ? "Replaced conditional addition with comparison-mask arithmetic"
                                  : "Replaced conditional addition with boolean-masked arithmetic",
    };
  }
  if (std::optional<Expression> minus = match_target_minus_delta(assign->second, assign->first)) {
    return ArithmeticIfCandidate{
        .target = assign->first,
        .expression =
            subtract_expression(current, multiply_expression(*minus, std::move(*selector))),
        .name = uses_comparison ? "arithmetic-if-comparison-update" : "arithmetic-if-update",
        .detail = uses_comparison
                      ? "Replaced conditional subtraction with comparison-mask arithmetic"
                      : "Replaced conditional subtraction with boolean-masked arithmetic",
    };
  }
  if (uses_comparison)
    return std::nullopt;
  if (expression_equals(assign->second, unary_expression("-", current))) {
    return ArithmeticIfCandidate{
        .target = assign->first,
        .expression = arithmetic_if_sign_toggle_expression(current, std::move(*selector)),
        .name = "arithmetic-if-sign-toggle",
        .detail = "Replaced conditional sign toggle with boolean-masked multiplier",
    };
  }
  if (arithmetic_if_identity_assignment(assign->first, assign->second))
    return std::nullopt;
  return ArithmeticIfCandidate{
      .target = assign->first,
      .expression = add_expression(multiply_expression(current, one_minus_expression(*selector)),
                                   multiply_expression(assign->second, std::move(*selector))),
      .name = "arithmetic-if-conditional-move",
      .detail = "Replaced conditional assignment with boolean-masked conditional move",
  };
}

std::optional<ArithmeticIfCandidate>
build_arithmetic_if_select_candidate(const LoweringContext& context, const V2Statement& statement,
                                     const V2Predicate& predicate) {
  if (statement.else_body.empty())
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> then_assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  const std::optional<std::pair<std::string, Expression>> else_assign =
      single_arithmetic_if_assignment(context, statement.else_body);
  if (!then_assign.has_value() || !else_assign.has_value() ||
      then_assign->first != else_assign->first) {
    return std::nullopt;
  }
  std::optional<Expression> selector =
      arithmetic_if_boolean_selector(context, predicate, statement.line);
  if (!selector.has_value())
    return std::nullopt;
  return ArithmeticIfCandidate{
      .target = then_assign->first,
      .expression = add_expression(
          multiply_expression(then_assign->second, *selector),
          multiply_expression(else_assign->second, one_minus_expression(std::move(*selector)))),
      .name = "arithmetic-if-select",
      .detail = "Replaced boolean if/else with arithmetic selection",
  };
}

std::optional<ArithmeticIfCandidate> build_arithmetic_if_candidate(const LoweringContext& context,
                                                                   const V2Statement& statement) {
  const std::optional<V2Predicate> predicate = arithmetic_if_comparison_predicate(statement);
  if (!predicate.has_value())
    return std::nullopt;
  if (std::optional<ArithmeticIfCandidate> candidate =
          build_arithmetic_if_comparison_boolean_candidate(context, statement, *predicate)) {
    return candidate;
  }
  if (std::optional<ArithmeticIfCandidate> candidate =
          build_arithmetic_if_boolean_algebra_candidate(context, statement, *predicate)) {
    return candidate;
  }
  if (std::optional<ArithmeticIfCandidate> candidate =
          build_arithmetic_if_abs_candidate(context, statement, *predicate)) {
    return candidate;
  }
  if (std::optional<ArithmeticIfCandidate> candidate =
          build_arithmetic_if_max_min_candidate(context, statement, *predicate)) {
    return candidate;
  }
  if (std::optional<ArithmeticIfCandidate> candidate =
          build_arithmetic_if_clamp_candidate(context, statement, *predicate)) {
    return candidate;
  }
  if (std::optional<ArithmeticIfCandidate> candidate =
          build_arithmetic_if_saturating_update_candidate(context, statement, *predicate)) {
    return candidate;
  }
  if (std::optional<ArithmeticIfCandidate> candidate =
          build_arithmetic_if_boolean_sign_toggle_candidate(context, statement, *predicate)) {
    return candidate;
  }
  if (std::optional<ArithmeticIfCandidate> candidate =
          build_arithmetic_if_boolean_update_candidate(context, statement, *predicate)) {
    return candidate;
  }
  return build_arithmetic_if_select_candidate(context, statement, *predicate);
}

bool lower_arithmetic_if_branch_removal(LoweringContext& context, const V2Statement& statement) {
  const std::optional<ArithmeticIfCandidate> candidate =
      build_arithmetic_if_candidate(context, statement);
  if (!candidate.has_value())
    return false;

  const int ordinary_cost = estimate_branch_order_statement_cost(context, statement);
  if (ordinary_cost >= branch_order_infinite_cost())
    return false;
  const int selected_cost = guarded_estimate_expression_cost(candidate->expression) + 1;
  const bool force_comparison_mask = context.comparison_guarded_update_selectors &&
                                     candidate->name == "arithmetic-if-comparison-update";
  const bool allow_sign_toggle_tie =
      candidate->name == "arithmetic-if-sign-toggle" && selected_cost == ordinary_cost;
  if (selected_cost >= ordinary_cost && !force_comparison_mask && !allow_sign_toggle_tie)
    return false;

  if (!lower_expression_to_x(context, candidate->expression))
    return false;
  emit_store(context, candidate->target, candidate->name + " " + candidate->target);
  context.optimizations.push_back(OptimizationReport{
      .name = "branch-removal",
      .detail = candidate->detail + " at line " + std::to_string(statement.line) +
                "; emitted branchless " + candidate->name + ".",
  });
  context.optimizations.push_back(OptimizationReport{
      .name = candidate->name,
      .detail = candidate->detail + " at line " + std::to_string(statement.line) + " (" +
                std::to_string(selected_cost) + " vs " + std::to_string(ordinary_cost) +
                " estimated steps).",
  });
  return true;
}

struct ArithmeticClampBound {
  std::string target;
  Expression bound;
};

std::optional<ArithmeticClampBound> arithmetic_clamp_bound(const LoweringContext& context,
                                                           const V2Statement& statement,
                                                           std::string_view direction) {
  const std::optional<V2Predicate> predicate = arithmetic_if_comparison_predicate(statement);
  if (!predicate.has_value())
    return std::nullopt;
  const std::optional<std::pair<std::string, Expression>> assign =
      single_arithmetic_if_assignment(context, statement.then_body);
  if (!assign.has_value())
    return std::nullopt;
  const Expression target = identifier_expression(assign->first);
  const Expression left = parse_expression(predicate->left, statement.line);
  const Expression right = parse_expression(predicate->right, statement.line);
  if (!expression_equals(left, target) || !expression_equals(assign->second, right))
    return std::nullopt;
  if (direction == "lower" && (predicate->op == "<" || predicate->op == "<=")) {
    return ArithmeticClampBound{.target = assign->first, .bound = right};
  }
  if (direction == "upper" && (predicate->op == ">" || predicate->op == ">=")) {
    return ArithmeticClampBound{.target = assign->first, .bound = right};
  }
  return std::nullopt;
}

bool lower_arithmetic_if_double_clamp(LoweringContext& context, const V2Statement& first,
                                      const V2Statement& second) {
  const std::optional<ArithmeticClampBound> lower = arithmetic_clamp_bound(context, first, "lower");
  const std::optional<ArithmeticClampBound> upper =
      arithmetic_clamp_bound(context, second, "upper");
  if (!lower.has_value() || !upper.has_value() || lower->target != upper->target)
    return false;
  Expression expression = min_expression(
      max_expression(identifier_expression(lower->target), lower->bound), upper->bound);
  const int ordinary_cost = estimate_branch_order_statement_cost(context, first) +
                            estimate_branch_order_statement_cost(context, second);
  if (ordinary_cost >= branch_order_infinite_cost())
    return false;
  const int selected_cost = guarded_estimate_expression_cost(expression) + 1;
  if (selected_cost >= ordinary_cost)
    return false;

  if (!lower_expression_to_x(context, expression))
    return false;
  emit_store(context, lower->target, "arithmetic-if-double-clamp " + lower->target);
  context.optimizations.push_back(OptimizationReport{
      .name = "branch-removal",
      .detail = "Replaced adjacent lower/upper clamp branches with min(max()) at lines " +
                std::to_string(first.line) + "/" + std::to_string(second.line) +
                "; emitted branchless arithmetic-if-double-clamp.",
  });
  context.optimizations.push_back(OptimizationReport{
      .name = "arithmetic-if-double-clamp",
      .detail = "Replaced adjacent lower/upper clamp branches with min(max()) at lines " +
                std::to_string(first.line) + "/" + std::to_string(second.line) + " (" +
                std::to_string(selected_cost) + " vs " + std::to_string(ordinary_cost) +
                " estimated steps).",
  });
  return true;
}

bool lower_residual_guarded_update(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value())
    return false;
  const std::optional<ResidualGuardedUpdateMatch> update = match_residual_guarded_update(statement);
  if (!update.has_value() || !residual_guarded_update_saves(context, *update))
    return false;

  const std::string false_label = context.emitter.fresh_label("if_false");
  const bool then_terminates = direct_terminal_statements_stop(context, update->tail);
  const std::optional<std::string> end_label =
      !statement.else_body.empty() && !then_terminates
          ? std::optional<std::string>{context.emitter.fresh_label("if_end")}
          : std::nullopt;

  if (!compile_residual_guarded_condition(context, *update, false_label, statement.line))
    return false;
  emit_residual_guarded_update(context, *update);
  if (!lower_statement_block(context, update->tail))
    return false;

  if (!statement.else_body.empty()) {
    if (end_label.has_value())
      context.emitter.emit_jump(0x51, "БП", *end_label, "if end", statement.line);
    context.emitter.emit_label(false_label, {.hidden = true});
    const Expression residual =
        subtract_expression(parse_expression(update->condition.left, statement.line),
                            parse_expression(update->condition.right, statement.line));
    if (!statement.else_body.empty() &&
        display_statement_is_single_expression(statement.else_body.front(), residual)) {
      mark_branch_residual_reuse(context, residual, statement.line, "false branch");
    }
    if (!lower_statement_block(context, statement.else_body))
      return false;
    if (end_label.has_value())
      context.emitter.emit_label(*end_label, {.hidden = true});
  } else {
    context.emitter.emit_label(false_label, {.hidden = true});
  }
  return true;
}

bool lower_nested_guard_shared_failure(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() ||
      statement.else_body.empty() || statement.then_body.size() != 1U) {
    return false;
  }
  const V2Statement& inner = statement.then_body.front();
  if (inner.kind != "v2_if" || !inner.predicate.has_value() || inner.else_body.empty())
    return false;
  if (!common_branch_statement_lists_equal(statement.else_body, inner.else_body))
    return false;

  const std::string failure_label = context.emitter.fresh_label("guard_failure");
  const bool then_terminates = direct_terminal_statements_stop(context, inner.then_body);
  const std::optional<std::string> end_label =
      then_terminates ? std::nullopt
                      : std::optional<std::string>{context.emitter.fresh_label("guard_end")};

  if (!lower_condition_false_branch(context, *statement.predicate, statement.negated, failure_label,
                                    statement.line))
    return false;

  const std::optional<ResidualGuardedUpdateMatch> residual_update =
      match_residual_guarded_update(inner);
  if (residual_update.has_value() && residual_guarded_update_saves(context, *residual_update)) {
    if (!compile_residual_guarded_condition(context, *residual_update, failure_label, inner.line))
      return false;
    emit_residual_guarded_update(context, *residual_update);
    if (!lower_statement_block(context, residual_update->tail))
      return false;
  } else {
    if (!lower_condition_false_branch(context, *inner.predicate, inner.negated, failure_label,
                                      inner.line))
      return false;
    if (!lower_statement_block(context, inner.then_body))
      return false;
  }

  if (end_label.has_value())
    context.emitter.emit_jump(0x51, "БП", *end_label, "guard success end", inner.line);
  context.emitter.emit_label(failure_label, {.hidden = true});
  if (!lower_statement_block(context, statement.else_body))
    return false;
  if (end_label.has_value())
    context.emitter.emit_label(*end_label, {.hidden = true});
  context.optimizations.push_back(OptimizationReport{
      .name = "nested-guard-shared-failure",
      .detail = "Shared identical nested failure branch at lines " +
                std::to_string(statement.line) + "/" + std::to_string(inner.line) + ".",
  });
  return true;
}

struct ExcludedNumericValues {
  std::string name;
  std::vector<int> values;
};

bool numeric_value_is_integer(double value);

std::optional<int> integer_numeric_literal_value(const Expression& expression) {
  const std::optional<double> value = numeric_literal_value(expression);
  if (!value.has_value() || !numeric_value_is_integer(*value))
    return std::nullopt;
  return static_cast<int>(std::round(*value));
}

std::optional<ExcludedNumericValues>
identifier_equals_numeric_condition(const Expression& identifier_side,
                                    const Expression& numeric_side) {
  const std::optional<int> value = integer_numeric_literal_value(numeric_side);
  if (!value.has_value())
    return std::nullopt;
  if (identifier_side.kind == "identifier") {
    return ExcludedNumericValues{.name = identifier_side.name, .values = {*value}};
  }
  if (identifier_side.kind == "call" && lower_ascii(identifier_side.callee) == "abs" &&
      identifier_side.args.size() == 1U && identifier_side.args.front().kind == "identifier") {
    if (*value == 0)
      return ExcludedNumericValues{.name = identifier_side.args.front().name, .values = {0}};
    return ExcludedNumericValues{.name = identifier_side.args.front().name,
                                 .values = {*value, -*value}};
  }
  return std::nullopt;
}

std::optional<ExcludedNumericValues>
frac_division_equals_zero_condition(LoweringContext& context, const Expression& expression_side,
                                    const Expression& zero_side) {
  if (!is_zero_expression(context, zero_side) || expression_side.kind != "call" ||
      lower_ascii(expression_side.callee) != "frac" || expression_side.args.size() != 1U) {
    return std::nullopt;
  }
  const Expression& divided = expression_side.args.front();
  if (divided.kind != "binary" || divided.op != "/" || divided.left == nullptr ||
      divided.right == nullptr || divided.left->kind != "identifier") {
    return std::nullopt;
  }
  const std::optional<int> divisor = integer_numeric_literal_value(*divided.right);
  if (!divisor.has_value() || *divisor == 0)
    return std::nullopt;
  const int abs_divisor = std::abs(*divisor);
  return ExcludedNumericValues{.name = divided.left->name,
                               .values = {0, abs_divisor, -abs_divisor}};
}

std::optional<ExcludedNumericValues>
false_branch_excluded_numeric_values(LoweringContext& context, const V2Predicate& predicate,
                                     int line) {
  if (predicate.op != "==")
    return std::nullopt;
  const Expression left = parse_expression(predicate.left, line);
  const Expression right = parse_expression(predicate.right, line);
  if (std::optional<ExcludedNumericValues> direct =
          identifier_equals_numeric_condition(left, right)) {
    return direct;
  }
  if (std::optional<ExcludedNumericValues> reverse =
          identifier_equals_numeric_condition(right, left)) {
    return reverse;
  }
  if (std::optional<ExcludedNumericValues> modulo =
          frac_division_equals_zero_condition(context, left, right)) {
    return modulo;
  }
  return frac_division_equals_zero_condition(context, right, left);
}

bool lower_statement_block_with_excluded_values(
    LoweringContext& context, const std::vector<V2Statement>& statements,
    const std::optional<ExcludedNumericValues>& excluded) {
  if (!excluded.has_value() || excluded->values.empty())
    return lower_statement_block(context, statements);

  const auto previous_it = context.path_excluded_numeric_values.find(excluded->name);
  const bool had_previous = previous_it != context.path_excluded_numeric_values.end();
  const std::set<int> previous = had_previous ? previous_it->second : std::set<int>{};

  std::set<int> next = previous;
  for (const int value : excluded->values)
    next.insert(value);
  context.path_excluded_numeric_values[excluded->name] = std::move(next);

  const bool lowered = lower_statement_block(context, statements);
  if (had_previous) {
    context.path_excluded_numeric_values[excluded->name] = previous;
  } else {
    context.path_excluded_numeric_values.erase(excluded->name);
  }
  return lowered;
}

bool lower_if_statement(LoweringContext& context, const V2Statement& statement) {
  const bool entered_with_errors = has_errors(context.diagnostics);

  if (statement.kind != "v2_if" || !statement.predicate.has_value())
    return false;

  if (lower_domain_error_guard(context, statement))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;
  if (lower_negative_zero_terminal_select(context, statement))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;
  if (lower_arithmetic_if_branch_removal(context, statement))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;
  if (lower_guarded_update_selector(context, statement))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;
  if (lower_nested_guard_shared_failure(context, statement))
    return true;
  if (lower_residual_guarded_update(context, statement))
    return true;
  if (lower_direct_terminal_if_branch(context, statement))
    return true;
  if (lower_local_terminal_else_tail(context, statement))
    return true;
  if (!entered_with_errors && has_errors(context.diagnostics))
    return false;

  const V2Statement selected = branch_order_statement(context, statement);
  const bool has_else = !selected.else_body.empty();
  const std::optional<Expression> branch_residual =
      branch_residual_expression(context, *selected.predicate, selected.negated, selected.line);
  const std::optional<std::string> fallthrough_identifier = fallthrough_current_x_candidate(
      context, *selected.predicate, selected.negated, selected.then_body, selected.line);
  const std::optional<std::string> false_branch_identifier =
      has_else ? false_branch_current_x_candidate(context, *selected.predicate, selected.negated,
                                                  selected.else_body, selected.line)
               : std::nullopt;
  const bool false_branch_known_zero =
      has_else && inequality_false_branch_leaves_zero(context, *selected.predicate,
                                                      selected.negated, selected.line);
  const bool true_fallthrough_known_zero = equality_true_fallthrough_leaves_zero(
                                               context, *selected.predicate, selected.negated,
                                               selected.line) ||
                                           equality_true_fallthrough_can_feed_zero_accumulator(
                                               context, *selected.predicate, selected.negated,
                                               selected.then_body, selected.line);
  const std::string false_label = context.emitter.fresh_label(has_else ? "if_else" : "if_end");
  const std::string end_label = has_else ? context.emitter.fresh_label("if_end") : false_label;
  if (!lower_condition_false_branch(context, *selected.predicate, selected.negated, false_label,
                                    selected.line))
    return false;
  if (fallthrough_identifier.has_value()) {
    mark_current_x(context, *fallthrough_identifier);
    context.emitter.current_x_known_zero = true_fallthrough_known_zero;
    context.optimizations.push_back(OptimizationReport{
        .name = "x-preserving-fallthrough-branch",
        .detail = "Preserved " + *fallthrough_identifier +
                  " in X across the true branch of the zero-test at line " +
                  std::to_string(selected.line) + ".",
    });
  } else if (true_fallthrough_known_zero) {
    context.emitter.current_x_known_zero = true;
    context.optimizations.push_back(OptimizationReport{
        .name = "equality-zero-fallthrough",
        .detail = "Reused the zero left in X by equality comparison at line " +
                  std::to_string(selected.line) + ".",
    });
  }
  const std::vector<V2Statement> then_body = compile_residual_head_if_possible(
      context, selected.then_body, branch_residual, selected.line, "fallthrough");
  if (!lower_statement_block(context, then_body))
    return false;

  if (has_else) {
    const bool then_stops = statements_always_stop(context, selected.then_body);
    if (!then_stops)
      context.emitter.emit_jump(0x51, "БП", end_label, "if end", selected.line);
    context.emitter.emit_label(false_label, {.hidden = true});
    if (false_branch_identifier.has_value()) {
      mark_current_x(context, *false_branch_identifier);
      context.emitter.current_x_known_zero = false_branch_known_zero;
      context.optimizations.push_back(OptimizationReport{
          .name = "x-preserving-false-branch",
          .detail = "Preserved " + *false_branch_identifier +
                    " in X across the false branch of the zero-test at line " +
                    std::to_string(selected.line) + ".",
      });
    } else if (false_branch_known_zero) {
      context.emitter.current_x_known_zero = true;
      context.optimizations.push_back(OptimizationReport{
          .name = "inequality-zero-false-branch",
          .detail = "Reused the zero left in X by false branch of inequality comparison at line " +
                    std::to_string(selected.line) + ".",
      });
    }
    const std::optional<ExcludedNumericValues> excluded =
        false_branch_excluded_numeric_values(context, *selected.predicate, selected.line);
    const std::vector<V2Statement> else_body = compile_residual_head_if_possible(
        context, selected.else_body, branch_residual, selected.line, "false branch");
    if (!lower_statement_block_with_excluded_values(context, else_body, excluded))
      return false;
    if (!then_stops)
      context.emitter.emit_label(end_label, {.hidden = true});
    if (then_stops) {
      context.optimizations.push_back(OptimizationReport{
          .name = "terminal-branch-end-elision",
          .detail = "Omitted unreachable if-end jump after terminal then branch at line " +
                    std::to_string(selected.line) + ".",
      });
    }
    return true;
  }

  context.emitter.emit_label(false_label, {.hidden = true});
  return true;
}

std::vector<V2Statement> inline_statement_invokes_once(LoweringContext& context,
                                                       const std::vector<V2Statement>& body) {
  std::vector<V2Statement> expanded;
  for (const V2Statement& statement : body) {
    if (statement.kind == "v2_invoke" && statement.name.has_value() && statement.args.empty() &&
        context.inline_statement_rules.contains(*statement.name) &&
        !context.inline_call_stack.contains(*statement.name)) {
      const auto rule_it = context.rules.find(*statement.name);
      if (rule_it != context.rules.end()) {
        expanded.insert(expanded.end(), rule_it->second->body.begin(), rule_it->second->body.end());
        continue;
      }
    }
    expanded.push_back(statement);
  }
  return expanded;
}

struct MaskMembershipCondition {
  std::string collection;
  Expression mask;
};

std::optional<MaskMembershipCondition> match_mask_membership_condition(LoweringContext& context,
                                                                       const V2Predicate& predicate,
                                                                       bool negated, int line) {
  const std::optional<NormalizedZeroComparison> normalized =
      normalize_zero_comparison(context, predicate, negated, line);
  if (!normalized.has_value() || normalized->op != "!=")
    return std::nullopt;
  const Expression& expression = normalized->expression;
  if (expression.kind != "call" || lower_ascii(expression.callee) != "bit_and" ||
      expression.args.size() != 2U) {
    return std::nullopt;
  }

  const Expression& first = expression.args.at(0);
  const Expression& second = expression.args.at(1);
  if (first.kind == "identifier")
    return MaskMembershipCondition{.collection = first.name, .mask = second};
  if (second.kind == "identifier")
    return MaskMembershipCondition{.collection = second.name, .mask = first};
  return std::nullopt;
}

bool membership_mask_preserves_y(const Expression& mask) {
  if (mask.kind == "identifier")
    return true;
  return mask.kind == "call" && lower_ascii(mask.callee) == "frac" && mask.args.size() == 1U &&
         mask.args.front().kind == "identifier";
}

bool expression_is_bit_not_of(const Expression& expression, const Expression& mask) {
  return expression.kind == "call" && lower_ascii(expression.callee) == "bit_not" &&
         expression.args.size() == 1U && expression_equals(expression.args.front(), mask);
}

bool expression_is_membership_clear(const Expression& expression, const std::string& collection,
                                    const Expression& mask) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "bit_and" ||
      expression.args.size() != 2U) {
    return false;
  }
  const auto matches = [&](const Expression& left, const Expression& right) {
    return left.kind == "identifier" && left.name == collection &&
           expression_is_bit_not_of(right, mask);
  };
  return matches(expression.args.at(0), expression.args.at(1)) ||
         matches(expression.args.at(1), expression.args.at(0));
}

bool expression_is_membership_set(const Expression& expression, const std::string& collection,
                                  const Expression& mask) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "bit_or" ||
      expression.args.size() != 2U) {
    return false;
  }
  const auto matches = [&](const Expression& left, const Expression& right) {
    return left.kind == "identifier" && left.name == collection && expression_equals(right, mask);
  };
  return matches(expression.args.at(0), expression.args.at(1)) ||
         matches(expression.args.at(1), expression.args.at(0));
}

bool expression_is_known_fractional(const Expression& expression) {
  const std::optional<double> literal = numeric_literal_value(expression);
  if (literal.has_value())
    return std::fabs(*literal) < 1.0;
  if (expression.kind == "unary" && expression.op == "-" && expression.expr != nullptr)
    return expression_is_known_fractional(*expression.expr);
  return expression.kind == "call" && lower_ascii(expression.callee) == "frac" &&
         expression.args.size() == 1U;
}

bool expression_is_decimal_cell_mask(const Expression& expression) {
  if (expression.kind != "call")
    return false;
  const std::string callee = lower_ascii(expression.callee);
  return (callee == "pow10" && expression.args.size() == 1U) ||
         (callee == "cell_mask" && expression.args.size() >= 2U);
}

bool expression_is_x2_preserving_decimal_membership_mask(const Expression& expression) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "pow10" ||
      expression.args.size() != 1U) {
    return false;
  }
  return expression.args.front().kind == "identifier";
}

void emit_membership_fraction_if_needed(LoweringContext& context, const Expression& mask,
                                        std::string comment, int line) {
  if (expression_is_known_fractional(mask)) {
    context.optimizations.push_back(OptimizationReport{
        .name = "fractional-membership-mask-test",
        .detail = "Skipped fractional extraction for a known-fractional membership mask at line " +
                  std::to_string(line) + ".",
    });
    return;
  }
  if (expression_is_decimal_cell_mask(mask))
    return;
  context.emitter.emit_op(0x35, "К {x}", std::move(comment), line);
}

bool emit_y_preserving_membership_mask(LoweringContext& context, const Expression& mask, int line) {
  if (mask.kind == "identifier") {
    emit_recall(context, mask.name);
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = "membership clear mask " + mask.name;
    return true;
  }
  if (mask.kind == "call" && lower_ascii(mask.callee) == "frac" && mask.args.size() == 1U &&
      mask.args.front().kind == "identifier") {
    emit_recall(context, mask.args.front().name);
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = "membership clear mask " + mask.args.front().name;
    context.emitter.emit_op(0x35, "К {x}", "membership clear mask frac", line);
    return true;
  }
  return false;
}

bool lower_membership_clear_delta_branch(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value())
    return false;
  const std::optional<MaskMembershipCondition> membership = match_mask_membership_condition(
      context, *statement.predicate, statement.negated, statement.line);
  if (!membership.has_value() || !membership_mask_preserves_y(membership->mask))
    return false;

  std::vector<V2Statement> then_body = inline_statement_invokes_once(context, statement.then_body);
  if (then_body.empty())
    return false;
  const V2Statement& clear = then_body.front();
  if (clear.kind != "v2_assign" || !clear.target.has_value() || !clear.expr.has_value() ||
      *clear.target != membership->collection) {
    return false;
  }
  if (!expression_is_membership_clear(parse_expression(*clear.expr, clear.line),
                                      membership->collection, membership->mask)) {
    return false;
  }

  const std::string false_label = context.emitter.fresh_label("if_false");
  const std::string end_label = context.emitter.fresh_label("if_end");

  emit_recall(context, membership->collection);
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "membership clear source " + membership->collection;
  if (!emit_y_preserving_membership_mask(context, membership->mask, statement.line))
    return false;
  context.emitter.emit_op(0x3a, "К ИНВ", "membership clear mask complement", statement.line);
  context.emitter.emit_op(0x37, "К ∧", "clear membership bit before test", statement.line);
  emit_store(context, membership->collection, "set " + membership->collection);
  context.emitter.emit_op(0x11, "-", "membership clear delta test", statement.line);
  context.emitter.emit_jump(0x57, "F x≠0", false_label, "false branch for !=", statement.line);

  std::vector<V2Statement> rest(then_body.begin() + 1, then_body.end());
  if (!lower_statement_block(context, rest))
    return false;
  if (!statement.else_body.empty()) {
    context.emitter.emit_jump(0x51, "БП", end_label, "if end", statement.line);
    context.emitter.emit_label(false_label, {.hidden = true});
    context.emitter.current_x_known_zero = true;
    if (!lower_statement_block(context, statement.else_body))
      return false;
    context.emitter.emit_label(end_label, {.hidden = true});
  } else {
    context.emitter.emit_label(false_label, {.hidden = true});
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "membership-clear-delta-branch",
      .detail = "Cleared " + membership->collection +
                " before branching and used the old value in Y to test membership at line " +
                std::to_string(statement.line) + ".",
  });
  return true;
}

bool lower_cells_contains_clear_if(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() || statement.negated)
    return false;
  const V2Predicate& predicate = *statement.predicate;
  if (predicate.kind != "v2_contains")
    return false;
  const std::string collection = trim_ascii(predicate.collection);
  const V2StateField* collection_field = state_field_named(context, collection);
  if (collection_field == nullptr || collection_field->type != "cells" ||
      is_segmented_cells_name(context, collection)) {
    return false;
  }

  std::vector<V2Statement> then_body = inline_statement_invokes_once(context, statement.then_body);
  if (then_body.empty())
    return false;
  const V2Statement& clear = then_body.front();
  if (clear.kind != "v2_update" || !clear.target.has_value() || !clear.expr.has_value() ||
      !clear.op.has_value() || *clear.target != collection || *clear.op != "-=" ||
      trim_ascii(*clear.expr) != trim_ascii(predicate.item)) {
    return false;
  }

  const Expression item = parse_expression(predicate.item, statement.line);
  if (const std::optional<Expression> mask =
          cell_mask_expression_for_collection(context, collection, item);
      mask.has_value() && membership_mask_preserves_y(*mask)) {
    const std::string false_label =
        context.emitter.fresh_label(statement.else_body.empty() ? "if_end" : "if_else");
    const std::string end_label =
        statement.else_body.empty() ? false_label : context.emitter.fresh_label("if_end");

    emit_recall(context, collection);
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = "membership clear source " + collection;
    if (!emit_y_preserving_membership_mask(context, *mask, statement.line))
      return false;
    context.emitter.emit_op(0x3a, "К ИНВ", "membership clear mask complement", statement.line);
    context.emitter.emit_op(0x37, "К ∧", "clear membership bit before test", statement.line);
    emit_store(context, collection, "set " + collection);
    context.emitter.emit_op(0x11, "-", "membership clear delta test", statement.line);
    context.emitter.emit_jump(0x57, "F x≠0", false_label, "false branch for !=", statement.line);

    std::vector<V2Statement> rest(then_body.begin() + 1, then_body.end());
    if (!lower_statement_block(context, rest))
      return false;
    if (!statement.else_body.empty()) {
      context.emitter.emit_jump(0x51, "БП", end_label, "if end", statement.line);
      context.emitter.emit_label(false_label, {.hidden = true});
      context.emitter.current_x_known_zero = true;
      if (!lower_statement_block(context, statement.else_body))
        return false;
      context.emitter.emit_label(end_label, {.hidden = true});
    } else {
      context.emitter.emit_label(false_label, {.hidden = true});
    }
    context.optimizations.push_back(OptimizationReport{
        .name = "membership-clear-delta-branch",
        .detail = "Cleared " + collection +
                  " before branching and used the old value in Y to test membership at line " +
                  std::to_string(statement.line) + ".",
    });
    return true;
  }

  const std::string false_label =
      context.emitter.fresh_label(statement.else_body.empty() ? "if_end" : "if_else");
  const std::string end_label =
      statement.else_body.empty() ? false_label : context.emitter.fresh_label("if_end");
  const bool uses_shared_membership_helper =
      context.register_index_by_name.contains(spatial_hit_scratch_name(collection));
  if (!lower_membership_clear_operands_to_stack(context, collection, item, statement.line))
    return false;
  context.emitter.emit_op(0x37, "К ∧",
                          uses_shared_membership_helper ? "bit membership test" : "bit_and()",
                          statement.line);
  context.emitter.emit_op(0x35, "К {x}",
                          uses_shared_membership_helper ? "bit membership fraction" : "frac()",
                          statement.line);
  if (!uses_shared_membership_helper)
    context.emitter.emit_op(0x32, "К ЗН", "sign()", statement.line);
  context.emitter.emit_jump(0x57, "F x≠0", false_label, "false branch for !=", statement.line);
  context.emitter.emit_op(0x3a, "К ИНВ", "reuse membership mask for clear", clear.line);
  emit_recall(context, collection);
  context.emitter.emit_op(0x37, "К ∧", "clear matched cell with reused mask", clear.line);
  emit_store(context, collection, "set " + collection);

  std::vector<V2Statement> rest(then_body.begin() + 1, then_body.end());
  const bool then_stops = statements_always_stop(context, rest);
  if (!lower_statement_block(context, rest))
    return false;
  if (!statement.else_body.empty()) {
    if (!then_stops)
      context.emitter.emit_jump(0x51, "БП", end_label, "if end", statement.line);
    context.emitter.emit_label(false_label, {.hidden = true});
    context.emitter.current_x_known_zero = true;
    if (!lower_statement_block(context, statement.else_body))
      return false;
    if (!then_stops)
      context.emitter.emit_label(end_label, {.hidden = true});
  } else {
    context.emitter.emit_label(false_label, {.hidden = true});
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "cell-membership-clear-reuse",
      .detail = "Reused the successful membership mask when clearing " + collection + " at line " +
                std::to_string(clear.line) + ".",
  });
  return true;
}

bool lower_segmented_cells_contains_clear_if(LoweringContext& context,
                                             const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() || statement.negated)
    return false;
  const V2Predicate& predicate = *statement.predicate;
  if (predicate.kind != "v2_contains")
    return false;
  const std::string collection = trim_ascii(predicate.collection);
  const V2StateField* collection_field = state_field_named(context, collection);
  if (collection_field == nullptr || collection_field->type != "cells" ||
      !is_segmented_cells_name(context, collection)) {
    return false;
  }

  std::vector<V2Statement> then_body = inline_statement_invokes_once(context, statement.then_body);
  if (then_body.empty())
    return false;
  const V2Statement& clear = then_body.front();
  if (clear.kind != "v2_update" || !clear.target.has_value() || !clear.expr.has_value() ||
      !clear.op.has_value() || *clear.target != collection || *clear.op != "-=" ||
      trim_ascii(*clear.expr) != trim_ascii(predicate.item)) {
    return false;
  }

  const std::string false_label =
      context.emitter.fresh_label(statement.else_body.empty() ? "if_end" : "if_else");
  const std::string end_label =
      statement.else_body.empty() ? false_label : context.emitter.fresh_label("if_end");
  const Expression item = parse_expression(predicate.item, statement.line);
  if (!lower_expression_to_x(context, item))
    return false;
  const std::optional<std::string> selector =
      emit_segmented_bitplane_indirect_select_from_current_x(context, statement.line);
  std::optional<std::string> then_label;
  if (selector.has_value()) {
    if (!lower_expression_to_x(context, bit_mask_expression(identifier_expression(
                                            std::string(kSegmentedBitplaneIndex)))))
      return false;
    if (!emit_selected_segmented_plane_recall(context, *selector,
                                              "segmented bitplane selected plane", statement.line))
      return false;
    context.emitter.emit_op(0x37, "К ∧", "segmented bitplane probe", statement.line);
    context.emitter.emit_op(0x35, "К {x}", "segmented bitplane hit fraction", statement.line);
    context.emitter.emit_jump(0x57, "F x≠0", false_label, "false branch for segmented hit",
                              statement.line);
    context.emitter.emit_op(0x3a, "К ИНВ", "segmented bitplane clear matched mask", clear.line);
    if (!emit_selected_segmented_plane_recall(
            context, *selector, "segmented bitplane clear selected plane", clear.line))
      return false;
    context.emitter.emit_op(0x37, "К ∧", "segmented bitplane clear matched bit", clear.line);
    if (!emit_selected_segmented_plane_store(context, *selector,
                                             "segmented bitplane store selected plane", clear.line))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "segmented-bitplane-hit-update-indirect",
        .detail = "Fused " + collection +
                  " probe/update through one indirect selected plane at line " +
                  std::to_string(statement.line) + ".",
    });
  } else {
    then_label = context.emitter.fresh_label("segmented_bitplane_then");
    if (!emit_segmented_bitplane_group_dispatch(
            context, collection, statement.line,
            [&](int /*group*/, const std::string& plane) {
              if (!emit_segmented_bitplane_local_mask(context, statement.line))
                return false;
              emit_recall(context, plane);
              if (!context.emitter.items.empty())
                context.emitter.items.back().comment = "segmented bitplane probe plane";
              context.emitter.emit_op(0x37, "К ∧", "segmented bitplane probe", statement.line);
              context.emitter.emit_op(0x35, "К {x}", "segmented bitplane hit fraction",
                                      statement.line);
              context.emitter.emit_jump(0x57, "F x≠0", false_label,
                                        "false branch for segmented hit", statement.line);
              context.emitter.emit_op(0x3a, "К ИНВ", "segmented bitplane clear matched mask",
                                      clear.line);
              emit_recall(context, plane);
              if (!context.emitter.items.empty())
                context.emitter.items.back().comment = "segmented bitplane clear plane";
              context.emitter.emit_op(0x37, "К ∧", "segmented bitplane clear matched bit",
                                      clear.line);
              emit_store(context, plane, "segmented bitplane clear plane");
              context.emitter.emit_jump(0x51, "БП", *then_label, "segmented bitplane hit tail",
                                        statement.line);
              return true;
            },
            false)) {
      return false;
    }
    context.optimizations.push_back(OptimizationReport{
        .name = "segmented-bitplane-hit-update",
        .detail = "Fused " + collection + " membership probe with -= update at line " +
                  std::to_string(statement.line) + ".",
    });
    context.emitter.emit_label(*then_label, {.hidden = true});
  }

  std::vector<V2Statement> rest(then_body.begin() + 1, then_body.end());
  const bool then_stops = statements_always_stop(context, rest);
  if (!lower_statement_block(context, rest))
    return false;
  if (!statement.else_body.empty()) {
    if (!then_stops)
      context.emitter.emit_jump(0x51, "БП", end_label, "if end", statement.line);
    context.emitter.emit_label(false_label, {.hidden = true});
    context.emitter.current_x_known_zero = true;
    if (!lower_statement_block(context, statement.else_body))
      return false;
    if (!then_stops)
      context.emitter.emit_label(end_label, {.hidden = true});
  } else {
    context.emitter.emit_label(false_label, {.hidden = true});
  }
  return true;
}

bool lower_while_statement(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_while" || !statement.predicate.has_value())
    return false;

  const std::string start_label = context.emitter.fresh_label("while");
  const std::string end_label = context.emitter.fresh_label("while_end");
  context.emitter.emit_label(start_label, {.hidden = true});
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  context.emitter.current_x_known_zero = false;
  context.emitter.current_x_expression.reset();
  context.emitter.current_x_formatted_coord_report_body.reset();
  context.scaled_coord_variables.clear();
  if (!lower_condition_false_branch(context, *statement.predicate, false, end_label,
                                    statement.line))
    return false;
  if (!lower_statement_block(context, statement.body))
    return false;
  context.emitter.emit_jump(0x51, "БП", start_label, "while loop back", statement.line);
  context.emitter.emit_label(end_label, {.hidden = true});
  return true;
}

bool lower_match_action(LoweringContext& context, const V2Statement& action) {
  if (action.kind == "v2_block")
    return lower_statement_block(context, action.body);
  return lower_statement(context, action, nullptr);
}

bool match_action_terminates_statically(const LoweringContext& context, const V2Statement* action) {
  if (context.program == nullptr || action == nullptr)
    return false;
  std::set<std::string> seen_rules;
  if (action->kind == "v2_block")
    return guarded_statement_list_terminates_statically(*context.program, action->body, seen_rules);
  return guarded_statement_terminates_statically(*context.program, *action, seen_rules);
}

std::optional<double> numeric_match_value(LoweringContext& context, const std::string& value,
                                          int line) {
  try {
    return numeric_value_of_expression(context, parse_expression(value, line));
  } catch (const std::exception&) {
    return std::nullopt;
  }
}

struct OptimizedMatchDefaultCases {
  V2Statement statement;
  int removed = 0;
};

bool later_match_case_has_numeric_value(LoweringContext& context,
                                        const std::vector<V2MatchCase>& cases,
                                        std::size_t current_case_index, double value) {
  for (std::size_t case_index = current_case_index + 1U; case_index < cases.size(); ++case_index) {
    const V2MatchCase& later_case = cases.at(case_index);
    for (const std::string& later_value_text : later_case.values) {
      const std::optional<double> later_value =
          numeric_match_value(context, later_value_text, later_case.line);
      if (later_value.has_value() && std::fabs(*later_value - value) <= 1e-12)
        return true;
    }
  }
  return false;
}

OptimizedMatchDefaultCases optimize_match_default_cases(LoweringContext& context,
                                                        const V2Statement& statement) {
  OptimizedMatchDefaultCases result{.statement = statement};
  if (statement.kind != "v2_match" || statement.cases.empty() || statement.otherwise == nullptr)
    return result;

  const std::vector<V2Statement> default_body = action_to_common_branch_body(statement.otherwise);
  std::vector<V2MatchCase> kept_cases;
  kept_cases.reserve(statement.cases.size());
  for (std::size_t case_index = 0; case_index < statement.cases.size(); ++case_index) {
    const V2MatchCase& match_case = statement.cases.at(case_index);
    if (match_case.action == nullptr) {
      kept_cases.push_back(match_case);
      continue;
    }

    const std::vector<V2Statement> case_body = action_to_common_branch_body(match_case.action);
    const bool case_matches_default = common_branch_statement_lists_equal(case_body, default_body);
    V2MatchCase kept_case = match_case;
    kept_case.values.clear();
    for (const std::string& value_text : match_case.values) {
      const std::optional<double> numeric =
          numeric_match_value(context, value_text, match_case.line);
      const bool can_remove =
          numeric.has_value() && case_matches_default &&
          !later_match_case_has_numeric_value(context, statement.cases, case_index, *numeric);
      if (can_remove) {
        result.removed += 1;
      } else {
        kept_case.values.push_back(value_text);
      }
    }
    if (!kept_case.values.empty())
      kept_cases.push_back(std::move(kept_case));
  }

  if (result.removed > 0)
    result.statement.cases = std::move(kept_cases);
  return result;
}

struct DispatchResidualSignMatch {
  double bound = 0.0;
  bool negate = false;
  std::optional<Expression> factor;
};

std::optional<double> numeric_expression_value(LoweringContext& context,
                                               const Expression& expression) {
  try {
    return numeric_value_of_expression(context, expression);
  } catch (const std::exception&) {
    return std::nullopt;
  }
}

std::optional<DispatchResidualSignMatch>
match_dispatch_residual_sign_expression(LoweringContext& context, const Expression& expression,
                                        const Expression& dispatch_expression) {
  if (expression.kind == "binary" && expression.op == "*" && expression.left != nullptr &&
      expression.right != nullptr) {
    if (std::optional<DispatchResidualSignMatch> left =
            match_dispatch_residual_sign_expression(context, *expression.left, dispatch_expression);
        left.has_value() && numeric_expression_value(context, *expression.right).has_value()) {
      left->factor = *expression.right;
      return left;
    }
    if (std::optional<DispatchResidualSignMatch> right = match_dispatch_residual_sign_expression(
            context, *expression.right, dispatch_expression);
        right.has_value() && numeric_expression_value(context, *expression.left).has_value()) {
      right->factor = *expression.left;
      return right;
    }
    return std::nullopt;
  }

  if (expression.kind != "call" || lower_ascii(expression.callee) != "sign" ||
      expression.args.size() != 1U) {
    return std::nullopt;
  }
  const Expression& arg = expression.args.front();
  if (arg.kind != "binary" || arg.op != "-" || arg.left == nullptr || arg.right == nullptr)
    return std::nullopt;

  if (const std::optional<double> right_bound = numeric_expression_value(context, *arg.right);
      right_bound.has_value() && expression_equals(*arg.left, dispatch_expression)) {
    return DispatchResidualSignMatch{.bound = *right_bound, .negate = false};
  }
  if (const std::optional<double> left_bound = numeric_expression_value(context, *arg.left);
      left_bound.has_value() && expression_equals(*arg.right, dispatch_expression)) {
    return DispatchResidualSignMatch{.bound = *left_bound, .negate = true};
  }
  return std::nullopt;
}

void emit_residual_compare_delta(LoweringContext& context, double delta, const std::string& comment,
                                 int line) {
  if (std::fabs(delta) <= 1e-12)
    return;
  emit_number_or_preload(context, format_number_literal(std::fabs(delta)), std::nullopt, line);
  context.emitter.emit_op(delta < 0 ? 0x10 : 0x11, delta < 0 ? "+" : "-", comment, line);
}

bool numeric_value_is_integer(double value) {
  return std::fabs(value - std::round(value)) <= 1e-12;
}

bool identifier_has_integer_domain(const LoweringContext& context, const std::string& name) {
  const V2StateField* field = state_field_named(context, name);
  return field != nullptr && field->type == "counter" && field->min.has_value() &&
         field->max.has_value();
}

bool can_skip_dispatch_residual_sign_unit_adjust(const LoweringContext& context,
                                                 const DispatchResidualSignMatch& matched,
                                                 const Expression& dispatch_expression,
                                                 double compared_value) {
  const double delta = matched.bound - compared_value;
  if (std::fabs(std::fabs(delta) - 1.0) > 1e-12)
    return false;
  if (!numeric_value_is_integer(matched.bound) || !numeric_value_is_integer(compared_value))
    return false;
  if (dispatch_expression.kind != "identifier")
    return false;
  if (!identifier_has_integer_domain(context, dispatch_expression.name))
    return false;
  const auto excluded_it = context.path_excluded_numeric_values.find(dispatch_expression.name);
  if (excluded_it == context.path_excluded_numeric_values.end())
    return false;
  return excluded_it->second.contains(static_cast<int>(std::round(matched.bound)));
}

bool emit_dispatch_residual_sign_expression(LoweringContext& context, const Expression& expression,
                                            const Expression& dispatch_expression,
                                            double compared_value, int line) {
  const std::optional<DispatchResidualSignMatch> matched =
      match_dispatch_residual_sign_expression(context, expression, dispatch_expression);
  if (!matched.has_value())
    return false;

  if (can_skip_dispatch_residual_sign_unit_adjust(context, *matched, dispatch_expression,
                                                  compared_value)) {
    context.optimizations.push_back(OptimizationReport{
        .name = "dispatch-default-residual-sign-domain",
        .detail = "Used integer-domain exclusions to derive " + expression_to_source(expression) +
                  " without shifting the dispatch residual at line " + std::to_string(line) + ".",
    });
  } else {
    emit_residual_compare_delta(context, matched->bound - compared_value,
                                "dispatch default residual adjust", line);
  }
  if (matched->negate)
    context.emitter.emit_op(0x0b, "/-/", "dispatch default residual sign direction", line);
  context.emitter.emit_op(0x32, "К ЗН", "dispatch default residual sign", line);
  if (matched->factor.has_value()) {
    if (!lower_expression_to_x(context, *matched->factor))
      return false;
    context.emitter.emit_op(0x12, "*", "dispatch default residual sign scale", line);
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "dispatch-default-residual-sign",
      .detail = "Derived " + expression_to_source(expression) +
                " from the dispatch residual at line " + std::to_string(line) + ".",
  });
  return true;
}

bool lower_dispatch_residual_default_x_param_call(LoweringContext& context,
                                                  const V2StatementPtr& action,
                                                  const Expression& dispatch_expression,
                                                  double compared_value) {
  if (action == nullptr || action->kind != "v2_invoke" || !action->name.has_value() ||
      action->args.size() != 1U) {
    return false;
  }
  const auto rule_it = context.rules.find(*action->name);
  const auto x_param_it = context.x_param_procs.find(*action->name);
  if (rule_it == context.rules.end() || x_param_it == context.x_param_procs.end())
    return false;

  const Expression arg = parse_expression(action->args.front(), action->line);
  if (!emit_dispatch_residual_sign_expression(context, arg, dispatch_expression, compared_value,
                                              action->line)) {
    return false;
  }

  const V2Rule& rule = *rule_it->second;
  context.emitter.emit_jump(0x53, "ПП", function_label(rule.name), "call function " + rule.name,
                            action->line);
  context.optimizations.push_back(OptimizationReport{
      .name = "dispatch-default-residual-sign",
      .detail = "Derived " + action->args.front() + " from the dispatch residual at line " +
                std::to_string(action->line) + ".",
  });
  context.optimizations.push_back(OptimizationReport{
      .name = "dispatch-default-residual-x-param",
      .detail = "Passed residual-derived " + x_param_it->second.param + " to " + rule.name +
                " through X at line " + std::to_string(action->line) + ".",
  });
  if (const std::optional<std::string> return_x = proc_return_x_variable(context, rule)) {
    mark_current_x(context, *return_x);
    context.emitter.current_x_known_zero = false;
  } else {
    clear_current_x_facts(context);
  }
  return true;
}

bool lower_dispatch_residual_default_inline_param_call(LoweringContext& context,
                                                       const V2StatementPtr& action,
                                                       const Expression& dispatch_expression,
                                                       double compared_value) {
  if (action == nullptr || action->kind != "v2_invoke" || !action->name.has_value() ||
      action->args.size() != 1U) {
    return false;
  }
  const auto rule_it = context.rules.find(*action->name);
  if (rule_it == context.rules.end())
    return false;
  const V2Rule& rule = *rule_it->second;
  if (rule.params.size() != 1U || rule.body.empty() || statements_contain_return(rule.body) ||
      count_identifier_reads_in_statements(rule.body, rule.params.front()) != 1 ||
      context.inline_call_stack.contains(rule.name)) {
    return false;
  }

  const Expression arg = parse_expression(action->args.front(), action->line);
  if (!emit_dispatch_residual_sign_expression(context, arg, dispatch_expression, compared_value,
                                              action->line)) {
    return false;
  }

  context.inline_call_stack.insert(rule.name);
  mark_current_x(context, rule.params.front());
  context.emitter.current_x_known_zero = false;
  const bool lowered = lower_statement_block(context, rule.body);
  context.inline_call_stack.erase(rule.name);
  if (lowered) {
    const int uses =
        context.proc_call_counts.contains(rule.name) ? context.proc_call_counts[rule.name] : 1;
    context.optimizations.push_back(OptimizationReport{
        .name = uses == 1 ? "single-use-rule-inline" : "size-model-rule-inline",
        .detail = uses == 1 ? "Inlined single-use rule " + rule.name + " at line " +
                                  std::to_string(action->line) + "."
                            : "Inlined " + std::to_string(uses) + "-use rule " + rule.name +
                                  " because it is smaller than a ПП/В/О subroutine.",
    });
  }
  return lowered;
}

struct NumericMatchCase {
  double value = 0.0;
  const V2Statement* action = nullptr;
  int line = 0;
};

bool numeric_match_case_values_are_unique(const std::vector<NumericMatchCase>& cases) {
  for (std::size_t left = 0; left < cases.size(); ++left) {
    for (std::size_t right = left + 1U; right < cases.size(); ++right) {
      if (std::fabs(cases.at(left).value - cases.at(right).value) <= 1e-12)
        return false;
    }
  }
  return true;
}

int residual_dispatch_step_cost(std::optional<double> previous, double value) {
  const double delta = previous.has_value() ? value - *previous : value;
  if (std::fabs(delta) <= 1e-12)
    return 0;
  return number_entry_cost(format_number_literal(std::fabs(delta))) + 1;
}

int residual_dispatch_order_cost(const std::vector<NumericMatchCase>& cases,
                                 const std::vector<std::size_t>& order) {
  std::optional<double> previous;
  int cost = 0;
  for (const std::size_t index : order) {
    const double value = cases.at(index).value;
    cost += residual_dispatch_step_cost(previous, value);
    previous = value;
  }
  return cost;
}

std::vector<std::size_t> identity_order(std::size_t count) {
  std::vector<std::size_t> order(count);
  std::iota(order.begin(), order.end(), 0U);
  return order;
}

bool order_is_identity(const std::vector<std::size_t>& order) {
  for (std::size_t index = 0; index < order.size(); ++index) {
    if (order.at(index) != index)
      return false;
  }
  return true;
}

std::vector<std::size_t> zero_first_dispatch_order(const std::vector<NumericMatchCase>& cases) {
  const std::vector<std::size_t> identity = identity_order(cases.size());
  const auto zero_it = std::find_if(cases.begin(), cases.end(), [](const NumericMatchCase& item) {
    return std::fabs(item.value) <= 1e-12;
  });
  if (zero_it == cases.end())
    return identity;
  const std::size_t zero_index = static_cast<std::size_t>(std::distance(cases.begin(), zero_it));
  if (zero_index == 0)
    return identity;
  std::vector<std::size_t> order{zero_index};
  for (std::size_t index = 0; index < cases.size(); ++index) {
    if (index != zero_index)
      order.push_back(index);
  }
  return order;
}

std::vector<std::size_t> best_residual_dispatch_order(const std::vector<NumericMatchCase>& cases) {
  const std::vector<std::size_t> current = identity_order(cases.size());
  if (cases.size() > 8U || !numeric_match_case_values_are_unique(cases))
    return current;

  std::vector<std::size_t> best = current;
  const int current_cost = residual_dispatch_order_cost(cases, current);
  int best_cost = current_cost;
  std::set<std::size_t> used;
  std::vector<std::size_t> order;

  std::function<void(std::optional<double>, int)> visit = [&](std::optional<double> previous,
                                                              int cost) {
    if (cost >= best_cost)
      return;
    if (order.size() == cases.size()) {
      best_cost = cost;
      best = order;
      return;
    }
    for (std::size_t index = 0; index < cases.size(); ++index) {
      if (used.contains(index))
        continue;
      used.insert(index);
      order.push_back(index);
      const double value = cases.at(index).value;
      visit(value, cost + residual_dispatch_step_cost(previous, value));
      order.pop_back();
      used.erase(index);
    }
  };
  visit(std::nullopt, 0);
  if (current_cost - best_cost < 3)
    return current;
  return best;
}

struct OrderedNumericMatchCases {
  std::vector<NumericMatchCase> cases;
  int reordered = 0;
};

OrderedNumericMatchCases
order_numeric_match_cases_for_residual(const std::vector<NumericMatchCase>& cases) {
  std::vector<std::size_t> order = best_residual_dispatch_order(cases);
  if (order_is_identity(order))
    order = zero_first_dispatch_order(cases);

  OrderedNumericMatchCases result;
  result.cases.reserve(cases.size());
  for (std::size_t index = 0; index < order.size(); ++index) {
    if (order.at(index) != index)
      result.reordered += 1;
    result.cases.push_back(cases.at(order.at(index)));
  }
  return result;
}

bool lower_numeric_residual_match_statement(LoweringContext& context,
                                            const V2Statement& statement) {
  if (statement.kind != "v2_match" || !statement.expr.has_value() || statement.cases.empty())
    return false;

  std::vector<NumericMatchCase> cases;
  for (const V2MatchCase& match_case : statement.cases) {
    if (match_case.action == nullptr)
      return false;
    for (const std::string& value : match_case.values) {
      const std::optional<double> numeric = numeric_match_value(context, value, match_case.line);
      if (!numeric.has_value())
        return false;
      cases.push_back(NumericMatchCase{
          .value = *numeric, .action = match_case.action.get(), .line = match_case.line});
    }
  }
  if (cases.empty())
    return false;
  if (!context.preserve_dispatch_case_order) {
    OrderedNumericMatchCases ordered = order_numeric_match_cases_for_residual(cases);
    if (ordered.reordered > 0) {
      context.optimizations.push_back(OptimizationReport{
          .name = "dispatch-case-ordering",
          .detail = "Reordered " + std::to_string(ordered.reordered) + " numeric dispatch case" +
                    (ordered.reordered == 1 ? "" : "s") + " to shorten residual comparisons.",
      });
      cases = std::move(ordered.cases);
    }
  }

  const Expression match_expr = parse_expression(*statement.expr, statement.line);
  if (!lower_expression_to_x(context, match_expr))
    return false;

  const std::string end_label = context.emitter.fresh_label("match_end");
  double compared_value = 0.0;
  bool has_compared_value = false;
  for (const NumericMatchCase& match_case : cases) {
    const std::string next_label = context.emitter.fresh_label("match_next");
    if (!has_compared_value) {
      emit_residual_compare_delta(context, match_case.value, "dispatch compare", match_case.line);
      has_compared_value = true;
    } else {
      const double delta = match_case.value - compared_value;
      emit_residual_compare_delta(context, delta, "dispatch residual compare", match_case.line);
    }
    compared_value = match_case.value;
    context.emitter.emit_jump(0x5e, "F x=0", next_label, "case mismatch", match_case.line);
    mark_dispatch_case_match_zero(context);
    if (!lower_match_action(context, *match_case.action))
      return false;
    if (!match_action_terminates_statically(context, match_case.action))
      context.emitter.emit_jump(0x51, "БП", end_label, "dispatch end", match_case.line);
    context.emitter.emit_label(next_label, {.hidden = true});
  }

  if (statement.otherwise != nullptr) {
    if (!lower_dispatch_residual_default_x_param_call(context, statement.otherwise, match_expr,
                                                      compared_value) &&
        !lower_dispatch_residual_default_inline_param_call(context, statement.otherwise, match_expr,
                                                           compared_value) &&
        !lower_match_action(context, *statement.otherwise)) {
      return false;
    }
  }
  context.emitter.emit_label(end_label, {.hidden = true});
  context.optimizations.push_back(OptimizationReport{
      .name = "numeric-dispatch-residual-chain",
      .detail = "Lowered numeric match cases as a residual comparison chain.",
  });
  return true;
}

// Computed-dispatch lowering: replace a k-way compare chain with a single
// indirect jump whose target is synthesized from the selector value by
// op(scale*x + offset). The formula in `plan` was solved post-layout by the
// address-formula solver so each case value lands on its case body entry. Only
// reached when a matching SynthesizedDispatchPlan is present (SizeRescue
// candidate); the behavioral-equivalence gate validates the result.
bool lower_synthesized_dispatch(LoweringContext& context, const V2Statement& statement,
                                const SynthesizedDispatchPlan& plan) {
  // Reserve the indirect-jump register up front (before emitting anything) so we
  // can bail cleanly to the compare-chain lowering if no register is free. The
  // allocator picks the physical register; the static resolver is
  // register-independent across stable (index >= 7) registers, so any stable one
  // reproduces the formula solved during discovery. A non-stable register would
  // mutate under К БП, so reject it.
  const std::string jump_var = "__dispatch_jump_" + std::to_string(statement.line);
  if (!ensure_hidden_register(context, jump_var))
    return false;
  const int jump_index = register_index_for(context, jump_var);
  if (jump_index < 7)
    return false;

  const Expression match_expr = parse_expression(*statement.expr, statement.line);
  if (!lower_expression_to_x(context, match_expr))
    return false;

  if (std::fabs(plan.scale - 1.0) > 1e-9) {
    emit_number_or_preload(context, format_number_literal(plan.scale), std::nullopt,
                           statement.line);
    context.emitter.emit_op(0x12, "×", "dispatch formula scale", statement.line);
  }
  if (std::fabs(plan.offset) > 1e-9) {
    emit_number_or_preload(context, format_number_literal(std::fabs(plan.offset)), std::nullopt,
                           statement.line);
    context.emitter.emit_op(plan.offset < 0 ? 0x11 : 0x10, plan.offset < 0 ? "-" : "+",
                            "dispatch formula offset", statement.line);
  }
  if (plan.op_opcode >= 0) {
    const std::string mnemonic =
        plan.op_name.empty() ? opcode_by_code(plan.op_opcode).name : plan.op_name;
    context.emitter.emit_op(plan.op_opcode, mnemonic, "dispatch formula op", statement.line);
  }

  // Pre-generate one entry label per case so the computed `К БП` can advertise
  // its (otherwise invisible) target edges to the reachability/overlay passes.
  std::vector<std::string> entry_labels;
  entry_labels.reserve(statement.cases.size());
  for (std::size_t index = 0; index < statement.cases.size(); ++index)
    entry_labels.push_back(context.emitter.fresh_label("dispatch_case_entry"));

  // Store the computed address into the reserved register, then jump through it.
  emit_store(context, jump_var, "dispatch computed address");

  std::string targets_marker = "computed-dispatch-targets=";
  for (std::size_t index = 0; index < entry_labels.size(); ++index) {
    if (index > 0)
      targets_marker += ",";
    targets_marker += entry_labels.at(index);
  }
  context.emitter.emit_op(0x80 + jump_index, "К БП " + register_text_for(context, jump_var),
                          "computed dispatch; " + targets_marker, statement.line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_expression.reset();
  context.emitter.current_x_aliases.clear();

  const std::string end_label = context.emitter.fresh_label("match_end");
  for (std::size_t index = 0; index < statement.cases.size(); ++index) {
    const V2MatchCase& match_case = statement.cases.at(index);
    context.emitter.emit_label(entry_labels.at(index), {.hidden = true});
    if (match_case.action != nullptr && !lower_match_action(context, *match_case.action))
      return false;
    if (!match_action_terminates_statically(context, match_case.action.get()))
      context.emitter.emit_jump(0x51, "БП", end_label, "dispatch end", match_case.line);
  }
  if (statement.otherwise != nullptr && !lower_match_action(context, *statement.otherwise))
    return false;
  context.emitter.emit_label(end_label, {.hidden = true});
  context.optimizations.push_back(OptimizationReport{
      .name = "computed-dispatch",
      .detail = "Lowered match at line " + std::to_string(statement.line) +
                " as a computed indirect dispatch via " + register_text_for(context, jump_var) + ".",
  });
  return true;
}

bool lower_match_statement(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_match" || !statement.expr.has_value())
    return false;

  const OptimizedMatchDefaultCases optimized = optimize_match_default_cases(context, statement);
  if (optimized.removed > 0) {
    context.optimizations.push_back(OptimizationReport{
        .name = "dispatch-default-merge",
        .detail = "Removed " + std::to_string(optimized.removed) + " dispatch case" +
                  (optimized.removed == 1 ? "" : "s") + " whose body matched the default branch.",
    });
  }
  const V2Statement& lowered_statement = optimized.statement;

  if (lowered_statement.cases.empty()) {
    if (lowered_statement.otherwise == nullptr)
      return true;
    return lower_match_action(context, *lowered_statement.otherwise);
  }

  for (const SynthesizedDispatchPlan& plan : context.synthesized_dispatch_plans) {
    if (plan.match_line != lowered_statement.line)
      continue;
    if (lower_synthesized_dispatch(context, lowered_statement, plan))
      return true;
    break;
  }

  if (lower_numeric_residual_match_statement(context, lowered_statement)) {
    context.optimizations.push_back(OptimizationReport{
        .name = "dispatch-lowering",
        .detail = "Selected residual-compare-chain for match at line " +
                  std::to_string(lowered_statement.line) + ".",
    });
    return true;
  }

  const Expression match_expr = parse_expression(*lowered_statement.expr, lowered_statement.line);
  std::string selector_name;
  const auto source_register_it = match_expr.kind == "identifier"
                                      ? context.registers.find(match_expr.name)
                                      : context.registers.end();
  if (source_register_it != context.registers.end()) {
    selector_name = match_expr.name;
    context.optimizations.push_back(OptimizationReport{
        .name = "dispatch-source-register",
        .detail = "Reused R" + source_register_it->second +
                  " as dispatch scratch for identifier expression.",
    });
  } else {
    selector_name = "__match_value_" + std::to_string(lowered_statement.line);
    assign_register(context, selector_name);
    if (has_errors(context.diagnostics))
      return false;
    if (!lower_expression_to_x(context, match_expr))
      return false;
    emit_store(context, selector_name, "match value");
  }

  const std::string end_label = context.emitter.fresh_label("match_end");
  for (const V2MatchCase& match_case : lowered_statement.cases) {
    for (const std::string& value : match_case.values) {
      const std::string next_label = context.emitter.fresh_label("match_next");
      V2Predicate predicate;
      predicate.kind = "v2_compare";
      predicate.left = selector_name;
      predicate.op = "==";
      predicate.right = value;
      if (!lower_condition_false_branch(context, predicate, false, next_label, match_case.line,
                                        "case mismatch"))
        return false;
      if (match_case.action != nullptr && !lower_match_action(context, *match_case.action))
        return false;
      if (!match_action_terminates_statically(context, match_case.action.get()))
        context.emitter.emit_jump(0x51, "БП", end_label, "dispatch end", match_case.line);
      context.emitter.emit_label(next_label, {.hidden = true});
    }
  }

  if (lowered_statement.otherwise != nullptr &&
      !lower_match_action(context, *lowered_statement.otherwise))
    return false;
  context.emitter.emit_label(end_label, {.hidden = true});
  context.optimizations.push_back(OptimizationReport{
      .name = "dispatch-lowering",
      .detail = "Selected scratch-compare-chain for match at line " +
                std::to_string(lowered_statement.line) + ".",
  });
  return true;
}

bool lower_guarded_decrement_consumer(LoweringContext& context, const V2Statement& consumer) {
  if (consumer.kind == "v2_if")
    return lower_if_statement(context, consumer);
  if (consumer.kind == "v2_match")
    return lower_match_statement(context, consumer);
  return lower_statement(context, consumer, nullptr);
}

bool lower_lunar_if(LoweringContext& context, const V2Statement& statement) {
  if (!context.lunar_shape || statement.kind != "v2_if" || !statement.predicate.has_value())
    return false;
  const V2Predicate& predicate = *statement.predicate;
  if (predicate.kind != "v2_compare" || predicate.left != "height" || predicate.op != "<" ||
      predicate.right != "2") {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                             "Native lunar lowering only supports height < 2"));
    return false;
  }

  emit_recall(context, "height");
  context.emitter.emit_number("2");
  context.emitter.emit_op(0x11, "-", "condition compare", statement.line);
  context.emitter.emit_op(0xc7, "К x<0 7",
                          "false branch for <; preloaded R7=B2 indirect-target=0 indirect flow",
                          statement.line);
  context.emitter.emit_number("5");
  emit_recall(context, "speed");
  context.emitter.emit_op(0x31, "К |x|", "abs()", statement.line);
  context.emitter.emit_op(0x11, "-", "condition compare", statement.line);
  context.emitter.emit_op(
      0x98, "К x>=0 8",
      "false branch for <=; preloaded R8=F3 indirect-target=41 shifted-forward indirect flow",
      statement.line);
  emit_recall(context, "__const_safe_777");
  context.emitter.items.back().comment = "preload const 777";
  context.emitter.emit_op(0x50, "С/П", "halt", statement.line);
  emit_recall(context, "__const_crash_666");
  context.emitter.items.back().comment = "preload const 666";
  context.emitter.emit_op(0x50, "С/П", "halt", statement.line);
  return true;
}

bool lower_clock_if(LoweringContext& context, const V2Statement& statement) {
  if (!context.clock_shape || statement.kind != "v2_if" || !statement.predicate.has_value())
    return false;
  const V2Predicate& predicate = *statement.predicate;
  if (predicate.kind != "v2_compare" || predicate.op != ">=" || statement.negated ||
      !statement.else_body.empty()) {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                             "Native clock lowering only supports simple >= ifs"));
    return false;
  }

  std::string limit_name;
  if (predicate.left == "minute" && predicate.right == "60") {
    limit_name = "__const_60";
  } else if (predicate.left == "hour" && predicate.right == "24") {
    limit_name = "__const_24";
  } else {
    context.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                   "Native clock lowering only supports minute/hour rollover"));
    return false;
  }

  emit_recall(context, predicate.left);
  emit_recall(context, limit_name);
  context.emitter.items.back().comment =
      limit_name == "__const_60" ? "preload const 60" : "preload const 24";
  context.emitter.emit_op(0x11, "-", "condition compare", statement.line);
  context.emitter.emit_op(0x97, "К x>=0 7", "false branch for >=", statement.line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  return lower_statement_block(context, statement.then_body);
}

bool lower_clock_wait_tick(LoweringContext& context, const V2Statement& statement) {
  if (!context.clock_shape || statement.kind != "v2_invoke" || statement.name != "wait_tick")
    return false;

  emit_recall(context, "__const_10");
  context.emitter.items.back().comment = "preload const 10";
  emit_store(context, "outer_delay", "set outer_delay");
  emit_recall(context, "outer_delay");
  context.emitter.items.back().raw = true;
  context.emitter.emit_op(
      0x7a, "К x≠0 a",
      "false branch for !=; preloaded Ra=D1 indirect-target=19 shifted-forward indirect flow",
      statement.line);
  context.emitter.emit_number("1");
  context.emitter.emit_op(0x11, "-", "expr -", statement.line);
  emit_store(context, "outer_delay", "set outer_delay");
  context.emitter.emit_number("11");
  context.emitter.emit_op(0x78, "К x≠0 8",
                          "false branch for !=; preloaded R8=C0 indirect-target=8 indirect flow",
                          statement.line);
  context.emitter.emit_number("1");
  context.emitter.emit_op(0x11, "-", "expr -", statement.line);
  context.emitter.emit_op(0x89, "К БП 9",
                          "while loop back; preloaded R9=C7 indirect-target=15 indirect flow",
                          statement.line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  return true;
}

bool lower_invoke_statement(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_invoke" || !statement.name.has_value())
    return false;
  const auto rule_it = context.rules.find(*statement.name);
  if (rule_it == context.rules.end()) {
    context.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                   "Native lowering does not support invocation of unknown function '" +
                       *statement.name + "'"));
    return false;
  }

  const V2Rule& rule = *rule_it->second;
  if (statement.args.empty() && context.inline_statement_rules.contains(rule.name)) {
    if (context.inline_call_stack.contains(rule.name)) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Recursive inline procedure '" + rule.name + "' is not supported"));
      return false;
    }
    context.inline_call_stack.insert(rule.name);
    const bool lowered = lower_statement_block(context, rule.body);
    context.inline_call_stack.erase(rule.name);
    if (lowered) {
      const int uses =
          context.proc_call_counts.contains(rule.name) ? context.proc_call_counts[rule.name] : 0;
      context.optimizations.push_back(OptimizationReport{
          .name = uses == 1 ? "single-use-rule-inline" : "size-model-rule-inline",
          .detail = uses == 1 ? "Inlined single-use rule " + rule.name + " at line " +
                                    std::to_string(statement.line) + "."
                              : "Inlined " + std::to_string(uses) + "-use rule " + rule.name +
                                    " because it is smaller than a ПП/В/О subroutine.",
      });
    }
    return lowered;
  }
  if (statement.args.empty() && rule.params.empty() && statements_always_stop(context, rule.body) &&
      !statements_contain_return(rule.body)) {
    context.emitter.emit_jump(0x51, "БП", function_label(rule.name), "terminal rule " + rule.name,
                              statement.line);
    context.optimizations.push_back(OptimizationReport{
        .name = "terminal-rule-tail-call",
        .detail = "Compiled terminal rule " + rule.name +
                  " as a direct jump instead of a subroutine call.",
    });
    return true;
  }

  std::vector<Expression> args;
  args.reserve(statement.args.size());
  for (std::size_t index = 0; index < statement.args.size(); ++index) {
    args.push_back(parse_expression(statement.args.at(index), statement.line));
  }
  if (lower_inline_param_rule_call(context, rule, args, statement.line))
    return true;
  if (lower_x_param_value_function_call(context, rule, args, statement.line))
    return true;
  if (lower_x_param_return_decay_call(context, rule, args, statement.line))
    return true;
  if (context.x_param_procs.contains(rule.name))
    return lower_x_param_rule_call(context, rule, args, statement.line);
  if (args.empty() && context.emitter.current_x_known_zero) {
    const std::optional<PackedLineFamilyScoreRule> score_rule =
        packed_line_family_score_rule(context, rule);
    if (score_rule.has_value() && context.stack_only_state_fields.contains(score_rule->score)) {
      context.emitter.emit_jump(0x53, "ПП", packed_line_family_score_zero_entry_label(rule.name),
                                "proc call " + rule.name + " zero-accumulator entry",
                                statement.line);
      mark_current_x(context, score_rule->score);
      context.emitter.current_x_known_zero = false;
      context.optimizations.push_back(OptimizationReport{
          .name = "zero-accumulator-proc-entry",
          .detail = "Entered " + rule.name +
                    " after its zero literal because X already held a proved zero at line " +
                    std::to_string(statement.line) + ".",
      });
      return true;
    }
  }
  if (!lower_rule_arguments(context, rule, args))
    return false;

  if (statements_always_stop(context, rule.body) && !statements_contain_return(rule.body)) {
    context.emitter.emit_jump(0x51, "БП", function_label(rule.name),
                              "terminal rule " + rule.name, statement.line);
    context.optimizations.push_back(OptimizationReport{
        .name = "terminal-rule-tail-call",
        .detail = "Compiled terminal rule " + rule.name +
                  " as a direct jump instead of a subroutine call.",
    });
    clear_current_x_facts(context);
    return true;
  }

  context.emitter.emit_jump(0x53, "ПП", function_label(rule.name), "proc call " + rule.name,
                            statement.line);
  context.optimizations.push_back(OptimizationReport{
      .name = "proc-call-lowering",
      .detail = "Compiled call to rule " + rule.name + " as ПП/В/О subroutine.",
  });
  if (const std::optional<std::string> return_x = proc_return_x_variable(context, rule)) {
    mark_current_x(context, *return_x);
    context.emitter.current_x_known_zero = false;
    context.optimizations.push_back(OptimizationReport{
        .name = "proc-return-x-reuse",
        .detail = "Tracked " + *return_x + " in X after returning from rule " + rule.name + ".",
    });
  } else {
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
  }
  return true;
}

// Faithful port of TS compileBlockCall (proc-raw-setup.ts): emits a subroutine
// call (or inline/terminal/zero-accumulator variant) with the argument already
// staged in X by the caller.
void compile_block_call(LoweringContext& context, const std::string& block_name, int line) {
  const auto rule_it = context.rules.find(block_name);
  if (rule_it == context.rules.end()) {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                             "Unknown block '" + block_name + "'."));
    return;
  }
  const V2Rule& rule = *rule_it->second;
  if (context.inline_statement_rules.contains(rule.name)) {
    if (context.inline_call_stack.contains(rule.name)) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                     "Recursive inline procedure '" + rule.name + "' is not supported"));
      return;
    }
    context.inline_call_stack.insert(rule.name);
    (void)lower_statement_block(context, rule.body);
    context.inline_call_stack.erase(rule.name);
    const int uses =
        context.proc_call_counts.contains(rule.name) ? context.proc_call_counts[rule.name] : 0;
    context.optimizations.push_back(OptimizationReport{
        .name = uses == 1 ? "single-use-rule-inline" : "size-model-rule-inline",
        .detail = uses == 1 ? "Inlined single-use rule " + rule.name + " at line " +
                                  std::to_string(line) + "."
                            : "Inlined " + std::to_string(uses) + "-use rule " + rule.name +
                                  " because it is smaller than a ПП/В/О subroutine.",
    });
    return;
  }
  if (statements_always_stop(context, rule.body) && !statements_contain_return(rule.body)) {
    context.emitter.emit_jump(0x51, "БП", function_label(rule.name), "terminal rule " + rule.name,
                              line);
    context.optimizations.push_back(OptimizationReport{
        .name = "terminal-rule-tail-call",
        .detail = "Compiled terminal rule " + rule.name +
                  " as a direct jump instead of a subroutine call.",
    });
    return;
  }
  if (context.emitter.current_x_known_zero && packed_line_family_score_rule(context, rule)) {
    context.emitter.emit_jump(0x53, "ПП", packed_line_family_score_zero_entry_label(rule.name),
                              "proc call " + rule.name + " zero-accumulator entry", line);
    if (const std::optional<std::string> return_x = proc_return_x_variable(context, rule)) {
      mark_current_x(context, *return_x);
      context.emitter.current_x_known_zero = false;
    }
    context.optimizations.push_back(OptimizationReport{
        .name = "zero-accumulator-proc-entry",
        .detail = "Entered " + rule.name +
                  " after its zero literal because X already held a proved zero at line " +
                  std::to_string(line) + ".",
    });
    return;
  }
  context.emitter.emit_jump(0x53, "ПП", function_label(rule.name), "proc call " + rule.name, line);
  context.optimizations.push_back(OptimizationReport{
      .name = "proc-call-lowering",
      .detail = "Compiled call to rule " + rule.name + " as ПП/В/О subroutine.",
  });
  if (const std::optional<std::string> return_x = proc_return_x_variable(context, rule)) {
    mark_current_x(context, *return_x);
    context.emitter.current_x_known_zero = false;
    context.optimizations.push_back(OptimizationReport{
        .name = "proc-return-x-reuse",
        .detail = "Tracked " + *return_x + " in X after returning from rule " + rule.name + ".",
    });
  } else {
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
  }
}

struct XParamPackedScoreAccumulationPlan {
  Expression line;
  std::string return_x;
  std::string helper_label;
};

// Faithful port of Compiler.xParamPackedScoreAccumulationPlan.
std::optional<XParamPackedScoreAccumulationPlan>
build_x_param_packed_score_accumulation_plan(LoweringContext& context, const Expression& argument,
                                             const std::string& block,
                                             const V2Statement& score_assign) {
  const auto lowering_it = context.x_param_procs.find(block);
  if (lowering_it == context.x_param_procs.end())
    return std::nullopt;
  if (!expression_pure_for_substitution(argument))
    return std::nullopt;
  if (!expression_preserves_previous_x_as_y_for_packed_line(argument))
    return std::nullopt;
  if (!x_param_proc_preserves_caller_y(context, block))
    return std::nullopt;

  const auto proc_it = context.rules.find(block);
  if (proc_it == context.rules.end() || proc_it->second == nullptr ||
      proc_it->second->body.size() != 1U)
    return std::nullopt;
  const std::optional<std::string> return_x = proc_return_x_variable(context, *proc_it->second);
  if (!return_x.has_value())
    return std::nullopt;

  if (!score_assign.target.has_value())
    return std::nullopt;
  const std::optional<Expression> line =
      stack_analysis_packed_score_accumulator(score_assign, *score_assign.target, *return_x);
  if (!line.has_value())
    return std::nullopt;
  if (!x_holds_identifier(context, *score_assign.target))
    return std::nullopt;
  if (!is_simple_stack_load(*line) ||
      expression_contains_identifier(*line, *score_assign.target))
    return std::nullopt;
  if (!context.use_packed_score_helper)
    return std::nullopt;

  return XParamPackedScoreAccumulationPlan{
      .line = *line,
      .return_x = *return_x,
      .helper_label = packed_score_helper_label(context),
  };
}

// Faithful port of Compiler.compileXParamProcPackedScoreAccumulationTail.
bool lower_x_param_proc_packed_score_accumulation_tail(LoweringContext& context,
                                                       const Expression& argument,
                                                       int argument_line, const std::string& block,
                                                       int call_line,
                                                       const V2Statement& score_assign) {
  const std::optional<XParamPackedScoreAccumulationPlan> plan =
      build_x_param_packed_score_accumulation_plan(context, argument, block, score_assign);
  if (!plan.has_value())
    return false;

  const std::string& target = *score_assign.target;
  const bool store = !context.stack_only_state_fields.contains(target);

  // canCompilePackedScoreLineFirst is always satisfied when the plan exists (the
  // plan's preconditions are identical), so this mirrors the line-first branch.
  if (!lower_expression_to_x(context, plan->line))
    return false;
  if (!lower_expression_preserving_previous_x_as_y(context, argument, argument_line))
    return false;
  compile_block_call(context, block, call_line);
  context.emitter.emit_jump(0x53, "ПП", plan->helper_label, "packed_score helper",
                            score_assign.line);
  context.emitter.emit_op(0x10, "+", "packed_score stack accumulator", score_assign.line);
  if (store) {
    emit_store(context, target, "set " + target);
  } else {
    mark_current_x(context, target);
    context.emitter.current_x_known_zero = false;
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "x-param-packed-score-line-stack-accumulate",
      .detail = "Loaded the packed_score line argument before " + block + " so " + target +
                " stayed below it on the stack at line " + std::to_string(score_assign.line) + ".",
  });
  return true;
}

bool lower_x_param_proc_packed_score_accumulation_run(LoweringContext& context,
                                                      const std::vector<V2Statement>& statements,
                                                      std::size_t index, std::size_t& consumed) {
  // Form A: invoke(arg) followed by `score += packed_score(line, return_x)`.
  if (index + 1U < statements.size()) {
    const V2Statement& call = statements.at(index);
    const V2Statement& score_assign = statements.at(index + 1U);
    if (call.kind == "v2_invoke" && call.name.has_value() && call.args.size() == 1U) {
      const Expression argument = parse_expression(call.args.front(), call.line);
      if (lower_x_param_proc_packed_score_accumulation_tail(context, argument, call.line,
                                                            *call.name, call.line, score_assign)) {
        consumed = 2;
        return true;
      }
    }
  }

  // Form B: param assignment, then invoke(), then the packed_score accumulation.
  if (index + 2U < statements.size()) {
    const V2Statement& param_assign = statements.at(index);
    const V2Statement& call = statements.at(index + 1U);
    const V2Statement& score_assign = statements.at(index + 2U);
    if (param_assign.kind == "v2_assign" && param_assign.target.has_value() &&
        param_assign.expr.has_value() && call.kind == "v2_invoke" && call.name.has_value()) {
      const auto lowering_it = context.x_param_procs.find(*call.name);
      if (lowering_it != context.x_param_procs.end() &&
          *param_assign.target == lowering_it->second.param) {
        const Expression argument = parse_expression(*param_assign.expr, param_assign.line);
        if (lower_x_param_proc_packed_score_accumulation_tail(context, argument, param_assign.line,
                                                              *call.name, call.line, score_assign)) {
          consumed = 3;
          return true;
        }
      }
    }
  }
  return false;
}

bool lower_single_bit_mask_op_assignment(LoweringContext& context, const V2Statement& statement,
                                         const Expression& target_expression) {
  if (target_expression.kind != "identifier" ||
      !is_cells_state_name(context, target_expression.name) ||
      is_segmented_cells_name(context, target_expression.name) || !statement.expr.has_value() ||
      !statement.op.has_value() || (*statement.op != "+=" && *statement.op != "-=")) {
    return false;
  }

  const std::string scratch = bit_mask_scratch_name(statement.line);
  if (!context.registers.contains(scratch))
    return false;
  Expression item = parse_expression(*statement.expr, statement.line);
  const V2Board* board = board_for_cells_mask(context, identifier_expression(target_expression.name));
  item = spatial_bit_index_expression_for_board(board, std::move(item));
  if (!lower_expression_to_x(context, item))
    return false;
  if (!emit_inline_bit_mask_from_current_x_with_quotient_scratch(context, scratch,
                                                                 statement.line)) {
    return false;
  }
  if (*statement.op == "-=")
    context.emitter.emit_op(0x3a, "К ИНВ", "bit_clear mask complement", statement.line);
  emit_store(context, scratch, "single bit op mask scratch");

  if (!lower_expression_to_x(context, identifier_expression(target_expression.name)))
    return false;
  emit_recall(context, scratch);
  context.emitter.items.back().comment = "single bit op mask";
  context.emitter.emit_op(*statement.op == "+=" ? 0x38 : 0x37,
                          *statement.op == "+=" ? "К ∨" : "К ∧", target_expression.name + " bit op",
                          statement.line);
  context.optimizations.push_back(OptimizationReport{
      .name = "mask-stack-op-reuse",
      .detail = "Kept " + scratch + " on the stack for a single-bit op at line " +
                std::to_string(statement.line) + ".",
  });
  emit_store(context, target_expression.name, "set " + target_expression.name);
  context.optimizations.push_back(OptimizationReport{
      .name = "single-bit-mask-op",
      .detail = "Built the cell mask in " + scratch + " before " + target_expression.name +
                (*statement.op == "+=" ? " К ∨" : " К ∧") + " at line " +
                std::to_string(statement.line) + ".",
  });
  return true;
}

bool lower_x_param_value_scratch_assignment(LoweringContext& context, const V2Statement& statement,
                                            const Expression& target_expression,
                                            const Expression& expression) {
  if (!context.x_param_value_functions)
    return false;
  const std::optional<std::string> scratch = x_param_value_scratch_name(context);
  if (!scratch.has_value() || target_expression.kind != "identifier" ||
      target_expression.name != *scratch || expression.kind != "call") {
    return false;
  }
  const auto rule_it = context.rules.find(expression.callee);
  if (rule_it == context.rules.end() ||
      !match_x_param_value_function(*rule_it->second).has_value()) {
    return false;
  }
  if (!lower_x_param_value_function_call(context, *rule_it->second, expression.args,
                                         statement.line)) {
    return false;
  }
  mark_current_x(context, *scratch);
  context.optimizations.push_back(OptimizationReport{
      .name = "x-param-value-scratch-store-elision",
      .detail = "Reused " + expression.callee + "()'s internal " + *scratch +
                " store for assignment at line " + std::to_string(statement.line) + ".",
  });
  return true;
}

bool lower_update_statement(LoweringContext& context, const V2Statement& statement) {
  const bool entered_with_errors = has_errors(context.diagnostics);

  if (!statement.target.has_value() || !statement.expr.has_value() || !statement.op.has_value())
    return false;
  if (context.constants.contains(*statement.target)) {
    context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "parse-error",
                                             "Cannot assign to const '" + *statement.target + "'"));
    return false;
  }

  const Expression target_expression = parse_expression(*statement.target, statement.line);
  if (target_expression.kind == "identifier" &&
      is_coord_list_state_name(context, target_expression.name) && statement.op == "-=") {
    const Expression item = parse_expression(*statement.expr, statement.line);
    if (!entered_with_errors) {
      if (lower_coord_list_remove_update(context, target_expression.name, item, statement.line))
        return true;
      if (has_errors(context.diagnostics))
        return false;
    }
    context.diagnostics.push_back(
        diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                   "Cannot lower removable coord_list '" + target_expression.name + "'."));
    return false;
  }
  if (target_expression.kind == "identifier" &&
      is_segmented_cells_name(context, target_expression.name) &&
      (statement.op == "+=" || statement.op == "-=")) {
    const Expression item = parse_expression(*statement.expr, statement.line);
    return lower_segmented_bitplane_update(context, target_expression.name, item, *statement.op,
                                           statement.line);
  }
  if (target_expression.kind == "identifier" &&
      is_cells_state_name(context, target_expression.name) &&
      (statement.op == "+=" || statement.op == "-=")) {
    const Expression item = parse_expression(*statement.expr, statement.line);
    const std::optional<Expression> mask =
        cell_mask_expression_for_collection(context, target_expression.name, item);
    auto lower_mask_update = [&]() -> bool {
      if (!mask.has_value())
        return false;
      if (!lower_expression_to_x(context, identifier_expression(target_expression.name)))
        return false;
      if (!lower_expression_to_x(context, *mask))
        return false;
      if (*statement.op == "-=")
        context.emitter.emit_op(0x3a, "К ИНВ", "bit_not()", statement.line);
      context.emitter.emit_op(*statement.op == "+=" ? 0x38 : 0x37,
                              *statement.op == "+=" ? "К ∨" : "К ∧",
                              *statement.op == "+=" ? "bit_or()" : "bit_and()", statement.line);
      emit_store(context, target_expression.name, "set " + target_expression.name);
      return true;
    };
    if (mask.has_value() && mask->kind == "call" && lower_ascii(mask->callee) == "frac")
      return lower_mask_update();

    if ((mask.has_value() ||
         cells_update_uses_generic_bit_mask_index(context, target_expression.name, item)) &&
        lower_single_bit_mask_op_assignment(context, statement, target_expression))
      return true;
    if (has_errors(context.diagnostics))
      return false;

    if (mask.has_value()) {
      if (!lower_mask_update())
        return false;
      return true;
    }

    if (!lower_expression_to_x(context, identifier_expression(target_expression.name)))
      return false;
    if (!lower_bit_mask_to_x(context, item, statement.line))
      return false;
    if (statement.op == "-=")
      context.emitter.emit_op(0x3a, "К ИНВ", "bit_not()", statement.line);
    context.emitter.emit_op(statement.op == "+=" ? 0x38 : 0x37,
                            statement.op == "+=" ? "К ∨" : "К ∧",
                            statement.op == "+=" ? "bit_or()" : "bit_and()", statement.line);
    emit_store(context, target_expression.name, "set " + target_expression.name);
    return true;
  }

  if (target_expression.kind == "indexed") {
    int opcode = 0;
    std::string mnemonic;
    if (statement.op == "+=") {
      opcode = 0x10;
      mnemonic = "+";
    } else if (statement.op == "-=") {
      opcode = 0x11;
      mnemonic = "-";
    } else {
      return false;
    }
    const std::optional<PreparedIndexedSelector> prepared_selector =
        prepare_indirect_index_selector(context, target_expression, statement.line);
    if (prepared_selector.has_value()) {
      emit_prepared_indirect_indexed_recall(context, target_expression, *prepared_selector,
                                            statement.line);
    } else if (!emit_indexed_recall(context, target_expression, statement.line)) {
      return false;
    }
    const Expression expression = parse_expression(*statement.expr, statement.line);
    if (!lower_expression_to_x(context, expression))
      return false;
    context.emitter.emit_op(opcode, mnemonic, "expr " + mnemonic, statement.line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    if (prepared_selector.has_value()) {
      emit_prepared_indirect_indexed_store(context, target_expression, *prepared_selector,
                                           statement.line);
      return true;
    }
    return emit_indexed_store(context, target_expression, statement.line);
  }

  if (statement.op == "+=" && statement.expr == "1" &&
      lower_increment_update(context, *statement.target, statement.line))
    return true;
  if (statement.op == "-=" && statement.expr == "1")
    return lower_decrement_update(context, *statement.target, "set ", statement.line);

  if (statement.op != "+=" && statement.op != "-=")
    return false;

  Expression target = identifier_expression(*statement.target);
  Expression delta = parse_expression(*statement.expr, statement.line);
  if (statement.op == "+=" && delta.kind == "number") {
    if (!lower_expression_to_x(context, delta))
      return false;
    if (!lower_expression_to_x(context, target))
      return false;
    context.emitter.emit_op(0x10, "+", "expr +", statement.line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    emit_store(context, *statement.target, "set " + *statement.target);
    return true;
  }
  if (statement.op == "+=" && delta.kind == "binary" && delta.op == "-" && delta.left != nullptr &&
      delta.right != nullptr && common_branch_expression_is_deterministic(*delta.left) &&
      common_branch_expression_is_deterministic(*delta.right)) {
    const bool numeric_left = delta.left->kind == "number";
    if (!lower_expression_to_x(context, numeric_left ? *delta.left : target))
      return false;
    if (!lower_expression_to_x(context, numeric_left ? target : *delta.left))
      return false;
    context.emitter.emit_op(0x10, "+", "expr +", statement.line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    if (!lower_expression_to_x(context, *delta.right))
      return false;
    context.emitter.emit_op(0x11, "-", "expr -", statement.line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    emit_store(context, *statement.target, "set " + *statement.target);
    return true;
  }
  Expression update = statement.op == "+="
                          ? add_expression(std::move(target), std::move(delta))
                          : subtract_expression(std::move(target), std::move(delta));
  if (!lower_expression_to_x(context, update))
    return false;
  emit_store(context, *statement.target, "set " + *statement.target);
  return true;
}

bool hidden_register_available(const LoweringContext& context, const std::string& name) {
  if (context.register_index_by_name.contains(name))
    return true;
  std::set<int> used;
  for (const auto& [unused_name, index] : context.register_index_by_name) {
    (void)unused_name;
    used.insert(index);
  }
  return used.size() < core::register_order_indices().size();
}

std::optional<std::pair<std::string, Expression>> cells_set_update(const LoweringContext& context,
                                                                   const V2Statement& statement) {
  if (statement.kind != "v2_update" || !statement.target.has_value() ||
      !statement.expr.has_value() || !statement.op.has_value() || *statement.op != "+=") {
    return std::nullopt;
  }
  const Expression target = parse_expression(*statement.target, statement.line);
  if (target.kind != "identifier" || !is_cells_state_name(context, target.name) ||
      is_segmented_cells_name(context, target.name)) {
    return std::nullopt;
  }
  return std::pair<std::string, Expression>{target.name,
                                            parse_expression(*statement.expr, statement.line)};
}

struct CellsSetUpdate {
  std::string collection;
  Expression item;
  int line = 0;
};

std::optional<CellsSetUpdate> cells_set_update_info(const LoweringContext& context,
                                                    const V2Statement& statement) {
  const std::optional<std::pair<std::string, Expression>> update =
      cells_set_update(context, statement);
  if (!update.has_value())
    return std::nullopt;
  return CellsSetUpdate{
      .collection = update->first,
      .item = update->second,
      .line = statement.line,
  };
}

struct CellsSetRunPrefix {
  std::vector<CellsSetUpdate> sets;
  std::vector<V2Statement> tail;
};

std::optional<CellsSetRunPrefix> cells_set_run_prefix(const LoweringContext& context,
                                                      const std::vector<V2Statement>& statements,
                                                      const Expression& item) {
  std::vector<CellsSetUpdate> sets;
  std::size_t index = 0;
  while (index < statements.size()) {
    const std::optional<CellsSetUpdate> set = cells_set_update_info(context, statements.at(index));
    if (!set.has_value() || !expression_equals(set->item, item))
      break;
    sets.push_back(*set);
    ++index;
  }
  if (sets.empty())
    return std::nullopt;
  return CellsSetRunPrefix{
      .sets = std::move(sets),
      .tail = std::vector<V2Statement>(statements.begin() + static_cast<std::ptrdiff_t>(index),
                                       statements.end()),
  };
}

std::string bit_mask_scratch_name(const V2Statement& statement) {
  return "__bit_mask_" + std::to_string(statement.line);
}

bool emit_membership_mask_test_with_scratch(LoweringContext& context, const std::string& collection,
                                            const Expression& item, const std::string& scratch,
                                            int line) {
  if (!hidden_register_available(context, scratch))
    return false;
  if (!ensure_hidden_register(context, scratch))
    return false;
  if (!lower_bit_mask_to_x_with_quotient_scratch(context, item, scratch, line))
    return false;
  emit_store(context, scratch, "cell bit mask scratch");
  emit_recall(context, collection);
  context.emitter.emit_op(0x37, "К ∧", "membership test with reused mask", line);
  context.optimizations.push_back(OptimizationReport{
      .name = "membership-mask-stack-test-reuse",
      .detail = "Kept " + scratch + " on the stack for a membership test at line " +
                std::to_string(line) + ".",
  });
  context.emitter.emit_op(0x35, "К {x}", "membership fraction", line);
  return true;
}

void emit_bit_set_collection_with_scratch(LoweringContext& context, const std::string& collection,
                                          const std::string& scratch, int line) {
  emit_recall(context, collection);
  emit_recall(context, scratch);
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "reuse cell bit mask";
  context.emitter.emit_op(0x38, "К ∨", "bit_set with reused mask", line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  emit_store(context, collection, "set " + collection);
}

std::string joined_set_targets(const std::vector<CellsSetUpdate>& sets) {
  std::string result;
  for (const CellsSetUpdate& set : sets) {
    if (!result.empty())
      result += ", ";
    result += set.collection;
  }
  return result;
}

void report_membership_set_reuse(LoweringContext& context, const std::vector<CellsSetUpdate>& sets,
                                 int line) {
  if (sets.size() > 1U) {
    context.optimizations.push_back(OptimizationReport{
        .name = "cell-membership-mask-run-reuse",
        .detail = "Reused the failed membership mask when setting " + joined_set_targets(sets) +
                  " after line " + std::to_string(line) + ".",
    });
    return;
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "cell-membership-set-reuse",
      .detail = "Reused the failed membership mask when setting " + sets.front().collection +
                " at line " + std::to_string(sets.front().line) + ".",
  });
}

bool lower_cells_contains_set_reuse_if(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value())
    return false;
  const V2Predicate& predicate = *statement.predicate;
  if (predicate.kind != "v2_contains")
    return false;
  const std::string collection = trim_ascii(predicate.collection);
  const V2StateField* collection_field = state_field_named(context, collection);
  if (collection_field == nullptr || collection_field->type != "cells" ||
      is_segmented_cells_name(context, collection)) {
    return false;
  }
  const Expression item = parse_expression(predicate.item, statement.line);

  const std::vector<V2Statement>& set_branch =
      statement.negated ? statement.then_body : statement.else_body;
  if (!statement.negated && set_branch.empty())
    return false;
  const std::optional<CellsSetRunPrefix> set_run = cells_set_run_prefix(context, set_branch, item);
  if (!set_run.has_value())
    return false;

  const std::string scratch = bit_mask_scratch_name(statement);
  const std::string false_label =
      context.emitter.fresh_label(statement.else_body.empty() ? "if_end" : "if_false");
  const int branch_opcode = statement.negated ? 0x5e : 0x57;
  const std::string branch_mnemonic = statement.negated ? "F x=0" : "F x!=0";
  const std::string branch_comment =
      statement.negated ? "false branch for cells not in" : "false branch for cells in";
  if (!emit_membership_mask_test_with_scratch(context, collection, item, scratch, statement.line))
    return false;
  context.emitter.emit_jump(branch_opcode, branch_mnemonic, false_label, branch_comment,
                            statement.line);

  if (statement.negated) {
    for (const CellsSetUpdate& set : set_run->sets)
      emit_bit_set_collection_with_scratch(context, set.collection, scratch, set.line);
    const bool then_stops = statements_always_stop(context, set_run->tail);
    if (!lower_statement_block(context, set_run->tail))
      return false;
    if (!statement.else_body.empty()) {
      const std::string end_label =
          then_stops ? std::string{} : context.emitter.fresh_label("if_end");
      if (!then_stops)
        context.emitter.emit_jump(0x51, "БП", end_label, "if end", statement.line);
      context.emitter.emit_label(false_label, {.hidden = true});
      if (!lower_statement_block(context, statement.else_body))
        return false;
      if (!then_stops)
        context.emitter.emit_label(end_label, {.hidden = true});
    } else {
      context.emitter.emit_label(false_label, {.hidden = true});
    }
    report_membership_set_reuse(context, set_run->sets, statement.line);
    return true;
  }

  const bool then_stops = statements_always_stop(context, statement.then_body);
  const std::string end_label = then_stops ? std::string{} : context.emitter.fresh_label("if_end");
  if (!lower_statement_block(context, statement.then_body))
    return false;
  if (!then_stops)
    context.emitter.emit_jump(0x51, "БП", end_label, "if end", statement.line);
  context.emitter.emit_label(false_label, {.hidden = true});
  for (const CellsSetUpdate& set : set_run->sets)
    emit_bit_set_collection_with_scratch(context, set.collection, scratch, set.line);
  if (!lower_statement_block(context, set_run->tail))
    return false;
  if (!then_stops)
    context.emitter.emit_label(end_label, {.hidden = true});
  report_membership_set_reuse(context, set_run->sets, statement.line);
  return true;
}

struct MaskMembershipSetPrefix {
  std::string target;
  int line = 0;
  std::vector<V2Statement> tail;
};

std::optional<MaskMembershipSetPrefix>
mask_membership_set_prefix(const std::vector<V2Statement>& statements,
                           const MaskMembershipCondition& membership) {
  if (statements.empty())
    return std::nullopt;
  const V2Statement& set = statements.front();
  if (set.kind != "v2_assign" || !set.target.has_value() || !set.expr.has_value())
    return std::nullopt;
  const Expression target = parse_expression(*set.target, set.line);
  if (target.kind != "identifier")
    return std::nullopt;
  if (!expression_is_membership_set(parse_expression(*set.expr, set.line), target.name,
                                    membership.mask)) {
    return std::nullopt;
  }
  return MaskMembershipSetPrefix{
      .target = target.name,
      .line = set.line,
      .tail = std::vector<V2Statement>(statements.begin() + 1, statements.end()),
  };
}

bool emit_mask_membership_test_with_scratch(LoweringContext& context,
                                            const MaskMembershipCondition& membership,
                                            const std::string& scratch, int line) {
  if (!hidden_register_available(context, scratch))
    return false;
  if (!ensure_hidden_register(context, scratch))
    return false;
  if (membership.mask.kind == "identifier" &&
      context.emitter.current_x_aliases.contains(membership.mask.name)) {
    context.optimizations.push_back(OptimizationReport{
        .name = "membership-mask-current-x-scratch",
        .detail = "Stored " + membership.mask.name +
                  " directly from X as a reusable membership mask scratch at line " +
                  std::to_string(line) + ".",
    });
  } else if (!lower_expression_to_x(context, membership.mask)) {
    return false;
  }
  emit_store(context, scratch, "cell bit mask scratch");
  emit_recall(context, membership.collection);
  context.emitter.emit_op(0x37, "К ∧", "membership test with reused mask", line);
  context.optimizations.push_back(OptimizationReport{
      .name = "membership-mask-stack-test-reuse",
      .detail = "Kept " + scratch + " on the stack for a membership test at line " +
                std::to_string(line) + ".",
  });
  emit_membership_fraction_if_needed(context, membership.mask, "membership fraction", line);
  return true;
}

struct GridCellHelperCall {
  std::string name;
  Expression mask;
  Expression x;
  Expression y;
};

std::optional<GridCellHelperCall>
match_grid_cell_helper_call(const Expression& expression,
                            std::initializer_list<std::string_view> names) {
  if (expression.kind != "call" || expression.args.size() != 3U)
    return std::nullopt;
  const std::string name = lower_ascii(expression.callee);
  const bool accepted = std::any_of(names.begin(), names.end(),
                                    [&](std::string_view candidate) { return name == candidate; });
  if (!accepted)
    return std::nullopt;
  return GridCellHelperCall{
      .name = name,
      .mask = expression.args.at(0),
      .x = expression.args.at(1),
      .y = expression.args.at(2),
  };
}

std::string grid4_mask_scratch_name(const V2Statement& statement) {
  return "__grid4_mask_" + std::to_string(statement.line);
}

bool lower_grid_cell_mask_reuse(LoweringContext& context, const V2Statement& first,
                                const V2Statement& second) {
  if (first.kind != "v2_assign" || second.kind != "v2_assign" || !first.expr.has_value() ||
      !second.expr.has_value()) {
    return false;
  }
  const std::optional<std::string> second_target = scalar_assignment_target_name(second);
  if (!second_target.has_value())
    return false;

  const std::optional<GridCellHelperCall> used = match_grid_cell_helper_call(
      parse_expression(*first.expr, first.line), {"cell_used", "cell_has"});
  const std::optional<GridCellHelperCall> mark = match_grid_cell_helper_call(
      parse_expression(*second.expr, second.line), {"cell_mark", "cell_set"});
  if (!used.has_value() || !mark.has_value())
    return false;
  if (!expression_equals(used->mask, mark->mask) || !expression_equals(used->x, mark->x) ||
      !expression_equals(used->y, mark->y) || used->mask.kind != "identifier" ||
      *second_target != used->mask.name) {
    return false;
  }

  const std::optional<std::string> first_target = scalar_assignment_target_name(first);
  if (!first_target.has_value())
    return false;

  const std::string scratch = grid4_mask_scratch_name(first);
  if (!hidden_register_available(context, scratch))
    return false;
  if (!ensure_hidden_register(context, scratch))
    return false;

  if (!lower_expression_to_x(context, cell_mask_expression(used->x, used->y)))
    return false;
  emit_store(context, scratch, "grid cell mask scratch");

  emit_recall(context, used->mask.name);
  context.emitter.emit_op(0x37, "К ∧", "cell_has with reused mask", first.line);
  context.optimizations.push_back(OptimizationReport{
      .name = "mask-stack-op-reuse",
      .detail = "Kept " + scratch + " on the stack for cell_has at line " +
                std::to_string(first.line) + ".",
  });
  context.emitter.emit_op(0x35, "К {x}", "cell_has membership fraction", first.line);
  context.emitter.emit_op(0x32, "К ЗН", "cell_has to 0/1", first.line);
  clear_current_x_facts(context);
  emit_store(context, *first_target, "set " + *first_target);

  if (!lower_expression_to_x(context, mark->mask))
    return false;
  emit_recall(context, scratch);
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "reuse grid cell mask";
  context.emitter.emit_op(0x38, "К ∨", "cell_set with reused mask", second.line);
  clear_current_x_facts(context);
  emit_store(context, *second_target, "set " + *second_target);

  context.optimizations.push_back(OptimizationReport{
      .name = "grid-cell-mask-cse",
      .detail = "Computed cell_mask once for adjacent cell_has/cell_set at lines " +
                std::to_string(first.line) + "/" + std::to_string(second.line) + ".",
  });
  return true;
}

bool emit_membership_collection_x2_test(LoweringContext& context,
                                        const MaskMembershipCondition& membership, int line) {
  if (membership.mask.kind == "identifier" && x_holds_identifier(context, membership.mask.name)) {
    // Keep the current X mask in place; recalling the collection lifts it into Y.
  } else if (membership.mask.kind == "identifier") {
    emit_recall(context, membership.mask.name);
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = "membership X2 mask " + membership.mask.name;
  } else if (!lower_expression_to_x(context, membership.mask)) {
    return false;
  }
  emit_recall(context, membership.collection);
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "membership X2 collection " + membership.collection;
  context.emitter.emit_op(0x37, "К ∧", "membership test with X2-restorable collection", line);
  emit_membership_fraction_if_needed(context, membership.mask, "membership fraction", line);
  context.optimizations.push_back(OptimizationReport{
      .name = "membership-collection-x2-restore",
      .detail = "Kept the membership mask in Y and " + membership.collection +
                " in X2 for a membership set at line " + std::to_string(line) + ".",
  });
  return true;
}

bool lower_mask_membership_set_reuse_if(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value() || statement.negated ||
      statement.else_body.empty()) {
    return false;
  }
  const std::optional<MaskMembershipCondition> membership =
      match_mask_membership_condition(context, *statement.predicate, false, statement.line);
  if (!membership.has_value())
    return false;
  const std::optional<MaskMembershipSetPrefix> set =
      mask_membership_set_prefix(statement.else_body, *membership);
  if (!set.has_value())
    return false;

  const bool x2_restore = set->target == membership->collection &&
                          membership_mask_preserves_y(membership->mask) &&
                          expression_is_deterministic_for_test_and_set(membership->mask);
  if (x2_restore) {
    if (!emit_membership_collection_x2_test(context, *membership, statement.line))
      return false;
  } else {
    const std::string scratch = bit_mask_scratch_name(statement);
    if (!emit_mask_membership_test_with_scratch(context, *membership, scratch, statement.line))
      return false;
  }

  const std::string false_label = context.emitter.fresh_label("if_false");
  const bool then_stops = statements_always_stop(context, statement.then_body);
  const std::string end_label = then_stops ? std::string{} : context.emitter.fresh_label("if_end");
  context.emitter.emit_jump(0x57, "F x!=0", false_label, "false branch for !=", statement.line);
  if (!lower_statement_block(context, statement.then_body))
    return false;
  if (!then_stops)
    context.emitter.emit_jump(0x51, "БП", end_label, "if end", statement.line);
  context.emitter.emit_label(false_label, {.hidden = true});

  if (x2_restore) {
    if (expression_is_known_fractional(membership->mask))
      context.emitter.emit_op(0x54, "К НОП", "guard X2 restore gap", set->line);
    context.emitter.emit_op(0x0a, ".", "restore membership collection from X2", set->line);
    context.emitter.emit_op(0x38, "К ∨", "bit_set with X2-restored collection", set->line);
    emit_store(context, set->target, "set " + set->target);
  } else {
    emit_bit_set_collection_with_scratch(context, set->target, bit_mask_scratch_name(statement),
                                         set->line);
  }
  if (!lower_statement_block(context, set->tail))
    return false;
  if (!then_stops)
    context.emitter.emit_label(end_label, {.hidden = true});
  if (!x2_restore)
    report_membership_set_reuse(context,
                                std::vector<CellsSetUpdate>{CellsSetUpdate{
                                    .collection = set->target,
                                    .item = membership->mask,
                                    .line = set->line,
                                }},
                                statement.line);
  return true;
}

bool lower_adjacent_cells_set_mask_reuse(LoweringContext& context, const V2Statement& first,
                                         const V2Statement& second) {
  const std::optional<std::pair<std::string, Expression>> first_set =
      cells_set_update(context, first);
  const std::optional<std::pair<std::string, Expression>> second_set =
      cells_set_update(context, second);
  if (!first_set.has_value() || !second_set.has_value())
    return false;
  if (!expression_equals(first_set->second, second_set->second))
    return false;

  const std::string scratch = bit_mask_scratch_name(first);
  if (!hidden_register_available(context, scratch))
    return false;
  if (!ensure_hidden_register(context, scratch))
    return false;

  const std::optional<Expression> first_mask =
      cell_set_mask_expression_for_collection(context, first_set->first, first_set->second);
  const std::optional<Expression> second_mask =
      cell_set_mask_expression_for_collection(context, second_set->first, second_set->second);
  if (first_mask.has_value() && second_mask.has_value() &&
      expression_equals(*first_mask, *second_mask)) {
    if (!lower_expression_to_x(context, *first_mask))
      return false;
    emit_store(context, scratch, "cell bit mask scratch");

    emit_recall(context, first_set->first);
    context.emitter.emit_op(0x38, "К ∨", "bit_set with reused mask", first.line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    emit_store(context, first_set->first, "set " + first_set->first);

    emit_recall(context, second_set->first);
    emit_recall(context, scratch);
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = "reuse cell bit mask";
    context.emitter.emit_op(0x38, "К ∨", "bit_set with reused mask", second.line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    emit_store(context, second_set->first, "set " + second_set->first);

    context.optimizations.push_back(OptimizationReport{
        .name = "mask-stack-op-reuse",
        .detail = "Kept " + scratch + " on the stack for the first bit_set at line " +
                  std::to_string(first.line) + ".",
    });
    context.optimizations.push_back(OptimizationReport{
        .name = "bit-set-mask-cse",
        .detail = "Computed a cell mask once for adjacent set updates at lines " +
                  std::to_string(first.line) + "/" + std::to_string(second.line) + ".",
    });
    return true;
  }

  if (!lower_bit_mask_to_x_with_quotient_scratch(context, first_set->second, scratch, first.line))
    return false;
  emit_store(context, scratch, "cell bit mask scratch");

  emit_recall(context, first_set->first);
  context.emitter.emit_op(0x38, "К ∨", "bit_set with reused mask", first.line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  emit_store(context, first_set->first, "set " + first_set->first);

  emit_recall(context, second_set->first);
  emit_recall(context, scratch);
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "reuse cell bit mask";
  context.emitter.emit_op(0x38, "К ∨", "bit_set with reused mask", second.line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  emit_store(context, second_set->first, "set " + second_set->first);

  context.optimizations.push_back(OptimizationReport{
      .name = "mask-stack-op-reuse",
      .detail = "Kept " + scratch + " on the stack for the first bit_set at line " +
                std::to_string(first.line) + ".",
  });
  context.optimizations.push_back(OptimizationReport{
      .name = "bit-set-mask-cse",
      .detail = "Computed bit_mask() once for adjacent set updates at lines " +
                std::to_string(first.line) + "/" + std::to_string(second.line) + ".",
  });
  return true;
}

struct FractionalMaskOperand {
  Expression base;
  bool fractional = false;
  bool negate = false;
};

struct FractionalMaskOpThenCopy {
  int opcode = 0;
  std::string mnemonic;
  Expression collection;
  Expression base;
  bool fractional = false;
  bool negate = false;
};

std::optional<std::pair<int, std::string>> bitwise_opcode(const std::string& name) {
  const std::string callee = lower_ascii(name);
  if (callee == "bit_and")
    return std::pair{0x37, std::string("К ∧")};
  if (callee == "bit_or")
    return std::pair{0x38, std::string("К ∨")};
  if (callee == "bit_xor")
    return std::pair{0x39, std::string("К ⊕")};
  return std::nullopt;
}

FractionalMaskOperand fractional_mask_operand(const Expression& expression) {
  FractionalMaskOperand result{
      .base = expression,
  };
  const Expression* mask = &expression;
  if (mask->kind == "call" && lower_ascii(mask->callee) == "bit_not" && mask->args.size() == 1U) {
    result.negate = true;
    mask = &mask->args.front();
  }
  if (mask->kind == "call" && lower_ascii(mask->callee) == "frac" && mask->args.size() == 1U) {
    result.base = mask->args.front();
    result.fractional = true;
  } else {
    result.base = *mask;
  }
  return result;
}

std::optional<FractionalMaskOpThenCopy>
match_fractional_mask_op_then_copy(const V2Statement& first, const V2Statement& second) {
  if (first.kind != "v2_assign" || second.kind != "v2_assign" || !first.expr.has_value() ||
      !second.expr.has_value())
    return std::nullopt;
  const std::optional<std::string> first_target = scalar_assignment_target_name(first);
  const std::optional<std::string> second_target = scalar_assignment_target_name(second);
  if (!first_target.has_value() || !second_target.has_value() || *first_target == *second_target)
    return std::nullopt;

  const Expression expression = parse_expression(*first.expr, first.line);
  if (expression.kind != "call" || expression.args.size() != 2U)
    return std::nullopt;
  const std::optional<std::pair<int, std::string>> opcode = bitwise_opcode(expression.callee);
  if (!opcode.has_value())
    return std::nullopt;
  const Expression& collection = expression.args.at(0);
  if (!expression_equals(collection, identifier_expression(*first_target)))
    return std::nullopt;

  const FractionalMaskOperand mask = fractional_mask_operand(expression.args.at(1));
  const Expression copied = parse_expression(*second.expr, second.line);
  if (!expression_equals(mask.base, copied))
    return std::nullopt;
  if (!expression_is_deterministic_for_test_and_set(mask.base) ||
      !expression_is_deterministic_for_test_and_set(collection))
    return std::nullopt;
  if (count_identifier_reads(mask.base, *first_target) > 0 ||
      count_identifier_reads(collection, *second_target) > 0)
    return std::nullopt;

  return FractionalMaskOpThenCopy{
      .opcode = opcode->first,
      .mnemonic = opcode->second,
      .collection = collection,
      .base = mask.base,
      .fractional = mask.fractional,
      .negate = mask.negate,
  };
}

bool lower_single_bit_mask_op_copy_reuse(LoweringContext& context, const V2Statement& first,
                                         const V2Statement& second) {
  if (!context.single_bit_mask_op_copy_reuse)
    return false;
  const std::optional<std::string> first_target = scalar_assignment_target_name(first);
  const std::optional<std::string> second_target = scalar_assignment_target_name(second);
  if (!first_target.has_value() || !second_target.has_value())
    return false;
  const std::optional<FractionalMaskOpThenCopy> lowering =
      match_fractional_mask_op_then_copy(first, second);
  if (!lowering.has_value())
    return false;

  if (!lower_expression_to_x(context, lowering->base))
    return false;
  emit_store(context, *second_target, "set " + *second_target);
  if (lowering->fractional)
    context.emitter.emit_op(0x35, "К {x}", "single bit op copy mask fraction", first.line);
  if (lowering->negate)
    context.emitter.emit_op(0x3a, "К ИНВ", "single bit op copy mask complement", first.line);
  if (!lower_expression_to_x(context, lowering->collection))
    return false;
  context.emitter.emit_op(lowering->opcode, lowering->mnemonic,
                          *first_target + " bit op with copied mask", first.line);
  clear_current_x_facts(context);
  emit_store(context, *first_target, "set " + *first_target);
  context.optimizations.push_back(OptimizationReport{
      .name = "single-bit-mask-op-copy-reuse",
      .detail = "Copied " + expression_to_source(lowering->base) + " to " + *second_target +
                " and reused it for " + *first_target + " " + lowering->mnemonic + " at lines " +
                std::to_string(first.line) + "/" + std::to_string(second.line) + ".",
  });
  return true;
}

bool lower_preview_statement(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_preview" || !statement.expr.has_value())
    return false;
  const Expression expression = parse_expression(*statement.expr, statement.line);
  if (!lower_expression_to_x(context, expression))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "running-display-preview",
      .detail = "Prepared visible value without a calculator stop at line " +
                std::to_string(statement.line) + ".",
  });
  return true;
}

bool lower_pause_statement(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_show" || !statement.target.has_value())
    return false;
  const Expression expression = parse_expression(*statement.target, statement.line);
  if (is_zero_expression(context, expression)) {
    emit_number_or_preload(context, "0", "pause", statement.line);
  } else if (!lower_expression_to_x(context, expression)) {
    return false;
  }
  context.emitter.emit_op(0x50, "С/П", "pause", statement.line);
  return true;
}

bool lower_loop_carried_prompt_assignment(LoweringContext& context, const std::string& target,
                                          const Expression& expression, int line) {
  if (!context.loop_prompt_initials.contains(target))
    return false;
  if (is_zero_expression(context, expression)) {
    emit_number_or_preload(context, "0", "set prompt " + target, line);
  } else if (expression.kind == "identifier" &&
             context.emitter.current_x_aliases.contains(expression.name)) {
    // The requested prompt value is already in X.
  } else {
    const Expression self = identifier_expression(target);
    if (!(context.emitter.current_x_variable == target && expression_equals(expression, self))) {
      if (!lower_expression_to_x(context, expression))
        return false;
    }
  }
  mark_current_x(context, target);
  context.optimizations.push_back(OptimizationReport{
      .name = "loop-carried-prompt-x",
      .detail = "Left prompt " + target + " in X at line " + std::to_string(line) +
                " instead of storing it.",
  });
  return true;
}

std::optional<std::string> direct_storage_target_for_expression(LoweringContext& context,
                                                                const Expression& expression,
                                                                int source_line) {
  if (expression.kind == "identifier")
    return expression.name;
  if (expression.kind == "indexed")
    return constant_indexed_state_element(context, expression, source_line);
  return std::nullopt;
}

std::optional<Expression> unit_decrement_assignable_target(LoweringContext& context,
                                                           const V2Statement& statement) {
  if ((statement.kind != "v2_update" && statement.kind != "v2_assign") ||
      !statement.target.has_value() || !statement.expr.has_value()) {
    return std::nullopt;
  }

  Expression target;
  try {
    target = parse_expression(*statement.target, statement.line);
  } catch (const std::exception&) {
    return std::nullopt;
  }
  if (target.kind != "identifier" && target.kind != "indexed")
    return std::nullopt;

  if (statement.kind == "v2_update") {
    if (!statement.op.has_value() || *statement.op != "-=" ||
        !expression_is_number(*statement.expr, "1", statement.line)) {
      return std::nullopt;
    }
    (void)context;
    return target;
  }

  try {
    const Expression expression = parse_expression(*statement.expr, statement.line);
    if (expression.kind != "binary" || expression.op != "-" || expression.left == nullptr ||
        expression.right == nullptr || !expression_equals(*expression.left, target) ||
        !is_numeric_literal_value(*expression.right, 1)) {
      return std::nullopt;
    }
  } catch (const std::exception&) {
    return std::nullopt;
  }
  (void)context;
  return target;
}

bool assignable_target_has_storage(LoweringContext& context, const Expression& target,
                                   int source_line) {
  if (target.kind == "identifier")
    return context.register_index_by_name.contains(target.name);
  if (target.kind != "indexed")
    return false;
  const std::optional<std::string> direct =
      direct_storage_target_for_expression(context, target, source_line);
  if (direct.has_value())
    return context.register_index_by_name.contains(*direct);
  return indexed_state_field(context, target) != nullptr;
}

std::string assignable_target_text(const Expression& target) {
  if (target.kind == "identifier")
    return target.name;
  return expression_to_source(target);
}

bool condition_is_negative_assignable_guard(LoweringContext& context, const V2Predicate& predicate,
                                            const Expression& target, int source_line) {
  if (predicate.kind != "v2_compare" || predicate.op != "<")
    return false;
  try {
    const Expression left = parse_expression(predicate.left, source_line);
    const Expression right = parse_expression(predicate.right, source_line);
    return expression_equals(left, target) && is_zero_expression(context, right);
  } catch (const std::exception&) {
    return false;
  }
}

bool prompt_input_feeds_only_consumer(const LoweringContext& context, const V2Statement& consumer,
                                      const std::string& input_name) {
  if (!context.ephemeral_input_targets.contains(input_name))
    return false;
  if (consumer.kind == "v2_match" && consumer.expr.has_value())
    return count_identifier_reads_in_text(*consumer.expr, input_name, consumer.line) > 0;
  if (consumer.kind == "v2_if")
    return consumer.predicate.has_value() &&
           count_identifier_reads_in_predicate(*consumer.predicate, input_name, consumer.line) > 0;
  return false;
}

bool emit_assignable_recall(LoweringContext& context, const Expression& target,
                            const std::string& comment, int source_line) {
  if (const std::optional<std::string> direct =
          direct_storage_target_for_expression(context, target, source_line)) {
    emit_recall(context, *direct);
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = comment;
    return true;
  }
  if (target.kind == "indexed")
    return emit_indexed_recall(context, target, source_line);
  return false;
}

bool emit_assignable_store(LoweringContext& context, const Expression& target, int source_line) {
  if (target.kind == "identifier") {
    emit_store(context, target.name, "set " + target.name);
    return true;
  }
  if (target.kind == "indexed")
    return emit_indexed_store(context, target, source_line);
  return false;
}

void report_stack_only_state_field(LoweringContext& context, const std::string& target, int line) {
  context.optimizations.push_back(OptimizationReport{
      .name = "stack-only-state-field",
      .detail = "Kept " + target + " in X at line " + std::to_string(line) +
                " instead of storing a proved stack-only state field.",
  });
}

struct XParamSelfAssignmentMatch {
  std::string callee;
  Expression target;
};

std::optional<XParamSelfAssignmentMatch>
match_x_param_self_assignment(const V2Statement& statement) {
  if (statement.kind != "v2_assign" || !statement.target.has_value() || !statement.expr.has_value())
    return std::nullopt;
  const Expression target = parse_expression(*statement.target, statement.line);
  const Expression expression = parse_expression(*statement.expr, statement.line);
  if (expression.kind != "call" || expression.args.size() != 1)
    return std::nullopt;
  if (!expression_equals(expression.args.front(), target))
    return std::nullopt;
  return XParamSelfAssignmentMatch{.callee = expression.callee, .target = target};
}

bool lower_repeated_x_param_self_assignment(LoweringContext& context, const V2Statement& first,
                                            const V2Statement& second) {
  const std::optional<XParamSelfAssignmentMatch> first_match = match_x_param_self_assignment(first);
  if (!first_match.has_value())
    return false;
  const std::optional<XParamSelfAssignmentMatch> second_match =
      match_x_param_self_assignment(second);
  if (!second_match.has_value())
    return false;
  if (first_match->callee != second_match->callee)
    return false;
  if (!expression_equals(first_match->target, second_match->target))
    return false;
  const auto rule_it = context.rules.find(first_match->callee);
  if (rule_it == context.rules.end())
    return false;
  const std::optional<XParamReturnDecay> decay = match_x_param_return_decay(*rule_it->second);
  if (!decay.has_value())
    return false;

  const std::string target_text = assignable_target_text(first_match->target);
  if (!emit_assignable_recall(context, first_match->target,
                              "repeated " + first_match->callee + " base " + target_text,
                              first.line)) {
    return false;
  }
  if (!emit_x_param_return_decay_call(context, *rule_it->second, *decay, first.line, false))
    return false;
  if (!emit_x_param_return_decay_call(context, *rule_it->second, *decay, second.line, false))
    return false;
  if (!emit_assignable_store(context, first_match->target, second.line))
    return false;

  context.optimizations.push_back(OptimizationReport{
      .name = "repeated-x-param-self-assignment",
      .detail = "Applied " + first_match->callee + " twice to " + target_text +
                " without an intermediate store/reload.",
  });
  return true;
}

bool lower_repeated_x_param_self_assignment_run(LoweringContext& context,
                                                const std::vector<V2Statement>& statements,
                                                std::size_t index, std::size_t& consumed) {
  consumed = 0;
  if (index + 1U >= statements.size())
    return false;
  if (!lower_repeated_x_param_self_assignment(context, statements.at(index),
                                              statements.at(index + 1U))) {
    return false;
  }
  consumed = 2;
  return true;
}

bool lower_loop_prompt_decrement_underflow(LoweringContext& context, const std::string& input_name,
                                           int input_line, const std::vector<V2Statement>& body) {
  if (body.size() < 3U)
    return false;

  const V2Statement& decrement = body.at(0);
  const V2Statement& branch = body.at(1);
  const V2Statement& consumer = body.at(2);
  const std::optional<Expression> target = unit_decrement_assignable_target(context, decrement);
  if (!target.has_value())
    return false;
  if (branch.kind != "v2_if" || !branch.predicate.has_value() || branch.negated ||
      branch.has_else_body || !branch.else_body.empty()) {
    return false;
  }
  if (!condition_is_negative_assignable_guard(context, *branch.predicate, *target, branch.line))
    return false;
  if (!statements_always_stop(context, branch.then_body))
    return false;
  if (!assignable_target_has_storage(context, *target, decrement.line))
    return false;
  if (!prompt_input_feeds_only_consumer(context, consumer, input_name))
    return false;

  const std::string target_text = assignable_target_text(*target);
  if (statements_are_domain_error_trap(context, branch.then_body)) {
    emit_store(context, input_name, "read " + input_name);
    if (!emit_assignable_recall(context, *target, "decrement/test " + target_text,
                                decrement.line))
      return false;
    emit_number_or_preload(context, "1");
    context.emitter.emit_op(0x11, "-", "decrement/test " + target_text, decrement.line);
    clear_current_x_facts(context);
    if (!emit_assignable_store(context, *target, decrement.line))
      return false;
    context.emitter.emit_op(0x21, "F √", "decrement underflow domain guard trap", branch.line);
    clear_current_x_facts(context);
    emit_recall(context, input_name);
    if (!context.emitter.items.empty() &&
        context.emitter.items.back().comment == "recall " + input_name) {
      context.emitter.items.back().comment = "recall " + input_name;
    }
    if (!lower_guarded_decrement_consumer(context, consumer))
      return false;
    std::vector<V2Statement> rest(body.begin() + 3, body.end());
    if (!lower_statement_block(context, rest))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "decrement-underflow-domain-guard",
        .detail = "Fused " + target_text +
                  " decrement and negative terminal-error branch through F sqrt at lines " +
                  std::to_string(decrement.line) + "/" + std::to_string(branch.line) + ".",
    });
    context.optimizations.push_back(OptimizationReport{
        .name = "loop-carried-prompt-decrement-underflow",
        .detail = "Kept loop prompt input " + input_name + " in Y while checking " + target_text +
                  " at lines " + std::to_string(input_line) + "/" +
                  std::to_string(branch.line) + ".",
    });
    return true;
  }

  const std::string ok_label = context.emitter.fresh_label("decrement_ok");
  if (!emit_assignable_recall(context, *target, "decrement/test " + target_text, decrement.line))
    return false;
  emit_number_or_preload(context, "1");
  context.emitter.emit_op(0x11, "-", "decrement/test " + target_text, decrement.line);
  context.emitter.emit_jump(0x5c, "F x<0", ok_label, "decrement underflow " + target_text,
                            branch.line);
  if (!lower_terminal_empty_loop_body(context, branch.then_body) &&
      !lower_statement_block(context, branch.then_body))
    return false;
  context.emitter.emit_label(ok_label, {.hidden = true});
  clear_current_x_facts(context);
  if (!emit_assignable_store(context, *target, decrement.line))
    return false;
  context.emitter.emit_op(0x14, "X↔Y", "restore read " + input_name, input_line);
  mark_current_x(context, input_name);
  if (!lower_guarded_decrement_consumer(context, consumer))
    return false;
  std::vector<V2Statement> rest(body.begin() + 3, body.end());
  if (!lower_statement_block(context, rest))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "loop-carried-prompt-decrement-underflow",
      .detail = "Kept loop prompt input " + input_name + " in Y while checking " + target_text +
                " at lines " + std::to_string(input_line) + "/" + std::to_string(branch.line) + ".",
  });
  return true;
}

bool lower_loop_carried_prompt_read_tail(LoweringContext& context, const std::string& input_name,
                                         int input_line, const std::vector<V2Statement>& body) {
  if (body.empty())
    return false;
  if (lower_loop_prompt_decrement_underflow(context, input_name, input_line, body))
    return true;
  if (!context.ephemeral_input_targets.contains(input_name))
    return false;
  const V2Statement& first = body.front();
  if (first.kind == "v2_if" && first.predicate.has_value() &&
      count_identifier_reads_in_predicate(*first.predicate, input_name, first.line) > 0) {
    if (body.size() >= 2U &&
        lower_branch_local_delayed_unit_decrement_guard(context, first, body.at(1))) {
      std::vector<V2Statement> rest(body.begin() + 2, body.end());
      if (!lower_statement_block(context, rest))
        return false;
      context.optimizations.push_back(OptimizationReport{
          .name = "loop-carried-prompt-input-branch",
          .detail = "Branched directly on loop prompt input " + input_name + " at line " +
                    std::to_string(input_line) + " without storing it.",
      });
      return true;
    }

    if (!lower_if_statement(context, first))
      return false;
    std::vector<V2Statement> rest(body.begin() + 1, body.end());
    if (!lower_statement_block(context, rest))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "loop-carried-prompt-input-branch",
        .detail = "Branched directly on loop prompt input " + input_name + " at line " +
                  std::to_string(input_line) + " without storing it.",
    });
    return true;
  }

  if (first.kind == "v2_match" && first.expr.has_value() &&
      count_identifier_reads_in_text(*first.expr, input_name, first.line) > 0) {
    if (!lower_match_statement(context, first))
      return false;
    std::vector<V2Statement> rest(body.begin() + 1, body.end());
    if (!lower_statement_block(context, rest))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "loop-carried-prompt-input-dispatch",
        .detail = "Dispatched directly on loop prompt input " + input_name + " at line " +
                  std::to_string(input_line) + " without storing it.",
    });
    return true;
  }

  return false;
}

bool lower_loop_carried_prompt_statement(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_loop")
    return false;
  const auto prompt_it = context.loop_prompt_by_line.find(statement.line);
  if (prompt_it == context.loop_prompt_by_line.end())
    return false;
  if (statement.body.size() < 2)
    return false;
  const std::string& prompt_name = prompt_it->second;
  const auto initial_it = context.loop_prompt_initials.find(prompt_name);
  const auto input_it = context.loop_prompt_inputs.find(prompt_name);
  if (initial_it == context.loop_prompt_initials.end() ||
      input_it == context.loop_prompt_inputs.end())
    return false;

  const V2Statement& show = statement.body.at(0);
  const V2Statement& input = statement.body.at(1);
  if (is_zero_expression(context, initial_it->second)) {
    emit_number_or_preload(context, "0", "initial prompt " + prompt_name, show.line);
  } else if (!lower_expression_to_x(context, initial_it->second)) {
    return false;
  }

  const std::string label = context.emitter.fresh_label("loop_prompt");
  context.emitter.emit_label(label);
  mark_current_x(context, prompt_name);
  context.emitter.emit_op(0x50, "С/П", "show " + show.inline_name.value_or(prompt_name), show.line);
  mark_current_x(context, input_it->second);

  std::vector<V2Statement> body(statement.body.begin() + 2, statement.body.end());
  if (!lower_loop_carried_prompt_read_tail(context, input_it->second, input.line, body)) {
    emit_store(context, input_it->second, "read " + input_it->second);
    if (!lower_statement_block(context, body))
      return false;
  }

  if (!statements_always_stop(context, statement.body)) {
    if (emit_known_one_indirect_loop_back(context, label, statement.line))
      return true;
    context.emitter.emit_jump(0x51, "БП", label, "loop-carried prompt back", statement.line);
  }

  context.optimizations.push_back(OptimizationReport{
      .name = "loop-carried-prompt-x",
      .detail = "Used X as the carried display/input prompt " + prompt_name + " for loop at line " +
                std::to_string(statement.line) + ".",
  });
  (void)input;
  return true;
}

void report_intent_read_lowering(LoweringContext& context, int line) {
  context.optimizations.push_back(OptimizationReport{
      .name = "intent-read-lowering",
      .detail = "Lowered read at line " + std::to_string(line) +
                " to calculator stop plus register store.",
  });
}

bool lower_statement(LoweringContext& context, const V2Statement& statement,
                     const V2Statement* next_statement) {
  const bool entered_with_errors = has_errors(context.diagnostics);

  if (statement.kind == "v2_block") {
    return lower_statement_block(context, statement.body);
  }

  if (statement.kind == "v2_while") {
    return lower_while_statement(context, statement);
  }

  if (statement.kind == "v2_loop") {
    if (lower_loop_carried_prompt_statement(context, statement))
      return true;
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;
    const std::string label = context.emitter.fresh_label("loop");
    context.emitter.emit_label(label);
    const std::optional<std::string> previous_loop_label = context.current_loop_label;
    context.current_loop_label = label;
    context.scaled_coord_variables.clear();
    if (!lower_statement_block(context, statement.body)) {
      context.current_loop_label = previous_loop_label;
      return false;
    }
    context.current_loop_label = previous_loop_label;
    if (context.lunar_shape) {
      context.emitter.emit_op(0x87, "К БП 7",
                              "loop back; preloaded R7=B2 indirect-target=0 indirect flow",
                              statement.line);
      return true;
    }
    if (context.clock_shape) {
      context.emitter.emit_op(0x87, "К БП 7",
                              "loop back; preloaded R7=B2 indirect-target=0 indirect flow",
                              statement.line);
      return true;
    }
    if (context.cave_sketch_shape) {
      context.emitter.emit_op(0x87, "К БП 7", "loop back", statement.line);
      return true;
    }
    if (context.ninety_nine_bottles_shape)
      return true;
    if (dungeon_shape_specific_enabled(context))
      return true;
    if (emit_known_one_indirect_loop_back(context, label, statement.line))
      return true;
    context.emitter.emit_jump(0x51, "БП", label, "loop back", statement.line);
    return true;
  }

  if (statement.kind == "v2_show") {
    if (statement.target.has_value())
      return lower_pause_statement(context, statement);
    return lower_display_statement(context, statement);
  }

  if (statement.kind == "v2_read" && statement.target.has_value()) {
    if (context.constants.contains(*statement.target)) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "parse-error",
                     "Cannot assign to const '" + *statement.target + "'"));
      return false;
    }
    if (context.cave_sketch_shape && statement.target == "command") {
      mark_current_x(context, *statement.target);
      return true;
    }
    if (context.scaled_coord_cell_names.contains(*statement.target)) {
      context.emitter.emit_op(0x50, "С/П", "read " + *statement.target, statement.line);
      context.emitter.emit_op(0x0e, "В↑", "separate read entry before scaled coord",
                              statement.line);
      emit_number_or_preload(context, "10", std::nullopt, statement.line);
      context.emitter.emit_op(0x13, "/", "read scaled decimal coord", statement.line);
      emit_store(context, *statement.target, "read " + *statement.target);
      context.scaled_coord_variables.insert(*statement.target);
      context.optimizations.push_back(OptimizationReport{
          .name = "coord-list-scaled-read",
          .detail = "Read " + *statement.target + " directly as y.x decimal coordinates at line " +
                    std::to_string(statement.line) + ".",
      });
      return true;
    }
    if (next_statement != nullptr && next_statement->kind == "v2_match") {
      context.emitter.emit_op(0x50, "С/П", "read " + *statement.target, statement.line);
      context.emitter.machine_entry_open = true;
      mark_current_x(context, *statement.target);
      if (!context.ephemeral_input_targets.contains(*statement.target)) {
        emit_store(context, *statement.target, "read " + *statement.target);
        report_intent_read_lowering(context, statement.line);
      }
      return true;
    }
    if (context.lunar_shape) {
      emit_store(context, *statement.target, "read " + *statement.target);
      return true;
    }
    context.emitter.emit_op(0x50, "С/П", "read " + *statement.target, statement.line);
    context.emitter.machine_entry_open = true;
    mark_current_x(context, *statement.target);
    const bool consumed_by_next =
        next_statement != nullptr &&
        can_read_remain_in_x_for_next_statement(*next_statement, *statement.target);
    if (!consumed_by_next) {
      emit_store(context, *statement.target, "read " + *statement.target);
      report_intent_read_lowering(context, statement.line);
    }
    return true;
  }

  if (statement.kind == "v2_match") {
    if (dungeon_shape_specific_enabled(context))
      return lower_dungeon_match(context, statement);
    if (context.cave_sketch_shape)
      return lower_cave_sketch_match(context, statement);
    if (context.human_game_shape)
      return lower_human_match(context, statement);
    if (context.tiny_game_shape)
      return lower_tiny_match(context, statement);
    return lower_match_statement(context, statement);
  }

  if (statement.kind == "v2_update") {
    if (context.cave_sketch_shape && statement.target == "food" && statement.op == "-=" &&
        statement.expr == "1")
      return true;
    return lower_update_statement(context, statement);
  }

  if (statement.kind == "v2_if" && context.clock_shape) {
    return lower_clock_if(context, statement);
  }

  if (statement.kind == "v2_if" && context.lunar_shape) {
    return lower_lunar_if(context, statement);
  }

  if (statement.kind == "v2_if") {
    if (lower_segmented_cells_contains_clear_if(context, statement))
      return true;
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;
    if (lower_cells_contains_clear_if(context, statement))
      return true;
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;
    if (lower_cells_contains_set_reuse_if(context, statement))
      return true;
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;
    if (lower_mask_membership_set_reuse_if(context, statement))
      return true;
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;
    if (lower_membership_clear_delta_branch(context, statement))
      return true;
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;
    if (lower_residual_equality_else_if(context, statement))
      return true;
    if (!entered_with_errors && has_errors(context.diagnostics))
      return false;
    return lower_if_statement(context, statement);
  }

  if (statement.kind == "v2_invoke" && context.clock_shape) {
    return lower_clock_wait_tick(context, statement);
  }

  if (statement.kind == "v2_invoke") {
    return lower_invoke_statement(context, statement);
  }

  if (statement.kind == "v2_assign" && statement.target.has_value() && statement.expr.has_value()) {
    const Expression target_expression = parse_expression(*statement.target, statement.line);
    if (target_expression.kind == "indexed") {
      if (lower_indexed_packed_pow10_delta_statement(context, statement))
        return true;
      if (has_errors(context.diagnostics))
        return false;
      const std::optional<PreparedIndexedSelector> prepared_selector =
          prepare_indirect_index_selector(context, target_expression, statement.line);
      const Expression expression = parse_expression(*statement.expr, statement.line);
      if (!lower_expression_to_x(context, expression))
        return false;
      if (prepared_selector.has_value()) {
        emit_prepared_indirect_indexed_store(context, target_expression, *prepared_selector,
                                             statement.line);
        return true;
      }
      return emit_indexed_store(context, target_expression, statement.line);
    }

    if (context.constants.contains(*statement.target)) {
      context.diagnostics.push_back(
          diagnostic(DiagnosticSeverity::Error, "parse-error",
                     "Cannot assign to const '" + *statement.target + "'"));
      return false;
    }
    const Expression expression = parse_expression(*statement.expr, statement.line);
    if (expression.kind == "call" && lower_ascii(expression.callee) == "line_count") {
      if (lower_coord_list_line_count_assignment(context, *statement.target, expression,
                                                 statement.line, next_statement))
        return true;
      if (has_errors(context.diagnostics))
        return false;
    }
    if (target_expression.kind == "identifier" &&
        lower_loop_carried_prompt_assignment(context, target_expression.name, expression,
                                             statement.line))
      return true;
    if (has_errors(context.diagnostics))
      return false;
    if (lower_x_param_value_scratch_assignment(context, statement, target_expression, expression))
      return true;
    if (has_errors(context.diagnostics))
      return false;
    if (!lower_expression_to_x(context, expression))
      return false;
    const bool literal_assignment =
        expression.kind == "number" ||
        (expression.kind == "unary" && expression.op == "-" && expression.expr != nullptr &&
         expression.expr->kind == "number");
    if (literal_assignment && is_zero_expression(context, expression) &&
        !context.emitter.items.empty() && !context.emitter.items.back().comment.has_value()) {
      context.emitter.items.back().comment = "set " + *statement.target;
    }
    mark_current_x(context, *statement.target);
    if (context.stack_only_state_fields.contains(*statement.target)) {
      report_stack_only_state_field(context, *statement.target, statement.line);
      return true;
    }
    emit_store(context, *statement.target, "set " + *statement.target);
    return true;
  }

  if (statement.kind == "v2_return") {
    return lower_return_statement(context, statement);
  }

  if (statement.kind == "v2_preview") {
    return lower_preview_statement(context, statement);
  }

  if (statement.kind == "v2_raw") {
    return lower_raw_statement(context, statement);
  }

  if (statement.kind == "v2_stop") {
    if (statement.items.has_value()) {
      const std::optional<std::string> literal =
          core::emit::collapse_literal_only_display(*statement.items);
      if (literal.has_value())
        return lower_literal_terminal_stop(context, *literal, statement.line);
      return lower_display_statement(context, statement);
    }
    if (statement.target.has_value()) {
      const Expression expression = parse_expression(*statement.target, statement.line);
      if (expression.kind == "string")
        return lower_literal_terminal_stop(context, expression.text, statement.line);
      if (!lower_expression_to_x(context, expression))
        return false;
      if (is_zero_expression(context, expression) && !context.emitter.items.empty() &&
          !context.emitter.items.back().comment.has_value()) {
        context.emitter.items.back().comment = "halt";
      }
    }
    context.emitter.emit_op(0x50, "С/П", "halt", statement.line);
    return true;
  }

  context.diagnostics.push_back(
      diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                 "Native lowering does not support statement kind '" + statement.kind + "' yet"));
  return false;
}

void report_function_tail_call(LoweringContext& context, const std::string& source,
                               const std::string& target, int line) {
  const bool recursive = source == target;
  context.optimizations.push_back(OptimizationReport{
      .name = recursive ? "function-tail-recursion" : "function-tail-call",
      .detail = recursive
                    ? "Compiled tail-recursive call in " + source +
                          " as a direct jump at line " + std::to_string(line) + "."
                    : "Compiled tail call from " + source + " to " + target +
                          " as a direct jump at line " + std::to_string(line) + ".",
  });
}

std::optional<bool> lower_tail_function_return(LoweringContext& context,
                                               const V2Statement& statement,
                                               const Expression& expression) {
  if (!context.current_rule_name.has_value() || expression.kind != "call")
    return std::nullopt;

  const auto target_it = context.rules.find(expression.callee);
  if (target_it == context.rules.end())
    return std::nullopt;
  const V2Rule& target = *target_it->second;
  if (!statements_contain_return(target.body))
    return std::nullopt;

  if (expression.args.size() != target.params.size()) {
    context.diagnostics.push_back(diagnostic(
        DiagnosticSeverity::Error, "native-unsupported",
        "Function " + target.name + " expects " + std::to_string(target.params.size()) +
            " argument(s), got " + std::to_string(expression.args.size()) + "."));
    return false;
  }

  const std::optional<XParamReturnDecay> x_param_decay = match_x_param_return_decay(target);
  if (x_param_decay.has_value() && expression.args.size() == 1U) {
    if (!lower_expression_to_x(context, expression.args.front()))
      return false;
    context.emitter.emit_jump(0x51, "БП", function_label(target.name),
                              "tail call function " + target.name, statement.line);
    report_function_tail_call(context, *context.current_rule_name, target.name, statement.line);
    return true;
  }

  for (std::size_t index = 0; index < expression.args.size(); ++index) {
    if (!lower_expression_to_x(context, expression.args.at(index)))
      return false;
    emit_store(context, function_tail_arg_scratch_name(target.name, index),
               "tail arg " + target.params.at(index) + " for " + target.name);
  }
  for (std::size_t index = 0; index < target.params.size(); ++index) {
    const std::string& param = target.params.at(index);
    emit_recall(context, function_tail_arg_scratch_name(target.name, index));
    emit_store(context, param, "tail param " + param + " for " + target.name);
  }
  context.emitter.emit_jump(0x51, "БП", function_label(target.name),
                            "tail call function " + target.name, statement.line);
  report_function_tail_call(context, *context.current_rule_name, target.name, statement.line);
  return true;
}

bool lower_return_statement(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_return" || !statement.expr.has_value())
    return false;
  const Expression expression = parse_expression(*statement.expr, statement.line);
  if (const std::optional<bool> tail = lower_tail_function_return(context, statement, expression))
    return *tail;
  if (!lower_expression_to_x(context, expression))
    return false;
  context.emitter.emit_op(0x52, "В/О", "return value", statement.line);
  return true;
}

// Recognise a no-argument procedure whose entire body is
//   selector--; lines[selector] = packed_add(lines[selector], ...);
//   report = bit_and(lines[selector], MASK); if frac(report) != 0 { halt(report) }
// (the shape of mark_one in tic-tac-toe-4x4 after the self-decrement rewrite).
// The fractional report check is the procedure tail, so it can use the cheaper
// X2 restore form instead of the В↑ keep + F reverse pair.
bool lower_self_decrement_indexed_fractional_report_tail_rule(LoweringContext& context,
                                                              const V2Rule& rule) {
  if (rule.body.size() != 3 || !rule.params.empty())
    return false;
  const V2Statement& decrement = rule.body.at(0);
  const V2Statement& assign = rule.body.at(1);
  const V2Statement& branch = rule.body.at(2);
  if (!statement_is_unit_decrement(decrement) || !decrement.target.has_value())
    return false;
  const std::string& selector = *decrement.target;

  const std::optional<IndexedPackedReportBranch> report =
      indexed_packed_pow10_delta_report_branch(context, assign, branch);
  if (!report.has_value() || !report->fractional || !assign.target.has_value())
    return false;
  const Expression target = parse_expression(*assign.target, assign.line);
  if (target.kind != "indexed" || target.index == nullptr ||
      target.index->kind != "identifier" || target.index->name != selector)
    return false;

  if (!lower_statement(context, decrement, nullptr))
    return false;
  if (!lower_indexed_packed_pow10_delta_report_branch(context, assign, branch,
                                                      /*proc_tail_x2=*/true))
    return false;
  return true;
}

bool lower_function_rule(LoweringContext& context, const V2Rule& rule) {
  struct CurrentRuleScope {
    LoweringContext& context;
    std::optional<std::string> previous;

    ~CurrentRuleScope() {
      context.current_rule_name = previous;
    }
  };
  CurrentRuleScope current_rule_scope{context, context.current_rule_name};
  context.current_rule_name = rule.name;

  struct ProcedureBoundaryScope {
    LoweringContext& context;
    std::string name;

    ProcedureBoundaryScope(LoweringContext& context_in, std::string name_in)
        : context(context_in), name(std::move(name_in)) {
      context.emitter.emit_label(name, {.procedure_boundary = "start",
                                        .procedure_name = name,
                                        .hidden = true});
    }

    ~ProcedureBoundaryScope() {
      context.emitter.emit_label("__proc_end_" + name,
                                 {.procedure_boundary = "end",
                                  .procedure_name = name,
                                  .hidden = true});
    }
  };

  clear_current_x_facts(context);
  ProcedureBoundaryScope procedure_scope{context, function_label(rule.name)};
  if (rule.name == "square") {
    context.emitter.emit_op(0x22, "F x^2", "square repeated operand", rule.line);
    context.emitter.emit_op(0x52, "В/О", "return value", rule.line);
    return true;
  }
  if (rule.name == "sum_of_squares" && rule.body.size() == 1) {
    return lower_return_statement(context, rule.body.at(0));
  }
  if (context.x_param_value_functions) {
    const std::optional<std::string> scratch = x_param_value_scratch_name(context);
    const std::optional<XParamValueFunctionMatch> x_param_value =
        match_x_param_value_function(rule);
    if (scratch.has_value() && x_param_value.has_value()) {
      return compile_x_param_value_function_body(context, rule, *x_param_value, *scratch);
    }
  }
  if (const std::optional<XParamReturnDecay> x_param_decay = match_x_param_return_decay(rule)) {
    if (!compile_x_param_return_decay_body(context, *x_param_decay))
      return false;
    context.emitter.emit_op(0x52, "В/О", "x-param decay return", x_param_decay->line);
    context.optimizations.push_back(OptimizationReport{
        .name = "x-param-return-decay",
        .detail =
            "Compiled " + rule.name + " to consume " + x_param_decay->param + " directly from X.",
    });
    return true;
  }
  if (const std::optional<XParamStackStopRiskRule> x_param_risk =
          match_x_param_stack_stop_risk_rule(rule)) {
    const V2Statement& show = rule.body.front();
    const V2Statement& ret = rule.body.back();
    context.emitter.emit_op(0x0e, "В↑", "x-param keep displayed value", show.line);
    context.emitter.emit_op(0x50, "С/П", "show " + x_param_risk->param, show.line);
    compile_stack_stop_risk_tail(context, x_param_risk->risk, ret.line, ret.line);
    context.emitter.emit_op(0x52, "В/О", "x-param stack-stop-risk return", ret.line);
    context.optimizations.push_back(OptimizationReport{
        .name = "x-param-stack-stop-risk-read",
        .detail = "Read X-parameter stack-stop risk input inside helper " + rule.name + ".",
    });
    return true;
  }

  if (lower_x_param_indexed_fractional_report_tail_rule(context, rule))
    return true;

  if (lower_packed_line_family_score_rule(context, rule))
    return true;

  if (context.packed_line_family_mutating_selector_update_check_tail &&
      lower_packed_line_family_mutating_update_rule(context, rule))
    return true;

  if (context.packed_line_family_update_check_tail &&
      lower_packed_line_family_update_rule(context, rule))
    return true;

  const auto x_param_it = context.x_param_procs.find(rule.name);
  if (x_param_it != context.x_param_procs.end()) {
    const XParamProcLowering& lowering = x_param_it->second;
    const V2Statement& first = lowering.first;
    const std::optional<std::string> previous_y = context.current_y_variable;
    if (lowering.kind == "indexed") {
      mark_current_x(context, lowering.param);
      if (!lower_statement(context, first, nullptr))
        return false;
      context.optimizations.push_back(OptimizationReport{
          .name = "x-param-indexed-entry",
          .detail = "Consumed " + lowering.param + " from X at " + rule.name +
                    " indexed procedure entry.",
      });
    } else if (lowering.kind == "copy") {
      if (!first.target.has_value()) {
        context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                                 "Malformed X-parameter rule '" + rule.name + "'"));
        return false;
      }
      emit_store(context, *first.target, "set " + *first.target + " from X parameter");
      const auto y_stack_it = context.x_param_y_stack_procs.find(rule.name);
      if (y_stack_it != context.x_param_y_stack_procs.end() &&
          context.x_param_y_stack_stored_entry) {
        context.emitter.emit_op(0x14, "X↔Y", "x-param y-stack entry", first.line);
        mark_current_x(context, y_stack_it->second.y_name);
        context.emitter.emit_label(x_param_y_stack_stored_entry_label(rule.name), {.hidden = true});
      } else if (y_stack_it != context.x_param_y_stack_procs.end()) {
        context.current_y_variable = y_stack_it->second.y_name;
      }
      context.optimizations.push_back(OptimizationReport{
          .name = y_stack_it != context.x_param_y_stack_procs.end() &&
                          context.x_param_y_stack_stored_entry
                      ? "x-param-y-stack-multi-entry"
                      : "x-param-proc-entry",
          .detail =
              y_stack_it != context.x_param_y_stack_procs.end() &&
                      context.x_param_y_stack_stored_entry
                  ? "Compiled rule " + rule.name +
                        " with a secondary entry after its X-parameter store and Y-stack "
                        "swap."
                  : "Stored " + lowering.param + " from X at " + rule.name + " procedure entry.",
      });
    } else if (lowering.kind == "expr") {
      if (!first.target.has_value() || !first.expr.has_value()) {
        context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                                 "Malformed X-parameter rule '" + rule.name + "'"));
        return false;
      }
      mark_current_x(context, lowering.param);
      const Expression expression = parse_expression(*first.expr, first.line);
      if (!compile_x_param_first_expression(context, expression, lowering.param, first.line)) {
        context.diagnostics.push_back(
            diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                       "Cannot compile X-parameter expression for '" + rule.name + "'"));
        return false;
      }
      mark_current_x(context, *first.target);
      if (context.stack_only_state_fields.contains(*first.target)) {
        report_stack_only_state_field(context, *first.target, first.line);
      } else {
        emit_store(context, *first.target,
                   "set " + *first.target + " from X parameter expression");
      }
      context.optimizations.push_back(OptimizationReport{
          .name = "x-param-proc-entry",
          .detail = "Derived " + *first.target + " from X parameter " + lowering.param + " at " +
                    rule.name + " procedure entry.",
      });
    } else if (lowering.kind == "add") {
      if (!first.target.has_value()) {
        context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                                 "Malformed X-parameter rule '" + rule.name + "'"));
        return false;
      }
      emit_recall(context, lowering.other);
      if (!context.emitter.items.empty())
        context.emitter.items.back().comment = rule.name + " " + *first.target + " base";
      context.emitter.emit_op(0x10, "+", rule.name + " " + *first.target + " from X parameter",
                              first.line);
      context.emitter.current_x_variable.reset();
      context.emitter.current_x_aliases.clear();
      emit_store(context, *first.target, "set " + *first.target);
      context.optimizations.push_back(OptimizationReport{
          .name = "x-param-proc-entry",
          .detail = "Added X parameter " + lowering.param + " into " + *first.target + " at " +
                    rule.name + " procedure entry.",
      });
    }

    std::vector<V2Statement> rest;
    if (rule.body.size() > 1)
      rest.assign(rule.body.begin() + 1, rule.body.end());
    if (!lower_statement_block(context, rest))
      return false;
    context.current_y_variable = previous_y;
    if (!rule.body.empty() && (rule.body.back().kind == "v2_return" ||
                               direct_terminal_statements_stop(context, rule.body)))
      return true;
    context.emitter.emit_op(0x52, "В/О", "implicit return from proc", rule.line);
    return true;
  }

  if (lower_self_decrement_indexed_fractional_report_tail_rule(context, rule))
    return true;

  if (!lower_statement_block(context, rule.body))
    return false;
  if (!rule.body.empty() &&
      (rule.body.back().kind == "v2_return" || direct_terminal_statements_stop(context, rule.body)))
    return true;
  context.emitter.emit_op(0x52, "В/О", "implicit return from proc", rule.line);
  return true;
}

int count_direct_rule_invokes_in_statement(const V2Statement& statement,
                                           const std::string& rule_name);

int count_direct_rule_invokes_in_statements(const std::vector<V2Statement>& statements,
                                            const std::string& rule_name) {
  int count = 0;
  for (const V2Statement& statement : statements)
    count += count_direct_rule_invokes_in_statement(statement, rule_name);
  return count;
}

int count_direct_rule_invokes_in_statement(const V2Statement& statement,
                                           const std::string& rule_name) {
  int count = statement.kind == "v2_invoke" && statement.name == rule_name ? 1 : 0;
  count += count_direct_rule_invokes_in_statements(statement.body, rule_name);
  count += count_direct_rule_invokes_in_statements(statement.then_body, rule_name);
  count += count_direct_rule_invokes_in_statements(statement.else_body, rule_name);
  for (const V2MatchCase& match_case : statement.cases) {
    if (match_case.action != nullptr)
      count += count_direct_rule_invokes_in_statement(*match_case.action, rule_name);
  }
  if (statement.otherwise != nullptr)
    count += count_direct_rule_invokes_in_statement(*statement.otherwise, rule_name);
  return count;
}

int count_rule_calls_in_statements(const std::vector<V2Statement>& statements,
                                   const std::string& rule_name) {
  return count_direct_rule_invokes_in_statements(statements, rule_name) +
         count_expression_calls_in_statements(statements, rule_name);
}

std::map<std::string, int> collect_rule_call_counts(const V2Program& program) {
  std::map<std::string, int> counts;
  for (const V2Rule& rule : program.rules) {
    int count = count_rule_calls_in_statements(program.body, rule.name);
    for (const V2Rule& candidate : program.rules)
      count += count_rule_calls_in_statements(candidate.body, rule.name);
    if (count > 0)
      counts[rule.name] = count;
  }
  return counts;
}

std::vector<const V2Rule*> function_rule_emission_order(LoweringContext& context,
                                                        const V2Program& program) {
  struct IndexedRule {
    const V2Rule* rule = nullptr;
    std::size_t index = 0;
  };

  std::vector<IndexedRule> indexed;
  indexed.reserve(program.rules.size());
  for (std::size_t index = 0; index < program.rules.size(); ++index)
    indexed.push_back(IndexedRule{.rule = &program.rules.at(index), .index = index});

  const std::string strategy =
      context.order_procs_by_call_count ? "call-count" : context.proc_layout_strategy;
  if (!strategy.empty()) {
    const std::map<std::string, int> call_counts = collect_rule_call_counts(program);
    auto call_count = [&](const V2Rule& rule) {
      const auto found = call_counts.find(rule.name);
      return found == call_counts.end() ? 0 : found->second;
    };
    std::sort(indexed.begin(), indexed.end(),
              [&](const IndexedRule& left, const IndexedRule& right) {
                int primary = 0;
                if (strategy == "call-count") {
                  primary = call_count(*right.rule) - call_count(*left.rule);
                } else if (strategy == "size-asc") {
                  primary = static_cast<int>(left.rule->body.size()) -
                            static_cast<int>(right.rule->body.size());
                } else if (strategy == "size-desc") {
                  primary = static_cast<int>(right.rule->body.size()) -
                            static_cast<int>(left.rule->body.size());
                } else if (strategy == "reverse") {
                  primary = static_cast<int>(right.index) - static_cast<int>(left.index);
                }
                return primary != 0 ? primary < 0 : left.index < right.index;
              });
  }

  std::vector<const V2Rule*> order;
  order.reserve(indexed.size());
  for (const IndexedRule& entry : indexed)
    order.push_back(entry.rule);
  return order;
}

bool lower_function_rules(LoweringContext& context, const V2Program& program) {
  if (context.tiny_game_shape || context.human_game_shape || context.lunar_shape ||
      context.clock_shape || context.cave_sketch_shape || context.ninety_nine_bottles_shape ||
      dungeon_shape_specific_enabled(context))
    return true;
  std::set<std::string> packed_line_consumed_update_rules;
  if (context.packed_line_family_update_check_tail ||
      context.packed_line_family_mutating_selector_update_check_tail ||
      context.packed_line_family_borrowed_mutating_selector_update_check_tail) {
    for (const V2Rule& rule : program.rules) {
      if (context.packed_line_family_mutating_selector_update_check_tail) {
        if (const std::optional<PackedLineFamilyUpdateRule> mutating_update =
                packed_line_family_update_rule(context, rule, PackedLineSelectorMode::Mutating)) {
          packed_line_consumed_update_rules.insert(mutating_update->update_rule);
          continue;
        }
      }
      if (context.packed_line_family_update_check_tail) {
        if (const std::optional<PackedLineFamilyUpdateRule> direct_update =
                packed_line_family_update_rule(context, rule)) {
          packed_line_consumed_update_rules.insert(direct_update->update_rule);
        }
      }
    }
  }
  for (const V2Rule* rule : function_rule_emission_order(context, program)) {
    if (rule == nullptr)
      continue;
    if (match_trig_near_rule(*rule).has_value())
      continue;
    if (context.inline_statement_rules.contains(rule->name))
      continue;
    if (packed_line_consumed_update_rules.contains(rule->name))
      continue;
    if (match_x_param_stack_stop_risk_rule(*rule).has_value()) {
      const int uses =
          context.proc_call_counts.contains(rule->name) ? context.proc_call_counts[rule->name] : 0;
      if (uses == 1)
        continue;
    }
    if (!lower_function_rule(context, *rule))
      return false;
  }
  return true;
}

bool lower_decrement_test_pair(LoweringContext& context, const V2Statement& update,
                               const V2Statement& branch) {
  if (update.kind != "v2_update" || !update.target.has_value() || !update.op.has_value() ||
      !update.expr.has_value() || *update.op != "-=" || trim_ascii(*update.expr) != "1") {
    return false;
  }
  if (branch.kind != "v2_if" || !branch.predicate.has_value()) {
    return false;
  }
  const V2Predicate& predicate = *branch.predicate;
  const std::string effective_op =
      branch.negated ? invert_comparison_op(predicate.op) : predicate.op;
  if (predicate.kind != "v2_compare" || trim_ascii(predicate.left) != *update.target ||
      trim_ascii(predicate.right) != "0") {
    return false;
  }
  const auto register_it = context.register_index_by_name.find(*update.target);
  if (register_it == context.register_index_by_name.end())
    return false;

  auto emit_decrement_to_x = [&]() {
    emit_recall(context, *update.target);
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = "decrement/test " + *update.target;
    emit_number_or_preload(context, "1");
    context.emitter.emit_op(0x11, "-", "decrement/test " + *update.target, update.line);
  };

  if ((effective_op == "<=" || effective_op == "==")) {
    const auto field_it = context.state_fields.find(*update.target);
    if (field_it == context.state_fields.end() || field_it->second == nullptr ||
        !field_it->second->min.has_value() || *field_it->second->min < 1) {
      return false;
    }

    const std::optional<std::pair<int, std::string>> fl =
        fl_loop_opcode_for_register(register_it->second);
    if (fl.has_value()) {
      const std::string else_label = context.emitter.fresh_label("decrement_else");
      const std::string end_label = context.emitter.fresh_label("decrement_end");
      context.emitter.emit_jump(fl->first, fl->second, else_label,
                                "decrement/test " + *update.target, update.line);
      const bool then_stops = statements_always_stop(context, branch.then_body);
      if (!lower_statement_block(context, branch.then_body))
        return false;
      if (!then_stops)
        context.emitter.emit_jump(0x51, "БП", end_label, "if end", branch.line);
      context.emitter.emit_label(else_label, {.hidden = true});
      if (!lower_statement_block(context, branch.else_body))
        return false;
      if (!then_stops)
        context.emitter.emit_label(end_label, {.hidden = true});
      context.optimizations.push_back(OptimizationReport{
          .name = "fl-decrement-zero-branch",
          .detail = "Fused " + *update.target + " decrement and zero branch at lines " +
                    std::to_string(update.line) + "/" + std::to_string(branch.line) + ".",
      });
      return true;
    }

    if (!statements_are_domain_error_trap(context, branch.then_body))
      return false;
    emit_decrement_to_x();
    emit_store(context, *update.target, "set " + *update.target);
    context.emitter.emit_op(0x23, "F 1/x", "decrement zero domain guard trap", branch.line);
    clear_current_x_facts(context);
    context.scaled_coord_variables.clear();
    if (!branch.else_body.empty() && !lower_statement_block(context, branch.else_body))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "decrement-zero-domain-guard",
        .detail = "Fused " + *update.target +
                  " decrement and zero terminal-error branch through F 1/x at lines " +
                  std::to_string(update.line) + "/" + std::to_string(branch.line) + ".",
    });
    return true;
  }

  if (effective_op != "<" || !branch.else_body.empty() ||
      !statements_always_stop(context, branch.then_body)) {
    return false;
  }

  if (statements_are_domain_error_trap(context, branch.then_body)) {
    emit_decrement_to_x();
    emit_store(context, *update.target, "set " + *update.target);
    context.emitter.emit_op(0x21, "F √", "decrement underflow domain guard trap", branch.line);
    clear_current_x_facts(context);
    context.scaled_coord_variables.clear();
    context.optimizations.push_back(OptimizationReport{
        .name = "decrement-underflow-domain-guard",
        .detail = "Fused " + *update.target +
                  " decrement and negative terminal-error branch through F sqrt at lines " +
                  std::to_string(update.line) + "/" + std::to_string(branch.line) + ".",
    });
    return true;
  }

  const std::string ok_label = context.emitter.fresh_label("decrement_ok");
  emit_decrement_to_x();
  context.emitter.emit_jump(0x5c, "F x<0", ok_label, "decrement underflow " + *update.target,
                            branch.line);
  if (!lower_statement_block(context, branch.then_body))
    return false;
  context.emitter.emit_label(ok_label, {.hidden = true});
  clear_current_x_facts(context);
  emit_store(context, *update.target, "set " + *update.target);
  context.optimizations.push_back(OptimizationReport{
      .name = "decrement-underflow-branch",
      .detail = "Fused " + *update.target + " decrement and negative branch at lines " +
                std::to_string(update.line) + "/" + std::to_string(branch.line) + ".",
  });
  return true;
}

std::optional<std::string> delayed_unit_decrement_guard_target(LoweringContext& context,
                                                               const V2Statement& guard) {
  if (guard.kind != "v2_if" || !guard.predicate.has_value() || guard.has_else_body ||
      !guard.else_body.empty()) {
    return std::nullopt;
  }
  const V2Predicate& predicate = *guard.predicate;
  if (predicate.kind != "v2_compare")
    return std::nullopt;
  try {
    const Expression left = parse_expression(predicate.left, guard.line);
    const Expression right = parse_expression(predicate.right, guard.line);
    if (right.kind == "number" && is_zero_expression(context, right) && left.kind == "identifier" &&
        (predicate.op == "<" || predicate.op == "<=")) {
      return left.name;
    }
    if (left.kind == "number" && is_zero_expression(context, left) && right.kind == "identifier" &&
        (predicate.op == ">" || predicate.op == ">=")) {
      return right.name;
    }
  } catch (const std::exception&) {
  }
  return std::nullopt;
}

bool delayed_unit_decrement_guard_matches(LoweringContext& context, const std::string& target,
                                          const V2Statement& guard) {
  const std::optional<std::string> guard_target =
      delayed_unit_decrement_guard_target(context, guard);
  return guard_target.has_value() && *guard_target == target;
}

bool statement_is_delayed_unit_decrement(const V2Statement& statement, const std::string& target) {
  if (!statement.target.has_value())
    return false;
  const std::optional<std::string> statement_target = scalar_statement_target_name(statement);
  if (!statement_target.has_value() || *statement_target != target)
    return false;
  if (statement.kind == "v2_update" && statement.op.has_value() && *statement.op == "-=" &&
      statement.expr.has_value() && expression_is_number(*statement.expr, "1", statement.line)) {
    return true;
  }
  if (statement.kind != "v2_assign" || !statement.expr.has_value())
    return false;
  try {
    const Expression expression = parse_expression(*statement.expr, statement.line);
    return expression.kind == "binary" && expression.op == "-" && expression.left != nullptr &&
           expression.right != nullptr && expression.left->kind == "identifier" &&
           expression.left->name == target && is_numeric_literal_value(*expression.right, 1);
  } catch (const std::exception&) {
    return false;
  }
}

bool expression_is_affine_self_update(const Expression& expression, const std::string& target) {
  int coefficient = 0;
  bool ok = true;
  std::function<void(const Expression&, int)> visit = [&](const Expression& current, int sign) {
    if (!ok)
      return;
    if (current.kind == "identifier" && current.name == target) {
      coefficient += sign;
      return;
    }
    if (!core::emit::expression_references_identifier(current, target))
      return;
    if (current.kind == "binary" && (current.op == "+" || current.op == "-") &&
        current.left != nullptr && current.right != nullptr) {
      visit(*current.left, sign);
      visit(*current.right, current.op == "+" ? sign : -sign);
      return;
    }
    ok = false;
  };
  visit(expression, 1);
  return ok && coefficient == 1;
}

bool delayed_statement_may_write_identifier(LoweringContext& context, const V2Statement& statement,
                                            const std::string& target,
                                            std::set<std::string>& seen_rules);

bool delayed_statements_may_write_identifier(LoweringContext& context,
                                             const std::vector<V2Statement>& statements,
                                             const std::string& target,
                                             std::set<std::string>& seen_rules) {
  return std::any_of(statements.begin(), statements.end(), [&](const V2Statement& statement) {
    std::set<std::string> child_seen = seen_rules;
    return delayed_statement_may_write_identifier(context, statement, target, child_seen);
  });
}

bool delayed_statement_may_write_identifier(LoweringContext& context, const V2Statement& statement,
                                            const std::string& target,
                                            std::set<std::string>& seen_rules) {
  const std::optional<std::string> assignment_target = scalar_assignment_target_name(statement);
  if (assignment_target.has_value() && *assignment_target == target)
    return true;
  if (statement.kind == "v2_raw") {
    for (const V2RawOutput& output : statement.outputs) {
      if (output.target == target)
        return true;
    }
  }
  if (delayed_statements_may_write_identifier(context, statement.body, target, seen_rules) ||
      delayed_statements_may_write_identifier(context, statement.then_body, target, seen_rules) ||
      delayed_statements_may_write_identifier(context, statement.else_body, target, seen_rules)) {
    return true;
  }
  for (const V2MatchCase& match_case : statement.cases) {
    if (match_case.action != nullptr &&
        delayed_statement_may_write_identifier(context, *match_case.action, target, seen_rules)) {
      return true;
    }
  }
  if (statement.otherwise != nullptr &&
      delayed_statement_may_write_identifier(context, *statement.otherwise, target, seen_rules)) {
    return true;
  }
  if (statement.kind == "v2_invoke" && statement.name.has_value()) {
    const auto rule_it = context.rules.find(*statement.name);
    if (rule_it == context.rules.end() || rule_it->second == nullptr ||
        seen_rules.contains(*statement.name)) {
      return true;
    }
    seen_rules.insert(*statement.name);
    const bool writes =
        delayed_statements_may_write_identifier(context, rule_it->second->body, target, seen_rules);
    seen_rules.erase(*statement.name);
    return writes;
  }
  return false;
}

bool delayed_statement_commutes_with_unit_decrement(LoweringContext& context,
                                                    const V2Statement& statement,
                                                    const std::string& target,
                                                    std::set<std::string>& seen_rules);

bool delayed_statements_commute_with_unit_decrement(LoweringContext& context,
                                                    const std::vector<V2Statement>& statements,
                                                    std::size_t start, const std::string& target,
                                                    std::set<std::string>& seen_rules) {
  for (std::size_t index = start; index < statements.size(); ++index) {
    std::set<std::string> child_seen = seen_rules;
    if (!delayed_statement_commutes_with_unit_decrement(context, statements.at(index), target,
                                                        child_seen)) {
      return false;
    }
  }
  return true;
}

bool delayed_statement_commutes_with_unit_decrement(LoweringContext& context,
                                                    const V2Statement& statement,
                                                    const std::string& target,
                                                    std::set<std::string>& seen_rules) {
  const std::optional<std::string> assignment_target = scalar_assignment_target_name(statement);
  if (assignment_target.has_value() && *assignment_target == target) {
    if (statement.kind == "v2_assign" && statement.expr.has_value()) {
      try {
        return expression_is_affine_self_update(parse_expression(*statement.expr, statement.line),
                                                target);
      } catch (const std::exception&) {
        return false;
      }
    }
    if (statement.kind == "v2_update" && statement.expr.has_value() && statement.op.has_value() &&
        (*statement.op == "+=" || *statement.op == "-=")) {
      try {
        const Expression delta = parse_expression(*statement.expr, statement.line);
        return !core::emit::expression_references_identifier(delta, target);
      } catch (const std::exception&) {
        return false;
      }
    }
    return false;
  }

  if (statement.kind == "v2_if") {
    if (!statement.predicate.has_value() ||
        predicate_reads_identifier(*statement.predicate, target))
      return false;
    std::set<std::string> then_seen = seen_rules;
    std::set<std::string> else_seen = seen_rules;
    return delayed_statements_commute_with_unit_decrement(context, statement.then_body, 0, target,
                                                          then_seen) &&
           delayed_statements_commute_with_unit_decrement(context, statement.else_body, 0, target,
                                                          else_seen);
  }

  if (statement.kind == "v2_match") {
    if (statement.expr.has_value() &&
        expression_text_contains_identifier(*statement.expr, target, statement.line)) {
      return false;
    }
    for (const V2MatchCase& match_case : statement.cases) {
      for (const std::string& value : match_case.values) {
        if (expression_text_contains_identifier(value, target, match_case.line))
          return false;
      }
      if (match_case.action != nullptr) {
        std::set<std::string> case_seen = seen_rules;
        if (!delayed_statement_commutes_with_unit_decrement(context, *match_case.action, target,
                                                            case_seen)) {
          return false;
        }
      }
    }
    if (statement.otherwise != nullptr) {
      std::set<std::string> otherwise_seen = seen_rules;
      return delayed_statement_commutes_with_unit_decrement(context, *statement.otherwise, target,
                                                            otherwise_seen);
    }
    return true;
  }

  if (statement.kind == "v2_invoke" && statement.name.has_value()) {
    for (const std::string& arg : statement.args) {
      if (expression_text_contains_identifier(arg, target, statement.line))
        return false;
    }
    const auto rule_it = context.rules.find(*statement.name);
    if (rule_it == context.rules.end() || rule_it->second == nullptr ||
        seen_rules.contains(*statement.name)) {
      return false;
    }
    seen_rules.insert(*statement.name);
    const bool commutes = delayed_statements_commute_with_unit_decrement(
        context, rule_it->second->body, 0, target, seen_rules);
    seen_rules.erase(*statement.name);
    return commutes;
  }

  if (statement.kind == "v2_loop" || statement.kind == "v2_while") {
    std::set<std::string> write_seen = seen_rules;
    return !statement_reads_identifier(statement, target, false) &&
           !delayed_statement_may_write_identifier(context, statement, target, write_seen);
  }

  std::set<std::string> write_seen = seen_rules;
  return !statement_reads_identifier(statement, target, false) &&
         !delayed_statement_may_write_identifier(context, statement, target, write_seen);
}

bool delayed_statements_commute_with_unit_decrement(LoweringContext& context,
                                                    const std::vector<V2Statement>& statements,
                                                    std::size_t start, const std::string& target) {
  std::set<std::string> seen_rules;
  return delayed_statements_commute_with_unit_decrement(context, statements, start, target,
                                                        seen_rules);
}

bool statement_may_terminate_before_delayed_decrement(LoweringContext& context,
                                                      const V2Statement& statement,
                                                      std::set<std::string>& seen_rules);

bool statements_may_terminate_before_delayed_decrement(LoweringContext& context,
                                                       const std::vector<V2Statement>& statements,
                                                       std::set<std::string>& seen_rules) {
  return std::any_of(statements.begin(), statements.end(), [&](const V2Statement& statement) {
    return statement_may_terminate_before_delayed_decrement(context, statement, seen_rules);
  });
}

bool delayed_action_may_terminate_before_decrement(LoweringContext& context,
                                                   const V2StatementPtr& action,
                                                   std::set<std::string>& seen_rules) {
  if (action == nullptr)
    return false;
  if (action->kind == "v2_block")
    return statements_may_terminate_before_delayed_decrement(context, action->body, seen_rules);
  return statement_may_terminate_before_delayed_decrement(context, *action, seen_rules);
}

bool statement_may_terminate_before_delayed_decrement(LoweringContext& context,
                                                      const V2Statement& statement,
                                                      std::set<std::string>& seen_rules) {
  if (statement.kind == "v2_stop" || statement.kind == "v2_loop" || statement.kind == "v2_return") {
    return true;
  }
  if (statement.kind == "v2_if") {
    std::set<std::string> then_seen = seen_rules;
    std::set<std::string> else_seen = seen_rules;
    return statements_may_terminate_before_delayed_decrement(context, statement.then_body,
                                                             then_seen) ||
           statements_may_terminate_before_delayed_decrement(context, statement.else_body,
                                                             else_seen);
  }
  if (statement.kind == "v2_match") {
    for (const V2MatchCase& match_case : statement.cases) {
      std::set<std::string> case_seen = seen_rules;
      if (delayed_action_may_terminate_before_decrement(context, match_case.action, case_seen))
        return true;
    }
    return delayed_action_may_terminate_before_decrement(context, statement.otherwise, seen_rules);
  }
  if (statement.kind == "v2_while")
    return statements_may_terminate_before_delayed_decrement(context, statement.body, seen_rules);
  if (statement.kind == "v2_invoke" && statement.name.has_value()) {
    const auto rule_it = context.rules.find(*statement.name);
    if (rule_it == context.rules.end() || rule_it->second == nullptr ||
        seen_rules.contains(*statement.name)) {
      return true;
    }
    seen_rules.insert(*statement.name);
    const bool terminates = statements_may_terminate_before_delayed_decrement(
        context, rule_it->second->body, seen_rules);
    seen_rules.erase(*statement.name);
    return terminates;
  }
  return false;
}

struct DelayedUnitDecrementBranchPlan {
  std::vector<V2Statement> body;
  V2Statement decrement;
  int register_index = -1;
};

std::optional<DelayedUnitDecrementBranchPlan>
delayed_unit_decrement_branch_plan(LoweringContext& context,
                                   const std::vector<V2Statement>& statements,
                                   const std::string& target) {
  const auto register_it = context.register_index_by_name.find(target);
  if (register_it == context.register_index_by_name.end() || register_it->second < 0 ||
      register_it->second > 3) {
    return std::nullopt;
  }
  const auto field_it = context.state_fields.find(target);
  if (field_it == context.state_fields.end() || field_it->second == nullptr ||
      !field_it->second->min.has_value() || *field_it->second->min < 0 ||
      (field_it->second->type != "range" && field_it->second->type != "counter")) {
    return std::nullopt;
  }

  for (std::size_t index = 0; index < statements.size(); ++index) {
    const V2Statement& candidate = statements.at(index);
    if (!statement_is_delayed_unit_decrement(candidate, target)) {
      continue;
    }
    if (target.rfind("__packed_counter_", 0) == 0) {
      continue;
    }
    if (!delayed_statements_commute_with_unit_decrement(context, statements, index + 1U, target)) {
      continue;
    }

    std::vector<V2Statement> body;
    body.insert(body.end(), statements.begin(),
                statements.begin() + static_cast<std::ptrdiff_t>(index));
    body.insert(body.end(), statements.begin() + static_cast<std::ptrdiff_t>(index + 1U),
                statements.end());
    std::set<std::string> seen_rules;
    if (statements_may_terminate_before_delayed_decrement(context, body, seen_rules)) {
      continue;
    }
    return DelayedUnitDecrementBranchPlan{
        .body = std::move(body),
        .decrement = candidate,
        .register_index = register_it->second,
    };
  }
  return std::nullopt;
}

void emit_delayed_indirect_unit_decrement(LoweringContext& context, const V2Statement& decrement,
                                          int register_index, const V2Statement& guard,
                                          const std::string& target) {
  context.emitter.emit_op(0xd0 + register_index, "К П->X " + register_text_for(context, target),
                          "delayed predecrement " + target, decrement.line);
  clear_current_x_facts(context);
  context.optimizations.push_back(OptimizationReport{
      .name = "delayed-indirect-underflow-decrement",
      .detail = "Delayed " + target + "-- to the terminal nonpositive guard at line " +
                std::to_string(guard.line) + ", then used К П->X " +
                register_text_for(context, target) + "'s pre-decrement side effect.",
  });
}

std::optional<std::vector<V2Statement>> delayed_unit_decrement_tail_with_guard(
    LoweringContext& context, const std::vector<V2Statement>& statements,
    const V2Statement& decrement, const std::string& target, std::set<std::string>& seen_rules) {
  if (statements.empty()) {
    return std::nullopt;
  }

  const V2Statement& last = statements.back();
  if (last.kind == "v2_if" && !last.has_else_body && last.else_body.empty() &&
      delayed_unit_decrement_guard_matches(context, target, last) &&
      statements_always_stop(context, last.then_body)) {
    std::vector<V2Statement> prefix(statements.begin(), statements.end() - 1);
    if (!delayed_statements_commute_with_unit_decrement(context, prefix, 0, target)) {
      return std::nullopt;
    }

    std::vector<V2Statement> result = std::move(prefix);
    result.push_back(decrement);
    result.push_back(last);
    return result;
  }

  if (last.kind != "v2_if" || !last.has_else_body || !last.predicate.has_value()) {
    return std::nullopt;
  }
  if (count_identifier_reads_in_predicate(*last.predicate, target, last.line) != 0) {
    return std::nullopt;
  }

  std::vector<V2Statement> prefix(statements.begin(), statements.end() - 1);
  if (!delayed_statements_commute_with_unit_decrement(context, prefix, 0, target)) {
    return std::nullopt;
  }

  std::set<std::string> then_seen = seen_rules;
  std::set<std::string> else_seen = seen_rules;
  std::optional<std::vector<V2Statement>> then_body =
      delayed_unit_decrement_tail_with_guard(context, last.then_body, decrement, target, then_seen);
  std::optional<std::vector<V2Statement>> else_body =
      delayed_unit_decrement_tail_with_guard(context, last.else_body, decrement, target, else_seen);
  if (!then_body.has_value() || !else_body.has_value()) {
    return std::nullopt;
  }

  V2Statement rewritten = last;
  rewritten.then_body = std::move(*then_body);
  rewritten.else_body = std::move(*else_body);

  std::vector<V2Statement> result = std::move(prefix);
  result.push_back(std::move(rewritten));
  return result;
}

bool lower_delayed_unit_decrement_underflow_guard_run(LoweringContext& context,
                                                      const std::vector<V2Statement>& statements,
                                                      std::size_t index, std::size_t& consumed) {
  consumed = 0;
  if (!context.indirect_underflow_decrement || index >= statements.size()) {
    return false;
  }

  const V2Statement& decrement = statements.at(index);
  const std::optional<std::string> target = scalar_statement_target_name(decrement);
  if (!target.has_value() || !statement_is_delayed_unit_decrement(decrement, *target)) {
    return false;
  }
  if (target->rfind("__packed_counter_", 0) == 0) {
    return false;
  }

  const std::size_t guard_index = statements.size() - 1U;
  if (index >= guard_index) {
    return false;
  }

  const auto register_it = context.register_index_by_name.find(*target);
  if (register_it == context.register_index_by_name.end() || register_it->second < 0 ||
      register_it->second > 3) {
    return false;
  }
  const auto field_it = context.state_fields.find(*target);
  if (field_it == context.state_fields.end() || field_it->second == nullptr ||
      (field_it->second->type != "range" && field_it->second->type != "counter") ||
      !field_it->second->min.has_value() || *field_it->second->min < 0) {
    return false;
  }

  const V2Statement& guard = statements.at(guard_index);
  if (guard.kind == "v2_if" && !guard.has_else_body && guard.else_body.empty() &&
      delayed_unit_decrement_guard_matches(context, *target, guard) &&
      statements_always_stop(context, guard.then_body)) {
    std::vector<V2Statement> middle(statements.begin() + static_cast<std::ptrdiff_t>(index + 1U),
                                    statements.begin() + static_cast<std::ptrdiff_t>(guard_index));
    if (!delayed_statements_commute_with_unit_decrement(context, middle, 0, *target)) {
      return false;
    }
    if (!lower_statement_block(context, middle))
      return false;
    emit_delayed_indirect_unit_decrement(context, decrement, register_it->second, guard, *target);
    if (!lower_statement(context, guard, nullptr))
      return false;
    consumed = guard_index - index + 1U;
    return true;
  }

  std::vector<V2Statement> tail(statements.begin() + static_cast<std::ptrdiff_t>(index + 1U),
                                statements.end());
  std::set<std::string> seen_rules;
  std::optional<std::vector<V2Statement>> transformed =
      delayed_unit_decrement_tail_with_guard(context, tail, decrement, *target, seen_rules);
  if (!transformed.has_value()) {
    return false;
  }
  if (!lower_statement_block(context, *transformed))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "delayed-indirect-underflow-decrement",
      .detail = "Sank " + *target + "-- at line " + std::to_string(decrement.line) +
                " into terminal nonpositive branch tails so pre-decrement side effects stay "
                "terminal on underflow.",
  });
  consumed = statements.size() - index;
  return true;
}

bool lower_delayed_unit_decrement_branch_body(
    LoweringContext& context, const std::optional<DelayedUnitDecrementBranchPlan>& plan,
    const std::vector<V2Statement>& fallback, const V2Statement& guard, const std::string& target) {
  if (!plan.has_value())
    return lower_statement_block(context, fallback);
  if (!lower_statement_block(context, plan->body))
    return false;
  emit_delayed_indirect_unit_decrement(context, plan->decrement, plan->register_index, guard,
                                       target);
  return true;
}

bool lower_branch_local_delayed_unit_decrement_guard(LoweringContext& context,
                                                     const V2Statement& branch,
                                                     const V2Statement& guard) {
  if (!context.indirect_underflow_decrement || branch.kind != "v2_if" ||
      !branch.predicate.has_value()) {
    return false;
  }
  const std::optional<std::string> target = delayed_unit_decrement_guard_target(context, guard);
  if (!target.has_value()) {
    return false;
  }
  if (!statements_always_stop(context, guard.then_body)) {
    return false;
  }
  if (statements_read_identifier(guard.then_body, *target, false)) {
    return false;
  }

  const std::optional<DelayedUnitDecrementBranchPlan> original_then_plan =
      delayed_unit_decrement_branch_plan(context, branch.then_body, *target);
  const std::optional<DelayedUnitDecrementBranchPlan> original_else_plan =
      branch.has_else_body ? delayed_unit_decrement_branch_plan(context, branch.else_body, *target)
                           : std::nullopt;
  if (!original_then_plan.has_value() && !original_else_plan.has_value())
    return false;

  const V2Statement selected = branch_order_statement(context, branch);
  if (!selected.predicate.has_value())
    return false;
  const std::optional<DelayedUnitDecrementBranchPlan> then_plan =
      delayed_unit_decrement_branch_plan(context, selected.then_body, *target);
  const std::optional<DelayedUnitDecrementBranchPlan> else_plan =
      selected.has_else_body
          ? delayed_unit_decrement_branch_plan(context, selected.else_body, *target)
          : std::nullopt;
  if (!then_plan.has_value() && !else_plan.has_value())
    return false;

  const bool has_else = selected.has_else_body;
  const std::string false_label = context.emitter.fresh_label(has_else ? "if_else" : "if_end");
  const bool then_stops = statements_always_stop(context, selected.then_body);
  const std::string end_label =
      has_else && !then_stops ? context.emitter.fresh_label("if_end") : false_label;
  if (!lower_condition_false_branch(context, *selected.predicate, selected.negated, false_label,
                                    selected.line))
    return false;
  if (!lower_delayed_unit_decrement_branch_body(context, then_plan, selected.then_body, guard,
                                                *target))
    return false;
  if (has_else) {
    if (!then_stops)
      context.emitter.emit_jump(0x51, "БП", end_label, "if end", selected.line);
    context.emitter.emit_label(false_label, {.hidden = true});
    if (!lower_delayed_unit_decrement_branch_body(context, else_plan, selected.else_body, guard,
                                                  *target))
      return false;
    if (!then_stops)
      context.emitter.emit_label(end_label, {.hidden = true});
  } else {
    context.emitter.emit_label(false_label, {.hidden = true});
  }
  if (!lower_statement(context, guard, nullptr))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "delayed-indirect-underflow-decrement",
      .detail = "Sank a branch-local " + *target +
                "-- into the shared terminal nonpositive guard at line " +
                std::to_string(guard.line) + ".",
  });
  return true;
}

bool statement_is_plain_zero_halt(LoweringContext& context, const V2Statement& statement) {
  if (statement.kind != "v2_stop" || statement.items.has_value() || !statement.target.has_value())
    return false;
  try {
    return is_zero_expression(context, parse_expression(*statement.target, statement.line));
  } catch (const std::exception&) {
    return false;
  }
}

bool show_target_equals_halt_target(const V2Statement& show, const V2Statement& halt) {
  if (show.kind != "v2_show" || halt.kind != "v2_stop" || !show.target.has_value() ||
      !halt.target.has_value() || halt.items.has_value()) {
    return false;
  }
  try {
    return expression_equals(parse_expression(*show.target, show.line),
                             parse_expression(*halt.target, halt.line));
  } catch (const std::exception&) {
    return trim_ascii(*show.target) == trim_ascii(*halt.target);
  }
}

std::optional<std::string> single_source_display_name(const V2Statement& show) {
  if (show.kind != "v2_show" || show.target.has_value() || !show.items.has_value() ||
      show.items->size() != 1U) {
    return std::nullopt;
  }
  const DisplayItem& item = show.items->front();
  if (item.kind != "source" || item.width.has_value() || item.pad.has_value())
    return std::nullopt;
  if (item.expr.has_value() && item.expr->kind == "identifier")
    return item.expr->name;
  if (!item.expr.has_value() && !item.name.empty())
    return item.name;
  return std::nullopt;
}

bool show_displays_same_initial_value_as_halt(LoweringContext& context, const V2Statement& show,
                                              const V2Statement& halt) {
  if (halt.kind != "v2_stop" || halt.items.has_value() || !halt.target.has_value())
    return false;
  const std::optional<std::string> source = single_source_display_name(show);
  if (!source.has_value())
    return false;
  const auto field_it = context.state_fields.find(*source);
  if (field_it == context.state_fields.end() || field_it->second == nullptr ||
      !field_it->second->initial.has_value()) {
    return false;
  }
  try {
    return expression_equals(parse_expression(*field_it->second->initial, field_it->second->line),
                             parse_expression(*halt.target, halt.line));
  } catch (const std::exception&) {
    return false;
  }
}

bool lower_terminal_literal_show_halt(LoweringContext& context, const V2Statement& show,
                                      const V2Statement& halt) {
  if (show.kind != "v2_show" || !show.items.has_value() ||
      !statement_is_plain_zero_halt(context, halt)) {
    return false;
  }
  const std::optional<std::string> literal = core::emit::collapse_literal_only_display(*show.items);
  if (!literal.has_value())
    return false;
  const std::optional<DisplayLiteralProgram> program = display_literal_program(*literal);
  if (!program.has_value() || program->kind != "error")
    return false;

  context.emitter.emit_op(0x29, "К ÷", "halt literal ЕГГ0Г", show.line);
  context.optimizations.push_back(OptimizationReport{
      .name = "terminal-display-fusion",
      .detail = "Folded literal screen before halt at line " + std::to_string(halt.line) +
                " into a terminal error stop.",
  });
  return true;
}

bool lower_terminal_display_fusion(LoweringContext& context, const V2Statement& show,
                                   const V2Statement& halt) {
  if (show.kind != "v2_show" || halt.kind != "v2_stop")
    return false;
  if (show_target_equals_halt_target(show, halt)) {
    if (!lower_statement(context, halt, nullptr))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "terminal-display-fusion",
        .detail = "Dropped duplicate terminal display before stop at line " +
                  std::to_string(halt.line) + ".",
    });
    return true;
  }
  if (lower_terminal_literal_show_halt(context, show, halt))
    return true;
  if (show_displays_same_initial_value_as_halt(context, show, halt)) {
    if (!lower_statement(context, halt, nullptr))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "terminal-display-fusion",
        .detail = "Dropped duplicate screen before stop at line " + std::to_string(halt.line) + ".",
    });
    return true;
  }
  return false;
}

std::optional<std::string> single_plain_show_source(const V2Statement& show) {
  if (show.kind != "v2_show")
    return std::nullopt;
  if (show.items.has_value()) {
    if (show.items->size() != 1U)
      return std::nullopt;
    const DisplayItem& item = show.items->front();
    if (item.kind != "source" || item.width.has_value() || item.pad.has_value())
      return std::nullopt;
    if (!item.expr.has_value() && !item.name.empty())
      return item.name;
    if (item.expr.has_value() && item.expr->kind == "identifier")
      return item.expr->name;
    return std::nullopt;
  }
  if (show.target.has_value()) {
    try {
      const Expression target = parse_expression(*show.target, show.line);
      if (target.kind == "identifier")
        return target.name;
    } catch (const std::exception&) {
      return std::nullopt;
    }
  }
  return std::nullopt;
}

std::string show_display_name(const V2Statement& show) {
  if (show.inline_name.has_value())
    return *show.inline_name;
  if (show.name.has_value())
    return *show.name;
  if (show.target.has_value())
    return *show.target;
  return "display";
}

bool lower_show_read_stack_stop_risk_result(LoweringContext& context, const V2Statement& show,
                                            const V2Statement* input,
                                            const V2Statement& consumer) {
  if (show.kind != "v2_show" ||
      (consumer.kind != "v2_assign" && consumer.kind != "v2_return") ||
      !consumer.expr.has_value()) {
    return false;
  }
  const std::optional<std::string> parked = single_plain_show_source(show);
  if (!parked.has_value())
    return false;

  std::optional<std::string> input_name;
  if (input != nullptr) {
    if (input->kind != "v2_read" || !input->target.has_value())
      return false;
    input_name = *input->target;
  }

  const Expression expression = parse_expression(*consumer.expr, consumer.line);
  if (input_name.has_value()) {
    const int input_reads = count_identifier_reads(expression, *input_name);
    if (input_reads == 0 || context.program == nullptr ||
        count_identifier_reads_in_program(*context.program, *input_name) != input_reads) {
      return false;
    }
  }

  const std::optional<StackStopRiskMatch> match =
      match_stack_stop_risk(expression, *parked, input_name);
  if (!match.has_value())
    return false;

  emit_recall(context, *parked);
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "display " + show_display_name(show) + " source";
  context.emitter.emit_op(0x0e, "В↑", "keep displayed value in Y", show.line);
  context.emitter.emit_op(0x50, "С/П", "show " + show_display_name(show), show.line);
  context.current_y_variable = *parked;
  compile_stack_stop_risk_tail(context, *match, input == nullptr ? consumer.line : input->line,
                               consumer.line);
  context.current_y_variable.reset();

  if (consumer.kind == "v2_return") {
    context.emitter.emit_op(0x52, "В/О", "return value", consumer.line);
    clear_current_x_facts(context);
  } else {
    if (!consumer.target.has_value())
      return false;
    const Expression target = parse_expression(*consumer.target, consumer.line);
    if (target.kind != "identifier")
      return false;
    mark_current_x(context, target.name);
    if (context.stack_only_state_fields.contains(target.name)) {
      report_stack_only_state_field(context, target.name, consumer.line);
    } else {
      emit_store(context, target.name, "set " + target.name);
    }
  }

  return true;
}

bool lower_show_read_fusion(LoweringContext& context, const V2Statement& show,
                            const V2Statement& read) {
  if (show.kind != "v2_show" || read.kind != "v2_read" || !read.target.has_value())
    return false;
  if (context.constants.contains(*read.target) ||
      context.scaled_coord_cell_names.contains(*read.target)) {
    return false;
  }

  if (show.target.has_value()) {
    if (!lower_pause_statement(context, show))
      return false;
  } else if (!lower_display_statement(context, show)) {
    return false;
  }

  mark_current_x(context, *read.target);
  emit_store(context, *read.target, "read " + *read.target);
  context.optimizations.push_back(OptimizationReport{
      .name = "show-read-fusion",
      .detail = "Fused show(...) and read " + *read.target + " into one calculator stop.",
  });
  return true;
}

bool lower_read_transform_tail_from_current_x(LoweringContext& context,
                                              const Expression& expression, int source_line);

bool expression_leads_with_read(const Expression& expression) {
  if (expression.kind != "call")
    return false;
  const std::string callee = lower_ascii(expression.callee);
  if (callee == "read")
    return expression.args.empty();
  return expression.args.size() == 1U && x_transform_unary_opcode(callee).has_value() &&
         expression_leads_with_read(expression.args.front());
}

bool lower_show_read_assign_fusion(LoweringContext& context, const V2Statement& show,
                                   const V2Statement& input) {
  if (show.kind != "v2_show" || input.kind != "v2_assign" || !input.target.has_value() ||
      !input.expr.has_value()) {
    return false;
  }

  Expression input_expression;
  try {
    input_expression = parse_expression(*input.expr, input.line);
  } catch (const std::exception&) {
    return false;
  }
  if (!expression_leads_with_read(input_expression))
    return false;

  if (show.target.has_value()) {
    if (!lower_pause_statement(context, show))
      return false;
  } else if (!lower_display_statement(context, show)) {
    return false;
  }

  clear_current_x_facts(context);
  if (!lower_read_transform_tail_from_current_x(context, input_expression, input.line))
    return false;
  emit_store(context, *input.target, "set " + *input.target);
  context.optimizations.push_back(OptimizationReport{
      .name = "show-read-fusion",
      .detail = "Fused show " + show_display_name(show) + " and the read in " + *input.target +
                " = " + expression_to_source(input_expression) +
                " into one calculator stop at line " + std::to_string(input.line) + ".",
  });
  return true;
}

std::optional<int> estimate_show_sequence_display_cost(LoweringContext& context,
                                                       const V2Statement& statement) {
  if (statement.kind != "v2_show" || statement.target.has_value() || !statement.items.has_value())
    return std::nullopt;
  const std::optional<std::vector<PackedDisplayField>> fields =
      numeric_display_fields(context, *statement.items);
  if (!fields.has_value())
    return std::nullopt;
  return estimate_decimal_packed_display_cost(context, *fields, false);
}

bool should_share_show_sequence(LoweringContext& context, const V2Statement& first,
                                const V2Statement& second) {
  if (context.emitting_show_sequence_helper)
    return false;
  const std::optional<std::string> key = show_sequence_key(first, second);
  if (!key.has_value())
    return false;
  const auto uses_it = context.show_sequence_use_counts.find(*key);
  if (uses_it == context.show_sequence_use_counts.end() || uses_it->second < 2)
    return false;

  const std::optional<int> first_cost = estimate_show_sequence_display_cost(context, first);
  const std::optional<int> second_cost = estimate_show_sequence_display_cost(context, second);
  if (!first_cost.has_value() || !second_cost.has_value())
    return false;

  const int body_cost = *first_cost + *second_cost;
  const int inline_total = uses_it->second * (body_cost + 1);
  const int helper_total = uses_it->second * 3 + body_cost + 1;
  return inline_total - helper_total >= kDisplayHelperMinSavings;
}

const ShowSequenceHelperRequest& ensure_show_sequence_helper(LoweringContext& context,
                                                             const V2Statement& first,
                                                             const V2Statement& second) {
  const std::optional<std::string> key = show_sequence_key(first, second);
  if (!key.has_value())
    throw std::logic_error("show sequence helper requested for non-show sequence");

  const auto existing = context.show_sequence_helper_labels.find(*key);
  if (existing != context.show_sequence_helper_labels.end()) {
    const auto helper =
        std::find_if(context.show_sequence_helpers.begin(), context.show_sequence_helpers.end(),
                     [&](const ShowSequenceHelperRequest& candidate) {
                       return candidate.label == existing->second;
                     });
    if (helper != context.show_sequence_helpers.end())
      return *helper;
  }

  const std::string label = "__showseq_" + std::to_string(context.show_sequence_helpers.size());
  context.show_sequence_helper_labels[*key] = label;
  context.show_sequence_helpers.push_back(ShowSequenceHelperRequest{
      .key = *key,
      .label = label,
      .first = first,
      .second = second,
      .line = first.line,
  });
  return context.show_sequence_helpers.back();
}

bool lower_show_sequence_read(LoweringContext& context, const std::vector<V2Statement>& statements,
                              std::size_t index, std::size_t& consumed) {
  consumed = 0;
  if (index + 2U >= statements.size())
    return false;

  const V2Statement& first = statements.at(index);
  const V2Statement& second = statements.at(index + 1U);
  const V2Statement& read = statements.at(index + 2U);
  if (read.kind != "v2_read" || !read.target.has_value())
    return false;
  if (context.constants.contains(*read.target) ||
      context.scaled_coord_cell_names.contains(*read.target)) {
    return false;
  }
  if (!should_share_show_sequence(context, first, second))
    return false;

  const ShowSequenceHelperRequest& helper = ensure_show_sequence_helper(context, first, second);
  context.emitter.emit_jump(0x53, "ПП", helper.label, "show sequence helper", first.line);
  mark_current_x(context, *read.target);
  emit_store(context, *read.target, "read " + *read.target);
  context.optimizations.push_back(OptimizationReport{
      .name = "show-sequence-helper-call",
      .detail = "Reused shared show-show-read helper before read " + *read.target + ".",
  });
  consumed = 3;
  return true;
}

bool lower_ephemeral_input_branch(LoweringContext& context,
                                  const std::vector<V2Statement>& statements, std::size_t index,
                                  std::size_t& consumed) {
  consumed = 0;
  const V2Statement* show = nullptr;
  const V2Statement* read = nullptr;
  const V2Statement* branch = nullptr;
  const V2Statement* guard = nullptr;

  if (index + 1U < statements.size() && statements.at(index).kind == "v2_read") {
    read = &statements.at(index);
    branch = &statements.at(index + 1U);
    consumed = 2;
    if (index + 2U < statements.size())
      guard = &statements.at(index + 2U);
  } else if (index + 2U < statements.size() && statements.at(index).kind == "v2_show" &&
             statements.at(index + 1U).kind == "v2_read") {
    show = &statements.at(index);
    read = &statements.at(index + 1U);
    branch = &statements.at(index + 2U);
    consumed = 3;
    if (index + 3U < statements.size())
      guard = &statements.at(index + 3U);
  } else {
    return false;
  }

  if (read == nullptr || branch == nullptr || read->kind != "v2_read" ||
      !read->target.has_value() || branch->kind != "v2_if" ||
      !context.ephemeral_input_targets.contains(*read->target)) {
    consumed = 0;
    return false;
  }

  if (show != nullptr) {
    if (show->target.has_value()) {
      if (!lower_pause_statement(context, *show))
        return false;
    } else if (!lower_display_statement(context, *show)) {
      return false;
    }
  } else {
    context.emitter.emit_op(0x50, "С/П", "read " + *read->target, read->line);
  }

  mark_current_x(context, *read->target);
  if (guard != nullptr &&
      lower_branch_local_delayed_unit_decrement_guard(context, *branch, *guard)) {
    consumed += 1U;
  } else {
    context.emitter.machine_entry_open = true;
    if (!lower_statement(context, *branch, nullptr))
      return false;
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "ephemeral-input-branch",
      .detail = "Branched directly on input " + *read->target + " at line " +
                std::to_string(read->line) + " without storing it.",
  });
  return true;
}

bool lower_ephemeral_input_dispatch(LoweringContext& context,
                                    const std::vector<V2Statement>& statements, std::size_t index,
                                    std::size_t& consumed) {
  consumed = 0;
  const V2Statement* show = nullptr;
  const V2Statement* read = nullptr;
  const V2Statement* match = nullptr;

  if (index + 1U < statements.size() && statements.at(index).kind == "v2_read") {
    read = &statements.at(index);
    match = &statements.at(index + 1U);
    consumed = 2;
  } else if (index + 2U < statements.size() && statements.at(index).kind == "v2_show" &&
             statements.at(index + 1U).kind == "v2_read") {
    show = &statements.at(index);
    read = &statements.at(index + 1U);
    match = &statements.at(index + 2U);
    consumed = 3;
  } else {
    return false;
  }

  if (read == nullptr || match == nullptr || read->kind != "v2_read" || !read->target.has_value() ||
      match->kind != "v2_match" || !match->expr.has_value() ||
      !context.ephemeral_input_targets.contains(*read->target)) {
    consumed = 0;
    return false;
  }

  if (show != nullptr) {
    if (show->target.has_value()) {
      if (!lower_pause_statement(context, *show))
        return false;
    } else if (!lower_display_statement(context, *show)) {
      return false;
    }
  } else {
    context.emitter.emit_op(0x50, "С/П", "read " + *read->target, read->line);
  }

  context.emitter.machine_entry_open = true;
  mark_current_x(context, *read->target);
  if (!lower_statement(context, *match, nullptr))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "ephemeral-input-dispatch",
      .detail = "Dispatched directly on single-use input " + *read->target +
                " without allocating a register.",
  });
  return true;
}

bool match_consumes_only_read_target(const V2Statement& statement, const std::string& target) {
  if (statement.kind != "v2_match" || !statement.expr.has_value() ||
      trim_ascii(*statement.expr) != target) {
    return false;
  }
  for (const V2MatchCase& match_case : statement.cases) {
    for (const std::string& value : match_case.values) {
      if (expression_text_contains_identifier(value, target, match_case.line))
        return false;
    }
    if (match_case.action != nullptr &&
        statement_reads_identifier(*match_case.action, target, false))
      return false;
  }
  return statement.otherwise == nullptr ||
         !statement_reads_identifier(*statement.otherwise, target, false);
}

bool if_consumes_only_read_target(const V2Statement& statement, const std::string& target) {
  if (statement.kind != "v2_if" || !statement.predicate.has_value())
    return false;
  if (count_identifier_reads_in_predicate(*statement.predicate, target, statement.line) == 0)
    return false;
  return !statements_read_identifier(statement.then_body, target, false) &&
         !statements_read_identifier(statement.else_body, target, false);
}

bool tail_reads_identifier(const std::vector<V2Statement>& statements, std::size_t start,
                           const std::string& target) {
  for (std::size_t index = start; index < statements.size(); ++index) {
    if (statement_reads_identifier(statements.at(index), target, false))
      return true;
  }
  return false;
}

std::optional<std::string> direct_storage_target_for_update(LoweringContext& context,
                                                            const std::string& target,
                                                            int source_line) {
  const Expression expression = parse_expression(target, source_line);
  if (expression.kind == "identifier")
    return expression.name;
  if (expression.kind == "indexed")
    return constant_indexed_state_element(context, expression, source_line);
  return std::nullopt;
}

bool lower_show_read_decrement_underflow_fusion(LoweringContext& context,
                                                const std::vector<V2Statement>& statements,
                                                std::size_t index, std::size_t& consumed) {
  consumed = 0;
  if (index + 4U >= statements.size())
    return false;

  const V2Statement& show = statements.at(index);
  const V2Statement& read = statements.at(index + 1U);
  const V2Statement& decrement = statements.at(index + 2U);
  const V2Statement& branch = statements.at(index + 3U);
  const V2Statement& consumer = statements.at(index + 4U);

  if (show.kind != "v2_show" || read.kind != "v2_read" || !read.target.has_value() ||
      decrement.kind != "v2_update" || !decrement.target.has_value() || !decrement.op.has_value() ||
      !decrement.expr.has_value() || *decrement.op != "-=" || trim_ascii(*decrement.expr) != "1" ||
      branch.kind != "v2_if" || !branch.predicate.has_value() || branch.negated ||
      !branch.else_body.empty()) {
    return false;
  }
  if (context.constants.contains(*read.target) ||
      context.scaled_coord_cell_names.contains(*read.target)) {
    return false;
  }

  const V2Predicate& predicate = *branch.predicate;
  if (predicate.kind != "v2_compare" || trim_ascii(predicate.left) != *decrement.target ||
      predicate.op != "<" || trim_ascii(predicate.right) != "0") {
    return false;
  }
  if (!statements_always_stop(context, branch.then_body))
    return false;
  const std::optional<std::string> decrement_storage =
      direct_storage_target_for_update(context, *decrement.target, decrement.line);
  if (!decrement_storage.has_value() ||
      !context.register_index_by_name.contains(*decrement_storage))
    return false;
  if (tail_reads_identifier(statements, index + 5U, *read.target))
    return false;

  const bool omit_input_store = match_consumes_only_read_target(consumer, *read.target) ||
                                if_consumes_only_read_target(consumer, *read.target);
  const bool keep_stored_input = !omit_input_store &&
                                 (consumer.kind == "v2_if" || consumer.kind == "v2_match") &&
                                 statement_reads_identifier(consumer, *read.target, false);
  if (!omit_input_store && !keep_stored_input)
    return false;

  if (show.target.has_value()) {
    if (!lower_pause_statement(context, show))
      return false;
  } else if (!lower_display_statement(context, show)) {
    return false;
  }

  if (keep_stored_input)
    emit_store(context, *read.target, "read " + *read.target);

  const std::string ok_label = context.emitter.fresh_label("decrement_ok");

  if (keep_stored_input && context.indirect_underflow_decrement) {
    const int decrement_register = register_index_for(context, *decrement_storage);
    if (decrement_register >= 0 && decrement_register <= 3) {
      context.emitter.emit_op(0xd0 + decrement_register,
                              "К П->X " + register_text_for(context, *decrement_storage),
                              "predecrement " + *decrement_storage, decrement.line);
      emit_recall(context, *decrement_storage);
      if (!context.emitter.items.empty())
        context.emitter.items.back().comment = "decrement/test " + *decrement_storage;
      context.emitter.emit_jump(0x5c, "F x<0", ok_label, "decrement underflow " + *decrement.target,
                                branch.line);
      if (!lower_terminal_empty_loop_body(context, branch.then_body) &&
          !lower_statement_block(context, branch.then_body))
        return false;
      context.emitter.emit_label(ok_label, {.hidden = true});
      mark_current_x(context, *decrement_storage);
      emit_recall(context, *read.target);
      if (!context.emitter.items.empty())
        context.emitter.items.back().comment = "restore read " + *read.target;
      mark_current_x(context, *read.target);
      if (!lower_guarded_decrement_consumer(context, consumer))
        return false;
      context.optimizations.push_back(OptimizationReport{
          .name = "show-read-stored-indirect-decrement-underflow",
          .detail = "Stored read " + *read.target + ", decremented " + *decrement.target +
                    " through К П->X " + register_text_for(context, *decrement_storage) +
                    ", and restored the read by recall at lines " + std::to_string(read.line) +
                    "/" + std::to_string(branch.line) + ".",
      });
      context.optimizations.push_back(OptimizationReport{
          .name = "indirect-underflow-decrement",
          .detail = "Used К П->X " + register_text_for(context, *decrement_storage) +
                    "'s pre-decrement side effect for " + *decrement_storage +
                    " before the underflow branch at lines " + std::to_string(decrement.line) +
                    "/" + std::to_string(branch.line) + ".",
      });
      consumed = 5;
      return true;
    }
  }

  emit_recall(context, *decrement_storage);
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "decrement/test " + *decrement_storage;
  emit_number_or_preload(context, "1");
  context.emitter.emit_op(0x11, "-", "decrement/test " + *decrement_storage, decrement.line);
  context.emitter.emit_jump(0x5c, "F x<0", ok_label, "decrement underflow " + *decrement.target,
                            branch.line);
  if (!lower_terminal_empty_loop_body(context, branch.then_body) &&
      !lower_statement_block(context, branch.then_body))
    return false;
  context.emitter.emit_label(ok_label, {.hidden = true});
  clear_current_x_facts(context);
  emit_store(context, *decrement_storage, "set " + *decrement_storage);
  if (keep_stored_input && context.recall_stored_input_after_decrement) {
    emit_recall(context, *read.target);
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = "restore read " + *read.target;
    context.optimizations.push_back(OptimizationReport{
        .name = "show-read-stored-decrement-recall-sync",
        .detail = "Restored stored read " + *read.target + " through П->X after checking " +
                  *decrement_storage + ", exposing an X2 sync.",
    });
  } else {
    context.emitter.emit_op(0x14, "X↔Y", "restore read " + *read.target, read.line);
  }
  mark_current_x(context, *read.target);
  if (!lower_guarded_decrement_consumer(context, consumer))
    return false;

  context.optimizations.push_back(OptimizationReport{
      .name = keep_stored_input ? "show-read-stored-decrement-underflow-fusion"
                                : "show-read-decrement-underflow-fusion",
      .detail = keep_stored_input
                    ? "Stored read " + *read.target +
                          " while also restoring it from Y after checking " + *decrement_storage +
                          " at lines " + std::to_string(read.line) + "/" +
                          std::to_string(branch.line) + "."
                    : "Kept read " + *read.target + " in Y while checking " + *decrement_storage +
                          " at lines " + std::to_string(read.line) + "/" +
                          std::to_string(branch.line) + ".",
  });
  consumed = 5;
  return true;
}

bool read_transform_is_stack_decrement_safe(const Expression& expression) {
  if (expression.kind != "call")
    return false;
  const std::string callee = lower_ascii(expression.callee);
  if (callee == "read")
    return expression.args.empty();
  return (callee == "int" || callee == "frac") && expression.args.size() == 1U &&
         read_transform_is_stack_decrement_safe(expression.args.front());
}

bool lower_read_transform_tail_from_current_x(LoweringContext& context,
                                              const Expression& expression, int source_line) {
  if (expression.kind != "call")
    return false;
  const std::string callee = lower_ascii(expression.callee);
  if (callee == "read")
    return expression.args.empty();
  if (expression.args.size() != 1U ||
      !lower_read_transform_tail_from_current_x(context, expression.args.front(), source_line)) {
    return false;
  }
  const std::optional<std::pair<int, std::string>> opcode = x_transform_unary_opcode(callee);
  if (opcode.has_value()) {
    context.emitter.emit_op(opcode->first, opcode->second, callee + "()", source_line);
    clear_current_x_facts(context);
    return true;
  }
  return false;
}

std::optional<Expression> self_update_assignable_target(const V2Statement& statement,
                                                        const std::string& op,
                                                        const std::string& temp) {
  if ((statement.kind != "v2_assign" && statement.kind != "v2_update") ||
      !statement.target.has_value() || !statement.expr.has_value()) {
    return std::nullopt;
  }

  try {
    const Expression target = parse_expression(*statement.target, statement.line);
    if (target.kind != "identifier" && target.kind != "indexed")
      return std::nullopt;

    if (statement.kind == "v2_update") {
      const std::string expected = op == "+" ? "+=" : "-=";
      if (!statement.op.has_value() || *statement.op != expected)
        return std::nullopt;
      const Expression amount = parse_expression(*statement.expr, statement.line);
      return expression_equals(amount, identifier_expression(temp))
                 ? std::optional<Expression>{target}
                 : std::nullopt;
    }

    const Expression expression = parse_expression(*statement.expr, statement.line);
    if (expression.kind != "binary" || expression.op != op || expression.left == nullptr ||
        expression.right == nullptr || !expression_equals(*expression.left, target) ||
        !expression_equals(*expression.right, identifier_expression(temp))) {
      return std::nullopt;
    }
    return target;
  } catch (const std::exception&) {
    return std::nullopt;
  }
}

bool lower_show_read_guarded_transfer(LoweringContext& context,
                                      const std::vector<V2Statement>& statements, std::size_t index,
                                      std::size_t& consumed) {
  consumed = 0;
  if (!context.domain_error_guards || !context.show_read_guarded_transfer ||
      index + 3U >= statements.size()) {
    return false;
  }

  const V2Statement& show = statements.at(index);
  const V2Statement& input = statements.at(index + 1U);
  const V2Statement& decrement = statements.at(index + 2U);
  const V2Statement& branch = statements.at(index + 3U);
  if (show.kind != "v2_show" || input.kind != "v2_assign" || !input.target.has_value() ||
      !input.expr.has_value() || branch.kind != "v2_if" || !branch.predicate.has_value() ||
      branch.negated || !branch.has_else_body || branch.else_body.size() < 2U) {
    return false;
  }

  const std::string temp = *input.target;
  if (context.constants.contains(temp))
    return false;

  Expression input_expression;
  try {
    input_expression = parse_expression(*input.expr, input.line);
  } catch (const std::exception&) {
    return false;
  }
  if (!read_transform_is_stack_decrement_safe(input_expression))
    return false;
  if (tail_reads_identifier(statements, index + 4U, temp))
    return false;

  const std::optional<Expression> decrement_target =
      self_update_assignable_target(decrement, "-", temp);
  if (!decrement_target.has_value())
    return false;
  if (!condition_is_negative_assignable_guard(context, *branch.predicate, *decrement_target,
                                              branch.line)) {
    return false;
  }
  if (!statements_are_domain_error_trap(context, branch.then_body))
    return false;

  const V2Statement& increment = branch.else_body.at(0);
  const V2Statement& increment_guard = branch.else_body.at(1);
  const std::optional<Expression> increment_target =
      self_update_assignable_target(increment, "+", temp);
  if (!increment_target.has_value())
    return false;
  if (increment_guard.kind != "v2_if" || !increment_guard.predicate.has_value() ||
      increment_guard.negated) {
    return false;
  }
  if (!condition_is_negative_assignable_guard(context, *increment_guard.predicate,
                                              *increment_target, increment_guard.line)) {
    return false;
  }
  if (!statements_are_domain_error_trap(context, increment_guard.then_body))
    return false;

  std::vector<V2Statement> continuation;
  if (increment_guard.has_else_body) {
    if (branch.else_body.size() != 2U)
      return false;
    continuation = increment_guard.else_body;
  } else {
    continuation.assign(branch.else_body.begin() + 2, branch.else_body.end());
  }
  if (statements_read_identifier(continuation, temp, false))
    return false;

  if (show.target.has_value()) {
    if (!lower_pause_statement(context, show))
      return false;
  } else if (!lower_display_statement(context, show)) {
    return false;
  }

  clear_current_x_facts(context);
  if (!lower_read_transform_tail_from_current_x(context, input_expression, input.line))
    return false;
  if (!emit_assignable_recall(context, *decrement_target,
                              "decrement " + assignable_target_text(*decrement_target),
                              decrement.line)) {
    return false;
  }
  context.emitter.emit_op(0x14, "X↔Y", "decrement input order", decrement.line);
  context.emitter.emit_op(0x11, "-", "decrement input", decrement.line);
  clear_current_x_facts(context);
  if (!emit_assignable_store(context, *decrement_target, decrement.line))
    return false;

  const std::string trap_label = context.emitter.fresh_label("decrement_increment_trap");
  context.emitter.emit_jump(0x59, "F x>=0", trap_label, "decrement negative trap", branch.line);
  context.emitter.emit_op(0x0f, "F Вx", "restore decremented input", input.line);
  clear_current_x_facts(context);
  if (!emit_assignable_recall(context, *increment_target,
                              "increment " + assignable_target_text(*increment_target),
                              increment.line)) {
    return false;
  }
  context.emitter.emit_op(0x10, "+", "increment input", increment.line);
  clear_current_x_facts(context);
  if (!emit_assignable_store(context, *increment_target, increment.line))
    return false;

  context.emitter.emit_label(trap_label, {.hidden = true});
  context.emitter.emit_op(0x21, "F √", "decrement/increment domain-error guard trap",
                          increment_guard.line);
  clear_current_x_facts(context);
  context.scaled_coord_variables.clear();
  if (!lower_statement_block(context, continuation))
    return false;

  context.optimizations.push_back(OptimizationReport{
      .name = "show-read-guarded-transfer",
      .detail = "Kept read " + temp + " on the stack while decrementing " +
                assignable_target_text(*decrement_target) + " and incrementing " +
                assignable_target_text(*increment_target) + ".",
  });
  consumed = 4;
  return true;
}

bool statement_always_stops_impl(LoweringContext& context, const V2Statement& statement,
                                 std::set<std::string>& seen_rules);

bool statements_always_stop_impl(LoweringContext& context,
                                 const std::vector<V2Statement>& statements,
                                 std::set<std::string>& seen_rules) {
  if (statements.empty())
    return false;
  return statement_always_stops_impl(context, statements.back(), seen_rules);
}

bool statements_always_stop(LoweringContext& context, const std::vector<V2Statement>& statements) {
  std::set<std::string> seen_rules;
  return statements_always_stop_impl(context, statements, seen_rules);
}

bool lower_terminal_empty_loop_body(LoweringContext& context,
                                    const std::vector<V2Statement>& statements) {
  if (statements.size() != 1U)
    return false;
  const V2Statement& statement = statements.front();
  if (statement.kind != "v2_loop" || !statement.body.empty())
    return false;
  const std::string label = context.emitter.fresh_label("loop");
  context.emitter.emit_label(label);
  context.emitter.emit_jump(0x51, "БП", label, "loop back", statement.line);
  return true;
}

bool statement_always_stops_impl(LoweringContext& context, const V2Statement& statement,
                                 std::set<std::string>& seen_rules) {
  if (statement.kind == "v2_stop")
    return true;
  if (statement.kind == "v2_loop")
    return true;
  if (statement.kind == "v2_block")
    return statements_always_stop_impl(context, statement.body, seen_rules);
  if (statement.kind == "v2_invoke" && statement.name.has_value() && statement.args.empty()) {
    const auto rule_it = context.rules.find(*statement.name);
    if (rule_it == context.rules.end() || seen_rules.contains(*statement.name))
      return false;
    seen_rules.insert(*statement.name);
    const bool stops = statements_always_stop_impl(context, rule_it->second->body, seen_rules);
    seen_rules.erase(*statement.name);
    return stops;
  }
  if (statement.kind == "v2_if" && !statement.else_body.empty())
    return statements_always_stop_impl(context, statement.then_body, seen_rules) &&
           statements_always_stop_impl(context, statement.else_body, seen_rules);
  return false;
}

std::optional<int>
integer_value_of_parsed_expression_without_constants(const Expression& expression) {
  const std::optional<double> value =
      core::numeric_value_of_expression(expression, std::map<std::string, Expression>{});
  if (!value.has_value() || std::fabs(*value - std::round(*value)) >= 1e-12)
    return std::nullopt;
  return static_cast<int>(round_to_long_long(*value));
}

std::optional<std::string> scalar_target_identifier(const std::optional<std::string>& target,
                                                    int line) {
  if (!target.has_value())
    return std::nullopt;
  try {
    const Expression expression = parse_expression(*target, line);
    if (expression.kind == "identifier")
      return expression.name;
  } catch (const std::exception&) {
    if (!target->empty())
      return trim_ascii(*target);
  }
  return std::nullopt;
}

std::optional<std::string> state_init_counted_while_target(const V2Statement& loop) {
  if (loop.kind != "v2_while" || !loop.predicate.has_value() || loop.body.empty())
    return std::nullopt;

  const V2Statement& final = loop.body.back();
  if (final.kind != "v2_update" || !final.target.has_value() || !final.op.has_value() ||
      !final.expr.has_value() || *final.op != "-=")
    return std::nullopt;
  const std::optional<std::string> target = scalar_target_identifier(final.target, final.line);
  if (!target.has_value())
    return std::nullopt;
  const std::optional<int> decrement = integer_literal_value(*final.expr, final.line);
  if (decrement != 1)
    return std::nullopt;

  const V2Predicate& predicate = *loop.predicate;
  if (predicate.kind != "v2_compare")
    return std::nullopt;
  try {
    const Expression left = parse_expression(predicate.left, loop.line);
    const Expression right = parse_expression(predicate.right, loop.line);
    const auto identifier_name = [](const Expression& expression) -> std::optional<std::string> {
      if (expression.kind != "identifier")
        return std::nullopt;
      return expression.name;
    };
    const std::optional<std::string> left_name = identifier_name(left);
    const std::optional<std::string> right_name = identifier_name(right);
    const std::optional<int> left_value =
        integer_value_of_parsed_expression_without_constants(left);
    const std::optional<int> right_value =
        integer_value_of_parsed_expression_without_constants(right);
    if (left_name == target && predicate.op == ">=" && right_value == 1)
      return target;
    if (left_name == target && predicate.op == ">" && right_value == 0)
      return target;
    if (right_name == target && predicate.op == "<=" && left_value == 1)
      return target;
    if (right_name == target && predicate.op == "<" && left_value == 0)
      return target;
  } catch (const std::exception&) {
    return std::nullopt;
  }
  return std::nullopt;
}

bool statement_references_scalar_outside_skipped_loop(const V2Statement& statement,
                                                      const std::string& name,
                                                      const V2Statement* skipped_loop);

bool statements_reference_scalar_outside_skipped_loop(const std::vector<V2Statement>& statements,
                                                      const std::string& name,
                                                      const V2Statement* skipped_loop) {
  return std::any_of(statements.begin(), statements.end(), [&](const V2Statement& statement) {
    return statement_references_scalar_outside_skipped_loop(statement, name, skipped_loop);
  });
}

bool statement_references_scalar_outside_skipped_loop(const V2Statement& statement,
                                                      const std::string& name,
                                                      const V2Statement* skipped_loop) {
  if (&statement == skipped_loop)
    return false;

  const std::optional<std::string> scalar_target =
      scalar_target_identifier(statement.target, statement.line);
  const bool target_is_write =
      statement.kind == "v2_assign" || statement.kind == "v2_update" || statement.kind == "v2_read";
  if (target_is_write && scalar_target == name)
    return true;

  if (statement.target.has_value() && (!target_is_write || scalar_target != name) &&
      expression_text_contains_identifier(*statement.target, name, statement.line))
    return true;
  if (statement.expr.has_value() &&
      expression_text_contains_identifier(*statement.expr, name, statement.line))
    return true;
  if (statement.predicate.has_value()) {
    const V2Predicate& predicate = *statement.predicate;
    if (expression_text_contains_identifier(predicate.left, name, statement.line) ||
        expression_text_contains_identifier(predicate.right, name, statement.line) ||
        (!predicate.collection.empty() &&
         expression_text_contains_identifier(predicate.collection, name, statement.line)) ||
        (!predicate.item.empty() &&
         expression_text_contains_identifier(predicate.item, name, statement.line)))
      return true;
  }
  for (const std::string& arg : statement.args) {
    if (expression_text_contains_identifier(arg, name, statement.line))
      return true;
  }
  if (statement.items.has_value()) {
    for (const DisplayItem& item : *statement.items) {
      if (item.expr.has_value() && expression_contains_identifier(*item.expr, name))
        return true;
      if (!item.name.empty() && item.name == name)
        return true;
    }
  }
  for (const V2RawInput& input : statement.inputs) {
    if (expression_text_contains_identifier(input.expr, name, input.line))
      return true;
  }
  for (const V2RawOutput& output : statement.outputs) {
    if (output.target == name ||
        expression_text_contains_identifier(output.target, name, output.line))
      return true;
  }
  for (const std::vector<V2Statement>* block :
       {&statement.body, &statement.then_body, &statement.else_body}) {
    if (statements_reference_scalar_outside_skipped_loop(*block, name, skipped_loop))
      return true;
  }
  for (const V2MatchCase& match_case : statement.cases) {
    for (const std::string& value : match_case.values) {
      if (expression_text_contains_identifier(value, name, match_case.line))
        return true;
    }
    if (match_case.action != nullptr &&
        statement_references_scalar_outside_skipped_loop(*match_case.action, name, skipped_loop))
      return true;
  }
  return statement.otherwise != nullptr &&
         statement_references_scalar_outside_skipped_loop(*statement.otherwise, name, skipped_loop);
}

V2StateField* find_state_field(V2Program& program, const std::string& name) {
  const auto found = std::find_if(program.state.begin(), program.state.end(),
                                  [&](const V2StateField& field) { return field.name == name; });
  return found == program.state.end() ? nullptr : &*found;
}

bool scalar_referenced_outside_loop(const V2Program& program, const std::string& name,
                                    const V2Statement& loop) {
  if (statements_reference_scalar_outside_skipped_loop(program.body, name, &loop))
    return true;
  return std::any_of(program.rules.begin(), program.rules.end(), [&](const V2Rule& rule) {
    return statements_reference_scalar_outside_skipped_loop(rule.body, name, &loop);
  });
}

int normalize_state_init_counted_loops(V2Program& program) {
  int normalized = 0;
  for (std::size_t index = 0; index < program.body.size(); ++index) {
    V2Statement& statement = program.body.at(index);
    const std::optional<std::string> target = state_init_counted_while_target(statement);
    if (!target.has_value())
      continue;
    V2StateField* field = find_state_field(program, *target);
    if (field == nullptr || !field->initial.has_value())
      continue;
    const std::optional<int> initial = integer_literal_value(*field->initial, field->line);
    if (!initial.has_value() || *initial < 1)
      continue;
    if (scalar_referenced_outside_loop(program, *target, statement))
      continue;

    V2Statement initializer;
    initializer.kind = "v2_assign";
    initializer.target = *target;
    initializer.expr = *field->initial;
    initializer.line = statement.line;
    field->initial.reset();
    program.body.insert(program.body.begin() + static_cast<std::ptrdiff_t>(index),
                        std::move(initializer));
    ++index;
    ++normalized;
  }
  return normalized;
}

bool counted_loop_condition_holds(const std::string& op, int value, int bound) {
  if (op == "<")
    return value < bound;
  if (op == "<=")
    return value <= bound;
  if (op == ">")
    return value > bound;
  if (op == ">=")
    return value >= bound;
  return false;
}

struct CountedLoopUpdate {
  std::string target;
  int step = 0;
  int line = 0;
};

std::optional<CountedLoopUpdate> match_linear_self_update(const V2Statement& statement) {
  if (!statement.target.has_value())
    return std::nullopt;
  const std::optional<std::string> target =
      scalar_target_identifier(statement.target, statement.line);
  if (!target.has_value())
    return std::nullopt;

  if (statement.kind == "v2_update" && statement.op.has_value() && statement.expr.has_value() &&
      (*statement.op == "+=" || *statement.op == "-=")) {
    const std::optional<int> value = integer_literal_value(*statement.expr, statement.line);
    if (!value.has_value())
      return std::nullopt;
    return CountedLoopUpdate{
        .target = *target,
        .step = *statement.op == "+=" ? *value : -*value,
        .line = statement.line,
    };
  }

  if (statement.kind != "v2_assign" || !statement.expr.has_value())
    return std::nullopt;

  const Expression expression = parse_expression(*statement.expr, statement.line);
  if (expression.kind != "binary" || (expression.op != "+" && expression.op != "-") ||
      expression.left == nullptr || expression.right == nullptr) {
    return std::nullopt;
  }

  std::optional<int> step;
  if (expression.left->kind == "identifier" && expression.left->name == *target) {
    step = integer_value_of_parsed_expression_without_constants(*expression.right);
  } else if (expression.op == "+" && expression.right->kind == "identifier" &&
             expression.right->name == *target) {
    step = integer_value_of_parsed_expression_without_constants(*expression.left);
  }
  if (!step.has_value())
    return std::nullopt;

  return CountedLoopUpdate{
      .target = *target,
      .step = expression.op == "-" ? -*step : *step,
      .line = statement.line,
  };
}

bool vector_contains_target(const std::vector<CountedLoopUpdate>& updates,
                            const std::string& target) {
  return std::any_of(updates.begin(), updates.end(),
                     [&](const CountedLoopUpdate& update) { return update.target == target; });
}

void collect_scalar_writes(const std::vector<V2Statement>& statements,
                           const std::map<std::string, const V2Rule*>& rules,
                           std::set<std::string>& out, std::set<std::string>& seen_rules);

void collect_scalar_writes_from_statement(const V2Statement& statement,
                                          const std::map<std::string, const V2Rule*>& rules,
                                          std::set<std::string>& out,
                                          std::set<std::string>& seen_rules) {
  if ((statement.kind == "v2_assign" || statement.kind == "v2_update" ||
       statement.kind == "v2_read") &&
      statement.target.has_value()) {
    if (const std::optional<std::string> target =
            scalar_target_identifier(statement.target, statement.line)) {
      out.insert(*target);
    }
  }

  if (statement.kind == "v2_loop" || statement.kind == "v2_while" || statement.kind == "v2_block") {
    collect_scalar_writes(statement.body, rules, out, seen_rules);
  }
  if (statement.kind == "v2_if") {
    collect_scalar_writes(statement.then_body, rules, out, seen_rules);
    collect_scalar_writes(statement.else_body, rules, out, seen_rules);
  }
  if (statement.kind == "v2_match") {
    for (const V2MatchCase& match_case : statement.cases) {
      if (match_case.action != nullptr)
        collect_scalar_writes_from_statement(*match_case.action, rules, out, seen_rules);
    }
    if (statement.otherwise != nullptr)
      collect_scalar_writes_from_statement(*statement.otherwise, rules, out, seen_rules);
  }
  if (statement.kind == "v2_invoke" && statement.name.has_value() &&
      !seen_rules.contains(*statement.name)) {
    seen_rules.insert(*statement.name);
    const auto rule_it = rules.find(*statement.name);
    if (rule_it != rules.end())
      collect_scalar_writes(rule_it->second->body, rules, out, seen_rules);
  }
}

void collect_scalar_writes(const std::vector<V2Statement>& statements,
                           const std::map<std::string, const V2Rule*>& rules,
                           std::set<std::string>& out, std::set<std::string>& seen_rules) {
  for (const V2Statement& statement : statements)
    collect_scalar_writes_from_statement(statement, rules, out, seen_rules);
}

std::optional<std::vector<V2Statement>>
build_counted_loop_unroll(const V2Statement& loop, std::vector<V2Statement>& preceding,
                          const std::map<std::string, const V2Rule*>& rules) {
  constexpr int kMaxTripCount = 8;
  if (loop.kind != "v2_while" || !loop.predicate.has_value() ||
      loop.predicate->kind != "v2_compare")
    return std::nullopt;

  Expression left;
  try {
    left = parse_expression(loop.predicate->left, loop.line);
  } catch (const std::exception&) {
    return std::nullopt;
  }
  if (left.kind != "identifier")
    return std::nullopt;

  const std::string condition_var = left.name;
  const std::optional<int> bound = integer_literal_value(loop.predicate->right, loop.line);
  if (!bound.has_value())
    return std::nullopt;
  if (loop.predicate->op != "<" && loop.predicate->op != "<=")
    return std::nullopt;

  std::vector<CountedLoopUpdate> prefix_updates;
  for (const V2Statement& statement : loop.body) {
    const std::optional<CountedLoopUpdate> update = match_linear_self_update(statement);
    if (!update.has_value())
      break;
    if (vector_contains_target(prefix_updates, update->target))
      break;
    prefix_updates.push_back(*update);
  }
  if (!vector_contains_target(prefix_updates, condition_var))
    return std::nullopt;

  std::map<std::string, int> entry_values;
  for (std::size_t cursor = preceding.size(); cursor > 0; --cursor) {
    const V2Statement& statement = preceding.at(cursor - 1U);
    if (statement.kind != "v2_assign" || !statement.target.has_value() ||
        !statement.expr.has_value())
      break;
    const std::optional<std::string> target =
        scalar_target_identifier(statement.target, statement.line);
    if (!target.has_value())
      break;
    const std::optional<int> value = integer_literal_value(*statement.expr, statement.line);
    if (!value.has_value())
      break;
    if (!entry_values.contains(*target))
      entry_values[*target] = *value;
  }
  if (std::any_of(
          prefix_updates.begin(), prefix_updates.end(),
          [&](const CountedLoopUpdate& update) { return !entry_values.contains(update.target); })) {
    return std::nullopt;
  }

  const std::vector<V2Statement> rest(
      loop.body.begin() + static_cast<std::ptrdiff_t>(prefix_updates.size()), loop.body.end());
  std::set<std::string> rest_writes;
  std::set<std::string> seen_rules;
  collect_scalar_writes(rest, rules, rest_writes, seen_rules);
  if (std::any_of(
          prefix_updates.begin(), prefix_updates.end(),
          [&](const CountedLoopUpdate& update) { return rest_writes.contains(update.target); })) {
    return std::nullopt;
  }

  std::vector<std::map<std::string, int>> iterations;
  std::map<std::string, int> current;
  for (const CountedLoopUpdate& update : prefix_updates)
    current[update.target] = entry_values.at(update.target);
  while (counted_loop_condition_holds(loop.predicate->op, current.at(condition_var), *bound)) {
    for (const CountedLoopUpdate& update : prefix_updates)
      current[update.target] = current.at(update.target) + update.step;
    iterations.push_back(current);
    if (iterations.size() > static_cast<std::size_t>(kMaxTripCount))
      return std::nullopt;
  }
  if (iterations.empty())
    return std::nullopt;

  std::vector<V2Statement> replacement;
  for (const std::map<std::string, int>& iteration : iterations) {
    for (const CountedLoopUpdate& update : prefix_updates) {
      V2Statement assignment;
      assignment.kind = "v2_assign";
      assignment.target = update.target;
      assignment.expr = std::to_string(iteration.at(update.target));
      assignment.line = update.line;
      replacement.push_back(std::move(assignment));
    }
    replacement.insert(replacement.end(), rest.begin(), rest.end());
  }

  while (!preceding.empty()) {
    const V2Statement& last = preceding.back();
    if (last.kind != "v2_assign" || !last.target.has_value() || !last.expr.has_value())
      break;
    const std::optional<std::string> target = scalar_target_identifier(last.target, last.line);
    if (!target.has_value() || !vector_contains_target(prefix_updates, *target))
      break;
    if (!integer_literal_value(*last.expr, last.line).has_value())
      break;
    preceding.pop_back();
  }
  return replacement;
}

V2Statement unroll_counted_loop_statement(V2Statement statement,
                                          const std::map<std::string, const V2Rule*>& rules,
                                          int& unrolled);

void unroll_counted_loop_action(V2StatementPtr& action,
                                const std::map<std::string, const V2Rule*>& rules, int& unrolled) {
  if (action != nullptr)
    *action = unroll_counted_loop_statement(std::move(*action), rules, unrolled);
}

std::vector<V2Statement>
unroll_counted_loop_statements(std::vector<V2Statement> statements,
                               const std::map<std::string, const V2Rule*>& rules, int& unrolled) {
  std::vector<V2Statement> result;
  for (V2Statement& statement : statements) {
    V2Statement visited = unroll_counted_loop_statement(std::move(statement), rules, unrolled);
    if (visited.kind == "v2_while") {
      if (std::optional<std::vector<V2Statement>> replacement =
              build_counted_loop_unroll(visited, result, rules)) {
        ++unrolled;
        result.insert(result.end(), replacement->begin(), replacement->end());
        continue;
      }
    }
    result.push_back(std::move(visited));
  }
  return result;
}

V2Statement unroll_counted_loop_statement(V2Statement statement,
                                          const std::map<std::string, const V2Rule*>& rules,
                                          int& unrolled) {
  if (statement.kind == "v2_loop" || statement.kind == "v2_while" || statement.kind == "v2_block") {
    statement.body = unroll_counted_loop_statements(std::move(statement.body), rules, unrolled);
    return statement;
  }
  if (statement.kind == "v2_if") {
    statement.then_body =
        unroll_counted_loop_statements(std::move(statement.then_body), rules, unrolled);
    statement.else_body =
        unroll_counted_loop_statements(std::move(statement.else_body), rules, unrolled);
    return statement;
  }
  if (statement.kind == "v2_match") {
    for (V2MatchCase& match_case : statement.cases)
      unroll_counted_loop_action(match_case.action, rules, unrolled);
    unroll_counted_loop_action(statement.otherwise, rules, unrolled);
    return statement;
  }
  return statement;
}

void unroll_counted_loops(V2Program& program, std::vector<OptimizationReport>& optimizations) {
  std::map<std::string, const V2Rule*> rules;
  for (const V2Rule& rule : program.rules)
    rules[rule.name] = &rule;

  int unrolled = 0;
  program.body = unroll_counted_loop_statements(std::move(program.body), rules, unrolled);
  for (V2Rule& rule : program.rules)
    rule.body = unroll_counted_loop_statements(rule.body, rules, unrolled);

  if (unrolled == 0)
    return;
  optimizations.push_back(OptimizationReport{
      .name = "counted-loop-unroll",
      .detail = "Fully unrolled " + std::to_string(unrolled) + " small constant-trip counted loop" +
                (unrolled == 1 ? "" : "s") +
                ", replacing induction variables with per-iteration constants.",
  });
}

std::optional<std::pair<int, int>> scalar_state_range(const V2Program& program,
                                                      const std::string& name) {
  const auto found =
      std::find_if(program.state.begin(), program.state.end(), [&](const V2StateField& field) {
        return field.name == name && !field.bank.has_value();
      });
  if (found == program.state.end() || !found->min.has_value() || !found->max.has_value())
    return std::nullopt;
  return std::pair<int, int>{*found->min, *found->max};
}

std::optional<std::pair<int, int>> range_for_max_min_lint_operand(const V2Program& program,
                                                                  const Expression& expression) {
  if (expression.kind != "identifier")
    return std::nullopt;
  return scalar_state_range(program, expression.name);
}

bool expression_is_numeric_literal_for_lint(const Expression& expression) {
  return expression.kind == "number";
}

void warn_hardware_max_min_zero_expression(const V2Program& program, const Expression& expression,
                                           int line, std::set<std::string>& seen,
                                           std::vector<Diagnostic>& diagnostics) {
  if (expression.index != nullptr)
    warn_hardware_max_min_zero_expression(program, *expression.index, line, seen, diagnostics);
  if (expression.expr != nullptr)
    warn_hardware_max_min_zero_expression(program, *expression.expr, line, seen, diagnostics);
  if (expression.left != nullptr)
    warn_hardware_max_min_zero_expression(program, *expression.left, line, seen, diagnostics);
  if (expression.right != nullptr)
    warn_hardware_max_min_zero_expression(program, *expression.right, line, seen, diagnostics);
  for (const Expression& arg : expression.args)
    warn_hardware_max_min_zero_expression(program, arg, line, seen, diagnostics);

  if (expression.kind != "call" || expression.args.size() != 2)
    return;
  const std::string callee = lower_ascii(expression.callee);
  if (callee != "max" && callee != "min")
    return;

  for (const Expression& arg : expression.args) {
    if (expression_is_numeric_literal_for_lint(arg))
      continue;
    const std::optional<std::pair<int, int>> range = range_for_max_min_lint_operand(program, arg);
    if (!range.has_value() || range->first > 0 || range->second < 0)
      continue;
    const std::string operand = arg.kind == "identifier" ? "'" + arg.name + "'" : "an operand";
    const std::string key = callee + ":" + std::to_string(line) + ":" + operand;
    if (seen.contains(key))
      continue;
    seen.insert(key);
    diagnostics.push_back(diagnostic(
        DiagnosticSeverity::Warning, "hardware-max-zero",
        callee + "() at line " + std::to_string(line) + ": " + operand +
            " can be exactly 0, and К max treats 0 as the largest value (max(5, 0) == 0). "
            "Use safe_" +
            callee + "() if you need the mathematical " +
            (callee == "max" ? "maximum" : "minimum") + "."));
  }
}

void warn_hardware_max_min_zero_text(const V2Program& program, const std::string& text, int line,
                                     std::set<std::string>& seen,
                                     std::vector<Diagnostic>& diagnostics) {
  try {
    warn_hardware_max_min_zero_expression(program, parse_expression(text, line), line, seen,
                                          diagnostics);
  } catch (const std::exception&) {
  }
}

void warn_hardware_max_min_zero_statements(const V2Program& program,
                                           const std::vector<V2Statement>& statements,
                                           std::set<std::string>& seen,
                                           std::vector<Diagnostic>& diagnostics);

void warn_hardware_max_min_zero_statement(const V2Program& program, const V2Statement& statement,
                                          std::set<std::string>& seen,
                                          std::vector<Diagnostic>& diagnostics) {
  if (statement.target.has_value())
    warn_hardware_max_min_zero_text(program, *statement.target, statement.line, seen, diagnostics);
  if (statement.expr.has_value())
    warn_hardware_max_min_zero_text(program, *statement.expr, statement.line, seen, diagnostics);
  if (statement.predicate.has_value()) {
    const V2Predicate& predicate = *statement.predicate;
    if (!predicate.left.empty())
      warn_hardware_max_min_zero_text(program, predicate.left, statement.line, seen, diagnostics);
    if (!predicate.right.empty())
      warn_hardware_max_min_zero_text(program, predicate.right, statement.line, seen, diagnostics);
    if (!predicate.collection.empty())
      warn_hardware_max_min_zero_text(program, predicate.collection, statement.line, seen,
                                      diagnostics);
    if (!predicate.item.empty())
      warn_hardware_max_min_zero_text(program, predicate.item, statement.line, seen, diagnostics);
  }
  for (const std::string& arg : statement.args)
    warn_hardware_max_min_zero_text(program, arg, statement.line, seen, diagnostics);
  if (statement.items.has_value()) {
    for (const DisplayItem& item : *statement.items) {
      if (item.expr.has_value())
        warn_hardware_max_min_zero_expression(program, *item.expr, item.line, seen, diagnostics);
    }
  }
  for (const V2RawInput& input : statement.inputs)
    warn_hardware_max_min_zero_text(program, input.expr, input.line, seen, diagnostics);
  warn_hardware_max_min_zero_statements(program, statement.body, seen, diagnostics);
  warn_hardware_max_min_zero_statements(program, statement.then_body, seen, diagnostics);
  warn_hardware_max_min_zero_statements(program, statement.else_body, seen, diagnostics);
  for (const V2MatchCase& match_case : statement.cases) {
    for (const std::string& value : match_case.values)
      warn_hardware_max_min_zero_text(program, value, match_case.line, seen, diagnostics);
    if (match_case.action != nullptr)
      warn_hardware_max_min_zero_statement(program, *match_case.action, seen, diagnostics);
  }
  if (statement.otherwise != nullptr)
    warn_hardware_max_min_zero_statement(program, *statement.otherwise, seen, diagnostics);
}

void warn_hardware_max_min_zero_statements(const V2Program& program,
                                           const std::vector<V2Statement>& statements,
                                           std::set<std::string>& seen,
                                           std::vector<Diagnostic>& diagnostics) {
  for (const V2Statement& statement : statements)
    warn_hardware_max_min_zero_statement(program, statement, seen, diagnostics);
}

void warn_hardware_max_min_zero_operands(const V2Program& program,
                                         std::vector<Diagnostic>& diagnostics) {
  std::set<std::string> seen;
  warn_hardware_max_min_zero_statements(program, program.body, seen, diagnostics);
  for (const V2Rule& rule : program.rules)
    warn_hardware_max_min_zero_statements(program, rule.body, seen, diagnostics);
}

std::set<std::string> declared_allocation_names(const V2Program& program) {
  std::set<std::string> declared;
  for (const V2StateField& field : program.state) {
    declared.insert(field.name);
    if (field.bank.has_value()) {
      declared.insert(field.bank->name);
      declared.insert(core::state_bank_key(field));
    }
    const std::vector<std::string> storage_names = storage_names_for_state_field(field);
    declared.insert(storage_names.begin(), storage_names.end());
  }
  for (const V2Const& constant : program.consts)
    declared.insert(constant.name);
  for (const V2Rule& rule : program.rules) {
    for (const std::string& param : rule.params)
      declared.insert(param);
  }
  return declared;
}

std::optional<std::string> allocation_target_name(const std::string& target, int line) {
  try {
    const Expression expression = parse_expression(target, line);
    if (expression.kind == "identifier")
      return expression.name;
    if (expression.kind == "indexed")
      return expression.base;
  } catch (const std::exception&) {
    const std::string trimmed = trim_ascii(target);
    if (!trimmed.empty())
      return trimmed;
  }
  return std::nullopt;
}

void warn_undeclared_allocations_in_statements(const std::vector<V2Statement>& statements,
                                               const std::set<std::string>& declared, bool strict,
                                               const std::set<std::string>& ignored_targets,
                                               std::set<std::string>& seen,
                                               std::vector<Diagnostic>& diagnostics);

void report_undeclared_allocation(const std::string& target, bool strict,
                                  std::set<std::string>& seen,
                                  std::vector<Diagnostic>& diagnostics) {
  if (target.starts_with("__") || seen.contains(target))
    return;
  seen.insert(target);
  diagnostics.push_back(
      diagnostic(strict ? DiagnosticSeverity::Error : DiagnosticSeverity::Warning,
                 strict ? "strict-allocation" : "implicit-allocation",
                 strict ? "Undeclared variable '" + target +
                              "' (strict allocation). Declare it in state { ... } or pass it as a "
                              "function parameter."
                        : "Implicit allocation for undeclared variable '" + target +
                              "'. Declare it in state { ... } to silence."));
}

void warn_undeclared_allocation_statement(const V2Statement& statement,
                                          const std::set<std::string>& declared, bool strict,
                                          const std::set<std::string>& ignored_targets,
                                          std::set<std::string>& seen,
                                          std::vector<Diagnostic>& diagnostics) {
  if ((statement.kind == "v2_assign" || statement.kind == "v2_update" ||
       statement.kind == "v2_read") &&
      statement.target.has_value()) {
    const std::optional<std::string> target =
        allocation_target_name(*statement.target, statement.line);
    if (target.has_value() && !ignored_targets.contains(*target) && !declared.contains(*target) &&
        (strict || statement.kind != "v2_read")) {
      report_undeclared_allocation(*target, strict, seen, diagnostics);
    }
  }

  warn_undeclared_allocations_in_statements(statement.body, declared, strict, ignored_targets, seen,
                                            diagnostics);
  warn_undeclared_allocations_in_statements(statement.then_body, declared, strict, ignored_targets,
                                            seen, diagnostics);
  warn_undeclared_allocations_in_statements(statement.else_body, declared, strict, ignored_targets,
                                            seen, diagnostics);
  for (const V2MatchCase& match_case : statement.cases) {
    if (match_case.action != nullptr)
      warn_undeclared_allocation_statement(*match_case.action, declared, strict, ignored_targets,
                                           seen, diagnostics);
  }
  if (statement.otherwise != nullptr)
    warn_undeclared_allocation_statement(*statement.otherwise, declared, strict, ignored_targets,
                                         seen, diagnostics);
}

void warn_undeclared_allocations_in_statements(const std::vector<V2Statement>& statements,
                                               const std::set<std::string>& declared, bool strict,
                                               const std::set<std::string>& ignored_targets,
                                               std::set<std::string>& seen,
                                               std::vector<Diagnostic>& diagnostics) {
  for (const V2Statement& statement : statements)
    warn_undeclared_allocation_statement(statement, declared, strict, ignored_targets, seen,
                                         diagnostics);
}

void warn_undeclared_allocations(const V2Program& program, bool strict,
                                 const std::set<std::string>& ignored_targets,
                                 std::vector<Diagnostic>& diagnostics) {
  const std::set<std::string> declared = declared_allocation_names(program);
  std::set<std::string> seen;
  if (strict) {
    for (const V2StateField& field : program.state) {
      if (field.implicit)
        report_undeclared_allocation(field.name, true, seen, diagnostics);
    }
  }
  warn_undeclared_allocations_in_statements(program.body, declared, strict, ignored_targets, seen,
                                            diagnostics);
  for (const V2Rule& rule : program.rules)
    warn_undeclared_allocations_in_statements(rule.body, declared, strict, ignored_targets, seen,
                                              diagnostics);
}

void warn_show_halt_style_statements(const std::vector<V2Statement>& statements,
                                     std::set<int>& seen_lines, std::vector<std::string>& warnings);

bool is_bare_halt_zero(const V2Statement& statement) {
  return statement.kind == "v2_stop" && !statement.items.has_value() &&
         statement.target.has_value() && trim_ascii(*statement.target) == "0";
}

void warn_show_halt_style_statement_children(const V2Statement& statement,
                                             std::set<int>& seen_lines,
                                             std::vector<std::string>& warnings) {
  warn_show_halt_style_statements(statement.body, seen_lines, warnings);
  warn_show_halt_style_statements(statement.then_body, seen_lines, warnings);
  warn_show_halt_style_statements(statement.else_body, seen_lines, warnings);
  for (const V2MatchCase& match_case : statement.cases) {
    if (match_case.action != nullptr)
      warn_show_halt_style_statements(std::vector<V2Statement>{*match_case.action}, seen_lines,
                                      warnings);
  }
  if (statement.otherwise != nullptr)
    warn_show_halt_style_statements(std::vector<V2Statement>{*statement.otherwise}, seen_lines,
                                    warnings);
}

void warn_show_halt_style_statements(const std::vector<V2Statement>& statements,
                                     std::set<int>& seen_lines,
                                     std::vector<std::string>& warnings) {
  for (std::size_t index = 0; index < statements.size(); ++index) {
    const V2Statement& statement = statements.at(index);
    if (statement.kind == "v2_show" && index + 1U < statements.size() &&
        is_bare_halt_zero(statements.at(index + 1U)) &&
        !seen_lines.contains(statements.at(index + 1U).line)) {
      const int line = statements.at(index + 1U).line;
      seen_lines.insert(line);
      warnings.push_back(
          "show(...) immediately followed by halt() at line " + std::to_string(line) +
          ": for one final screen put the visible value directly in halt(...) instead of "
          "describing two display effects");
    }
    warn_show_halt_style_statement_children(statement, seen_lines, warnings);
  }
}

void warn_show_halt_style_rule(const V2Program& program, std::vector<std::string>& warnings) {
  std::set<int> seen_lines;
  warn_show_halt_style_statements(program.body, seen_lines, warnings);
  for (const V2Rule& rule : program.rules)
    warn_show_halt_style_statements(rule.body, seen_lines, warnings);
}

bool expression_is_deterministic_for_test_and_set(const Expression& expression) {
  if (expression.kind == "call") {
    const std::string callee = lower_ascii(expression.callee);
    if (callee == "read" || callee == "entered" || callee == "random")
      return false;
  }
  if (expression.index != nullptr &&
      !expression_is_deterministic_for_test_and_set(*expression.index))
    return false;
  if (expression.expr != nullptr && !expression_is_deterministic_for_test_and_set(*expression.expr))
    return false;
  if (expression.left != nullptr && !expression_is_deterministic_for_test_and_set(*expression.left))
    return false;
  if (expression.right != nullptr &&
      !expression_is_deterministic_for_test_and_set(*expression.right))
    return false;
  return std::all_of(expression.args.begin(), expression.args.end(),
                     expression_is_deterministic_for_test_and_set);
}

enum class IdentifierAccess { None, Read, Write };

IdentifierAccess first_identifier_access(LoweringContext& context,
                                         const std::vector<V2Statement>& statements,
                                         const std::string& name,
                                         std::set<std::string>& seen_rules);

IdentifierAccess statement_first_identifier_access(LoweringContext& context,
                                                   const V2Statement& statement,
                                                   const std::string& name,
                                                   std::set<std::string>& seen_rules) {
  if (statement.kind == "v2_assign" || statement.kind == "v2_update" ||
      statement.kind == "v2_read") {
    if (statement.target.has_value()) {
      const Expression target = parse_expression(*statement.target, statement.line);
      if (target.kind == "identifier" && target.name == name)
        return IdentifierAccess::Write;
      if (expression_contains_identifier(target, name))
        return IdentifierAccess::Read;
    }
  }
  if (statement.target.has_value() && statement.kind != "v2_assign" &&
      statement.kind != "v2_update" && statement.kind != "v2_read") {
    if (expression_contains_identifier(parse_expression(*statement.target, statement.line), name))
      return IdentifierAccess::Read;
  }
  if (statement.expr.has_value() &&
      expression_contains_identifier(parse_expression(*statement.expr, statement.line), name))
    return IdentifierAccess::Read;
  if (statement.predicate.has_value()) {
    const V2Predicate& predicate = *statement.predicate;
    if (expression_contains_identifier(parse_expression(predicate.left, statement.line), name) ||
        expression_contains_identifier(parse_expression(predicate.right, statement.line), name) ||
        (!predicate.collection.empty() &&
         expression_contains_identifier(parse_expression(predicate.collection, statement.line),
                                        name)) ||
        (!predicate.item.empty() &&
         expression_contains_identifier(parse_expression(predicate.item, statement.line), name)))
      return IdentifierAccess::Read;
  }
  for (const std::string& arg : statement.args) {
    if (expression_contains_identifier(parse_expression(arg, statement.line), name))
      return IdentifierAccess::Read;
  }
  if (statement.items.has_value()) {
    for (const DisplayItem& item : *statement.items) {
      if (item.expr.has_value() && expression_contains_identifier(*item.expr, name))
        return IdentifierAccess::Read;
      if (!item.name.empty() && item.name == name)
        return IdentifierAccess::Read;
    }
  }
  if (statement.kind == "v2_invoke" && statement.name.has_value()) {
    const auto rule_it = context.rules.find(*statement.name);
    if (rule_it != context.rules.end() && rule_it->second != nullptr &&
        !seen_rules.contains(*statement.name)) {
      seen_rules.insert(*statement.name);
      const IdentifierAccess access =
          first_identifier_access(context, rule_it->second->body, name, seen_rules);
      seen_rules.erase(*statement.name);
      if (access != IdentifierAccess::None)
        return access;
    }
  }

  for (const std::vector<V2Statement>* block :
       {&statement.body, &statement.then_body, &statement.else_body}) {
    const IdentifierAccess access = first_identifier_access(context, *block, name, seen_rules);
    if (access != IdentifierAccess::None)
      return access;
  }
  for (const V2MatchCase& match_case : statement.cases) {
    if (match_case.action != nullptr) {
      const IdentifierAccess access =
          statement_first_identifier_access(context, *match_case.action, name, seen_rules);
      if (access != IdentifierAccess::None)
        return access;
    }
  }
  if (statement.otherwise != nullptr)
    return statement_first_identifier_access(context, *statement.otherwise, name, seen_rules);
  return IdentifierAccess::None;
}

IdentifierAccess first_identifier_access(LoweringContext& context,
                                         const std::vector<V2Statement>& statements,
                                         const std::string& name,
                                         std::set<std::string>& seen_rules) {
  for (const V2Statement& statement : statements) {
    const IdentifierAccess access =
        statement_first_identifier_access(context, statement, name, seen_rules);
    if (access != IdentifierAccess::None)
      return access;
  }
  return IdentifierAccess::None;
}

bool statements_read_identifier_before_write(LoweringContext& context,
                                             const std::vector<V2Statement>& statements,
                                             const std::string& name) {
  std::set<std::string> seen_rules;
  return first_identifier_access(context, statements, name, seen_rules) == IdentifierAccess::Read;
}

std::optional<std::string> bit_and_membership_for_temp(const LoweringContext& context,
                                                       const std::string& expression_text,
                                                       const std::string& zero_text,
                                                       const std::string& temp, int line) {
  const Expression zero = parse_expression(zero_text, line);
  if (!is_zero_expression(context, zero))
    return std::nullopt;
  const Expression expression = parse_expression(expression_text, line);
  if (expression.kind != "call" || lower_ascii(expression.callee) != "bit_and" ||
      expression.args.size() != 2)
    return std::nullopt;
  const Expression& left = expression.args.at(0);
  const Expression& right = expression.args.at(1);
  if (left.kind == "identifier" && right.kind == "identifier" && right.name == temp)
    return left.name;
  if (left.kind == "identifier" && left.name == temp && right.kind == "identifier")
    return right.name;
  return std::nullopt;
}

bool is_bit_or_update(const Expression& expression, const std::string& collection,
                      const std::string& temp) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "bit_or" ||
      expression.args.size() != 2)
    return false;
  const auto identifier_name = [](const Expression& candidate) -> std::optional<std::string> {
    if (candidate.kind != "identifier")
      return std::nullopt;
    return candidate.name;
  };
  const std::optional<std::string> left = identifier_name(expression.args.at(0));
  const std::optional<std::string> right = identifier_name(expression.args.at(1));
  return (left == collection && right == temp) || (left == temp && right == collection);
}

struct BitOrTestAndSetBranch {
  std::string collection;
  std::vector<V2Statement> else_tail;
  int update_line = 0;
};

std::optional<BitOrTestAndSetBranch> bit_or_test_and_set_branch(LoweringContext& context,
                                                                const V2Statement& assign,
                                                                const V2Statement& branch) {
  if (assign.kind != "v2_assign" || !assign.target.has_value() || !assign.expr.has_value() ||
      branch.kind != "v2_if" || !branch.predicate.has_value())
    return std::nullopt;
  const Expression assigned = parse_expression(*assign.expr, assign.line);
  if (!expression_is_deterministic_for_test_and_set(assigned))
    return std::nullopt;
  const V2Predicate& predicate = *branch.predicate;
  if (predicate.kind != "v2_compare" || predicate.op != "!=" || branch.else_body.empty())
    return std::nullopt;
  std::optional<std::string> collection = bit_and_membership_for_temp(
      context, predicate.left, predicate.right, *assign.target, branch.line);
  if (!collection.has_value()) {
    collection = bit_and_membership_for_temp(context, predicate.right, predicate.left,
                                             *assign.target, branch.line);
  }
  if (!collection.has_value() || *collection == *assign.target)
    return std::nullopt;
  const V2Statement& update = branch.else_body.front();
  if (update.kind != "v2_assign" || !update.target.has_value() || *update.target != *collection ||
      !update.expr.has_value())
    return std::nullopt;
  if (!is_bit_or_update(parse_expression(*update.expr, update.line), *collection, *assign.target))
    return std::nullopt;
  std::vector<V2Statement> else_tail(branch.else_body.begin() + 1, branch.else_body.end());
  if (statements_read_identifier_before_write(context, branch.then_body, *assign.target) ||
      statements_read_identifier_before_write(context, else_tail, *assign.target))
    return std::nullopt;
  return BitOrTestAndSetBranch{
      .collection = *collection,
      .else_tail = std::move(else_tail),
      .update_line = update.line,
  };
}

std::size_t lower_bit_or_test_and_set_negative_arg_prefix(LoweringContext& context,
                                                          const std::vector<V2Statement>& tail) {
  if (tail.empty())
    return 0;
  const V2Statement& call = tail.front();
  if (call.kind != "v2_invoke" || !call.name.has_value() || call.args.size() != 1)
    return 0;
  const auto lowering_it = context.x_param_procs.find(*call.name);
  if (lowering_it == context.x_param_procs.end())
    return 0;
  const Expression arg = parse_expression(call.args.front(), call.line);
  const std::optional<double> value = numeric_value_of_expression(context, arg);
  if (!value.has_value() || std::fabs(*value + 1.0) >= 1e-12)
    return 0;
  context.emitter.emit_op(0x32, "К ЗН",
                          "bit_or test-and-set " + lowering_it->second.param + " = -1", call.line);
  mark_current_x(context, lowering_it->second.param);
  context.emitter.emit_jump(0x53, "ПП", function_label(*call.name), "proc call " + *call.name,
                            call.line);
  clear_current_x_facts(context);
  context.optimizations.push_back(OptimizationReport{
      .name = "bit-or-test-and-set-negative-arg",
      .detail = "Derived " + lowering_it->second.param +
                " = -1 from the negative changed value in a bit_or test-and-set success path at "
                "line " +
                std::to_string(call.line) + ".",
  });
  return 1;
}

bool lower_bit_or_test_and_set_branch(LoweringContext& context, const V2Statement& assign,
                                      const V2Statement& branch) {
  const std::optional<BitOrTestAndSetBranch> match =
      bit_or_test_and_set_branch(context, assign, branch);
  if (!match.has_value() || !assign.expr.has_value())
    return false;

  emit_recall(context, match->collection);
  if (!lower_expression_to_x(context, parse_expression(*assign.expr, assign.line)))
    return false;
  context.emitter.emit_op(0x38, "К ∨", "bit_or test-and-set value", assign.line);
  emit_store(context, match->collection, "bit_or test-and-set " + match->collection);
  context.emitter.emit_op(0x11, "-", "bit_or test-and-set changed", branch.line);

  const std::string changed_label = context.emitter.fresh_label("bit_or_test_set_changed");
  const std::string end_label = context.emitter.fresh_label("bit_or_test_set_end");
  context.emitter.emit_jump(0x5e, "F x=0", changed_label,
                            "false branch for bit_or test-and-set occupied", branch.line);
  if (!lower_statement_block(context, branch.then_body))
    return false;
  context.emitter.emit_jump(0x51, "БП", end_label, "if end", branch.line);
  context.emitter.emit_label(changed_label, {.hidden = true});
  const std::size_t consumed =
      lower_bit_or_test_and_set_negative_arg_prefix(context, match->else_tail);
  std::vector<V2Statement> rest;
  if (consumed < match->else_tail.size())
    rest.assign(match->else_tail.begin() + static_cast<std::ptrdiff_t>(consumed),
                match->else_tail.end());
  if (!lower_statement_block(context, rest))
    return false;
  context.emitter.emit_label(end_label, {.hidden = true});
  context.optimizations.push_back(OptimizationReport{
      .name = "bit-or-test-and-set-branch",
      .detail = "Combined " + match->collection +
                " membership test, bit_or update, and occupied branch at line " +
                std::to_string(branch.line) + ".",
  });
  return true;
}

bool condition_tests_identifier_against_zero(LoweringContext& context, const V2Predicate& predicate,
                                             const std::string& name, const std::string& op,
                                             int line) {
  if (predicate.kind != "v2_compare" || predicate.op != op)
    return false;
  const Expression left = parse_expression(predicate.left, line);
  const Expression right = parse_expression(predicate.right, line);
  return (left.kind == "identifier" && left.name == name && is_zero_expression(context, right)) ||
         (right.kind == "identifier" && right.name == name && is_zero_expression(context, left));
}

bool lower_assign_zero_fallback_store(LoweringContext& context, const V2Statement& assign,
                                      const V2Statement& branch) {
  if (assign.kind != "v2_assign" || !assign.target.has_value() || !assign.expr.has_value() ||
      branch.kind != "v2_if" || !branch.predicate.has_value() || branch.has_else_body ||
      !branch.else_body.empty() || branch.then_body.size() != 1U) {
    return false;
  }
  const Expression target = parse_expression(*assign.target, assign.line);
  if (target.kind != "identifier")
    return false;
  V2Predicate effective_predicate = *branch.predicate;
  if (branch.negated)
    effective_predicate.op = invert_comparison_op(effective_predicate.op);
  if (!condition_tests_identifier_against_zero(context, effective_predicate, target.name, "==",
                                               branch.line)) {
    return false;
  }

  const V2Statement& fallback = branch.then_body.front();
  if (fallback.kind != "v2_assign" || !fallback.target.has_value() ||
      *fallback.target != target.name || !fallback.expr.has_value()) {
    return false;
  }
  const Expression assign_expression = parse_expression(*assign.expr, assign.line);
  const Expression fallback_expression = parse_expression(*fallback.expr, fallback.line);
  if (expression_contains_identifier(fallback_expression, target.name) ||
      !expression_pure_for_substitution(assign_expression) ||
      !expression_pure_for_substitution(fallback_expression)) {
    return false;
  }

  if (!lower_expression_to_x(context, assign_expression))
    return false;
  const std::string store_label = context.emitter.fresh_label("zero_fallback_store");
  context.emitter.emit_jump(0x5e, "F x=0", store_label, "zero fallback " + target.name,
                            branch.line);
  if (!lower_expression_to_x(context, fallback_expression))
    return false;
  context.emitter.emit_label(store_label, {.hidden = true});
  emit_store(context, target.name, "set " + target.name);
  context.optimizations.push_back(OptimizationReport{
      .name = "assign-zero-fallback-store",
      .detail = "Deferred storing " + target.name + " until after its zero fallback at lines " +
                std::to_string(assign.line) + "/" + std::to_string(branch.line) + ".",
  });
  return true;
}

bool lower_max_assign_equality_branch(LoweringContext& context, const V2Statement& assign,
                                      const V2Statement& branch) {
  if (assign.kind != "v2_assign" || !assign.target.has_value() || !assign.expr.has_value() ||
      branch.kind != "v2_if" || !branch.predicate.has_value() || !branch.else_body.empty())
    return false;
  const std::optional<std::string> target = scalar_statement_target_name(assign);
  if (!target.has_value())
    return false;
  const std::optional<Expression> candidate = max_assign_candidate(assign);
  if (!candidate.has_value())
    return false;
  if (!expression_is_deterministic_for_test_and_set(*candidate) ||
      expression_contains_identifier(*candidate, *target))
    return false;
  if (!condition_compares_expression_with_identifier(*branch.predicate, *candidate, *target,
                                                     "==", branch.line))
    return false;

  if (candidate->kind == "identifier" &&
      context.stack_only_state_fields.contains(candidate->name)) {
    if (context.emitter.current_x_variable != candidate->name)
      return false;
    if (statements_read_identifier_before_write(context, branch.then_body, candidate->name))
      return false;
  }

  if (!(candidate->kind == "identifier" && context.emitter.current_x_variable == candidate->name)) {
    if (!lower_expression_to_x(context, *candidate))
      return false;
  }
  if (!lower_expression_to_x(context, identifier_expression(*target)))
    return false;
  context.emitter.emit_op(0x36, "К max", "max-assignment update", assign.line);
  emit_store(context, *target, "set " + *target);
  context.emitter.emit_op(0x11, "-", "max-assignment equality compare", branch.line);

  const std::string false_label = context.emitter.fresh_label("max_assign_false");
  context.emitter.emit_jump(0x5e, "F x=0", false_label, "false branch for max assignment equality",
                            branch.line);
  if (!lower_statement_block(context, branch.then_body))
    return false;
  context.emitter.emit_label(false_label, {.hidden = true});
  context.optimizations.push_back(OptimizationReport{
      .name = "max-assign-equality-branch",
      .detail = "Reused the candidate left on Y by max() for the following equality branch at "
                "line " +
                std::to_string(branch.line) + ".",
  });
  return true;
}

std::optional<std::string> unit_decrement_counted_while_target(LoweringContext& context,
                                                               const V2Statement& loop) {
  if (loop.kind != "v2_while" || !loop.predicate.has_value() || loop.body.empty())
    return std::nullopt;
  const V2Statement& decrement = loop.body.back();
  if (decrement.kind != "v2_update" || !decrement.target.has_value() || !decrement.op.has_value() ||
      !decrement.expr.has_value() || *decrement.op != "-=")
    return std::nullopt;
  const Expression decrement_expr = parse_expression(*decrement.expr, decrement.line);
  const std::optional<int> decrement_value = integer_value_of_expression(context, decrement_expr);
  if (!decrement_value.has_value() || *decrement_value != 1)
    return std::nullopt;

  const V2Predicate& predicate = *loop.predicate;
  if (predicate.kind != "v2_compare")
    return std::nullopt;
  const Expression left = parse_expression(predicate.left, loop.line);
  const Expression right = parse_expression(predicate.right, loop.line);
  const auto identifier_name = [](const Expression& expression) -> std::optional<std::string> {
    if (expression.kind != "identifier")
      return std::nullopt;
    return expression.name;
  };
  const auto numeric_int = [&](const Expression& expression) {
    return integer_value_of_expression(context, expression);
  };

  const std::optional<std::string> left_name = identifier_name(left);
  const std::optional<std::string> right_name = identifier_name(right);
  const std::optional<int> left_value = numeric_int(left);
  const std::optional<int> right_value = numeric_int(right);
  std::optional<std::string> target;
  if (left_name.has_value() && predicate.op == ">=" && right_value == 1)
    target = *left_name;
  else if (left_name.has_value() && predicate.op == ">" && right_value == 0)
    target = *left_name;
  else if (right_name.has_value() && predicate.op == "<=" && left_value == 1)
    target = *right_name;
  else if (right_name.has_value() && predicate.op == "<" && left_value == 0)
    target = *right_name;
  if (!target.has_value() || *target != *decrement.target)
    return std::nullopt;

  const auto register_it = context.register_index_by_name.find(*target);
  if (register_it == context.register_index_by_name.end() ||
      !fl_loop_opcode_for_register(register_it->second).has_value())
    return std::nullopt;
  return target;
}

bool intervening_statement_is_safe_for_counted_loop(LoweringContext& context,
                                                    const V2Statement& statement,
                                                    const std::string& target) {
  std::set<std::string> seen_rules;
  return statement_first_identifier_access(context, statement, target, seen_rules) ==
         IdentifierAccess::None;
}

bool emit_counted_while_body(LoweringContext& context, const V2Statement& loop,
                             const std::pair<int, std::string>& fl, const std::string& label_prefix,
                             const std::string& jump_comment) {
  std::vector<V2Statement> body_tail(loop.body.begin(), loop.body.end() - 1);
  if (statements_always_stop(context, body_tail))
    return false;
  const std::string start_label = context.emitter.fresh_label(label_prefix);
  context.emitter.emit_label(start_label, {.hidden = true});
  clear_current_x_facts(context);
  if (!lower_statement_block(context, body_tail))
    return false;
  context.emitter.emit_jump(fl.first, fl.second, start_label, jump_comment, loop.line);
  return true;
}

bool lower_setup_only_counted_while(LoweringContext& context,
                                    const std::vector<V2Statement>& statements, std::size_t index,
                                    std::size_t& consumed) {
  consumed = 0;
  if (!context.setup_only_counted_loop_init || context.program == nullptr ||
      &statements != &context.program->body)
    return false;

  const V2Statement& loop = statements.at(index);
  if (loop.kind != "v2_while")
    return false;

  const std::optional<std::string> counted_target =
      unit_decrement_counted_while_target(context, loop);
  if (!counted_target.has_value())
    return false;

  const auto field_it = context.state_fields.find(*counted_target);
  if (field_it == context.state_fields.end() || field_it->second == nullptr ||
      !field_it->second->initial.has_value())
    return false;

  const Expression initial_expression =
      parse_expression(*field_it->second->initial, field_it->second->line);
  const std::optional<int> initial_value = integer_value_of_expression(context, initial_expression);
  if (!initial_value.has_value() || *initial_value < 1)
    return false;
  if (scalar_referenced_outside_loop(*context.program, *counted_target, loop))
    return false;

  const auto register_it = context.register_index_by_name.find(*counted_target);
  if (register_it == context.register_index_by_name.end())
    return false;
  const std::optional<std::pair<int, std::string>> fl =
      fl_loop_opcode_for_register(register_it->second);
  if (!fl.has_value())
    return false;

  if (!emit_counted_while_body(context, loop, *fl, "setup_counted_while",
                               "setup-counted while " + *counted_target))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "setup-only-counted-loop-init",
      .detail = "Used setup initializer for " + *counted_target + " and lowered while " +
                *counted_target + " >= 1 through " + fl->second + " at line " +
                std::to_string(loop.line) + ".",
  });
  consumed = 1;
  return true;
}

bool lower_initialized_counted_while_run(LoweringContext& context,
                                         const std::vector<V2Statement>& statements,
                                         std::size_t index, std::size_t& consumed) {
  const V2Statement& initializer = statements.at(index);
  if (initializer.kind != "v2_assign" || !initializer.target.has_value() ||
      !initializer.expr.has_value())
    return false;
  const Expression target_expression = parse_expression(*initializer.target, initializer.line);
  if (target_expression.kind != "identifier")
    return false;
  const Expression initial_expression = parse_expression(*initializer.expr, initializer.line);
  const std::optional<int> initial_value = integer_value_of_expression(context, initial_expression);
  if (!initial_value.has_value() || *initial_value < 1)
    return false;

  for (std::size_t cursor = index + 1; cursor < statements.size(); ++cursor) {
    const V2Statement& statement = statements.at(cursor);
    if (statement.kind == "v2_while") {
      const std::optional<std::string> counted_target =
          unit_decrement_counted_while_target(context, statement);
      if (!counted_target.has_value() || *counted_target != target_expression.name)
        return false;

      const auto register_it = context.register_index_by_name.find(*counted_target);
      if (register_it == context.register_index_by_name.end())
        return false;
      const std::optional<std::pair<int, std::string>> fl =
          fl_loop_opcode_for_register(register_it->second);
      if (!fl.has_value())
        return false;

      if (!lower_statement(context, initializer, nullptr))
        return false;
      if (cursor > index + 1) {
        std::vector<V2Statement> intervening(
            statements.begin() + static_cast<std::ptrdiff_t>(index + 1),
            statements.begin() + static_cast<std::ptrdiff_t>(cursor));
        if (!lower_statement_block(context, intervening))
          return false;
      }

      if (!emit_counted_while_body(context, statement, *fl, "counted_while",
                                   "counted while " + *counted_target))
        return false;
      context.optimizations.push_back(OptimizationReport{
          .name = "initialized-counted-while-loop",
          .detail = "Lowered initialized while " + *counted_target + " >= 1 through " + fl->second +
                    " at line " + std::to_string(statement.line) + ".",
      });
      consumed = cursor - index + 1;
      return true;
    }
    if (!intervening_statement_is_safe_for_counted_loop(context, statement, target_expression.name))
      return false;
  }
  return false;
}

bool lower_repeated_assignment_counted_loop_reuse_run(LoweringContext& context,
                                                      const std::vector<V2Statement>& statements,
                                                      std::size_t index, std::size_t& consumed) {
  consumed = 0;
  if (index + 2U >= statements.size())
    return false;
  const V2Statement& first = statements.at(index);
  if (first.kind != "v2_assign" || !first.target.has_value() || !first.expr.has_value())
    return false;
  const Expression first_target = parse_expression(*first.target, first.line);
  if (first_target.kind != "identifier")
    return false;
  const Expression first_expression = parse_expression(*first.expr, first.line);
  const std::optional<int> first_value = integer_value_of_expression(context, first_expression);
  if (!first_value.has_value() || *first_value < 1)
    return false;

  for (std::size_t cursor = index + 1U; cursor < statements.size(); ++cursor) {
    const V2Statement& candidate = statements.at(cursor);
    if (candidate.kind != "v2_assign" || !candidate.target.has_value() ||
        !candidate.expr.has_value()) {
      return false;
    }
    const Expression candidate_target = parse_expression(*candidate.target, candidate.line);
    if (candidate_target.kind != "identifier")
      return false;
    const Expression candidate_expression = parse_expression(*candidate.expr, candidate.line);
    if (!expression_equals(candidate_expression, first_expression))
      return false;

    for (std::size_t loop_index = cursor + 1U; loop_index < statements.size(); ++loop_index) {
      const V2Statement& loop = statements.at(loop_index);
      if (loop.kind == "v2_while") {
        const std::optional<std::string> counted_target =
            unit_decrement_counted_while_target(context, loop);
        if (!counted_target.has_value() || *counted_target != candidate_target.name)
          return false;
        const auto register_it = context.register_index_by_name.find(*counted_target);
        if (register_it == context.register_index_by_name.end())
          return false;
        const std::optional<std::pair<int, std::string>> fl =
            fl_loop_opcode_for_register(register_it->second);
        if (!fl.has_value())
          return false;

        if (!lower_expression_to_x(context, first_expression))
          return false;
        for (std::size_t store_index = index; store_index <= cursor; ++store_index) {
          const V2Statement& assignment = statements.at(store_index);
          if (!assignment.target.has_value())
            return false;
          const Expression assignment_target =
              parse_expression(*assignment.target, assignment.line);
          if (assignment_target.kind != "identifier")
            return false;
          emit_store(context, assignment_target.name, "set " + assignment_target.name);
        }
        if (loop_index > cursor + 1U) {
          std::vector<V2Statement> intervening(
              statements.begin() + static_cast<std::ptrdiff_t>(cursor + 1U),
              statements.begin() + static_cast<std::ptrdiff_t>(loop_index));
          if (!lower_statement_block(context, intervening))
            return false;
        }
        if (!emit_counted_while_body(context, loop, *fl, "counted_while",
                                     "counted while " + *counted_target))
          return false;
        context.optimizations.push_back(OptimizationReport{
            .name = "repeated-assignment-counted-loop-reuse",
            .detail = "Reused " + expression_to_source(first_expression) + " across " +
                      std::to_string(cursor - index) + " prefix store(s) and counted loop " +
                      *counted_target + " at line " + std::to_string(loop.line) + ".",
        });
        context.optimizations.push_back(OptimizationReport{
            .name = "initialized-counted-while-loop",
            .detail = "Lowered initialized while " + *counted_target + " >= 1 through " +
                      fl->second + " at line " + std::to_string(loop.line) + ".",
        });
        consumed = loop_index - index + 1U;
        return true;
      }
      if (!intervening_statement_is_safe_for_counted_loop(context, loop, candidate_target.name))
        break;
    }
  }
  return false;
}

bool repeated_assignment_feeds_later_unit_decrement_loop(LoweringContext& context,
                                                         const std::vector<V2Statement>& statements,
                                                         std::size_t index) {
  const V2Statement& initializer = statements.at(index);
  if (initializer.kind != "v2_assign" || !initializer.target.has_value() ||
      !initializer.expr.has_value())
    return false;
  const Expression target = parse_expression(*initializer.target, initializer.line);
  if (target.kind != "identifier")
    return false;
  const Expression initial_expression = parse_expression(*initializer.expr, initializer.line);
  const std::optional<int> initial_value = integer_value_of_expression(context, initial_expression);
  if (!initial_value.has_value() || *initial_value < 1)
    return false;
  const auto register_it = context.register_index_by_name.find(target.name);
  if (register_it == context.register_index_by_name.end() ||
      !fl_loop_opcode_for_register(register_it->second).has_value())
    return false;

  for (std::size_t cursor = index + 1U; cursor < statements.size(); ++cursor) {
    const V2Statement& statement = statements.at(cursor);
    if (statement.kind == "v2_while") {
      const std::optional<std::string> counted_target =
          unit_decrement_counted_while_target(context, statement);
      return counted_target.has_value() && *counted_target == target.name;
    }
    if (!intervening_statement_is_safe_for_counted_loop(context, statement, target.name))
      return false;
  }
  return false;
}

bool lower_repeated_assignment_value_run(LoweringContext& context,
                                         const std::vector<V2Statement>& statements,
                                         std::size_t index, std::size_t& consumed) {
  consumed = 0;
  const V2Statement& first = statements.at(index);
  if (first.kind != "v2_assign" || !first.target.has_value() || !first.expr.has_value())
    return false;
  const Expression first_target = parse_expression(*first.target, first.line);
  if (first_target.kind != "identifier" ||
      !context.register_index_by_name.contains(first_target.name))
    return false;
  const Expression first_expression = parse_expression(*first.expr, first.line);
  if (!expression_pure_for_substitution(first_expression))
    return false;

  std::size_t end = index + 1U;
  for (; end < statements.size(); ++end) {
    const V2Statement& candidate = statements.at(end);
    if (candidate.kind != "v2_assign" || !candidate.target.has_value() ||
        !candidate.expr.has_value())
      break;
    const Expression candidate_expression = parse_expression(*candidate.expr, candidate.line);
    if (!expression_equals(candidate_expression, first_expression))
      break;
    if (repeated_assignment_feeds_later_unit_decrement_loop(context, statements, end))
      break;
  }

  if (end - index <= 1U)
    return false;

  std::vector<std::string> targets;
  targets.reserve(end - index);
  for (std::size_t store_index = index; store_index < end; ++store_index) {
    const V2Statement& assignment = statements.at(store_index);
    if (!assignment.target.has_value())
      return false;
    const Expression target = parse_expression(*assignment.target, assignment.line);
    if (target.kind != "identifier" || !context.register_index_by_name.contains(target.name))
      return false;
    targets.push_back(target.name);
  }

  if (!lower_expression_to_x(context, first_expression))
    return false;
  for (const std::string& target : targets) {
    emit_store(context, target, "set " + target);
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "repeated-assignment-value-reuse",
      .detail = "Stored one computed value into " + std::to_string(targets.size()) +
                " consecutive assignment targets at line " + std::to_string(first.line) + ".",
  });
  consumed = end - index;
  return true;
}

std::optional<std::string> random_update_proc_target(LoweringContext& context,
                                                     const std::string& name) {
  const auto rule_it = context.rules.find(name);
  if (rule_it == context.rules.end() || rule_it->second == nullptr ||
      rule_it->second->body.size() != 1U) {
    return std::nullopt;
  }
  const V2Statement& statement = rule_it->second->body.front();
  if (statement.kind != "v2_assign" || !statement.target.has_value() ||
      !statement.expr.has_value()) {
    return std::nullopt;
  }
  const Expression expression = parse_expression(*statement.expr, statement.line);
  if (expression.kind != "call" || lower_ascii(expression.callee) != "random" ||
      !expression.args.empty()) {
    return std::nullopt;
  }
  return *statement.target;
}

std::optional<std::string> random_update_target(LoweringContext& context,
                                                const V2Statement& statement) {
  if (statement.kind == "v2_invoke" && statement.name.has_value() && statement.args.empty())
    return random_update_proc_target(context, *statement.name);
  if (statement.kind != "v2_assign" || !statement.target.has_value() || !statement.expr.has_value())
    return std::nullopt;
  const Expression expression = parse_expression(*statement.expr, statement.line);
  if (expression.kind != "call" || lower_ascii(expression.callee) != "random" ||
      !expression.args.empty()) {
    return std::nullopt;
  }
  return *statement.target;
}

std::optional<std::pair<std::string, std::string>>
match_prior_random_seed_update(LoweringContext& context, const V2Statement& previous,
                               const V2Statement& random_update) {
  if (previous.kind != "v2_assign" || !previous.target.has_value() || !previous.expr.has_value())
    return std::nullopt;
  const Expression previous_expression = parse_expression(*previous.expr, previous.line);
  if (previous_expression.kind != "identifier")
    return std::nullopt;
  const std::string& seed = previous_expression.name;
  const std::optional<std::string> updated_seed = random_update_target(context, random_update);
  if (!updated_seed.has_value() || *updated_seed != seed)
    return std::nullopt;
  return std::pair{*previous.target, seed};
}

void emit_prior_random_seed_update(LoweringContext& context, const std::string& seed,
                                   int recall_line, int update_line) {
  emit_recall(context, seed);
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "prior random " + seed;
  context.emitter.emit_op(0x0e, "В↑", "prior random keep " + seed, update_line);
  context.emitter.emit_op(0x3b, "К СЧ", "random()", update_line);
  clear_current_x_facts(context);
  emit_store(context, seed, "set " + seed);
  (void)recall_line;
}

void additive_terms(const Expression& expression, std::vector<Expression>& terms) {
  if (expression.kind == "binary" && expression.op == "+" && expression.left != nullptr &&
      expression.right != nullptr) {
    additive_terms(*expression.left, terms);
    additive_terms(*expression.right, terms);
    return;
  }
  terms.push_back(expression);
}

std::optional<std::vector<Expression>> prior_random_additive_rest(const Expression& expression,
                                                                  const std::string& previous,
                                                                  const std::string& seed) {
  std::vector<Expression> terms;
  additive_terms(expression, terms);
  bool saw_previous = false;
  bool saw_seed = false;
  std::vector<Expression> rest;
  for (const Expression& term : terms) {
    if (expression_is_identifier_named(term, previous)) {
      if (saw_previous)
        return std::nullopt;
      saw_previous = true;
      continue;
    }
    if (expression_is_identifier_named(term, seed)) {
      if (saw_seed)
        return std::nullopt;
      saw_seed = true;
      continue;
    }
    if (!expression_pure_for_substitution(term))
      return std::nullopt;
    rest.push_back(term);
  }
  if (!saw_previous || !saw_seed)
    return std::nullopt;
  return rest;
}

bool expression_can_use_prior_random_prefix(const Expression& expression,
                                            const std::string& previous, const std::string& seed) {
  if (prior_random_additive_rest(expression, previous, seed).has_value())
    return true;
  if (expression.kind == "binary" && expression.left != nullptr && expression.right != nullptr) {
    return expression_can_use_prior_random_prefix(*expression.left, previous, seed) ||
           ((expression.op == "+" || expression.op == "*") &&
            expression_can_use_prior_random_prefix(*expression.right, previous, seed));
  }
  return expression.kind == "call" && lower_ascii(expression.callee) == "int" &&
         expression.args.size() == 1U &&
         expression_can_use_prior_random_prefix(expression.args.front(), previous, seed);
}

bool lower_expression_with_prior_random_prefix(LoweringContext& context,
                                               const Expression& expression,
                                               const std::string& previous, const std::string& seed,
                                               int line) {
  if (const std::optional<std::vector<Expression>> rest =
          prior_random_additive_rest(expression, previous, seed)) {
    context.emitter.emit_op(0x10, "+", "prior random + random()", line);
    clear_current_x_facts(context);
    for (const Expression& term : *rest) {
      if (!lower_expression_to_x(context, term))
        return false;
      context.emitter.emit_op(0x10, "+", "prior random additive term", line);
      clear_current_x_facts(context);
    }
    return true;
  }

  if (expression.kind == "binary" && expression.left != nullptr && expression.right != nullptr) {
    const std::optional<std::pair<int, std::string>> opcode = binary_opcode(expression.op);
    if (!opcode.has_value())
      return false;
    if (expression_can_use_prior_random_prefix(*expression.left, previous, seed)) {
      if (!lower_expression_with_prior_random_prefix(context, *expression.left, previous, seed,
                                                     line))
        return false;
      if (!lower_expression_to_x(context, *expression.right))
        return false;
      context.emitter.emit_op(opcode->first, opcode->second, "expr " + expression.op, line);
      clear_current_x_facts(context);
      return true;
    }
    if ((expression.op == "+" || expression.op == "*") &&
        expression_can_use_prior_random_prefix(*expression.right, previous, seed)) {
      if (!lower_expression_with_prior_random_prefix(context, *expression.right, previous, seed,
                                                     line))
        return false;
      if (!lower_expression_to_x(context, *expression.left))
        return false;
      context.emitter.emit_op(opcode->first, opcode->second, "expr " + expression.op, line);
      clear_current_x_facts(context);
      return true;
    }
    return false;
  }

  if (expression.kind == "call" && lower_ascii(expression.callee) == "int" &&
      expression.args.size() == 1U &&
      expression_can_use_prior_random_prefix(expression.args.front(), previous, seed)) {
    if (!lower_expression_with_prior_random_prefix(context, expression.args.front(), previous, seed,
                                                   line))
      return false;
    context.emitter.emit_op(0x34, "К [x]", "int()", line);
    clear_current_x_facts(context);
    return true;
  }

  return false;
}

bool lower_expression_from_prior_random(LoweringContext& context, const Expression& expression,
                                        const std::string& previous, const std::string& seed,
                                        int recall_line, int update_line, int line) {
  emit_prior_random_seed_update(context, seed, recall_line, update_line);
  return lower_expression_with_prior_random_prefix(context, expression, previous, seed, line);
}

bool lower_prior_random_stack_reuse_run(LoweringContext& context,
                                        const std::vector<V2Statement>& statements,
                                        std::size_t index, std::size_t& consumed) {
  consumed = 0;
  if (index + 2U >= statements.size())
    return false;
  const V2Statement& previous = statements.at(index);
  const V2Statement& random_update = statements.at(index + 1U);
  const V2Statement& consumer = statements.at(index + 2U);
  const std::optional<std::pair<std::string, std::string>> seed_update =
      match_prior_random_seed_update(context, previous, random_update);
  if (!seed_update.has_value() || consumer.kind != "v2_assign" || !consumer.target.has_value() ||
      !consumer.expr.has_value()) {
    return false;
  }
  const std::string& temp = seed_update->first;
  const std::string& seed = seed_update->second;
  if (*consumer.target != temp)
    return false;
  const Expression consumer_expression = parse_expression(*consumer.expr, consumer.line);
  if (!expression_contains_identifier(consumer_expression, temp) ||
      !expression_contains_identifier(consumer_expression, seed))
    return false;
  if (!expression_can_use_prior_random_prefix(consumer_expression, temp, seed))
    return false;
  if (!lower_expression_from_prior_random(context, consumer_expression, temp, seed, previous.line,
                                          random_update.line, consumer.line))
    return false;
  emit_store(context, *consumer.target, "set " + *consumer.target);
  context.optimizations.push_back(OptimizationReport{
      .name = "prior-random-stack-reuse",
      .detail = "Kept previous " + seed + " in Y while updating " + seed + " with random() for " +
                temp + " at line " + std::to_string(consumer.line) + ".",
  });
  consumed = 3;
  return true;
}

bool prior_random_less_than_current_predicate(const LoweringContext& context,
                                              const V2Predicate& predicate, const std::string& temp,
                                              const std::string& seed, int line) {
  if (predicate.kind != "v2_compare" || predicate.op != "<")
    return false;
  try {
    const Expression left = parse_expression(predicate.left, line);
    const Expression right = parse_expression(predicate.right, line);
    if (!is_zero_expression(context, right))
      return false;
    return left.kind == "binary" && left.op == "-" && left.left != nullptr &&
           left.right != nullptr && expression_is_identifier_named(*left.left, temp) &&
           expression_is_identifier_named(*left.right, seed);
  } catch (const std::exception&) {
    return false;
  }
}

bool lower_prior_random_branch_stack_reuse_run(LoweringContext& context,
                                               const std::vector<V2Statement>& statements,
                                               std::size_t index, std::size_t& consumed) {
  consumed = 0;
  if (index + 2U >= statements.size())
    return false;
  const V2Statement& previous = statements.at(index);
  const V2Statement& random_update = statements.at(index + 1U);
  const V2Statement& branch = statements.at(index + 2U);
  const std::optional<std::pair<std::string, std::string>> seed_update =
      match_prior_random_seed_update(context, previous, random_update);
  if (!seed_update.has_value() || branch.kind != "v2_if" || !branch.predicate.has_value())
    return false;
  const std::string& temp = seed_update->first;
  const std::string& seed = seed_update->second;
  std::vector<V2Statement> tail(statements.begin() + static_cast<std::ptrdiff_t>(index + 3U),
                                statements.end());
  if (statements_read_identifier_before_write(context, tail, temp))
    return false;
  if (!prior_random_less_than_current_predicate(context, *branch.predicate, temp, seed,
                                                branch.line))
    return false;

  emit_prior_random_seed_update(context, seed, previous.line, random_update.line);
  context.emitter.emit_op(0x11, "-", "prior random compare", branch.line);

  const std::string false_label = context.emitter.fresh_label("prior_random_false");
  const bool then_stops = statements_always_stop(context, branch.then_body);
  const bool has_else = branch.has_else_body || !branch.else_body.empty();
  const std::string end_label =
      has_else && !then_stops ? context.emitter.fresh_label("prior_random_end") : "";
  context.emitter.emit_jump(0x5c, "F x<0", false_label, "false branch for prior random <",
                            branch.line);
  if (!lower_statement_block(context, branch.then_body))
    return false;
  if (has_else) {
    if (!then_stops)
      context.emitter.emit_jump(0x51, "БП", end_label, "if end", branch.line);
    context.emitter.emit_label(false_label, {.hidden = true});
    if (!lower_statement_block(context, branch.else_body))
      return false;
    if (!then_stops)
      context.emitter.emit_label(end_label, {.hidden = true});
  } else {
    context.emitter.emit_label(false_label, {.hidden = true});
  }

  context.optimizations.push_back(OptimizationReport{
      .name = "prior-random-branch-stack-reuse",
      .detail = "Kept previous " + seed + " in Y while updating " + seed +
                " for a following branch at line " + std::to_string(branch.line) + ".",
  });
  consumed = 3;
  return true;
}

struct PriorRandomFractionalDecrementPlan {
  Expression amount;
  Expression divisor;
  std::string factor;
  std::string scale;
};

bool expression_is_numeric_value(const LoweringContext& context, const Expression& expression,
                                 double expected) {
  const std::optional<double> value = numeric_value_of_expression(context, expression);
  return value.has_value() && std::fabs(*value - expected) < 1e-12;
}

bool fractional_decrement_update_matches(const V2Statement& update, const Expression& amount,
                                         const std::string& temp) {
  if (!update.target.has_value() || !update.expr.has_value())
    return false;
  const Expression target = parse_expression(*update.target, update.line);
  if (!expression_equals(target, amount))
    return false;
  const Expression expression = parse_expression(*update.expr, update.line);
  if (update.kind == "v2_update" && update.op.has_value() && *update.op == "-=")
    return expression_is_identifier_named(expression, temp);
  return update.kind == "v2_assign" && expression.kind == "binary" && expression.op == "-" &&
         expression.left != nullptr && expression.right != nullptr &&
         expression_equals(*expression.left, amount) &&
         expression_is_identifier_named(*expression.right, temp);
}

bool fractional_decrement_guard_matches(LoweringContext& context, const V2Statement& guarded,
                                        const Expression& amount, const std::string& temp) {
  if (guarded.kind != "v2_if" || !guarded.predicate.has_value() || guarded.negated)
    return false;
  const V2Predicate& predicate = *guarded.predicate;
  if (predicate.kind != "v2_compare" || predicate.op != "<=")
    return false;
  const Expression left = parse_expression(predicate.left, guarded.line);
  const Expression right = parse_expression(predicate.right, guarded.line);
  if (!is_zero_expression(context, right))
    return false;
  if (left.kind != "binary" || left.op != "-" || left.left == nullptr || left.right == nullptr)
    return false;
  const Expression& frac = *left.left;
  if (frac.kind != "call" || lower_ascii(frac.callee) != "frac" || frac.args.size() != 1U ||
      !expression_equals(frac.args.front(), amount)) {
    return false;
  }
  if (!expression_is_identifier_named(*left.right, temp))
    return false;
  if (!statements_are_domain_error_trap(context, guarded.then_body))
    return false;
  return guarded.else_body.size() == 1U &&
         fractional_decrement_update_matches(guarded.else_body.front(), amount, temp);
}

std::optional<PriorRandomFractionalDecrementPlan>
match_prior_random_fractional_decrement(LoweringContext& context, const Expression& expression,
                                        const std::string& temp, const std::string& seed,
                                        const V2Statement& guarded) {
  if (expression.kind != "binary" || expression.op != "/" || expression.left == nullptr ||
      expression.right == nullptr || expression.right->kind != "number") {
    return std::nullopt;
  }
  const std::string scale =
      expression.right->raw.empty() ? expression.right->text : expression.right->raw;
  const Expression& int_call = *expression.left;
  if (int_call.kind != "call" || lower_ascii(int_call.callee) != "int" ||
      int_call.args.size() != 1U) {
    return std::nullopt;
  }
  const Expression& ratio = int_call.args.front();
  if (ratio.kind != "binary" || ratio.op != "/" || ratio.left == nullptr ||
      ratio.right == nullptr || ratio.right->kind != "indexed") {
    return std::nullopt;
  }
  const Expression divisor = *ratio.right;
  const Expression& with_distance = *ratio.left;
  if (with_distance.kind != "binary" || with_distance.op != "*" || with_distance.left == nullptr ||
      with_distance.right == nullptr || with_distance.right->kind != "indexed") {
    return std::nullopt;
  }
  const Expression amount = *with_distance.right;
  const Expression& with_factor = *with_distance.left;
  if (with_factor.kind != "binary" || with_factor.op != "*" || with_factor.left == nullptr ||
      with_factor.right == nullptr || with_factor.right->kind != "number") {
    return std::nullopt;
  }
  const std::string factor =
      with_factor.right->raw.empty() ? with_factor.right->text : with_factor.right->raw;
  std::vector<Expression> terms;
  additive_terms(*with_factor.left, terms);
  const bool has_temp = std::any_of(terms.begin(), terms.end(), [&](const Expression& term) {
    return expression_is_identifier_named(term, temp);
  });
  const bool has_seed = std::any_of(terms.begin(), terms.end(), [&](const Expression& term) {
    return expression_is_identifier_named(term, seed);
  });
  const bool has_one = std::any_of(terms.begin(), terms.end(), [&](const Expression& term) {
    return expression_is_numeric_value(context, term, 1.0);
  });
  if (terms.size() != 3U || !has_temp || !has_seed || !has_one)
    return std::nullopt;
  if (!fractional_decrement_guard_matches(context, guarded, amount, temp))
    return std::nullopt;
  return PriorRandomFractionalDecrementPlan{
      .amount = amount,
      .divisor = divisor,
      .factor = factor,
      .scale = scale,
  };
}

bool previous_statement_leaves_assignable_in_x(const std::vector<V2Statement>& statements,
                                               std::size_t index, const Expression& amount) {
  if (index == 0)
    return false;
  const V2Statement& previous = statements.at(index - 1U);
  if (previous.kind != "v2_assign" && previous.kind != "v2_update")
    return false;
  if (!previous.target.has_value())
    return false;
  try {
    return expression_equals(parse_expression(*previous.target, previous.line), amount);
  } catch (const std::exception&) {
    return false;
  }
}

bool lower_prior_random_fractional_decrement_run(LoweringContext& context,
                                                 const std::vector<V2Statement>& statements,
                                                 std::size_t index, std::size_t& consumed) {
  consumed = 0;
  if (index + 3U >= statements.size())
    return false;
  const V2Statement& previous = statements.at(index);
  const V2Statement& random_update = statements.at(index + 1U);
  const V2Statement& consumer = statements.at(index + 2U);
  const V2Statement& guarded = statements.at(index + 3U);
  const std::optional<std::pair<std::string, std::string>> seed_update =
      match_prior_random_seed_update(context, previous, random_update);
  if (!seed_update.has_value() || consumer.kind != "v2_assign" || !consumer.target.has_value() ||
      !consumer.expr.has_value() || guarded.kind != "v2_if") {
    return false;
  }
  const std::string& temp = seed_update->first;
  const std::string& seed = seed_update->second;
  if (*consumer.target != temp)
    return false;
  std::vector<V2Statement> tail(statements.begin() + static_cast<std::ptrdiff_t>(index + 4U),
                                statements.end());
  if (statements_read_identifier_before_write(context, tail, temp))
    return false;
  const Expression consumer_expression = parse_expression(*consumer.expr, consumer.line);
  const std::optional<PriorRandomFractionalDecrementPlan> plan =
      match_prior_random_fractional_decrement(context, consumer_expression, temp, seed, guarded);
  if (!plan.has_value())
    return false;

  const bool amount_already_in_x =
      previous_statement_leaves_assignable_in_x(statements, index, plan->amount);
  const std::string amount_text = assignable_target_text(plan->amount);
  if (!amount_already_in_x &&
      !emit_assignable_recall(context, plan->amount, "fractional decrement " + amount_text,
                              previous.line)) {
    return false;
  }
  context.emitter.emit_op(0x35, "К {x}", "fractional decrement amount frac", previous.line);
  emit_prior_random_seed_update(context, seed, previous.line, random_update.line);
  context.emitter.emit_op(0x10, "+", "prior random + random()", consumer.line);
  emit_number_or_preload(context, "1");
  context.emitter.emit_op(0x10, "+", "prior random additive term", consumer.line);
  emit_number_or_preload(context, plan->factor);
  context.emitter.emit_op(0x12, "*", "fractional decrement factor", consumer.line);
  if (!emit_assignable_recall(
          context, plan->divisor,
          "fractional decrement divisor " + assignable_target_text(plan->divisor), consumer.line))
    return false;
  if (!emit_assignable_recall(context, plan->amount,
                              "fractional decrement numerator " + amount_text, consumer.line))
    return false;
  context.emitter.emit_op(0x13, "/", "fractional decrement amount ratio", consumer.line);
  context.emitter.emit_op(0x13, "/", "fractional decrement scaled step", consumer.line);
  context.emitter.emit_op(0x34, "К [x]", "fractional decrement int step", consumer.line);
  emit_number_or_preload(context, plan->scale);
  context.emitter.emit_op(0x13, "/", "fractional decrement scale", consumer.line);
  context.emitter.emit_op(0x11, "-", "fractional decrement remaining amount", guarded.line);
  context.emitter.emit_op(0x17, "F lg", "fractional decrement domain-error guard trap",
                          guarded.line);
  context.emitter.emit_op(0x0f, "F Вx", "fractional decrement restore remaining amount",
                          guarded.line);
  if (!emit_assignable_recall(context, plan->amount, "fractional decrement integer " + amount_text,
                              guarded.line))
    return false;
  context.emitter.emit_op(0x34, "К [x]", "fractional decrement integer part", guarded.line);
  context.emitter.emit_op(0x10, "+", "fractional decrement rebuild value", guarded.line);
  if (!emit_assignable_store(context, plan->amount, guarded.line))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "prior-random-fractional-decrement",
      .detail = "Kept previous " + seed + " and frac(" + amount_text +
                ") on the stack while applying guarded fractional decrement" +
                (amount_already_in_x ? " and reused the just-stored amount in X." : "."),
  });
  consumed = 4;
  return true;
}

bool predicate_is_truthy_identifier(const LoweringContext& context, const V2Predicate& predicate,
                                    const std::string& name, int source_line) {
  if (predicate.kind != "v2_compare" || predicate.op != "!=")
    return false;
  const Expression left = parse_expression(predicate.left, source_line);
  const Expression right = parse_expression(predicate.right, source_line);
  return left.kind == "identifier" && left.name == name && is_zero_expression(context, right);
}

std::optional<int> expression_is_source_minus_integer(LoweringContext& context,
                                                      const std::string& text,
                                                      const std::string& source, int source_line) {
  const Expression expression = parse_expression(text, source_line);
  if (expression.kind != "binary" || expression.op != "-" || expression.left == nullptr ||
      expression.right == nullptr || expression.left->kind != "identifier" ||
      expression.left->name != source) {
    return std::nullopt;
  }
  return integer_value_of_expression(context, *expression.right);
}

std::optional<int> expression_is_source_minus_integer(LoweringContext& context,
                                                      const Expression& expression,
                                                      const std::string& source) {
  if (expression.kind != "binary" || expression.op != "-" || expression.left == nullptr ||
      expression.right == nullptr || expression.left->kind != "identifier" ||
      expression.left->name != source) {
    return std::nullopt;
  }
  return integer_value_of_expression(context, *expression.right);
}

bool expression_is_int_reciprocal_of_temp(const Expression& expression, const std::string& temp) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "int" ||
      expression.args.size() != 1)
    return false;
  const Expression& arg = expression.args.front();
  if (arg.kind != "binary" || arg.op != "/" || arg.left == nullptr || arg.right == nullptr)
    return false;
  return arg.left->kind == "number" &&
         trim_ascii(arg.left->raw.empty() ? arg.left->text : arg.left->raw) == "1" &&
         arg.right->kind == "identifier" && arg.right->name == temp;
}

bool expression_is_sign_of_source_minus_integer(LoweringContext& context,
                                                const Expression& expression,
                                                const std::string& source, int residual_value,
                                                int source_line) {
  if (expression.kind != "call" || lower_ascii(expression.callee) != "sign" ||
      expression.args.size() != 1)
    return false;
  (void)source_line;
  return expression_is_source_minus_integer(context, expression.args.front(), source) ==
         residual_value;
}

bool stop_targets(const V2Statement& statement, const std::string& target) {
  return statement.kind == "v2_stop" && statement.target.has_value() &&
         trim_ascii(*statement.target) == target;
}

bool lower_dead_source_residual_temp_reuse(LoweringContext& context,
                                           const std::vector<V2Statement>& statements,
                                           std::size_t index, std::size_t& consumed) {
  if (index + 2U >= statements.size())
    return false;

  const V2Statement& read = statements.at(index);
  const V2Statement& residual_assign = statements.at(index + 1U);
  const V2Statement& outer = statements.at(index + 2U);
  if (read.kind != "v2_read" || !read.target.has_value() || residual_assign.kind != "v2_assign" ||
      !residual_assign.target.has_value() || !residual_assign.expr.has_value() ||
      outer.kind != "v2_if" || !outer.predicate.has_value() || !outer.negated ||
      outer.then_body.size() != 1 || outer.else_body.size() != 2) {
    return false;
  }

  const std::string source = *read.target;
  const std::string temp = *residual_assign.target;
  const std::optional<int> residual_value = expression_is_source_minus_integer(
      context, *residual_assign.expr, source, residual_assign.line);
  if (!residual_value.has_value() ||
      !predicate_is_truthy_identifier(context, *outer.predicate, temp, outer.line) ||
      !stop_targets(outer.then_body.front(), "0")) {
    return false;
  }

  const V2Statement& reciprocal_assign = outer.else_body.at(0);
  const V2Statement& inner = outer.else_body.at(1);
  if (reciprocal_assign.kind != "v2_assign" || !reciprocal_assign.target.has_value() ||
      *reciprocal_assign.target != temp || !reciprocal_assign.expr.has_value() ||
      inner.kind != "v2_if" || !inner.predicate.has_value() || !inner.negated ||
      inner.then_body.size() != 2 || inner.else_body.size() != 1 ||
      !predicate_is_truthy_identifier(context, *inner.predicate, temp, inner.line)) {
    return false;
  }
  const Expression reciprocal = parse_expression(*reciprocal_assign.expr, reciprocal_assign.line);
  if (!expression_is_int_reciprocal_of_temp(reciprocal, temp))
    return false;

  const V2Statement& sign_assign = inner.then_body.front();
  const V2Statement& sign_halt = inner.then_body.back();
  const V2Statement& else_halt = inner.else_body.front();
  if (sign_assign.kind != "v2_assign" || !sign_assign.target.has_value() ||
      *sign_assign.target != temp || !sign_assign.expr.has_value() ||
      !stop_targets(sign_halt, temp) || !stop_targets(else_halt, temp)) {
    return false;
  }
  const Expression sign_expr = parse_expression(*sign_assign.expr, sign_assign.line);
  if (!expression_is_sign_of_source_minus_integer(context, sign_expr, source, *residual_value,
                                                  sign_assign.line)) {
    return false;
  }

  context.emitter.emit_op(0x50, "С/П", "read " + source, read.line);
  mark_current_x(context, source);
  emit_store(context, source, "read " + source);
  emit_number_or_preload(context, std::to_string(*residual_value));
  context.emitter.emit_op(0x11, "-", "expr -", residual_assign.line);
  emit_store(context, source, "set " + source);

  const std::string outer_else_label = context.emitter.fresh_label("residual_temp_else");
  context.emitter.emit_jump(0x5e, "F x=0", outer_else_label, "false branch for ==", outer.line);
  context.emitter.emit_op(0x50, "С/П", "halt", outer.then_body.front().line);

  context.emitter.emit_label(outer_else_label, {.hidden = true});
  mark_current_x(context, source);
  context.emitter.emit_op(0x23, "F 1/x", "reciprocal division", reciprocal_assign.line);
  context.emitter.emit_op(0x34, "К [x]", "int()", reciprocal_assign.line);

  const std::string inner_else_label = context.emitter.fresh_label("residual_temp_inner_else");
  context.emitter.emit_jump(0x5e, "F x=0", inner_else_label, "false branch for ==", inner.line);
  emit_recall(context, source);
  context.emitter.emit_op(0x32, "К ЗН", "sign()", sign_assign.line);
  context.emitter.emit_op(0x50, "С/П", "halt", sign_halt.line);

  context.emitter.emit_label(inner_else_label, {.hidden = true});
  context.emitter.emit_op(0x50, "С/П", "halt", else_halt.line);
  context.optimizations.push_back(OptimizationReport{
      .name = "dead-source-residual-temp-reuse",
      .detail = "Reused " + source + " as a residual temporary before allocation.",
  });
  consumed = 3;
  return true;
}

bool statements_tail_assigns_or_stops(LoweringContext& context,
                                      const std::vector<V2Statement>& statements,
                                      const std::string& target);

bool statement_tail_assigns_or_stops(LoweringContext& context, const V2Statement& statement,
                                     const std::string& target) {
  if (statement.kind == "v2_stop")
    return true;
  if (statement.kind == "v2_assign" && statement.target.has_value() && *statement.target == target)
    return true;
  if (statement.kind == "v2_block")
    return statements_tail_assigns_or_stops(context, statement.body, target);
  if (statement.kind == "v2_invoke" && statement.name.has_value() && statement.args.empty() &&
      context.inline_statement_rules.contains(*statement.name)) {
    const auto rule_it = context.rules.find(*statement.name);
    return rule_it != context.rules.end() &&
           statements_tail_assigns_or_stops(context, rule_it->second->body, target);
  }
  if (statement.kind == "v2_if" && !statement.else_body.empty()) {
    return statements_tail_assigns_or_stops(context, statement.then_body, target) &&
           statements_tail_assigns_or_stops(context, statement.else_body, target);
  }
  return false;
}

bool statements_tail_assigns_or_stops(LoweringContext& context,
                                      const std::vector<V2Statement>& statements,
                                      const std::string& target) {
  if (statements.empty())
    return false;
  return statement_tail_assigns_or_stops(context, statements.back(), target);
}

void emit_stack_resident_restore(LoweringContext& context, std::size_t temp_index,
                                 std::size_t temp_count, int line) {
  for (const core::emit::StackResidentRestoreOp op :
       core::emit::stack_resident_restore_ops(temp_index, temp_count)) {
    if (op == core::emit::StackResidentRestoreOp::Reverse) {
      context.emitter.emit_op(0x25, "F reverse", "stack-resident temp restore", line);
    } else {
      context.emitter.emit_op(0x14, "X↔Y", "stack-resident temp restore", line);
    }
  }
}

bool stack_expression_references_any_temp(const Expression& expression,
                                          const std::vector<std::string>& temps) {
  return std::any_of(temps.begin(), temps.end(), [&](const std::string& temp) {
    return core::emit::count_identifier_reads(expression, temp) > 0;
  });
}

bool lower_stack_resident_expression_to_x(LoweringContext& context, const Expression& expression,
                                          const std::vector<std::string>& temps, int line) {
  if (expression.kind == "identifier") {
    const auto found = std::find(temps.begin(), temps.end(), expression.name);
    if (found == temps.end())
      return lower_expression_to_x(context, expression);
    emit_stack_resident_restore(context, static_cast<std::size_t>(found - temps.begin()),
                                temps.size(), line);
    mark_current_x(context, expression.name);
    return true;
  }
  if (expression.kind == "number" || expression.kind == "string" || expression.kind == "indexed" ||
      expression.kind == "call") {
    return lower_expression_to_x(context, expression);
  }
  if (expression.kind == "unary" && expression.expr != nullptr) {
    if (!lower_stack_resident_expression_to_x(context, *expression.expr, temps, line))
      return false;
    context.emitter.emit_op(0x0b, "/-/", "stack-resident unary minus", line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }
  if (expression.kind != "binary" || expression.left == nullptr || expression.right == nullptr)
    return false;

  const bool left_refs = stack_expression_references_any_temp(*expression.left, temps);
  const bool right_refs = stack_expression_references_any_temp(*expression.right, temps);
  const std::optional<std::pair<int, std::string>> opcode = binary_opcode(expression.op);
  if (!opcode.has_value())
    return false;

  if (left_refs && right_refs && expression.left->kind == "identifier" &&
      expression.right->kind == "identifier") {
    const auto left = std::find(temps.begin(), temps.end(), expression.left->name);
    const auto right = std::find(temps.begin(), temps.end(), expression.right->name);
    if (left == temps.end() || right == temps.end())
      return false;
    const std::size_t left_index = static_cast<std::size_t>(left - temps.begin());
    const std::size_t right_index = static_cast<std::size_t>(right - temps.begin());
    if (temps.size() == 2U) {
      if (left_index == 1U && right_index == 0U)
        context.emitter.emit_op(0x14, "X↔Y", "stack-resident operand order", line);
      context.emitter.emit_op(opcode->first, opcode->second, "expr " + opcode->second, line);
      context.emitter.current_x_variable.reset();
      context.emitter.current_x_aliases.clear();
      return true;
    }
    emit_stack_resident_restore(context, right_index, temps.size(), line);
    emit_stack_resident_restore(context, left_index, temps.size(), line);
    context.emitter.emit_op(0x14, "X↔Y", "stack-resident operand order", line);
    context.emitter.emit_op(opcode->first, opcode->second, "expr " + opcode->second, line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }

  if (left_refs) {
    if (!lower_stack_resident_expression_to_x(context, *expression.left, temps, line))
      return false;
    if (!lower_expression_to_x(context, *expression.right))
      return false;
    context.emitter.emit_op(opcode->first, opcode->second, "expr " + opcode->second, line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }

  if (!lower_stack_resident_expression_to_x(context, *expression.right, temps, line))
    return false;
  if (!lower_expression_to_x(context, *expression.left))
    return false;
  if (expression.op != "+" && expression.op != "*")
    context.emitter.emit_op(0x14, "X↔Y", "stack-resident operand order", line);
  context.emitter.emit_op(opcode->first, opcode->second, "expr " + opcode->second, line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  return true;
}

bool same_indexed_cell_expression(const Expression& expression, const Expression& target) {
  if (expression.kind != "indexed" || target.kind != "indexed" || expression.index == nullptr ||
      target.index == nullptr) {
    return false;
  }
  return expression.base == target.base && expression.field == target.field &&
         expression_to_json(*expression.index) == expression_to_json(*target.index);
}

bool expression_references_same_indexed_cell(const Expression& expression,
                                             const Expression& target) {
  if (same_indexed_cell_expression(expression, target))
    return true;
  if (expression.index != nullptr &&
      expression_references_same_indexed_cell(*expression.index, target))
    return true;
  if (expression.expr != nullptr &&
      expression_references_same_indexed_cell(*expression.expr, target))
    return true;
  if (expression.left != nullptr &&
      expression_references_same_indexed_cell(*expression.left, target))
    return true;
  if (expression.right != nullptr &&
      expression_references_same_indexed_cell(*expression.right, target))
    return true;
  return std::any_of(expression.args.begin(), expression.args.end(), [&](const Expression& arg) {
    return expression_references_same_indexed_cell(arg, target);
  });
}

bool can_compile_indexed_stack_temp_expression(const Expression& expression,
                                               const std::string& temp) {
  if (core::emit::count_identifier_reads(expression, temp) != 1)
    return false;
  if (expression.kind == "identifier")
    return expression.name == temp;
  if (expression.kind == "unary" && expression.expr != nullptr)
    return can_compile_indexed_stack_temp_expression(*expression.expr, temp);
  if (expression.kind == "binary" && expression.left != nullptr && expression.right != nullptr) {
    const int left_reads = core::emit::count_identifier_reads(*expression.left, temp);
    const int right_reads = core::emit::count_identifier_reads(*expression.right, temp);
    if (left_reads == 1 && right_reads == 0) {
      return can_compile_indexed_stack_temp_expression(*expression.left, temp) &&
             expression_pure_for_substitution(*expression.right);
    }
    if (left_reads == 0 && right_reads == 1) {
      return can_compile_indexed_stack_temp_expression(*expression.right, temp) &&
             expression_pure_for_substitution(*expression.left) &&
             (expression.op == "+" || expression.op == "*" ||
              is_simple_stack_load(*expression.left));
    }
  }
  return false;
}

bool lower_indexed_stack_temp_expression_to_x(
    LoweringContext& context, const Expression& expression, const std::string& temp,
    const Expression& indexed_target,
    const std::optional<PreparedIndexedSelector>& prepared_selector, int line) {
  if (expression.kind == "identifier" && expression.name == temp) {
    mark_current_x(context, temp);
    return true;
  }
  if (same_indexed_cell_expression(expression, indexed_target)) {
    if (prepared_selector.has_value()) {
      emit_prepared_indirect_indexed_recall(context, indexed_target, *prepared_selector, line);
      return true;
    }
    return emit_indexed_recall(context, indexed_target, line);
  }
  if (core::emit::count_identifier_reads(expression, temp) == 0)
    return lower_expression_to_x(context, expression);
  if (expression.kind == "unary" && expression.expr != nullptr) {
    if (!lower_indexed_stack_temp_expression_to_x(context, *expression.expr, temp, indexed_target,
                                                  prepared_selector, line))
      return false;
    context.emitter.emit_op(0x0b, "/-/", "stack temp unary minus", line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }
  if (expression.kind != "binary" || expression.left == nullptr || expression.right == nullptr)
    return false;

  const int left_reads = core::emit::count_identifier_reads(*expression.left, temp);
  const std::optional<std::pair<int, std::string>> opcode = binary_opcode(expression.op);
  if (!opcode.has_value())
    return false;

  if (left_reads == 1) {
    if (!lower_indexed_stack_temp_expression_to_x(context, *expression.left, temp, indexed_target,
                                                  prepared_selector, line))
      return false;
    if (!lower_indexed_stack_temp_expression_to_x(context, *expression.right, temp, indexed_target,
                                                  prepared_selector, line))
      return false;
    context.emitter.emit_op(opcode->first, opcode->second, "expr " + opcode->second, line);
    context.emitter.current_x_variable.reset();
    context.emitter.current_x_aliases.clear();
    return true;
  }

  if (!lower_indexed_stack_temp_expression_to_x(context, *expression.right, temp, indexed_target,
                                                prepared_selector, line))
    return false;
  if (!lower_indexed_stack_temp_expression_to_x(context, *expression.left, temp, indexed_target,
                                                prepared_selector, line))
    return false;
  if (expression.op != "+" && expression.op != "*")
    context.emitter.emit_op(0x14, "X↔Y", "stack temp operand order", line);
  context.emitter.emit_op(opcode->first, opcode->second, "expr " + opcode->second, line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_aliases.clear();
  return true;
}

struct IndexedAssignmentConsumer {
  Expression target;
  Expression expression;
  int line = 0;
};

std::optional<IndexedAssignmentConsumer> indexed_assignment_consumer(const V2Statement& statement) {
  if (!statement.target.has_value())
    return std::nullopt;
  Expression target = parse_expression(*statement.target, statement.line);
  if (target.kind != "indexed")
    return std::nullopt;

  if (statement.kind == "v2_assign" && statement.expr.has_value()) {
    return IndexedAssignmentConsumer{
        .target = std::move(target),
        .expression = parse_expression(*statement.expr, statement.line),
        .line = statement.line,
    };
  }
  if (statement.kind == "v2_update" && statement.expr.has_value() && statement.op.has_value()) {
    Expression delta = parse_expression(*statement.expr, statement.line);
    if (*statement.op == "+=") {
      return IndexedAssignmentConsumer{
          .target = target,
          .expression = add_expression(std::move(target), std::move(delta)),
          .line = statement.line,
      };
    }
    if (*statement.op == "-=") {
      return IndexedAssignmentConsumer{
          .target = target,
          .expression = subtract_expression(std::move(target), std::move(delta)),
          .line = statement.line,
      };
    }
  }
  return std::nullopt;
}

bool is_unit_increment_expression(const Expression& expression, const std::string& pointer) {
  if (expression.kind != "binary" || expression.op != "+" || expression.left == nullptr ||
      expression.right == nullptr) {
    return false;
  }
  const auto is_pointer = [&](const Expression& candidate) {
    return candidate.kind == "identifier" && candidate.name == pointer;
  };
  return (is_pointer(*expression.left) && is_numeric_literal_value(*expression.right, 1)) ||
         (is_pointer(*expression.right) && is_numeric_literal_value(*expression.left, 1));
}

bool is_unit_increment_statement(const V2Statement& statement, const std::string& pointer) {
  return statement.kind == "v2_update" && statement.target.has_value() &&
         *statement.target == pointer && statement.op.has_value() && *statement.op == "+=" &&
         statement.expr.has_value() && expression_is_number(*statement.expr, "1", statement.line);
}

bool lower_preincrement_indexed_store(LoweringContext& context, const V2Statement& store_statement,
                                      const V2Statement& increment_statement) {
  const std::optional<IndexedAssignmentConsumer> store =
      indexed_assignment_consumer(store_statement);
  if (!store.has_value() || store->target.index == nullptr)
    return false;

  if (increment_statement.kind != "v2_update" || !increment_statement.target.has_value())
    return false;
  const std::string pointer = *increment_statement.target;
  if (!is_unit_increment_statement(increment_statement, pointer) ||
      !is_unit_increment_expression(*store->target.index, pointer)) {
    return false;
  }

  const auto pointer_register_it = context.register_index_by_name.find(pointer);
  if (pointer_register_it == context.register_index_by_name.end() ||
      !core::emit::lowering::is_preincrement_indirect_register(pointer_register_it->second)) {
    return false;
  }
  const V2StateField* field = indexed_state_field(context, store->target);
  if (field == nullptr)
    return false;
  const std::optional<int> selector_offset =
      indirect_memory_selector_offset_for_field(context, *field);
  if (!selector_offset.has_value() || *selector_offset != 0)
    return false;

  if (is_zero_expression(context, store->expression)) {
    if (!emit_zero(context, "set " + bank_member_key(store->target.base, store->target.field),
                   store->line)) {
      context.emitter.emit_number("0");
    }
  } else if (!lower_expression_to_x(context, store->expression)) {
    return false;
  }

  const int pointer_register = pointer_register_it->second;
  context.emitter.emit_op(0xb0 + pointer_register, "К X->П " + register_text_for(context, pointer),
                          "preincrement indexed set " +
                              bank_member_key(store->target.base, store->target.field),
                          store->line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_expression.reset();
  context.emitter.current_x_aliases.clear();
  context.emitter.current_x_known_zero = false;
  context.optimizations.push_back(OptimizationReport{
      .name = "preincrement-indexed-store",
      .detail = "Lowered " + bank_member_key(store->target.base, store->target.field) + "[" +
                pointer + "+1] and " + pointer + "++ through К X->П " +
                register_text_for(context, pointer) + " at line " + std::to_string(store->line) +
                ".",
  });
  return true;
}

std::optional<std::string> x_param_y_stack_stored_entry_target(const LoweringContext& context,
                                                               const std::string& rule_name,
                                                               const Expression& argument) {
  if (!context.x_param_y_stack_stored_entry || !analysis_simple_stack_load(argument))
    return std::nullopt;
  const auto y_stack_it = context.x_param_y_stack_procs.find(rule_name);
  const auto lowering_it = context.x_param_procs.find(rule_name);
  if (y_stack_it == context.x_param_y_stack_procs.end() ||
      lowering_it == context.x_param_procs.end() || lowering_it->second.kind != "copy" ||
      !lowering_it->second.first.target.has_value()) {
    return std::nullopt;
  }
  return *lowering_it->second.first.target;
}

bool can_compile_y_stack_producer_after_param_store(LoweringContext& context,
                                                    const V2Statement& producer,
                                                    const std::string& y_name,
                                                    const std::string& stored_target) {
  std::set<std::string> seen_rules;
  if (statement_first_identifier_access(context, producer, stored_target, seen_rules) !=
      IdentifierAccess::None)
    return false;
  if (producer.kind == "v2_assign" && producer.target.has_value() && producer.expr.has_value()) {
    const Expression target = parse_expression(*producer.target, producer.line);
    const Expression expression = parse_expression(*producer.expr, producer.line);
    return target.kind == "identifier" && target.name == y_name &&
           expression_pure_for_substitution(expression) &&
           !expression_contains_identifier(expression, y_name);
  }
  if (producer.kind == "v2_invoke" && producer.name.has_value()) {
    const auto rule_it = context.rules.find(*producer.name);
    return rule_it != context.rules.end() && rule_it->second != nullptr &&
           proc_return_x_variable(context, *rule_it->second) == y_name;
  }
  return false;
}

bool lower_y_stack_producer_after_param_store(LoweringContext& context, const V2Statement& producer,
                                              const std::string& y_name) {
  if (producer.kind == "v2_assign" && producer.expr.has_value()) {
    const Expression expression = parse_expression(*producer.expr, producer.line);
    if (!lower_expression_to_x(context, expression))
      return false;
    mark_current_x(context, y_name);
    return true;
  }
  if (producer.kind == "v2_invoke") {
    if (!lower_statement(context, producer, nullptr))
      return false;
    if (context.emitter.current_x_variable != y_name &&
        !context.emitter.current_x_aliases.contains(y_name)) {
      mark_current_x(context, y_name);
    }
    return true;
  }
  return false;
}

bool lower_x_param_y_stack_proc_call_run(LoweringContext& context,
                                         const std::vector<V2Statement>& statements,
                                         std::size_t index, std::size_t& consumed) {
  if (index + 1U >= statements.size())
    return false;
  const V2Statement& producer = statements.at(index);
  const V2Statement& call = statements.at(index + 1U);
  if (call.kind != "v2_invoke" || !call.name.has_value() || call.args.size() != 1)
    return false;
  const auto y_stack_it = context.x_param_y_stack_procs.find(*call.name);
  if (y_stack_it == context.x_param_y_stack_procs.end())
    return false;
  const auto rule_it = context.rules.find(*call.name);
  if (rule_it == context.rules.end() || rule_it->second == nullptr)
    return false;

  const Expression argument = parse_expression(call.args.front(), call.line);
  if (!analysis_simple_stack_load(argument))
    return false;
  const XParamYStackProcLowering& y_stack = y_stack_it->second;

  const std::optional<std::string> stored_entry =
      x_param_y_stack_stored_entry_target(context, *call.name, argument);
  if (stored_entry.has_value() && can_compile_y_stack_producer_after_param_store(
                                      context, producer, y_stack.y_name, *stored_entry)) {
    if (!lower_expression_to_x(context, argument))
      return false;
    emit_store(context, *stored_entry,
               "set " + *stored_entry + " from X parameter before y-stack entry");
    if (!lower_y_stack_producer_after_param_store(context, producer, y_stack.y_name))
      return false;
    context.emitter.emit_jump(0x53, "ПП", x_param_y_stack_stored_entry_label(*call.name),
                              "proc call " + *call.name + " y-stack entry", call.line);
    if (const std::optional<std::string> return_x =
            proc_return_x_variable(context, *rule_it->second)) {
      mark_current_x(context, *return_x);
      context.emitter.current_x_known_zero = false;
    } else {
      clear_current_x_facts(context);
    }
    context.optimizations.push_back(OptimizationReport{
        .name = "x-param-y-stack-stored-entry-call",
        .detail = "Stored " + y_stack.x_param + " before producing " + y_stack.y_name +
                  " and entered " + *call.name + " after its X-parameter prologue at line " +
                  std::to_string(call.line) + ".",
    });
    consumed = 2;
    return true;
  }

  if (producer.kind == "v2_invoke" && producer.name.has_value()) {
    const auto producer_rule_it = context.rules.find(*producer.name);
    if (producer_rule_it != context.rules.end() && producer_rule_it->second != nullptr &&
        proc_return_x_variable(context, *producer_rule_it->second) == y_stack.y_name) {
      if (!lower_statement(context, producer, nullptr))
        return false;
      if (context.emitter.current_x_variable != y_stack.y_name &&
          !context.emitter.current_x_aliases.contains(y_stack.y_name)) {
        mark_current_x(context, y_stack.y_name);
      }
      if (!lower_expression_to_x(context, argument))
        return false;
      const std::optional<std::string> previous_y = context.current_y_variable;
      context.current_y_variable = y_stack.y_name;
      context.emitter.emit_jump(0x53, "ПП", function_label(*call.name), "proc call " + *call.name,
                                call.line);
      context.current_y_variable = previous_y;
      if (const std::optional<std::string> return_x =
              proc_return_x_variable(context, *rule_it->second)) {
        mark_current_x(context, *return_x);
        context.emitter.current_x_known_zero = false;
      } else {
        clear_current_x_facts(context);
      }
      context.optimizations.push_back(OptimizationReport{
          .name = "x-param-y-stack-proc-call",
          .detail = "Passed " + y_stack.x_param + " in X while forwarding current " +
                    y_stack.y_name + " in Y for " + *call.name + " at line " +
                    std::to_string(call.line) + ".",
      });
      consumed = 2;
      return true;
    }
  }

  if (producer.kind != "v2_assign" || !producer.target.has_value() || !producer.expr.has_value())
    return false;
  const Expression producer_target = parse_expression(*producer.target, producer.line);
  const Expression producer_expression = parse_expression(*producer.expr, producer.line);
  if (producer_target.kind != "identifier" || producer_target.name != y_stack.y_name ||
      !expression_pure_for_substitution(producer_expression) ||
      expression_contains_identifier(producer_expression, y_stack.y_name)) {
    return false;
  }

  if (!lower_expression_to_x(context, producer_expression))
    return false;
  mark_current_x(context, y_stack.y_name);
  if (!lower_expression_to_x(context, argument))
    return false;
  const std::optional<std::string> previous_y = context.current_y_variable;
  context.current_y_variable = y_stack.y_name;
  context.emitter.emit_jump(0x53, "ПП", function_label(*call.name), "proc call " + *call.name,
                            call.line);
  context.current_y_variable = previous_y;
  if (const std::optional<std::string> return_x =
          proc_return_x_variable(context, *rule_it->second)) {
    mark_current_x(context, *return_x);
    context.emitter.current_x_known_zero = false;
  } else {
    clear_current_x_facts(context);
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "x-param-y-stack-proc-call",
      .detail = "Passed " + y_stack.x_param + " in X and kept " + y_stack.y_name + " in Y for " +
                *call.name + " at line " + std::to_string(call.line) + ".",
  });
  consumed = 2;
  return true;
}

bool lower_stack_only_call_return_consumer_run(LoweringContext& context,
                                               const std::vector<V2Statement>& statements,
                                               std::size_t index, std::size_t& consumed) {
  if (index + 1U >= statements.size())
    return false;
  const V2Statement& call = statements.at(index);
  const V2Statement& assignment = statements.at(index + 1U);
  if (call.kind != "v2_invoke" || !call.name.has_value() || assignment.kind != "v2_assign" ||
      !assignment.target.has_value() || !assignment.expr.has_value())
    return false;
  const auto rule_it = context.rules.find(*call.name);
  if (rule_it == context.rules.end() || rule_it->second == nullptr)
    return false;
  const std::optional<std::string> returned =
      proc_return_x_variable(context, *rule_it->second);
  if (!returned.has_value() || !context.stack_only_state_fields.contains(*returned))
    return false;
  const Expression expression = parse_expression(*assignment.expr, assignment.line);
  if (!stack_analysis_bit_or_update(expression, *assignment.target, *returned))
    return false;

  if (!lower_statement(context, call, &assignment))
    return false;
  if (context.emitter.current_x_variable != *returned &&
      !context.emitter.current_x_aliases.contains(*returned)) {
    mark_current_x(context, *returned);
  }
  emit_recall(context, *assignment.target);
  context.emitter.emit_op(0x38, "К ∨", "bit_or()", assignment.line);
  context.emitter.current_x_variable.reset();
  context.emitter.current_x_expression.reset();
  context.emitter.current_x_aliases.clear();
  context.emitter.current_x_known_zero = false;
  emit_store(context, *assignment.target, "set " + *assignment.target);
  consumed = 2;
  return true;
}

Expression substitute_expression_identifier(const Expression& expression, const std::string& name,
                                            const Expression& replacement) {
  if (expression.kind == "identifier" && expression.name == name)
    return replacement;

  Expression result = expression;
  if (expression.index != nullptr) {
    result.index = std::make_shared<Expression>(
        substitute_expression_identifier(*expression.index, name, replacement));
  }
  if (expression.expr != nullptr) {
    result.expr = std::make_shared<Expression>(
        substitute_expression_identifier(*expression.expr, name, replacement));
  }
  if (expression.left != nullptr) {
    result.left = std::make_shared<Expression>(
        substitute_expression_identifier(*expression.left, name, replacement));
  }
  if (expression.right != nullptr) {
    result.right = std::make_shared<Expression>(
        substitute_expression_identifier(*expression.right, name, replacement));
  }
  result.args.clear();
  result.args.reserve(expression.args.size());
  for (const Expression& arg : expression.args)
    result.args.push_back(substitute_expression_identifier(arg, name, replacement));
  return result;
}

std::optional<V2Predicate> substitute_predicate_identifier(const V2Predicate& predicate,
                                                           const std::string& name,
                                                           const Expression& replacement,
                                                           int source_line) {
  try {
    V2Predicate result = predicate;
    if (predicate.kind == "v2_compare") {
      result.left = expression_to_source(substitute_expression_identifier(
          parse_expression(predicate.left, source_line), name, replacement));
      result.right = expression_to_source(substitute_expression_identifier(
          parse_expression(predicate.right, source_line), name, replacement));
      return result;
    }
    if (predicate.kind == "v2_contains") {
      result.collection = expression_to_source(substitute_expression_identifier(
          parse_expression(predicate.collection, source_line), name, replacement));
      result.item = expression_to_source(substitute_expression_identifier(
          parse_expression(predicate.item, source_line), name, replacement));
      return result;
    }
  } catch (const std::exception&) {
    return std::nullopt;
  }
  return std::nullopt;
}

bool lower_guard_assignment_substitution(LoweringContext& context, const V2Statement& assign,
                                         const V2Statement& guarded,
                                         const V2Statement* after_guard) {
  if (context.program == nullptr || assign.kind != "v2_assign" || !assign.target.has_value() ||
      !assign.expr.has_value() || guarded.kind != "v2_if" || !guarded.predicate.has_value()) {
    return false;
  }

  const Expression target = parse_expression(*assign.target, assign.line);
  if (target.kind != "identifier")
    return false;
  const std::string& target_name = target.name;
  const int reads_in_condition =
      count_identifier_reads_in_predicate(*guarded.predicate, target_name, guarded.line);
  if (reads_in_condition == 0 ||
      count_identifier_reads_in_program(*context.program, target_name) != reads_in_condition) {
    return false;
  }

  const Expression assigned = parse_expression(*assign.expr, assign.line);
  if (!expression_pure_for_substitution(assigned))
    return false;
  const std::optional<V2Predicate> substituted =
      substitute_predicate_identifier(*guarded.predicate, target_name, assigned, guarded.line);
  if (!substituted.has_value())
    return false;

  const int ordinary_cost = guarded_estimate_expression_cost(assigned) + 1 +
                            guarded_condition_compile_cost(*guarded.predicate, guarded.line);
  const int substituted_cost = guarded_condition_compile_cost(*substituted, guarded.line);
  if (substituted_cost + 4 >= ordinary_cost)
    return false;

  V2Statement lowered = guarded;
  lowered.predicate = *substituted;
  if (!lower_statement(context, lowered, after_guard))
    return false;
  context.optimizations.push_back(OptimizationReport{
      .name = "single-use-guard-substitution",
      .detail = "Substituted " + target_name + " directly into the following condition at lines " +
                std::to_string(assign.line) + "/" + std::to_string(guarded.line) + ".",
  });
  return true;
}

bool lower_stack_resident_indexed_temp(LoweringContext& context,
                                       const std::vector<V2Statement>& statements,
                                       std::size_t start, std::size_t& consumed) {
  consumed = 0;
  if (!context.stack_resident_temps || start + 1U >= statements.size())
    return false;
  const V2Statement& temp = statements.at(start);
  const V2Statement& consumer_statement = statements.at(start + 1U);
  if (temp.kind != "v2_assign" || !temp.target.has_value() || !temp.expr.has_value())
    return false;
  const std::optional<IndexedAssignmentConsumer> parsed_consumer =
      indexed_assignment_consumer(consumer_statement);
  if (!parsed_consumer.has_value())
    return false;
  const IndexedAssignmentConsumer& consumer = *parsed_consumer;

  const Expression temp_expression = parse_expression(*temp.expr, temp.line);
  if (!expression_pure_for_substitution(temp_expression) ||
      expression_contains_identifier(temp_expression, *temp.target)) {
    return false;
  }
  const std::vector<V2Statement> tail(
      statements.begin() + static_cast<std::vector<V2Statement>::difference_type>(start + 2U),
      statements.end());
  if (statements_read_identifier_before_write(context, tail, *temp.target))
    return false;
  if (consumer.target.index != nullptr &&
      expression_contains_identifier(*consumer.target.index, *temp.target)) {
    return false;
  }
  if (!expression_references_same_indexed_cell(consumer.expression, consumer.target))
    return false;
  if (!can_compile_indexed_stack_temp_expression(consumer.expression, *temp.target))
    return false;

  std::optional<PreparedIndexedSelector> prepared_selector;
  if (consumer.target.index != nullptr &&
      !numeric_index_value(*consumer.target.index).has_value()) {
    prepared_selector = prepare_indirect_index_selector(context, consumer.target, consumer.line);
    if (!prepared_selector.has_value())
      return false;
  }

  if (!lower_expression_to_x(context, temp_expression))
    return false;
  mark_current_x(context, *temp.target);
  if (!lower_indexed_stack_temp_expression_to_x(context, consumer.expression, *temp.target,
                                                consumer.target, prepared_selector,
                                                consumer.line)) {
    return false;
  }
  if (prepared_selector.has_value()) {
    emit_prepared_indirect_indexed_store(context, consumer.target, *prepared_selector,
                                         consumer.line);
  } else if (!emit_indexed_store(context, consumer.target, consumer.line)) {
    return false;
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "stack-resident-indexed-temp",
      .detail = "Kept single-use temp " + *temp.target + " in X for the indexed update " +
                bank_member_key(consumer.target.base, consumer.target.field) + " at line " +
                std::to_string(consumer.line) + ".",
  });
  consumed = 2;
  return true;
}

bool stack_preserve_requires_rebuild(const V2Statement& statement) {
  if (statement.kind == "v2_if" || statement.kind == "v2_while" || statement.kind == "v2_match")
    return true;
  if (statement.kind == "v2_loop") {
    return std::any_of(statement.body.begin(), statement.body.end(), [](const V2Statement& child) {
      return stack_preserve_requires_rebuild(child);
    });
  }
  return true;
}

bool stack_preserve_region_requires_rebuild(const std::vector<V2Statement>& statements) {
  return std::any_of(statements.begin(), statements.end(), stack_preserve_requires_rebuild);
}

bool lower_stack_resident_consumer(LoweringContext& context, const V2Statement& consumer) {
  if (consumer.kind == "v2_assign" && consumer.target.has_value()) {
    if (context.stack_only_state_fields.contains(*consumer.target)) {
      mark_current_x(context, *consumer.target);
      report_stack_only_state_field(context, *consumer.target, consumer.line);
      return true;
    }
    emit_store(context, *consumer.target, "set " + *consumer.target);
    return true;
  }
  if (consumer.kind == "v2_stop") {
    context.emitter.emit_op(0x50, "С/П", "halt", consumer.line);
    return true;
  }
  if (consumer.kind == "v2_preview")
    return true;
  if (consumer.kind == "v2_return") {
    context.emitter.emit_op(0x52, "В/О", "return value", consumer.line);
    return true;
  }
  return false;
}

bool lower_stack_resident_temps(LoweringContext& context,
                                const std::vector<V2Statement>& statements, std::size_t start,
                                std::size_t& consumed) {
  consumed = 0;
  if (!context.stack_resident_temps)
    return false;
  const std::optional<core::emit::StackResidentFusionSite> site =
      core::emit::find_stack_resident_fusion_site(statements, start);
  if (!site.has_value())
    return false;

  std::vector<std::string> temp_names;
  temp_names.reserve(site->temps.size());
  for (const core::emit::StackResidentTempSegment& segment : site->temps) {
    if (!segment.assign.target.has_value() || !segment.assign.expr.has_value())
      return false;
    temp_names.push_back(*segment.assign.target);
  }
  if (!site->consumer.expr.has_value())
    return false;
  const Expression consumer_expression =
      parse_expression(*site->consumer.expr, site->consumer.line);
  if (!core::emit::can_lower_stack_resident_expression(consumer_expression, temp_names))
    return false;

  for (std::size_t index = 0; index < site->temps.size(); ++index) {
    const core::emit::StackResidentTempSegment& segment = site->temps.at(index);
    if (index > 0U) {
      context.emitter.emit_op(0x0e, "В↑",
                              "stack-resident lift " + *site->temps.at(index - 1U).assign.target,
                              segment.assign.line);
    }
    const Expression expression = parse_expression(*segment.assign.expr, segment.assign.line);
    if (!lower_expression_to_x(context, expression))
      return false;
    mark_current_x(context, *segment.assign.target);
    if (!segment.preserve_after.empty()) {
      if (!lower_statement_block(context, segment.preserve_after))
        return false;
      if (stack_preserve_region_requires_rebuild(segment.preserve_after)) {
        for (std::size_t rebuild = 0; rebuild <= index; ++rebuild) {
          if (rebuild > 0U) {
            context.emitter.emit_op(
                0x0e, "В↑", "stack-resident rebuild " + *site->temps.at(rebuild - 1U).assign.target,
                segment.assign.line);
          }
          const Expression rebuild_expression = parse_expression(
              *site->temps.at(rebuild).assign.expr, site->temps.at(rebuild).assign.line);
          if (!lower_expression_to_x(context, rebuild_expression))
            return false;
          mark_current_x(context, *site->temps.at(rebuild).assign.target);
        }
      }
    }
  }

  if (!lower_stack_resident_expression_to_x(context, consumer_expression, temp_names,
                                            site->consumer.line))
    return false;
  if (!lower_stack_resident_consumer(context, site->consumer))
    return false;

  context.optimizations.push_back(OptimizationReport{
      .name = site->crosses_control_flow ? "stack-resident-control-flow" : "stack-resident-temps",
      .detail = "Kept " + temp_names.front() + (temp_names.size() > 1U ? ", ..." : "") +
                " on the X/Y/Z/T stack for expression at line " +
                std::to_string(site->consumer.line) + ".",
  });
  if (!site->crosses_control_flow && temp_names.size() == 1U) {
    context.optimizations.push_back(OptimizationReport{
        .name = "stack-current-x-scheduling",
        .detail = "Kept single-use temp " + temp_names.front() + " in X for the following " +
                  expression_to_source(consumer_expression) + " at line " +
                  std::to_string(site->consumer.line) + ".",
    });
  }
  consumed = site->consumer_index - start + 1U;
  return consumed > 0U;
}

bool expression_calls_user_rule(const LoweringContext& context, const Expression& expression) {
  if (expression.kind == "call" && context.rules.contains(expression.callee))
    return true;
  if (expression.index != nullptr && expression_calls_user_rule(context, *expression.index))
    return true;
  if (expression.expr != nullptr && expression_calls_user_rule(context, *expression.expr))
    return true;
  if (expression.left != nullptr && expression_calls_user_rule(context, *expression.left))
    return true;
  if (expression.right != nullptr && expression_calls_user_rule(context, *expression.right))
    return true;
  return std::any_of(expression.args.begin(), expression.args.end(), [&](const Expression& arg) {
    return expression_calls_user_rule(context, arg);
  });
}

bool lower_single_use_stack_temp(LoweringContext& context,
                                 const std::vector<V2Statement>& statements, std::size_t start,
                                 std::size_t& consumed) {
  consumed = 0;
  if (start + 1U >= statements.size())
    return false;
  const V2Statement& temp = statements.at(start);
  const V2Statement& consumer = statements.at(start + 1U);
  if (temp.kind != "v2_assign" || !temp.target.has_value() || !temp.expr.has_value() ||
      consumer.kind != "v2_assign" || !consumer.target.has_value() || !consumer.expr.has_value()) {
    return false;
  }

  const Expression temp_expression = parse_expression(*temp.expr, temp.line);
  if (!expression_pure_for_substitution(temp_expression) ||
      expression_calls_user_rule(context, temp_expression) ||
      expression_contains_identifier(temp_expression, *temp.target)) {
    return false;
  }

  const Expression consumer_expression = parse_expression(*consumer.expr, consumer.line);
  if (core::emit::count_identifier_reads(consumer_expression, *temp.target) != 1 ||
      !can_compile_indexed_stack_temp_expression(consumer_expression, *temp.target)) {
    return false;
  }

  const std::vector<V2Statement> tail(
      statements.begin() + static_cast<std::vector<V2Statement>::difference_type>(start + 2U),
      statements.end());
  if (*consumer.target != *temp.target &&
      statements_read_identifier_before_write(context, tail, *temp.target)) {
    return false;
  }

  if (!lower_expression_to_x(context, temp_expression))
    return false;
  mark_current_x(context, *temp.target);
  if (!lower_stack_resident_expression_to_x(context, consumer_expression, {*temp.target},
                                            consumer.line)) {
    return false;
  }
  if (!lower_loop_carried_prompt_assignment(context, *consumer.target, consumer_expression,
                                            consumer.line)) {
    emit_store(context, *consumer.target, "set " + *consumer.target);
  }
  context.optimizations.push_back(OptimizationReport{
      .name = "stack-current-x-scheduling",
      .detail = "Kept single-use temp " + *temp.target + " in X for the following " +
                expression_to_source(consumer_expression) + " at line " +
                std::to_string(consumer.line) + ".",
  });
  consumed = 2;
  return true;
}

const V2Statement* coord_list_line_count_assignment_from_statement(LoweringContext& context,
                                                                   const V2Statement& statement) {
  if (statement.kind == "v2_assign" && statement.expr.has_value()) {
    const Expression expression = parse_expression(*statement.expr, statement.line);
    if (coord_list_line_count_call(context, expression).has_value())
      return &statement;
  }
  if (statement.kind != "v2_invoke" || !statement.name.has_value() ||
      !context.rules.contains(*statement.name))
    return nullptr;
  const V2Rule& rule = *context.rules.at(*statement.name);
  if (rule.body.size() != 1U)
    return nullptr;
  const V2Statement& only = rule.body.front();
  if (only.kind != "v2_assign" || !only.expr.has_value())
    return nullptr;
  const Expression expression = parse_expression(*only.expr, only.line);
  return coord_list_line_count_call(context, expression).has_value() ? &only : nullptr;
}

bool coord_list_fused_hit_body_allowed(LoweringContext& context,
                                       const std::vector<V2Statement>& statements,
                                       std::set<std::string>& seen_rules) {
  for (const V2Statement& statement : statements) {
    if (statement.kind == "v2_show")
      continue;
    if (statement.kind != "v2_invoke" || !statement.name.has_value() ||
        !context.rules.contains(*statement.name) || seen_rules.contains(*statement.name))
      return false;
    seen_rules.insert(*statement.name);
    const bool allowed = coord_list_fused_hit_body_allowed(
        context, context.rules.at(*statement.name)->body, seen_rules);
    seen_rules.erase(*statement.name);
    if (!allowed)
      return false;
  }
  return true;
}

bool lower_fused_coord_list_scan(LoweringContext& context,
                                 const std::vector<V2Statement>& statements, std::size_t index,
                                 std::size_t& consumed) {
  consumed = 0;
  if (index + 1U >= statements.size())
    return false;
  const V2Statement& branch = statements.at(index);
  const V2Statement& next = statements.at(index + 1U);
  if (branch.kind != "v2_if" || !branch.predicate.has_value() || !branch.else_body.empty())
    return false;
  std::set<std::string> seen_rules;
  if (!coord_list_fused_hit_body_allowed(context, branch.then_body, seen_rules))
    return false;

  const std::optional<CoordListCall> has_call =
      coord_list_has_condition_call(context, *branch.predicate, branch.line);
  const V2Statement* line_count = coord_list_line_count_assignment_from_statement(context, next);
  if (!has_call.has_value() || line_count == nullptr || !line_count->target.has_value() ||
      !line_count->expr.has_value())
    return false;
  const Expression line_count_expression = parse_expression(*line_count->expr, line_count->line);
  const std::optional<CoordListCall> line_count_call =
      coord_list_line_count_call(context, line_count_expression);
  if (!line_count_call.has_value() || !same_coord_list_call(*has_call, *line_count_call))
    return false;

  const std::optional<CoordListIndirectContext> indirect =
      coord_list_indirect_context(context, line_count_expression);
  if (!indirect.has_value() ||
      !context.register_index_by_name.contains(std::string(kCoordListCurrent)))
    return false;

  const bool scaled = context.scaled_coord_lists.contains(line_count_call->list_name);
  if (scaled && !scale_coord_list_cell_in_place(context, indirect->cell, branch.line))
    return false;
  const V2Statement* after_line_count =
      index + 2U < statements.size() ? &statements.at(index + 2U) : nullptr;
  const std::optional<FormattedCoordReportPlan> formatted_report =
      index + 3U == statements.size()
          ? formatted_coord_report_plan_after_line_count(context, *line_count->target,
                                                         line_count_expression, after_line_count)
          : std::nullopt;

  auto api = coord_list_emit_api(context);
  emit_coord_list_line_count_initial_total(context, *line_count->target, branch.line,
                                           formatted_report, "coord_list fused");
  core::emit::lowering::emit_coord_list_loop_setup(api, *indirect, branch.line);

  const std::string start_label = context.emitter.fresh_label("coord_list_fused_loop");
  const std::string hit_label = context.emitter.fresh_label("coord_list_fused_hit");
  const std::string visible_label = context.emitter.fresh_label("coord_list_fused_visible");
  const std::string count_next_label = context.emitter.fresh_label("coord_list_fused_next");
  context.emitter.emit_label(start_label);
  core::emit::lowering::emit_coord_list_indirect_recall(api, indirect->pointer, branch.line,
                                                        "coord_list fused candidate");
  emit_store(context, std::string(kCoordListCurrent), "coord_list fused current");
  if (context.removable_coord_lists.contains(line_count_call->list_name)) {
    emit_recall(context, std::string(kCoordListCurrent));
    if (!context.emitter.items.empty())
      context.emitter.items.back().comment = "coord_list fused candidate maybe removed";
    context.emitter.emit_jump(0x5c, "F x<0", count_next_label, "coord_list fused removed candidate",
                              branch.line);
  }

  if (!lower_expression_to_x(context, indirect->cell))
    return false;
  emit_recall(context, std::string(kCoordListCurrent));
  if (!context.emitter.items.empty())
    context.emitter.items.back().comment = "coord_list fused current";
  context.emitter.emit_op(0x11, "-", "coord_list fused hit compare", branch.line);
  context.emitter.emit_jump(0x57, "F x!=0", hit_label, "coord_list fused hit", branch.line);

  if (scaled) {
    if (!emit_scaled_coord_list_visibility_test(context, indirect->cell, visible_label,
                                                count_next_label, branch.line, "coord_list fused"))
      return false;
  } else {
    const Expression current = identifier_expression(std::string(kCoordListCurrent));
    if (!lower_coord_ones_digit_to_x(context, current, branch.line))
      return false;
    if (!lower_coord_ones_digit_to_x(context, indirect->cell, branch.line))
      return false;
    context.emitter.emit_op(0x11, "-", "coord_list fused dx", branch.line);
    context.emitter.emit_jump(0x57, "F x!=0", visible_label, "coord_list fused same column",
                              branch.line);
    if (!lower_coord_tens_digit_to_x(context, current, branch.line))
      return false;
    if (!lower_coord_tens_digit_to_x(context, indirect->cell, branch.line))
      return false;
    context.emitter.emit_op(0x11, "-", "coord_list fused dy", branch.line);
    context.emitter.emit_jump(0x57, "F x!=0", visible_label, "coord_list fused same row",
                              branch.line);
    context.emitter.emit_op(0x31, "К |x|", "coord_list fused |dy|", branch.line);
    context.emitter.emit_op(0x14, "<->", "coord_list fused dx", branch.line);
    context.emitter.emit_op(0x31, "К |x|", "coord_list fused |dx|", branch.line);
    context.emitter.emit_op(0x11, "-", "coord_list fused diagonal compare", branch.line);
    context.emitter.emit_jump(0x57, "F x!=0", visible_label, "coord_list fused same diagonal",
                              branch.line);
    context.emitter.emit_jump(0x51, "БП", count_next_label, "coord_list fused not visible",
                              branch.line);
  }

  context.emitter.emit_label(hit_label, {.hidden = true});
  if (!lower_statement_block(context, branch.then_body))
    return false;
  context.emitter.emit_label(visible_label, {.hidden = true});
  if (!emit_indirect_unit_increment(context, *line_count->target, "coord_list fused total",
                                    branch.line)) {
    emit_recall(context, *line_count->target);
    emit_number_or_preload(context, "1", "coord_list fused visible increment", branch.line);
    context.emitter.emit_op(0x10, "+", "coord_list fused add visible", branch.line);
    emit_store(context, *line_count->target, "coord_list fused total");
  }

  context.emitter.emit_label(count_next_label, {.hidden = true});
  core::emit::lowering::emit_coord_list_counter_loop(api, indirect->counter, start_label,
                                                     branch.line, "coord_list fused loop");
  emit_coord_list_line_count_result(context, *line_count->target, branch.line, formatted_report,
                                    "coord_list fused");
  context.optimizations.push_back(OptimizationReport{
      .name = scaled ? "coord-list-scaled-fused-hit-line-count" : "coord-list-fused-hit-line-count",
      .detail = scaled
                    ? "Fused coord_list membership and line_count through scaled decimal "
                      "coordinates at line " +
                          std::to_string(branch.line) + "."
                    : "Fused coord_list membership and line_count into one indirect scan at line " +
                          std::to_string(branch.line) + ".",
  });
  if (formatted_report.has_value()) {
    context.optimizations.push_back(OptimizationReport{
        .name = "coord-list-fused-formatted-report-body",
        .detail = "Accumulated " + *line_count->target +
                  " as a packed formatted report body during the fused scan at line " +
                  std::to_string(branch.line) + ".",
    });
  }
  consumed = 2;
  return true;
}

bool lower_statement_block(LoweringContext& context, const std::vector<V2Statement>& statements) {
  if (has_errors(context.diagnostics)) {
    for (std::size_t index = 0; index < statements.size(); ++index) {
      const V2Statement* next = index + 1U < statements.size() ? &statements.at(index + 1U) : nullptr;
      (void)lower_statement(context, statements.at(index), next);
    }
    return false;
  }

  for (std::size_t index = 0; index < statements.size(); ++index) {
    std::size_t coord_list_consumed = 0;
    if (lower_fused_coord_list_scan(context, statements, index, coord_list_consumed)) {
      index += coord_list_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    std::size_t x_param_y_stack_consumed = 0;
    if (lower_x_param_y_stack_proc_call_run(context, statements, index, x_param_y_stack_consumed)) {
      index += x_param_y_stack_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    std::size_t packed_score_accumulation_consumed = 0;
    if (lower_x_param_proc_packed_score_accumulation_run(context, statements, index,
                                                         packed_score_accumulation_consumed)) {
      index += packed_score_accumulation_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    std::size_t stack_only_return_consumed = 0;
    if (lower_stack_only_call_return_consumer_run(context, statements, index,
                                                  stack_only_return_consumed)) {
      index += stack_only_return_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    std::size_t repeated_x_param_consumed = 0;
    if (lower_repeated_x_param_self_assignment_run(context, statements, index,
                                                   repeated_x_param_consumed)) {
      index += repeated_x_param_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    std::size_t delayed_underflow_consumed = 0;
    if (lower_delayed_unit_decrement_underflow_guard_run(context, statements, index,
                                                         delayed_underflow_consumed)) {
      index += delayed_underflow_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    std::size_t prior_random_consumed = 0;
    if (lower_prior_random_fractional_decrement_run(context, statements, index,
                                                    prior_random_consumed)) {
      index += prior_random_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    prior_random_consumed = 0;
    if (lower_prior_random_stack_reuse_run(context, statements, index, prior_random_consumed)) {
      index += prior_random_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    prior_random_consumed = 0;
    if (lower_prior_random_branch_stack_reuse_run(context, statements, index,
                                                  prior_random_consumed)) {
      index += prior_random_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    std::size_t stack_resident_consumed = 0;
    if (lower_stack_resident_indexed_temp(context, statements, index, stack_resident_consumed)) {
      index += stack_resident_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    stack_resident_consumed = 0;
    if (lower_stack_resident_temps(context, statements, index, stack_resident_consumed)) {
      index += stack_resident_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;

    if (context.dead_source_residual_temp_reuse) {
      std::size_t residual_temp_consumed = 0;
      if (lower_dead_source_residual_temp_reuse(context, statements, index,
                                                residual_temp_consumed)) {
        index += residual_temp_consumed - 1;
        continue;
      }
    }
    if (has_errors(context.diagnostics))
      return false;

    std::size_t counted_consumed = 0;
    if (lower_repeated_assignment_counted_loop_reuse_run(context, statements, index,
                                                         counted_consumed)) {
      index += counted_consumed - 1;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    counted_consumed = 0;
    if (lower_setup_only_counted_while(context, statements, index, counted_consumed)) {
      index += counted_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    counted_consumed = 0;
    if (lower_initialized_counted_while_run(context, statements, index, counted_consumed)) {
      index += counted_consumed - 1;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    std::size_t repeated_assignment_consumed = 0;
    if (lower_repeated_assignment_value_run(context, statements, index,
                                            repeated_assignment_consumed)) {
      index += repeated_assignment_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    std::size_t stack_unary_consumed = 0;
    if (lower_stack_unary_derived_assignments_run(context, statements, index,
                                                  stack_unary_consumed)) {
      index += stack_unary_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    std::size_t single_use_stack_temp_consumed = 0;
    if (lower_single_use_stack_temp(context, statements, index, single_use_stack_temp_consumed)) {
      index += single_use_stack_temp_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size()) {
      const V2Statement* after_guard =
          index + 2U < statements.size() ? &statements.at(index + 2U) : nullptr;
      if (lower_guard_assignment_substitution(context, statements.at(index),
                                              statements.at(index + 1U), after_guard)) {
        ++index;
        continue;
      }
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_max_assign_equality_branch(context, statements.at(index),
                                         statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_indexed_packed_pow10_delta_report_branch(context, statements.at(index),
                                                       statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_bit_or_test_and_set_branch(context, statements.at(index),
                                         statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_branch_local_delayed_unit_decrement_guard(context, statements.at(index),
                                                        statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_decrement_test_pair(context, statements.at(index), statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_one_based_modulo_normalization(context, statements.at(index),
                                             statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_int_frac_shared_tail(context, statements.at(index), statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_terminal_display_fusion(context, statements.at(index), statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    std::size_t show_read_decrement_consumed = 0;
    if (lower_show_read_guarded_transfer(context, statements, index,
                                         show_read_decrement_consumed)) {
      index += show_read_decrement_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    show_read_decrement_consumed = 0;
    if (lower_show_read_decrement_underflow_fusion(context, statements, index,
                                                   show_read_decrement_consumed)) {
      index += show_read_decrement_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 2U < statements.size() &&
        lower_show_read_stack_stop_risk_result(context, statements.at(index),
                                               &statements.at(index + 1U),
                                               statements.at(index + 2U))) {
      index += 2U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_show_read_stack_stop_risk_result(context, statements.at(index), nullptr,
                                               statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    std::size_t ephemeral_input_consumed = 0;
    if (lower_ephemeral_input_branch(context, statements, index, ephemeral_input_consumed)) {
      index += ephemeral_input_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    ephemeral_input_consumed = 0;
    if (lower_ephemeral_input_dispatch(context, statements, index, ephemeral_input_consumed)) {
      index += ephemeral_input_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    std::size_t show_sequence_consumed = 0;
    if (lower_show_sequence_read(context, statements, index, show_sequence_consumed)) {
      index += show_sequence_consumed - 1U;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_show_read_assign_fusion(context, statements.at(index), statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_show_read_fusion(context, statements.at(index), statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_assign_then_domain_trap(context, statements.at(index), statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_assign_zero_fallback_store(context, statements.at(index),
                                         statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_preincrement_indexed_store(context, statements.at(index),
                                         statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_grid_cell_mask_reuse(context, statements.at(index), statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_adjacent_cells_set_mask_reuse(context, statements.at(index),
                                            statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_single_bit_mask_op_copy_reuse(context, statements.at(index),
                                            statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    if (index + 1U < statements.size() &&
        lower_arithmetic_if_double_clamp(context, statements.at(index),
                                         statements.at(index + 1U))) {
      ++index;
      continue;
    }
    if (has_errors(context.diagnostics))
      return false;
    const V2Statement* next = index + 1U < statements.size() ? &statements.at(index + 1U) : nullptr;
    const std::optional<std::string> next_show_target =
        next == nullptr ? std::nullopt : simple_show_target(*next);
    if (next_show_target.has_value() &&
        context.transient_show_targets.contains(*next_show_target) &&
        statement_tail_assigns_or_stops(context, statements.at(index), *next_show_target)) {
      const std::optional<std::string> previous_tail_show_target = context.tail_show_target;
      context.tail_show_target = *next_show_target;
      if (!lower_statement(context, statements.at(index), next))
        return false;
      context.tail_show_target = previous_tail_show_target;
      const V2Statement* after_show =
          index + 2U < statements.size() ? &statements.at(index + 2U) : nullptr;
      if (!lower_statement(context, *next, after_show))
        return false;
      ++index;
      continue;
    }
    if (!lower_statement(context, statements.at(index), next))
      return false;
  }
  return true;
}

bool lower_terminal_tail_helpers(LoweringContext& context) {
  for (std::size_t index = 0; index < context.terminal_tail_helpers.size(); ++index) {
    const TerminalTailHelperRequest helper = context.terminal_tail_helpers.at(index);
    context.emitter.emit_label(helper.label, {.hidden = true});
    if (!lower_statement_block(context, helper.body))
      return false;
    context.optimizations.push_back(OptimizationReport{
        .name = "local-terminal-tail",
        .detail =
            "Emitted local terminal tail for branch at line " + std::to_string(helper.line) + ".",
    });
  }
  return true;
}

bool lower_packed_display_helpers(LoweringContext& context) {
  for (const PackedDisplayHelperRequest& helper : context.packed_display_helpers) {
    if (!helper.statement.items.has_value())
      return false;
    const std::optional<std::vector<PackedDisplayField>> fields =
        numeric_display_fields(context, *helper.statement.items);
    if (!fields.has_value()) {
      if (const std::optional<std::string> literal =
              unlowerable_decimal_display_literal(*helper.statement.items)) {
        const std::string screen =
            helper.statement.inline_name.value_or(helper.statement.name.value_or("display"));
        context.diagnostics.push_back(diagnostic(DiagnosticSeverity::Error, "native-unsupported",
                                                 "Screen '" + screen +
                                                     "' contains display literal \"" + *literal +
                                                     "\" that is not lowerable yet."));
      }
      return false;
    }

    context.emitter.emit_label(
        helper.label,
        {.procedure_boundary = "start", .procedure_name = helper.label, .hidden = true});
    const bool previous = context.emitting_packed_display_helper;
    context.emitting_packed_display_helper = true;
    clear_current_x_facts(context);
    const bool lowered = lower_packed_display_fields_in_order(context, *fields, helper.line, false);
    context.emitting_packed_display_helper = previous;
    if (!lowered)
      return false;
    context.emitter.emit_op(0x50, "С/П", "show", helper.line);
    context.emitter.emit_op(0x52, "В/О", "packed display return", helper.line);
    context.optimizations.push_back(OptimizationReport{
        .name = "packed-display-helper",
        .detail =
            "Emitted shared packed display helper at line " + std::to_string(helper.line) + ".",
    });
  }
  return true;
}

